-- Poems batch 117
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('930fdb3e-1512-46c6-ba65-b7d3e5ba52bc','河南張應之東齋','梅堯臣','宋','宋诗','song-poetry','','[]','昔我居此時，鑿池通竹圃。',48,'全唐诗/poet.song.13000.json','["昔我居此時，鑿池通竹圃。", "池清少游魚，林淺無棲羽。", "至今寒窗風，靜送枯荷雨。", "雨歇吏人稀，知君獨吟苦。"]'),
('864adad9-a8a5-47f2-b581-7f44a6e877ec','河南王尉西齋','梅堯臣','宋','宋诗','song-poetry','','[]','官舍古城隅，西齋何寂寂。',72,'全唐诗/poet.song.13000.json','["官舍古城隅，西齋何寂寂。", "種竹幽趣深，開屏翠光滴。", "青山露南牆，落日明東壁。", "危臺起其傍，平隰坐可覿。", "幾暮野田空，天高霜隼擊。", "更憐風月時，幾弄林間笛。"]'),
('a061ea43-4801-4527-94c1-1f73862d0790','劉秀才歸河內','梅堯臣','宋','宋诗','song-poetry','','[]','君家太行下，應復近蘇門。',48,'全唐诗/poet.song.13000.json','["君家太行下，應復近蘇門。", "河氣知寒早，嵐煙覺暮昏。", "犬鳴林外火，笛響月中村。", "久作山陽客，逢人爲寄言。"]'),
('b0d5b3a4-13d1-4dd6-8976-e5e7cc1d3b04','憶洛中舊居寄永叔兼簡師魯彥國','梅堯臣','宋','宋诗','song-poetry','','[]','東堂石榴下，夜飲曉未還。',96,'全唐诗/poet.song.13000.json','["東堂石榴下，夜飲曉未還。", "絺衣濕浩露，桂酒生朱顔。", "君同尹與富，高論曾莫攀。", "開吐仁義奧，傲倪天地間。", "以此爲朋樂，衡門未嘗關。", "自從北闕來，擾擾時少閑。", "登危欲引望，尚不見雲山。", "何由覿夫子，客袂淚瀾斑。"]'),
('6517f2a8-e272-458a-8a29-092a35ba15d5','武陵行','梅堯臣','宋','宋诗','song-poetry','','[]','生事在漁樵，所居亦烟水。',264,'全唐诗/poet.song.13000.json','["生事在漁樵，所居亦烟水。", "野艇一竿絲，朝朝狎清泚。", "忽自傍藤陰，乘流轉山觜。", "始覺景氣佳，潛通小溪裏。", "常時不見春，入谷驚紅蕊。", "幽興窮綠波，翫芳心莫已。", "花外一峯明，林間碧洞啟。", "遥聞雞犬音，漸悟人煙邇。", "捨舟遂潛行，石徑劣容屣。", "豁然有田園，竹果相叢倚。", "厖眉髽髻人，倏遇心顔喜。", "尚作秦衣裳，那知漢名氏。", "自言逢世亂，避地因居此。", "來時手種桃，今日開如綺。", "更看水上花，幾度逐風委。", "競引飯彫胡，邀飲酌瓊醴。", "復呼童稚前，綠鬢仍皓齒。", "翻遣念還茅，思歸釣鱣鮪。", "將辭亦贈言，勿道丘壑美。", "鼓枻出僊源，繁英猶邐迤。", "薄暮返蒼洲，微風吹白芷。", "他日欲重過，茫茫何處是。"]'),
('1e51a828-c8fa-4fcc-8c45-00110c639a57','西宮怨','梅堯臣','宋','宋诗','song-poetry','','[]','漢宮中選時，天下誰爲校。',48,'全唐诗/poet.song.13000.json','["漢宮中選時，天下誰爲校。", "寵至莫言非，恩移難恃貌。", "一朝居別館，悔妬何由效。", "買賦豈無金，其如君不樂。"]'),
('458cd010-800a-4a1b-902b-23203f951a99','夏夜小亭有懷','梅堯臣','宋','宋诗','song-poetry','','[]','西南雨氣濃，林上昏月色。',24,'全唐诗/poet.song.13000.json','["西南雨氣濃，林上昏月色。", "寒影不隨人，寥寥空露白。"]'),
('b8df5344-0af0-406f-b334-d2cc396a3c9a','外兄施伯侃下第赴并門叔父招','梅堯臣','宋','宋诗','song-poetry','','[]','共是干時者，同爲失意人。',48,'全唐诗/poet.song.13000.json','["共是干時者，同爲失意人。", "言趨太原召，如慰宛陵親。", "茄鼓聽臨塞，琴書未離身。", "別君無斗酒，當識士安貧。"]'),
('83f9fa93-2272-4413-b45f-15d939b5b074','鄭戭及第東歸後赴洋州幕','梅堯臣','宋','宋诗','song-poetry','','[]','却生方得桂，王粲始從戎。',48,'全唐诗/poet.song.13000.json','["却生方得桂，王粲始從戎。", "一舸辭吳會，單車入漢中。", "亂山雲木古，側徑野泉通。", "欲識風煙美，心知故國同。"]'),
('8ca77f26-ee90-49bd-ade6-55d669669ad2','施判官赴饒州','梅堯臣','宋','宋诗','song-poetry','','[]','昔日里中舊，今爲幙下英。',48,'全唐诗/poet.song.13000.json','["昔日里中舊，今爲幙下英。", "煙波歸楚國，風月滿都城。", "食有江魚美，時無羽檄驚。", "他年儻行縣，肯使折腰迎。"]'),
('c1abd621-fd23-46d5-bff7-b0665b14b752','楊畋赴官并州','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞地近胡，寒氣盛中都。',48,'全唐诗/poet.song.13000.json','["嘗聞地近胡，寒氣盛中都。", "車馬行臨塞，關山見落榆。", "吳鉤皆尚壯，章甫幾爲儒。", "寄謝西曹掾，能吟秀句無。"]'),
('f826a29c-7291-4c7a-9b0d-209a6b699dd1','歐陽寺丞桐城宰','梅堯臣','宋','宋诗','song-poetry','','[]','葉落淮南樹，青山徧馬頭。',48,'全唐诗/poet.song.13000.json','["葉落淮南樹，青山徧馬頭。", "人煙將近郭，松竹不知秋。", "夜虎林間嘯，溪泉舍下流。", "門前仲卿廟，遺跡待君求。"]'),
('9967cfe8-3ee8-4f06-b1ba-d6e66332b9f6','祝熙載赴任東陽','梅堯臣','宋','宋诗','song-poetry','','[]','東陽美山水，之子本風流。',48,'全唐诗/poet.song.13000.json','["東陽美山水，之子本風流。", "稍去何平叔，還追沈隠侯。", "清江飛晚雨，斜日半滄洲。", "縣道行無愧，煙蘿有勝遊。"]'),
('82aca136-6d80-4cf8-9f90-0b36f82940c4','彥國通判絳州','梅堯臣','宋','宋诗','song-poetry','','[]','結交時未久，情親心已照。',120,'全唐诗/poet.song.13000.json','["結交時未久，情親心已照。", "氛埃外自遣，風月還同調。", "復與任浮沉，未嘗趨近要。", "以此雖處貧，寧防俗者誚。", "今將辭我去，盡日來談笑。", "窮巷敞茅茨，高言出廊廟。", "且作朱韍行，聊能發光耀。", "當亦就銅墨，遠之江海徼。", "山郭寂無喧，雲川不妨釣。", "所嗟胡越人，千里煩登眺。"]'),
('7f8ba14d-d14e-4a56-9711-85bd8b57c87a','餘姚陳寺丞','梅堯臣','宋','宋诗','song-poetry','','[]','試邑來勾越，風煙復上游。',48,'全唐诗/poet.song.13000.json','["試邑來勾越，風煙復上游。", "江潮自迎客，山月亦隨舟。", "海貨通閭市，漁歌入縣樓。", "絃琴無外事，坐見浦帆收。"]'),
('ba4a73cf-332e-4a6e-b4fd-6b53d0b4da05','明州推官鄭先輩','梅堯臣','宋','宋诗','song-poetry','','[]','應幕海邊郡，秋風千里歸。',48,'全唐诗/poet.song.13000.json','["應幕海邊郡，秋風千里歸。", "隨潮吳榜駛，轉浦楚山微。", "野橘霜前熟，江螯露下肥。", "還家候靈鵲，人想罷鳴機。"]'),
('056bed4c-0682-474f-bfbc-b75e85fc90c7','聚蚊','梅堯臣','宋','宋诗','song-poetry','','[]','日落月復昏，飛蚊稍離隙。',144,'全唐诗/poet.song.13000.json','["日落月復昏，飛蚊稍離隙。", "聚空雷殷殷，舞庭煙冪冪。", "蛛網徒爾施，螗斧詎能磔。", "猛蝎亦助惡，腹毒將肆螫。", "不能有兩翅，索索緣暗壁。", "貴人居大第，蛟綃圍枕席。", "嗟爾於其中，寧夸觜如戟。", "忍哉傍窮困，曾未哀癯瘠。", "利吻競相侵，飲血自求益。", "蝙蝠空翱翔，何嘗爲屏獲。", "鳴蟬飽風露，亦不慙喙息。", "薨薨勿久恃，會有東方白。"]'),
('f351e714-c8d6-42b0-8d9c-c5fe88a03dc2','賦秋鴻送劉衡州','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋鴻整羽翮，去就自因時。',120,'全唐诗/poet.song.13000.json','["秋鴻整羽翮，去就自因時。", "往春南方來，遂止天泉池。", "天泉水清泚，鴛鷺日追隨。", "蒲藻豈不樂，江湖信所宜。", "今朝風色便，塹向衡陽歸。", "洞庭逢葉下，瀟湘先客飛。", "渚有蘭杜美，心無稻粱卑。", "罾繳勿爾念，鷹隼寧爾窺。", "煙波千萬里，足以資盤嬉。", "峯前想回日，青冥生路歧。"]'),
('fcc40f6e-590c-4a82-af28-afd2dd14bb4b','清池','梅堯臣','宋','宋诗','song-poetry','','[]','泠泠清水池，藻荇何參差。',120,'全唐诗/poet.song.13000.json','["泠泠清水池，藻荇何參差。", "美人留采掇，玉鮪自揚鬐。", "波瀾日已淺，龜鼈日復滋。", "蝦蟆縱跳梁，得以緣其涯。", "競此長科斗，凌亂滿澄漪。", "空有文字質，非無簡策施。", "僊鯉勿苦羨，寧將蠯蛤卑。", "徒剖腹中書，悠悠誰爾知。", "聊保性命理，遠潛江海湄。", "泚泚曷足道，任彼蛙黽爲。"]'),
('523b727b-ba99-4937-9e51-1aab941c3020','弟得臣歸覲并州','梅堯臣','宋','宋诗','song-poetry','','[]','知君歸去心，已逐秋風起。',48,'全唐诗/poet.song.13000.json','["知君歸去心，已逐秋風起。", "明發登太行，遠將望汾水。", "藹藹白雲下，吾親正居此。", "拜慶曷爲榮，新除一官美。"]'),
('935dac8c-854f-4009-96c8-46149ba0181e','張脩赴威勝軍判官','梅堯臣','宋','宋诗','song-poetry','','[]','青驪渡河水，俠氣動刀環。',48,'全唐诗/poet.song.13000.json','["青驪渡河水，俠氣動刀環。", "入幕沙塵暗，臨風鼓角閑。", "地形通栢谷，秋色滿榆關。", "誰復輕儒者，難淹筆硯間。"]'),
('7623d499-433c-40e2-ab43-e6ade0d32e45','弔唐俞','梅堯臣','宋','宋诗','song-poetry','','[]','通閨年最少，才俊罕能雙。',48,'全唐诗/poet.song.13000.json','["通閨年最少，才俊罕能雙。", "鵩去塵棲室，魂歸霧起窗。", "慈親流漢水，愛妾返荆江。", "一稚纔能語，煢然寄遠邦。"]'),
('bb19c8dd-dc20-45b8-bea7-7af25ce7ade2','任適尉烏程','梅堯臣','宋','宋诗','song-poetry','','[]','俛作程鄉尉，折腰還自甘。',48,'全唐诗/poet.song.13000.json','["俛作程鄉尉，折腰還自甘。", "卞峰晴照黛，霅水曉澄藍。", "葑上春田闢，蘆中走吏參。", "到時蘋葉長，柳惲在江南。"]'),
('13eac176-104c-404f-bb1f-b1848401ac4c','馬殿丞通判密州','梅堯臣','宋','宋诗','song-poetry','','[]','晨裝辭北闕，懷紱貳東侯。',48,'全唐诗/poet.song.13000.json','["晨裝辭北闕，懷紱貳東侯。", "地本全齊勝，風仍變魯優。", "危帆淮上去，古木海邊秋。", "相送江潭客，曾同十載遊。"]'),
('19b79998-0c82-40b0-9bb4-c7c3b333a7fd','夏侯彥濟武陟主簿','梅堯臣','宋','宋诗','song-poetry','','[]','懷縣曾余往，風謠爲爾知。',48,'全唐诗/poet.song.13000.json','["懷縣曾余往，風謠爲爾知。", "寒先太行近，潤接大河卑。", "賓酒栽公秫，晨羹翦露葵。", "簿書行正委，何似布衣時。"]'),
('5afa048b-9f4b-4536-99f9-78b4356cc0ab','余居御橋南夜聞妖鳥鳴效昌黎體','梅堯臣','宋','宋诗','song-poetry','','[]','都城夜半陰雲黑，忽聞轉轂聲咿呦。',144,'全唐诗/poet.song.13000.json','["都城夜半陰雲黑，忽聞轉轂聲咿呦。", "嘗憶楚鄉有妖鳥，一身九首如贅疣。", "或時月暗過閭里，緩音低語若有求。", "小兒藏頭婦滅火，閉門雞犬不爾留。", "我問楚俗何苦爾，云是鬼車載鬼遊。", "鬼車載鬼奚所及，抽人之筋繫車輈。", "昔聽此言未能信，欲訪上天終無由。", "今來中土百物正，安得遂與南方儔。", "上帝因風如可達，願令驅逐出九州。"]'),
('25eccc35-2299-4272-b2f5-1774b1f5cd65','月夜與兄公度納凉閑行至御橋','梅堯臣','宋','宋诗','song-poetry','','[]','夕月吐澄明，陰雲浄如掃。',120,'全唐诗/poet.song.13000.json','["夕月吐澄明，陰雲浄如掃。", "空庭引天翠，爽氣生懷抱。", "家近御橋頭，因爲橋畔遊。", "倚欄波上影，不共水東流。", "思歸此清夜，何處是江樓。", "四望遠寂歷，微風動颼飀。", "觀闕垂萬象，山河趨九州。", "壯哉帝王宅，顧我一蜉蝣。", "富貴非可取，田園今向秋。", "明當拂衣去，試與問扁舟。"]'),
('b200e64a-1054-4861-8f49-f12e6d5e29bd','隨州錢相公挽歌三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','築巖無往夢，遊岱有飛魂。',48,'全唐诗/poet.song.13000.json','["築巖無往夢，遊岱有飛魂。", "墮淚隋侯國，遺金漢帝恩。", "文章留日域，忠孝在王門。", "天道何由問，秋風徧九原。"]'),
('c7d20770-807c-4fde-b616-7a3899410638','隨州錢相公挽歌三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','昔日傷歸國，今朝歎舉輀。',48,'全唐诗/poet.song.13000.json','["昔日傷歸國，今朝歎舉輀。", "憂愁傳楚些，殄悴感周詩。", "文草明時訪，忠言故吏知。", "居常嗚咽涕，翻作衆人悲。"]'),
('e8e45463-1775-4ea9-9198-80fc03f26418','隨州錢相公挽歌三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','去年伊水上，傾府望雲岑。',48,'全唐诗/poet.song.13000.json','["去年伊水上，傾府望雲岑。", "路轉猶迴首，人誰不殞心。", "可憐飛語後，擠恨九幽深。", "從此埋英骨，空令淚滿襟。"]'),
('7738bad1-0a9d-4e5b-9969-cd08da0443e4','僧可真東歸因謁范蘇州','梅堯臣','宋','宋诗','song-poetry','','[]','姑蘇臺畔去，雲壑付清機。',48,'全唐诗/poet.song.13000.json','["姑蘇臺畔去，雲壑付清機。", "野策過寒水，山童護衲衣。", "松門正投宿，竹笠带餘暉。", "誰愛杼山句，使君應性韋。"]'),
('b0528b5a-bce8-4591-9e2f-0b45a06c49d8','廖秀才歸衡山縣','梅堯臣','宋','宋诗','song-poetry','','["\u8861\u5c71"]','千里倦爲客，秋歸烏榜輕。',48,'全唐诗/poet.song.13000.json','["千里倦爲客，秋歸烏榜輕。", "過林湘橘暗，收潦楚江清。", "晚泊親鷗鷺，殘芳襲杜蘅。", "長沙幾日到，天際見高城。"]'),
('8c284c29-a877-40dd-bfd7-01a2906d44ad','魏屯田知楚州','梅堯臣','宋','宋诗','song-poetry','','[]','淮南木葉驚，淮上使君行。',48,'全唐诗/poet.song.13000.json','["淮南木葉驚，淮上使君行。", "天外高帆出，沙頭候吏迎。", "夜潮通廢埭，秋月滿孤城。", "正遲文翁化，從來楚俗輕。"]'),
('e3c13be3-1925-4c86-ad56-c6be8eb52ca1','張子野赴官鄭州','梅堯臣','宋','宋诗','song-poetry','','[]','盡室寄東里，一官辭上都。',48,'全唐诗/poet.song.13000.json','["盡室寄東里，一官辭上都。", "只應乘小駟，寧肯躡雙鳬。", "秋雨生陂水，高風落廟梧。", "梅山爲余訪，還有舊家無。"]'),
('1f8048bc-59e5-4468-a517-6c436e123099','擬王維偶然作','梅堯臣','宋','宋诗','song-poetry','','[]','嵇康任天性，傲散喜端居。',96,'全唐诗/poet.song.13000.json','["嵇康任天性，傲散喜端居。", "自云安卑者，竊比老莊歟。", "一月十五日，頭面忘洗梳。", "危坐恣搔虱，於時懶作書。", "一曲情自寄，一杯歡有餘。", "尚子志所慕，阮生甘不如。", "黄精可養壽，廣澤宜覩魚。", "不堪行作吏，章服裹猿狙。"]'),
('5055fb54-a315-41cf-88cb-22c422618bf9','蘇祠部通判洪州','梅堯臣','宋','宋诗','song-poetry','','[]','飛鷁去江西，秋飈滿桂旗。',48,'全唐诗/poet.song.13000.json','["飛鷁去江西，秋飈滿桂旗。", "蘆洲花白處，楓岸葉丹時。", "沙鳥看來沒，雲山愛後移。", "高才屬滕閣，家擅子卿詩。"]'),
('dbe033cf-345f-47c6-903c-c523e3e940ec','中秋與希深別後月下寄','梅堯臣','宋','宋诗','song-poetry','','[]','薄霧生寒水，寥寥艤畫船。',48,'全唐诗/poet.song.13000.json','["薄霧生寒水，寥寥艤畫船。", "人傷千里別，桂吐十分圓。", "把酒非前夕，追歡憶去年。", "南樓足佳興，好在謝林川。"]'),
('7c4b1d64-07de-4734-bf79-53a8f5e67a8c','望芒碭山','梅堯臣','宋','宋诗','song-poetry','','[]','出舟跳古岸，林外見脩岡。',96,'全唐诗/poet.song.13000.json','["出舟跳古岸，林外見脩岡。", "迴頭問榜子，前巘是芒碭。", "其顛有高廟，松柏鬰蒼蒼。", "迤邐堆阜屬，蕭條茆葉黄。", "千古收王氣，一川平夕陽。", "人家纔四五，雞犬自相望。", "尚爾想新豐，誰復思沛鄉。", "臨流一舉酒，可以喻悲傷。"]'),
('ff76331b-2087-4b6f-bf5f-0ee087bac78c','初見淮山','梅堯臣','宋','宋诗','song-poetry','','[]','遊宦久去國，扁舟今始還。',48,'全唐诗/poet.song.13000.json','["遊宦久去國，扁舟今始還。", "朝來汴口望，喜見淮上山。", "斷嶺碧峯出，平沙白鳥閑。", "南歸不厭遠，况在水雲間。"]'),
('f31e2962-c3e6-47b2-8c27-f2d9480ddc0e','旌義港阻風','梅堯臣','宋','宋诗','song-poetry','','[]','清晨下長淮，忽值秋風惡。',120,'全唐诗/poet.song.13000.json','["清晨下長淮，忽值秋風惡。", "渺瀰雲霧昏，掀合魚龍作。", "方驚白浪高，又以寒潮落。", "遠渚時出沒，輕舟自前却。", "將投古戍迷，偶得孤港泊。", "下纜寄蘆林，尋村步芒屩。", "儻有白醪沽，聊爲野田酌。", "茆屋何颼颼，瓦罌空索索。", "却持杖頭歸，相顧還寂寞。", "一夕不能眠，孤吟當狂藥。"]'),
('6348345b-55e1-43c8-9935-a3f3779d75d5','依韻和劉六淮潮','梅堯臣','宋','宋诗','song-poetry','','[]','汐潮如有信，時向舊痕生。',48,'全唐诗/poet.song.13000.json','["汐潮如有信，時向舊痕生。", "始覺回波定，還看曲渚平。", "舞鷗隨下上，寒日共浮傾。", "後夜人無寐，遥聽入浦聲。"]'),
('4144267b-e705-49aa-9269-236a25ac2550','舟中聞蛩','梅堯臣','宋','宋诗','song-poetry','','[]','秋月滿行舟，秋蟲響孤岸。',72,'全唐诗/poet.song.13000.json','["秋月滿行舟，秋蟲響孤岸。", "豈獨居者愁，當令客心亂。", "展轉重興嗟，所嗟時節換。", "時節不苦留，川塗行已半。", "霜落草根枯，清音從此斷。", "誰復過江南，哀鴻爲我伴。"]'),
('604ab5b7-d13f-4ccc-9f88-64581f8cb424','雙鳧觀','梅堯臣','宋','宋诗','song-poetry','','[]','野水雙紋翼，雲蘿謾自媒。',48,'全唐诗/poet.song.13000.json','["野水雙紋翼，雲蘿謾自媒。", "驚飛带波起，行啑拂萍開。", "暖日浮還沒，寒汀去復來。", "王喬如可挹，仙舄此徘徊。"]'),
('afe5b1a3-b5d3-4939-91b6-5bdad9da1f0b','和才叔岸傍古廟','梅堯臣','宋','宋诗','song-poetry','','[]','樹老垂纓亂，祠荒向水開。',48,'全唐诗/poet.song.13000.json','["樹老垂纓亂，祠荒向水開。", "偶人經雨踣，古屋爲風摧。", "野鳥棲塵坐，漁郎奠竹杯。", "欲傳山鬼曲，無奈楚辭哀。"]'),
('427996b6-e693-4fa8-a4de-28e947c6a304','山光寺','梅堯臣','宋','宋诗','song-poetry','','[]','古橋經廢寺，蒼蘚舊離宮。',48,'全唐诗/poet.song.13000.json','["古橋經廢寺，蒼蘚舊離宮。", "柏殿秋陰冷，蓮堂暮色空。", "鳥啼山藹裏，僧語竹林中。", "寂寞蕪城近，蕭蕭牧笛風。"]'),
('1af72e20-1fbe-4416-802d-076d8667ff13','自急流口至長蘆江入金陵','梅堯臣','宋','宋诗','song-poetry','','[]','始發碧江口，曠然諧遠心。',48,'全唐诗/poet.song.13000.json','["始發碧江口，曠然諧遠心。", "風清舟在鑑，日落水浮金。", "瓜步逢潮信，臺城過雁音。", "故鄉何處是，雲外即喬林。"]'),
('a77f0e39-c5a0-4e1f-8f6f-e318dc9ac1a4','早渡長蘆江','梅堯臣','宋','宋诗','song-poetry','','[]','带月出寒浦，殘星浸水濆。',48,'全唐诗/poet.song.13000.json','["带月出寒浦，殘星浸水濆。", "帆開風色正，舟急浪花分。", "霧氣橫江白，雞聲隔岸聞。", "天晴建業近，鐘岫起孤雲。"]'),
('6d7c6d30-64df-48d2-adf4-7b5349313454','采石懷古','梅堯臣','宋','宋诗','song-poetry','','[]','青峯來合沓，勢壓大江雄。',48,'全唐诗/poet.song.13000.json','["青峯來合沓，勢壓大江雄。", "舟渡神兵後，城荒王氣空。", "山根魚浪白，巖壁石蘿紅。", "弄月人何在，孤墳細草中。"]'),
('2061fe39-ce29-4b68-87da-cf25cdd0fe75','望夫山','梅堯臣','宋','宋诗','song-poetry','','[]','亭亭千古質，曾是念征夫。',48,'全唐诗/poet.song.13000.json','["亭亭千古質，曾是念征夫。", "一作山頭石，畏看天際途。", "猶如託蘿蔓，不似采蘼蕪。", "時有江雲近，僊衣挂六銖。"]'),
('4f5f5eda-a91a-44c5-a279-150c1a0ad60e','泊牛渚磯','梅堯臣','宋','宋诗','song-poetry','','[]','落帆牛渚前，便爲牛渚宿。',72,'全唐诗/poet.song.13000.json','["落帆牛渚前，便爲牛渚宿。", "波摇殘照中，采翠浮巖谷。", "巖谷足幽篁，石上羅寒玉。", "裁作媧氏笙，堪吹凰鳳曲。", "楚客夕無眠，獨將清籟續。", "更看江月來，還想燃犀燭。"]'),
('7173b522-1a46-4100-943c-ed9801b4e546','遊響山','梅堯臣','宋','宋诗','song-poetry','','[]','久憶門前勝，聊乘逸興遊。',48,'全唐诗/poet.song.13000.json','["久憶門前勝，聊乘逸興遊。", "寒篙進溪曲，古木暗城頭。", "鳥過空潭響，船隨碧瀨流。", "梅花三疊罷，煙火起滄洲。"]'),
('4f7c0d3e-a391-4299-806b-6d98bed69f19','蕪湖口留別弟信臣','梅堯臣','宋','宋诗','song-poetry','','[]','少也遠辭親，俱爲異鄉客。',72,'全唐诗/poet.song.13000.json','["少也遠辭親，俱爲異鄉客。", "昨日偶同歸，今朝復南適。", "南遷畏簡書，叨茲六百石。", "重念我當去，送我江之側。", "溪山遠更清，溪水深轉碧。", "因知惜別情，愈賒應愈劇。"]'),
('d9fd8fc4-19d8-4205-8aeb-fb9502c3d5a1','金霞閣','梅堯臣','宋','宋诗','song-poetry','','[]','登臨無盡興，清燕日徘徊。',48,'全唐诗/poet.song.13000.json','["登臨無盡興，清燕日徘徊。", "霞影緣觚落，嵐光入牖來。", "離宮分碧瓦，太液俯青槐。", "好待邀明月，瑶琴爲一開。"]'),
('212b492f-2354-48ea-9e35-ab65249709b3','送蟾上人遊南嶽','梅堯臣','宋','宋诗','song-poetry','','["\u8861\u5c71"]','葉下瀟湘闊，杯浮豈道遲。',48,'全唐诗/poet.song.13000.json','["葉下瀟湘闊，杯浮豈道遲。", "賓鴻不到處，危彴獨行時。", "翠嶺祝融宅，喬松虞舜祠。", "雲霞遊徧日，振錫更何之。"]'),
('d0318ffc-d0f2-4e33-8b6e-3ef4d54b0008','王公慥東歸','梅堯臣','宋','宋诗','song-poetry','','[]','行色上東陌，秋槐葉亂飛。',48,'全唐诗/poet.song.13000.json','["行色上東陌，秋槐葉亂飛。", "囊無一錢用，篋有古書歸。", "羸駟嘶寒草，荒城背落暉。", "莫嫌牛馬隔，走別八行稀。"]'),
('4d0043f6-b63b-4b78-bebe-0a92f6cf1643','幾道隰州判官','梅堯臣','宋','宋诗','song-poetry','','[]','清曉赴國門，西風生早凉。',228,'全唐诗/poet.song.13000.json','["清曉赴國門，西風生早凉。", "天地大道出，苑樹短亭傍。", "相看車馬色，共照池水光。", "舉酒酒非淺，明朝誰重觴。", "話別語難盡，去後空回腸。", "計彼行路遠，幾日至洛陽。", "洛陽多舊友，一一道相望。", "失意非憔悴，懷昔無悲傷。", "無由戀中國，不久之南方。", "音書儻能問，鴻雁亦將翔。", "此外念出處，便爲參與商。", "到官秋節晚，塞近百草黄。", "定隨劉武威，校獵赤土崗。", "余方楓林下，野艇泛滄浪。", "弄月江波闊，罥衣菱荇香。", "雖知各有適，未免涕霑裳。", "操袂却引顧，煙蕪平夕陽。", "獨回唯鳥影，相與過林塘。", "朋遊頓茲減，客心仍未央。"]'),
('f400264b-8001-4834-883c-9194350e9b83','池州進士陳生惠然見過不日且行因以詩贈別','梅堯臣','宋','宋诗','song-poetry','','[]','呼童具雞黍，頗識故人期。',48,'全唐诗/poet.song.13000.json','["呼童具雞黍，頗識故人期。", "竹館忽枉駕，山樽聊解頤。", "醉歌返北郭，春雨生東陂。", "便與千峯隔，登高空復思。"]'),
('054bfc6a-728c-47bd-a492-e26cfc027b51','春陰','梅堯臣','宋','宋诗','song-poetry','','[]','濃淡雲無定，凄微氣宇寒。',48,'全唐诗/poet.song.13000.json','["濃淡雲無定，凄微氣宇寒。", "鳩鳴桑葉吐，村暗杏花殘。", "客子行裘薄，春塘野水寬。", "輕雷欣已發，謬作採茶官。"]'),
('ef2cca9d-71f1-44da-87a2-79779063af24','春晴對月','梅堯臣','宋','宋诗','song-poetry','','[]','雲掃魚鱗靜，天開桂魄清。',48,'全唐诗/poet.song.13000.json','["雲掃魚鱗靜，天開桂魄清。", "梨花鑑中色，杜宇晝時聲。", "寥落將寒食，羈離念故京。", "都無惜春意，罇酒爲誰傾。"]'),
('e90e6033-3b40-4511-9082-4d78251019bc','植梔子樹二窠十一本於松側','梅堯臣','宋','宋诗','song-poetry','','[]','舉世多植梨，而我學種梔。',48,'全唐诗/poet.song.13000.json','["舉世多植梨，而我學種梔。", "顔色固不別，良苦誠異宜。", "團團綠堦側，豈畏秋風吹。", "同心誰可贈，爲詠昔人詩。"]'),
('d0ba4d26-e672-4883-b2e7-1b873714705d','百舌','梅堯臣','宋','宋诗','song-poetry','','[]','天窗明未明，颯颯過微雨。',40,'全唐诗/poet.song.13000.json','["天窗明未明，颯颯過微雨。", "已聞高樹頭，百舌間關語。", "幽人枕上聽不聽，變盡春聲始飛去。"]'),
('bd93449c-543c-4e88-b8b0-347f41727315','提壺鳥','梅堯臣','宋','宋诗','song-poetry','','[]','山路暗松篠，幽禽語前後。',48,'全唐诗/poet.song.13000.json','["山路暗松篠，幽禽語前後。", "上言勸提壺，下言勸酤酒。", "但取醒復醉，莫問升與斗。", "人生朝菌榮，綠髮可無負。"]'),
('c0d8db0b-be00-4d43-a451-18b90f8120ca','青梅','梅堯臣','宋','宋诗','song-poetry','','[]','梅葉未藏禽，梅子青可摘。',48,'全唐诗/poet.song.13000.json','["梅葉未藏禽，梅子青可摘。", "江南小家女，手弄門前劇。", "齒軟莫勝酸，棄之曾不惜。", "寧顧馬上郎，春風滿行陌。"]'),
('754f9c34-b89a-49ef-8d4a-4cbdf5d13f49','挾彈篇','梅堯臣','宋','宋诗','song-poetry','','[]','長安細侯年尚小，獨出春郊不須曉。',80,'全唐诗/poet.song.13000.json','["長安細侯年尚小，獨出春郊不須曉。", "手持柘彈霸陵邊，豈惜金丸射飛鳥。", "金丸射盡飛鳥空，解衣市酒向新豐。", "醉倒銀缾方肯去，去卧紅樓歌吹中。", "不管花開與花老，明朝還去杜城東。"]'),
('88409604-6461-4f2e-9bb2-29e3b0d73e5e','五日登北山望競渡','梅堯臣','宋','宋诗','song-poetry','','[]','南方傳競渡，多在屈平祠。',48,'全唐诗/poet.song.13000.json','["南方傳競渡，多在屈平祠。", "簫鼓滿流水，風煙生畫旗。", "千橈速飛鳥，兩舸刻靈螭。", "盡日來江畔，誰知輕薄兒。"]'),
('a6783a26-0691-4657-b84f-b5e7d3606157','寄新安通判錢學士','梅堯臣','宋','宋诗','song-poetry','','[]','昔人言訪舟，江水賦清泚。',48,'全唐诗/poet.song.13000.json','["昔人言訪舟，江水賦清泚。", "冬春常一色，深淺皆見底。", "崖日半寒潭，澄明動朱鯉。", "君懷素已高，塵慮都應洗。"]'),
('1d965429-37b1-47bc-94a7-f6b5c0a823ff','得歐陽永叔回書云見來客問予動靜備詳','梅堯臣','宋','宋诗','song-poetry','','[]','昨日使人回，聞君與之坐。',48,'全唐诗/poet.song.13000.json','["昨日使人回，聞君與之坐。", "君問我何爲，但云思寡過。", "寡過真未能，得便北窗卧。", "此趣今已深，世間誰與和。"]'),
('7dcf13bb-b7f1-4164-91cd-c3d4422755e2','建德新牆詩','梅堯臣','宋','宋诗','song-poetry','','[]','山廨不營堵，筠篁爲密籬。',240,'全唐诗/poet.song.13000.json','["山廨不營堵，筠篁爲密籬。", "初年固可蔽，晏歲不能支。", "已被巢蜂蠹，復爲荒葛虆。", "夏雨久枯脆，秋風遂傾敧。", "雞鶩恣穿逸，牛羊來踐窺。", "我議欲板築，羣走皆不怡。", "首吏先進白，土踈不可爲。", "潦雨忽暴集，澗流如突馳。", "我心賾其極，斯語其見欺。", "用竹乃戶率，破得緣而私。", "冬斂葺西角，春調完北陲。", "循環日有壞，煩擾無虛時。", "介决弗爾惑，遂飭闢其基。", "榛莽一芟去，畚鍤能悅隨。", "膏潤非朽壤，峭削隠金鎚。", "荏苒未踰月，屹如長雲垂。", "疏壍備水害，既圬復蓬茨。", "豈唯禦貛豹，亦以防狐狸。", "且有內外隔，絕聞閭巷卑。", "安然茲燕息，來者勿吾隳。"]'),
('55a0c308-3293-432b-8cab-c329b633e8e6','九月五日得姑蘇謝學士寄木蘭堂官醖','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','公田五十畝，種秫秋未成。',96,'全唐诗/poet.song.13000.json','["公田五十畝，種秫秋未成。", "杯中無濁酒，案上唯丹經。", "忽有洞庭客，美傳烏與程。", "言盛木蘭露，釀作甕間清。", "木蘭香未歇，玉盎貯華英。", "正值菊初坼，便來花下傾。", "一飲爲君醉，誰能解吾酲。", "吾酲已不解，百日毛骨輕。"]'),
('9aa0c099-c415-4d61-ad5f-acbed1d99b51','九月見梅花','梅堯臣','宋','宋诗','song-poetry','','[]','江南風土暖，九月見梅花。',48,'全唐诗/poet.song.13000.json','["江南風土暖，九月見梅花。", "遠客思邊草，孤根暗磧沙。", "何曾逢寄驛，空自聽吹笳。", "今日樽前勝，其如秋鬢華。"]'),
('7f86e020-303b-4e19-b105-95f004e8e91a','新安錢學士以近詩一軸見貺輒成短言用敘單悃','梅堯臣','宋','宋诗','song-poetry','','[]','早事太尉府，謬以才見論。',192,'全唐诗/poet.song.13000.json','["早事太尉府，謬以才見論。", "身作邑中吏，日陪丞相尊。", "嵩山雲外寺，伊水渡頭村。", "泉味入香茗，松色開清罇。", "題詩人半醉，馬上景已昏。", "歸來屬後乘，冠蓋迎國門。", "悠悠失貧賤，苒苒歷凉溫。", "而今處窮僻，落莫思舊恩。", "終日自鮮適，終年長不言。", "已覺人事寡，惟聞雞犬喧。", "東風有來信，滿幅蘭與蓀。", "深知故人意，遺我滌冥煩。", "一章言罨畫，谿好如目存。", "何須到雲壑，便若遊花源。", "一一先造化，可以輕瑶琨。", "成誦今在口，願將醒病魂。"]'),
('2cbb227b-e514-4338-8af6-803620db913d','答陳五進士遺山水枕屏','梅堯臣','宋','宋诗','song-poetry','','[]','妙畫能成趣，谿山迥得君。',48,'全唐诗/poet.song.13000.json','["妙畫能成趣，谿山迥得君。", "漁舟長映浦，巖樹半藏雲。", "征雁無時沒，橫橋有處分。", "數峯來枕席，曾不愧移文。"]'),
('9f2e5590-d434-412c-ba54-27627846436e','謝賓客挽歌三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','位不登三事，才宜列四科。',72,'全唐诗/poet.song.13000.json','["位不登三事，才宜列四科。", "清名時自得，華冕世空多。", "望氣悲埋劍，臨風歎逝波。", "吳阡蒿作里，楚挽薤成歌。", "會葬千人至，來觀數郡過。", "無由親執紼，東首淚滂沱。"]'),
('7a150258-7367-4eb4-8166-d2d1959cfd89','謝賓客挽歌三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','自昔居門下，游觀必許偕。',72,'全唐诗/poet.song.13000.json','["自昔居門下，游觀必許偕。", "豈將千里別，遂作九泉乖。", "已恨霜松折，行嗟玉樹埋。", "蒼生空有望，丹旐不勝懷。", "曩日言歸里，飛章願乞骸。", "今朝赤松畔，煙壠對蒼崖。"]'),
('7b5bd6cf-2ae7-43f2-9bac-faf55c2c9605','謝賓客挽歌三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','當年罷會稽，還郡錦爲衣。',72,'全唐诗/poet.song.13000.json','["當年罷會稽，還郡錦爲衣。", "老作龍樓貴，終將鳳沼違。", "英魂遊岱去，石槨渡江歸。", "揚子春風惡，南徐過客稀。", "衆帆看屢溺，素舸獨如飛。", "始見中郎孝，松門自有輝。"]'),
('be911a81-a6ba-484f-aa5b-fa8753f8e531','往東流江口寄內','梅堯臣','宋','宋诗','song-poetry','','[]','艇子逐溪流，來至碧江頭。',72,'全唐诗/poet.song.13000.json','["艇子逐溪流，來至碧江頭。", "隨山知幾曲，一曲一增愁。", "巢蘆有翠鳥，雄雌自相求。", "擘波投遠空，丹喙橫輕鯈。", "呼鳴仍不已，共啄向蒼洲。", "而我無羽翼，安得與子遊。"]'),
('244b3e20-6054-4cde-bd5e-5aba572a1ed0','代內答','梅堯臣','宋','宋诗','song-poetry','','[]','結髮事君子，衣袂未嘗分。',72,'全唐诗/poet.song.13000.json','["結髮事君子，衣袂未嘗分。", "今朝別君思，歷亂如絲棼。", "征僕尚顧侶，嘶馬猶索羣。", "相送不出壼，倚楹羨飛雲。", "日暮秋風急，雀聲簷上集。", "併作千里愁，愁極翻成泣。"]'),
('33ecfef6-1b4e-4321-ba92-dfcaed00801e','訪礦坑老僧','梅堯臣','宋','宋诗','song-poetry','','[]','山深無外事，日夕愛潺湲。',48,'全唐诗/poet.song.13000.json','["山深無外事，日夕愛潺湲。", "趺坐樹間石，力耕溪上田。", "解言南國事，能詠碧雲篇。", "莫貰遠公酒，余非陶令賢。"]'),
('ddec7f71-679c-49c9-85e2-afa54beaf58a','除夕與家人飲','梅堯臣','宋','宋诗','song-poetry','','[]','莫嫌寒漏盡，春色來應早。',48,'全唐诗/poet.song.13000.json','["莫嫌寒漏盡，春色來應早。", "風開玉砌梅，薰歇金爐草。", "稚齒喜成人，白頭嗟更老。", "年華箇裏催，清鏡寧長好。"]'),
('a3cdf7d8-466c-470a-9f09-090bef4cccdb','立春在元日','梅堯臣','宋','宋诗','song-poetry','','[]','新春與新歲，時候不相先。',48,'全唐诗/poet.song.13000.json','["新春與新歲，時候不相先。", "未肯欺殘臘，何曾占舊年。", "綴條花翦綵，插戶柳生煙。", "獨坐空山裏，唯驚節物遷。"]'),
('7a5d7669-319b-42f3-b828-71e321b42b03','遊水簾巖','梅堯臣','宋','宋诗','song-poetry','','[]','春山時獨往，榛穢旋芟斸。',72,'全唐诗/poet.song.13000.json','["春山時獨往，榛穢旋芟斸。", "飛泉蔽幽巖，杳藹疏朝旭。", "光垂白龍髯，鳴漱寒潭玉。", "半壁生晝寒，陰草潤秋綠。", "穿藤出溪口，流沫縈山足。", "莫遣吏人來，方歌白雲曲。"]'),
('891da768-b52d-425a-af5a-1cdccfe4e875','詠官妓從人','梅堯臣','宋','宋诗','song-poetry','','[]','少爲輕薄悞，失行落優倡。',48,'全唐诗/poet.song.13000.json','["少爲輕薄悞，失行落優倡。", "去作小家婦，願同貧里裝。", "無心歌子夜，有意學流黄。", "他日東郊上，誰人見採桑。"]'),
('431a5a4b-ef15-4688-b55c-2501699d87be','夏雨','梅堯臣','宋','宋诗','song-poetry','','[]','林梅初弄熟，密雨閉重關。',48,'全唐诗/poet.song.13000.json','["林梅初弄熟，密雨閉重關。", "潤裛衣巾上，凉生竹樹間。", "水聲通遠澗，雲色暝前山。", "野鳥寂無語，公庭盡晝閑。"]'),
('c82afc9a-0ba1-458b-a164-df2d6d333544','五日與陳真卿飲','梅堯臣','宋','宋诗','song-poetry','','[]','五日逢南國，三年別舊都。',48,'全唐诗/poet.song.13000.json','["五日逢南國，三年別舊都。", "招魂傳楚客，撫節見靈巫。", "蒿艾因時採，蛟龍爲俗驅。", "清罇與鵝炙，忻此故人俱。"]'),
('5c266fc3-4561-468c-be37-504e8c8599a4','彼鴷吟','梅堯臣','宋','宋诗','song-poetry','','[]','斷木喙雖長，不啄柏與松。',120,'全唐诗/poet.song.13000.json','["斷木喙雖長，不啄柏與松。", "松柏本堅直，中心無蠹蟲。", "廣庭木云美，不與松柏比。", "臃腫質性虛，杇蝎招猛觜。", "主人赫然怒，我愛爾何毀。", "彈射出窮山，羣鳥亦相喜。", "啁啾弄好音，自謂得天理。", "哀哉彼鴷禽，吻血徒爲爾。", "座鸇不搏擊，狐兔縱橫起。", "況茲樹腹怠，力去宜濱死。"]'),
('57b46a30-e5a3-48c5-b9c0-a59cb58fe7fd','感遇','梅堯臣','宋','宋诗','song-poetry','','[]','衆默瘖莫辨，衆寐盲不知。',48,'全唐诗/poet.song.13000.json','["衆默瘖莫辨，衆寐盲不知。", "問而使之對，覺而使之窺。", "瘖盲自窮矣，所感在一時。", "苟昧哲人理，寐默定妍媸。"]'),
('a52ef047-b2c1-4950-87f8-c9be7b5e6d7a','雪詠','梅堯臣','宋','宋诗','song-poetry','','[]','雪色混青冥，搴幃宿酒醒。',48,'全唐诗/poet.song.13000.json','["雪色混青冥，搴幃宿酒醒。", "龍蛇緣古木，鳳鵠舞幽庭。", "密勢因風力，輕姿任物形。", "公堂何寂寞，橫案對玄經。"]'),
('a9c36ff2-cf3b-41de-9b59-f60cd61bc06c','臘日出獵因遊梅山蘭若','梅堯臣','宋','宋诗','song-poetry','','[]','我與二三騎，爭馳孤戍旁。',48,'全唐诗/poet.song.13000.json','["我與二三騎，爭馳孤戍旁。", "逐麋逢野寺，息馬據胡牀。", "鷹想支公好，人思灞上狂。", "歸來何薄暮，煙火照溪光。"]'),
('fbe7e575-bdb0-40e7-b16f-b56353b159f3','依韻和楊敏叔吳門秋晚見寄','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','方在洞庭上，秋懷那得禁。',48,'全唐诗/poet.song.13000.json','["方在洞庭上，秋懷那得禁。", "西風楚波惡，度雁海雲陰。", "洛客吟初苦，騷人思已深。", "顛毛隨日減，冉冉不勝簪。"]'),
('e2a1aec5-1018-4452-ae6d-d52e814ba7ee','田家','梅堯臣','宋','宋诗','song-poetry','','[]','南山嘗種豆，碎莢落風雨。',24,'全唐诗/poet.song.13000.json','["南山嘗種豆，碎莢落風雨。", "空收一束萁，無物充煎釜。"]'),
('57c4d833-7fdd-4a65-9198-8d697f5112f1','陶者','梅堯臣','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u751f\u6d3b", "\u5b8b\u8bd7", "\u519c\u6c11"]','陶盡門前土，屋上無片瓦。',24,'全唐诗/poet.song.13000.json','["陶盡門前土，屋上無片瓦。", "寸指不霑泥，鱗鱗居大厦。"]'),
('74c9676a-3817-47d2-ac41-a0ff9a91c565','縣署叢竹','梅堯臣','宋','宋诗','song-poetry','','[]','裊裊幽亭竹，團團自結叢。',48,'全唐诗/poet.song.13000.json','["裊裊幽亭竹，團團自結叢。", "寒生綠罇上，影入翠屏中。", "陶柳應慙弱，潘花只競紅。", "方持雪霜操，不敢倚春風。"]'),
('1c52d2bf-3802-417b-84c6-f8c1c6a98e18','巧婦','梅堯臣','宋','宋诗','song-poetry','','[]','巧婦口流血，辛勤非一朝。',48,'全唐诗/poet.song.13000.json','["巧婦口流血，辛勤非一朝。", "莠荼時補紩，風雨畏漂摇。", "所託樹枝弱，而嗟巢室翹。", "周公誠自感，聊復賦鴟鴞。"]'),
('5a5516c3-998d-494b-89ac-2487c0bdbade','聞歐陽永叔謫夷陵','梅堯臣','宋','宋诗','song-poetry','','[]','共在西都日，居常慷慨言。',48,'全唐诗/poet.song.13000.json','["共在西都日，居常慷慨言。", "今嬰明主怒，直雪諫臣冤。", "謫向蠻荆去，行當霧雨繁。", "黄牛三峽近，切莫聽愁猿。"]'),
('fc6cf9cb-60e1-41e5-bcdc-b6762fe18eab','聞尹師魯謫富水','梅堯臣','宋','宋诗','song-poetry','','[]','朝見諫臣逐，暮章從謫官。',48,'全唐诗/poet.song.13000.json','["朝見諫臣逐，暮章從謫官。", "附炎人所易，抱義爾惟難。", "寧作沉泥玉，無爲媚渚蘭。", "心知歸有日，時向斗牛看。"]'),
('d73083fd-7afd-4f34-8a23-0b481faea56f','寄饒州范待制','梅堯臣','宋','宋诗','song-poetry','','[]','山水番君國，文章漢侍臣。',48,'全唐诗/poet.song.13000.json','["山水番君國，文章漢侍臣。", "古來中酒地，今見獨醒人。", "坐嘯安浮俗，談詩接上賓。", "何由趨盛府，徒爾望清塵。"]'),
('1c36fff3-9b6e-4d9b-bdc9-72fc39d22334','詠王右丞所畫阮步兵醉圖','梅堯臣','宋','宋诗','song-poetry','','[]','右丞筆通妙，阮籍思玄虛。',144,'全唐诗/poet.song.13000.json','["右丞筆通妙，阮籍思玄虛。", "獨畫來東平，倒冠醉乘馿。", "力頑不肯進，俛首耳前驅。", "一人牽且顧，一士旁挾扶。", "捉鞍舉雙足，閉目忘窮途。", "想像得風度，纖悉古衣裾。", "玉骨化爲土，丹青終不渝。", "而今幾百歲，乃有胡公疎。", "買石遂留刻，漬墨許傳模。", "白黑就髣髴，毫芒辨精麤。", "千古畜深意，終朝懸座隅。", "誰謂盈尺紙，不慙雲霧圖。"]'),
('e96b38b4-9a7a-447f-b33f-e4d8e078cb9a','猛虎行','梅堯臣','宋','宋诗','song-poetry','','[]','山木暮蒼蒼，風凄茆葉黄。',120,'全唐诗/poet.song.13000.json','["山木暮蒼蒼，風凄茆葉黄。", "有虎始離穴，熊羆安敢當。", "掉尾爲旗纛，磨牙爲劍鋩。", "猛氣吞赤豹，雄威躡封狼。", "不貪犬與豕，不窺藩與牆。", "當途食人肉，所獲乃堂堂。", "食人既我分，安得爲不祥。", "麋鹿豈非命，其類寧不傷。", "滿野設罝網，競以充圓方。", "而欲我無殺，奈何饑餒腸。"]'),
('4f36941a-b0f2-4dbb-bf01-86b1617a95e2','白鷴','梅堯臣','宋','宋诗','song-poetry','','[]','喬木暗青山，晴川下白鷴。',48,'全唐诗/poet.song.13000.json','["喬木暗青山，晴川下白鷴。", "春雲生嶺上，積雪在囂間。", "綠草張新翳，柔冠總翠鬟。", "時哉養文素，不是雜斑斑。"]'),
('28b8bda0-e846-4435-b2ec-774071322bb6','後園桃李花','梅堯臣','宋','宋诗','song-poetry','','[]','後園桃李花，灼灼復皎皎。',48,'全唐诗/poet.song.13000.json','["後園桃李花，灼灼復皎皎。", "南枝開已繁，北枝縈尚少。", "蘤萼相輝映，根本自鈎繞。", "無爲驚風吹，紛紛逐飛鳥。"]'),
('2a8219c8-dd1b-4c6f-8cc5-027a29edc1ce','道傍虎跡行','梅堯臣','宋','宋诗','song-poetry','','[]','朝履猛虎跡，暮宿猛虎林。',48,'全唐诗/poet.song.13000.json','["朝履猛虎跡，暮宿猛虎林。", "猛虎終夜嘯，陰風生遠岑。", "我懷何所畏，所畏在官箴。", "傷哉此遺體，冒險輕百金。"]'),
('eca42f5e-c62c-46e8-b9d7-5c8eec304948','脩真觀李道士年老貧餓無所依忽縊死因爲詩以悼之','梅堯臣','宋','宋诗','song-poetry','','[]','唐室王子後，黄冠事隠淪。',60,'全唐诗/poet.song.13000.json','["唐室王子後，黄冠事隠淪。", "餐霞不滿腹，披雲不蔽身。", "八十不能死，縊以頭上巾。", "始慕老莊術，終厭道德貧。", "營營求長生，反困甑中塵。"]'),
('f4226deb-e8a1-466c-8814-a7ae431f5619','野田行','梅堯臣','宋','宋诗','song-poetry','','[]','輕雷長陂水，農事乃及辰。',48,'全唐诗/poet.song.13000.json','["輕雷長陂水，農事乃及辰。", "茅旌送山鬼，瓦鼓迎田神。", "青臯暗藏雉，萬木欣已春。", "桑間偶耕者，誰復來問津。"]'),
('6885ec0c-5aab-4ea3-b2b0-a83fdd2a418d','水輪詠','梅堯臣','宋','宋诗','song-poetry','','[]','孤輪運寒水，無乃農者營。',48,'全唐诗/poet.song.13000.json','["孤輪運寒水，無乃農者營。", "隨流轉自速，居高還復傾。", "利纔畎澮間，功欲霖雨并。", "不學假混沌，亡機抱甕罌。"]'),
('ddc4aa55-3886-45b2-b919-2566843e7d50','山村行','梅堯臣','宋','宋诗','song-poetry','','[]','征馬去不息，幽禽隨處聞。',48,'全唐诗/poet.song.13000.json','["征馬去不息，幽禽隨處聞。", "深源樹蓊鬰，曲塢花芬蒀。", "澹澹平田水，濛濛半嶺雲。", "長鬟弄春女，溪上自湔裙。"]'),
('1c8b6b5c-915a-4158-a8a5-0b9b5e15c920','鳴雉詞','梅堯臣','宋','宋诗','song-poetry','','[]','雄雉鳴桑林，雌雉雊麥隴。',48,'全唐诗/poet.song.13000.json','["雄雉鳴桑林，雌雉雊麥隴。", "結愛誠有宜，別啄義亦竦。", "哺雛深莽中，摧頹錦翅擁。", "辛勤何爾爲，應自念遺種。"]'),
('eb08cdde-98fc-4a6e-ba2d-749245ef3cea','寄公異弟','梅堯臣','宋','宋诗','song-poetry','','[]','池塘去後春，一夕生綠草。',24,'全唐诗/poet.song.13000.json','["池塘去後春，一夕生綠草。", "無由夢阿連，詩句何能好。"]'),
('01c6c280-f0e6-461e-8e3b-8e52139514c5','去春城','梅堯臣','宋','宋诗','song-poetry','','[]','前日去春城，今朝還故陌。',36,'全唐诗/poet.song.13000.json','["前日去春城，今朝還故陌。", "馬有甚煩意，人多遠行色。", "暫爾厭風埃，那堪爲久客。"]'),
('2168331b-dbcd-464f-8779-e90991d9076c','讀范桐廬述嚴先生祠堂碑','梅堯臣','宋','宋诗','song-poetry','','[]','二蛇志不同，相得榛莽裏。',192,'全唐诗/poet.song.13000.json','["二蛇志不同，相得榛莽裏。", "一蛇化爲龍，一蛇化爲雉。", "龍飛上高衢，雉飛入深水。", "爲蜃自得宜，潛游滄海涘。", "變化雖各殊，有道固終始。", "光武與嚴陵，其義亦云爾。", "所遇在草昧，既貴不爲起。", "翻然歸富春，曾不相助治。", "至今存清芬，烜赫耀圖史。", "人傳七里灘，昔日來釣此。", "灘上水濺濺，灘下石齒齒。", "其人不可見，其事清且美。", "有客乘朱輪，徘徊想前軌。", "著辭刻之碑，復使存厥祀。", "欲以廉貪夫，又以立懦士。", "千載名不忘，休哉古君子。"]'),
('25cc4ed9-216c-4132-88e9-da0bc13159d5','禽言四首 子規','梅堯臣','宋','宋诗','song-poetry','','[]','不如歸去，春山云暮。',38,'全唐诗/poet.song.13000.json','["不如歸去，春山云暮。", "萬木兮參雲，蜀天兮何處。", "人言有翼可歸飛，安用空啼向高樹。"]'),
('6bd57b3c-cd51-487c-a3d6-810c2dfffc14','禽言四首 提壺','梅堯臣','宋','宋诗','song-poetry','','[]','提壺蘆，沽美酒。',32,'全唐诗/poet.song.13000.json','["提壺蘆，沽美酒。", "風爲賓，樹爲友。", "山花繚亂目前開，勸爾今朝千萬壽。"]'),
('ca1bbe36-72eb-47ea-868b-ccc6a16ad716','禽言四首 山鳥','梅堯臣','宋','宋诗','song-poetry','','[]','婆餠焦，兒不食。',38,'全唐诗/poet.song.13000.json','["婆餠焦，兒不食。", "爾父向何之，爾母山頭化爲石。", "山頭化石可奈何，遂作微禽啼不息。"]'),
('597e35c1-27f6-49a9-b02c-b4ce34675b55','禽言四首 竹雞','梅堯臣','宋','宋诗','song-poetry','','[]','泥滑滑，苦竹岡。',32,'全唐诗/poet.song.13000.json','["泥滑滑，苦竹岡。", "雨蕭蕭，馬上郎。", "馬蹄凌兢雨又急，此鳥爲君應斷腸。"]'),
('866a9bf8-7236-48bc-9c33-cbf4dd836bec','讀漢書梅子真傳','梅堯臣','宋','宋诗','song-poetry','','[]','子真實吾祖，耿介仕炎漢。',120,'全唐诗/poet.song.13000.json','["子真實吾祖，耿介仕炎漢。", "權臣始擅朝，忠良被塗炭。", "輦下莫敢言，上書陳治亂。", "是時卿大夫，曾不負愧汗。", "其文信雄深，爛然今可玩。", "危言識禍機，滅迹思汗漫。", "一朝棄妻子，龍性寧羈絆。", "九江傳神僊，會稽隠廛閈。", "舊市越溪陰，家山鏡湖畔。", "唯餘千載名，撫卷一長歎。"]'),
('56219b45-ae0b-45a8-a524-5b3486e07df8','贈黄庭筠舉進士','梅堯臣','宋','宋诗','song-poetry','','[]','橘柚生南國，幽林日葱蒨。',48,'全唐诗/poet.song.13000.json','["橘柚生南國，幽林日葱蒨。", "上有嘉禽鳴，五色被餘絢。", "彼美發華英，厥包待秋薦。", "根本當自持，無爲風土變。"]'),
('1af88c6d-c3a8-40a5-85c2-802f850e320b','和滕公遊穿山洞','梅堯臣','宋','宋诗','song-poetry','','[]','洞口水石淺，潺潺瀉綠蒲。',120,'全唐诗/poet.song.13000.json','["洞口水石淺，潺潺瀉綠蒲。", "緣源進巖竇，陰黑人境殊。", "中言有物怪，蟠蟄春未蘇。", "霖雨雖有意，風雷莫肯扶。", "風雷自鼓盪，不久當何如。", "幸欣禪林近，鍾梵來有無。", "回策履幽逕，衣香草露濡。", "老僧長松下，麋鹿與之俱。", "溪雲時見起，山鳥自相呼。", "羨爾得茲樂，何用勞形軀。"]'),
('f54b66ac-1d59-49b7-be07-7df6326f8498','陳真卿將有秋試倏見訪不日告行送於北門歌鵠庭爲五言以贈','梅堯臣','宋','宋诗','song-poetry','','[]','送君北崗上，舉酒歌黄鵠。',48,'全唐诗/poet.song.13000.json','["送君北崗上，舉酒歌黄鵠。", "黄鵠去何高，天池待棲宿。", "寧復戀江湖，聊茲混雞鶩。", "暉暉振羽裳，不羨淵明菊。"]'),
('16f50cbd-5b7d-4184-aa03-1e82685a7a6f','秋日詠蟬','梅堯臣','宋','宋诗','song-poetry','','[]','羣蟲喜炎熱，此獨愛高陰。',48,'全唐诗/poet.song.13000.json','["羣蟲喜炎熱，此獨愛高陰。", "薄蛻聊依葉，清聲已出林。", "人閑感衰節，風急雜遥砧。", "虛腹曾何竟，常憂螗斧侵。"]'),
('83da6483-7f85-4cd4-8ca1-fb5fb4b12948','范饒州夫人挽詞二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','聽飲大夫日，止言京兆辰。',48,'全唐诗/poet.song.13000.json','["聽飲大夫日，止言京兆辰。", "常憂伯宗直，曾識仲卿貧。", "蒿里歸魂遠，芝山旅殯新。", "江邊有孤鶴，嘹唳獨傷神。"]'),
('c18c9531-85db-45b9-a034-0c0c32659b98','范饒州夫人挽詞二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','君子喪良偶，拊棺哀有餘。',48,'全唐诗/poet.song.13000.json','["君子喪良偶，拊棺哀有餘。", "莊生慙擊缶，潘岳感游魚。", "夕苑凋朱槿，秋江落晚蕖。", "猶應思所歷，入室淚漣如。"]'),
('88270f24-469e-478e-9f75-55c779a4fdcd','弔礦坑惠燈上人','梅堯臣','宋','宋诗','song-poetry','','[]','生棲雲際巘，沒葬寺傍村。',48,'全唐诗/poet.song.13000.json','["生棲雲際巘，沒葬寺傍村。", "破案殘經卷，新墳出樹根。", "松悲隔溪路，月照舊山門。", "自昔多詩句，而今幾許存。"]'),
('84fb850d-0371-40af-9347-b425b388f2d1','寄題石埭權縣樂尉碧瀾亭','梅堯臣','宋','宋诗','song-poetry','','[]','遥知溪上亭，秋水瀁泠泠。',48,'全唐诗/poet.song.13000.json','["遥知溪上亭，秋水瀁泠泠。", "雲影無時翠，嵐光到底清。", "危樓喧晚鼓，驚鷺起寒汀。", "聊作淵明飲，臨流酒易醒。"]'),
('5d95998d-f198-4721-962e-2e313cd47fe3','斑竹管筆','梅堯臣','宋','宋诗','song-poetry','','[]','翠管江潭竹，斑斑紅淚滋。',48,'全唐诗/poet.song.13000.json','["翠管江潭竹，斑斑紅淚滋。", "束毫何勁直，在橐許操持。", "欲寫湘靈怨，堪傳虞舜辭。", "蔚然君子器，安用俗人知。"]'),
('9bb403eb-f972-41a3-8f9b-1f0870586aae','古意','梅堯臣','宋','宋诗','song-poetry','','[]','月缺不改光，劍折不改剛。',48,'全唐诗/poet.song.13000.json','["月缺不改光，劍折不改剛。", "月缺魄易滿，劍折鑄復良。", "勢利壓山岳，難屈志士腸。", "男兒自有守，可殺不可苟。"]'),
('44f87e61-1d93-491f-9c69-de4e9124996b','觀博陽山火','梅堯臣','宋','宋诗','song-poetry','','[]','十月原野枯，連山起狂燒。',144,'全唐诗/poet.song.13000.json','["十月原野枯，連山起狂燒。", "高焰過危峯，飛火入遐嶠。", "玉石被焚灼，誰能見輝耀。", "猿猱失輕捷，亦不暇相弔。", "長風又助惡，怒號生萬竅。", "炎炎赤龍奔，劃劃陰電笑。", "願傾寒江潮，勢逆難沃澆。", "願傾天河水，雖順雲衢遥。", "青松心已爛，蔓草根未焦。", "小農候春鋤，寒客失冬樵。", "誰知兼并子，平陸閑肥饒。", "不易天地意，長養非一朝。"]'),
('f8701224-b6ad-4fdc-a8d4-d30828a7aad3','聞雁寄歐陽夷陵','梅堯臣','宋','宋诗','song-poetry','','[]','閑坐獨無寐，雁來更未闌。',48,'全唐诗/poet.song.13000.json','["閑坐獨無寐，雁來更未闌。", "聲長河漢迥，影落戶庭寒。", "荆楚橘包熟，瀟湘楓葉丹。", "南飛過三峽，試問故人看。"]'),
('9979f3a4-bfd6-4966-97c6-d5bad07b7db3','送謝舍人奉使北朝','梅堯臣','宋','宋诗','song-poetry','','[]','漢使下西清，胡人擁道迎。',96,'全唐诗/poet.song.13000.json','["漢使下西清，胡人擁道迎。", "寒笳隨宿堡，衛甲出孤城。", "犯雪貂裘重，衝風錦綬輕。", "山川辭國遠，車騎踏沙行。", "授館氊爲幄，供庖酪和羹。", "戎王拜天賜，虜帥伏名卿。", "紫塞千烽靜，黄雲萬里平。", "甘泉歸奏日，重見鳳池榮。"]'),
('caa8eea2-46c9-46c2-be6e-806a001b5c5f','觀放鷂子','梅堯臣','宋','宋诗','song-poetry','','[]','白皙少年子，秋郊臂蒼隼。',72,'全唐诗/poet.song.13000.json','["白皙少年子，秋郊臂蒼隼。", "日暖饑目開，風微雙翅緊。", "草際鳴鶉驚，蒿間黄雀窘。", "下鞲誠必獲，得俊還復哂。", "碎腦此非辜，食肉爾何忍。", "取樂在須臾，我心良惻憫。"]'),
('5f48466d-beb2-4301-8032-465bd072d07c','食橙寄謝舍人','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭朱橘未弄色，襄水錦橙已變黄。',64,'全唐诗/poet.song.13000.json','["洞庭朱橘未弄色，襄水錦橙已變黄。", "玉臼擣虀憐鱠美，金盤按酒助杯香。", "雖生南土名猶重，未信中州客厭嘗。", "欲寄白苞憑驛去，只應佳味怯風霜。"]'),
('ee393ebb-b7d1-4e0a-ba7a-4863b69869d1','夜聞居人喊虎','梅堯臣','宋','宋诗','song-poetry','','[]','猛虎豈云猛，潛藏伺天昏。',48,'全唐诗/poet.song.13000.json','["猛虎豈云猛，潛藏伺天昏。", "行行出叢薄，稍稍入孤村。", "孤村何所利，所利犬與㹠。", "誰知仁者勇，去惡義自敦。"]'),
('1eaedeb6-3873-4822-aba2-01c5b8b28b36','採白朮','梅堯臣','宋','宋诗','song-poetry','','[]','吳山霧露清，羣草多秀發。',72,'全唐诗/poet.song.13000.json','["吳山霧露清，羣草多秀發。", "白朮結靈根，持鋤採秋月。", "歸來濯寒澗，香氣流不歇。", "夜火煮石泉，朝煙徧巖窟。", "千歲扶玉顔，終年固玄髮。", "曾非首陽人，敢慕食薇蕨。"]'),
('beb86022-679e-403f-87a3-f63d6113550c','寓言','梅堯臣','宋','宋诗','song-poetry','','[]','寒燈不照遠，光止一室明。',48,'全唐诗/poet.song.13000.json','["寒燈不照遠，光止一室明。", "小人不慮遠，義止目前榮。", "燈既無久焰，人亦無久情。", "誰言結明月，明月豈長盈。"]'),
('61126fb8-ea1d-4505-9dab-cb8273fcda48','送李尉子京之邵武光澤','梅堯臣','宋','宋诗','song-poetry','','[]','母老不擇祿，一官勤夙興。',48,'全唐诗/poet.song.13000.json','["母老不擇祿，一官勤夙興。", "長河未結凍，去客已懷冰。", "露蟬不飽腹，志士甘曲肱。", "遠方人所畏，所畏非所兢。"]'),
('150f1a96-caaa-4394-b24b-bf3495a452c5','銅坑','梅堯臣','宋','宋诗','song-poetry','','[]','碧礦不出土，青山鑿不休。',24,'全唐诗/poet.song.13000.json','["碧礦不出土，青山鑿不休。", "青山鑿不休，坐令鬼神愁。"]'),
('d8340f2e-7102-401a-9719-b56c707bb7a6','朝日','梅堯臣','宋','宋诗','song-poetry','','[]','日色纔出海，曉月無光彩。',36,'全唐诗/poet.song.13000.json','["日色纔出海，曉月無光彩。", "曉月在青空，不與日色同。", "誠知大君德，照耀無不通。"]'),
('9905c9e6-54a0-4096-98b2-31363c4ba11e','失鷓鴣','梅堯臣','宋','宋诗','song-poetry','','[]','愛翫日已久，開籠爲馴故。',48,'全唐诗/poet.song.13000.json','["愛翫日已久，開籠爲馴故。", "點臆雪花圓，連袪浪紋素。", "鉤輈格磔鳴，𣭷㲞翻翁去。", "誰知煙渚深，綠水脩篁處。"]'),
('a83dfa0e-6746-4068-ba1a-dd2f37c548db','過小石潭','梅堯臣','宋','宋诗','song-poetry','','[]','樹老石連潭，潭深煙翠入。',48,'全唐诗/poet.song.13000.json','["樹老石連潭，潭深煙翠入。", "羣魚石下游，獨鳥潭上立。", "泉暖草長綠，山高風自急。", "徘徊興不窮，苔屐雲霑濕。"]'),
('06f85f5c-4857-4bc6-8d5b-67579811799f','縣齋對雪','梅堯臣','宋','宋诗','song-poetry','','[]','密雪夜來積，起見萬物春。',48,'全唐诗/poet.song.13000.json','["密雪夜來積，起見萬物春。", "山川忽改色，草木一以新。", "古邑失荒穢，王路覆平均。", "從茲慶豐年，蹈詠慙小臣。"]'),
('99e6db90-9d32-401a-8c49-992cbd138ff3','對花有感','梅堯臣','宋','宋诗','song-poetry','','[]','新花朝竟妍，故花色顦顇。',24,'全唐诗/poet.song.13000.json','["新花朝竟妍，故花色顦顇。", "明日花更開，新花何以異。"]'),
('09c1673c-a7b6-44df-9909-63cf5c6baa0f','山中夜行','梅堯臣','宋','宋诗','song-poetry','','[]','孤客心多恐，寒風夜度溪。',48,'全唐诗/poet.song.13000.json','["孤客心多恐，寒風夜度溪。", "山長羸馬困，月黑怪禽啼。", "遠火生樵舍，荒榛亂野蹊。", "喜言林館近，聞犬入猶迷。"]'),
('57b0f05b-6eb2-4f4d-ab8c-c83ef7b3d2b9','啄木','梅堯臣','宋','宋诗','song-poetry','','[]','中園啄盡蠹，未肯出林飛。',24,'全唐诗/poet.song.13000.json','["中園啄盡蠹，未肯出林飛。", "不識黄金彈，雙翎墜落暉。"]'),
('e7490a5c-bd7d-454a-8a76-7a4d808b7211','夢與公度同賦藕華追錄之','梅堯臣','宋','宋诗','song-poetry','','[]','吳王舊宮闕，水殿芙蓉披。',36,'全唐诗/poet.song.13000.json','["吳王舊宮闕，水殿芙蓉披。", "濁泥留玉骨，疑是葬西施。", "西施魂不滅，嬌豔葬清池。"]'),
('b9399d0f-690e-4363-9fa0-153d5f6faef9','和綺翁遊齊山寺次其韻','梅堯臣','宋','宋诗','song-poetry','','[]','蒼山南望截雲煙，中有紺宇通諸天。',272,'全唐诗/poet.song.13000.json','["蒼山南望截雲煙，中有紺宇通諸天。", "長橋直度清溪水，寒湖收潦曠平田。", "古木陰森大堤上，千峯濃淡高樓前。", "龍筍未迸角出縮，虎石亂踞筋拳攣。", "陰崖乳泉濕苔蘚，陽谷暖氣留蘭荃。", "澗戶曉闢煙的的，松軒夜啟月娟娟。", "聞有謫僊乘興入，飄然欲拍洪崖肩。", "玩遊逐勝不覺遠，露奇發怪工無全。", "捫蘿但識康樂徑，飲酒安問遠公禪。", "清猿不到俗士耳，香草已入騷人篇。", "水鳥念佛次浄界，野鹿銜花來象筵。", "在昔探賞猶可數，深景秀句今得傳。", "辭韻險絕茲所駭，何特杜牧專當年。", "重以平淡若古樂，聽之疏越如朱絃。", "秘藏褚中爲不朽，咨諏坐上皆曰然。", "誰意麤官獲此貺，洗去鄙吝空池邊。", "聊欲報言罕驛使，春郊唯見雁連連。"]'),
('e39c452d-e46f-4bc1-9805-98684746617c','范待制約遊廬山以故不往因寄','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','平昔愛山水，茲聞廬嶽遊。',48,'全唐诗/poet.song.13000.json','["平昔愛山水，茲聞廬嶽遊。", "遠期無逸興，獨往畏湍流。", "舉手謝雲壑，棲心慙鳥鷗。", "香爐碧峯下，應爲一遲留。"]'),
('f83b8a8b-c749-4b40-a896-dbbebfc60ccf','范饒州坐中客語食河豚魚','梅堯臣','宋','宋诗','song-poetry','','[]','春洲生荻芽，春岸飛楊花。',168,'全唐诗/poet.song.13000.json','["春洲生荻芽，春岸飛楊花。", "河豚當是時，貴不數魚蝦。", "其狀已可怪，其毒亦莫加。", "忿腹若封豕，怒目猶吳蛙。", "庖煎苟失所，入喉爲鏌鋣。", "若此喪軀體，何須資齒牙。", "持問南方人，黨護復矜誇。", "皆言美無度，誰謂死如麻。", "我語不能屈，自思空咄嗟。", "退之來潮陽，始憚餐籠蛇。", "子厚居柳州，而甘食蝦蟆。", "二物雖可憎，性命無舛差。", "斯味曾不比，中藏禍無涯。", "甚美惡亦稱，此言誠可嘉。"]'),
('3edb2675-e8d7-4d9d-9986-c650de521286','徐元輿見邀與諸君同遊至峯山溪上作','梅堯臣','宋','宋诗','song-poetry','','[]','春霽重行行，行行在墟里。',96,'全唐诗/poet.song.13000.json','["春霽重行行，行行在墟里。", "攄懷厭樓觀，寓興欣山水。", "斷壁翠連雲，寒流清見底。", "主人開綠樽，下馬臨芳芷。", "澄溜瀉灣漘，跳波生石齒。", "園林始弄萼，臯壠時鳴雉。", "談謔忘機心，笑言驚俗耳。", "曠哉茲日遊，何羨稽山美。"]'),
('07b5187e-964c-4375-974b-b694203b4beb','和元輿遊春次用其韻','梅堯臣','宋','宋诗','song-poetry','','[]','乘閑多遠興，信馬與君行。',48,'全唐诗/poet.song.13000.json','["乘閑多遠興，信馬與君行。", "碧樹斜通市，清流曲抱城。", "山花高下色，春鳥短長聲。", "日暮吾廬近，還歌空復情。"]'),
('a68fd8c8-fcac-4b71-9f73-a0151cf74203','留別李君君頗有歸意而未遂','梅堯臣','宋','宋诗','song-poetry','','[]','酌我罇中酒，知君羨北歸。',24,'全唐诗/poet.song.13000.json','["酌我罇中酒，知君羨北歸。", "如何沙上鳥，遠逐片帆飛。"]'),
('265c5df8-9298-494c-b2e7-cc16e608af96','離蕪湖至觀頭橋','梅堯臣','宋','宋诗','song-poetry','','[]','江口泊來久，菰蒲長舊苗。',48,'全唐诗/poet.song.13000.json','["江口泊來久，菰蒲長舊苗。", "爭雛洲鵲鬭，遺子浦魚跳。", "宿岸欣逢戍，歸船競趁潮。", "時時望鄉樹，已恨白雲遥。"]'),
('42f46ec6-5e91-45be-9864-793106ad6413','馬秘書始約同行久而未至因以寄','梅堯臣','宋','宋诗','song-poetry','','[]','渡江落我前，入汴居我後。',48,'全唐诗/poet.song.13000.json','["渡江落我前，入汴居我後。", "日日是南風，時時爲迴首。", "逢船一借問，遠棹見來否。", "明朝儻相及，閑步河堤柳。"]'),
('92cef4c1-25cb-40f2-879b-8b734d7bd7a0','寄建德徐元輿','梅堯臣','宋','宋诗','song-poetry','','[]','才子方爲邑，千峯對縣門。',48,'全唐诗/poet.song.13000.json','["才子方爲邑，千峯對縣門。", "靜寒琴意古，閑厭鳥聲喧。", "山茗烹仍綠，池蓮摘更繁。", "訟稀應物詠，庭下長蘭蓀。"]'),
('d6308ed7-05ac-4e7d-9b77-8ab608a08de4','詠苜蓿','梅堯臣','宋','宋诗','song-poetry','','[]','苜蓿來西域，蒲萄亦既隨。',48,'全唐诗/poet.song.13000.json','["苜蓿來西域，蒲萄亦既隨。", "胡人初未惜，漢使始能持。", "宛馬當求日，離宮舊種時。", "黄花今自發，撩亂牧牛陂。"]'),
('7db26d0b-a73e-44cb-909f-fb1006bb072a','汴河雨後呈同行馬秘書','梅堯臣','宋','宋诗','song-poetry','','[]','雨霽晚虹收，河堤浄如掃。',48,'全唐诗/poet.song.13000.json','["雨霽晚虹收，河堤浄如掃。", "清陰拂人樹，翠色垂流草。", "漢漕走王都，華言雜夷獠。", "時方同馬生，野泊聊論道。"]'),
('ab5de997-da3c-4a2e-b1b8-a04791a91dfc','夏日汴中作','梅堯臣','宋','宋诗','song-poetry','','[]','倚棹望平野，低雲密未收。',48,'全唐诗/poet.song.13000.json','["倚棹望平野，低雲密未收。", "黄鸝度高柳，歸燕拂行舟。", "濁水不堪照，清江空憶遊。", "晚晴蒸潤劇，喘月見吳牛。"]'),
('80a2a070-ffc4-4675-991f-f69632b4ed3b','夢故府錢公','梅堯臣','宋','宋诗','song-poetry','','[]','故相方來夢，分明接座隅。',48,'全唐诗/poet.song.13000.json','["故相方來夢，分明接座隅。", "只知冠劍是，不道死生殊。", "西府看如舊，東山詠久徂。", "遽然興寤歎，不覺淚霑鬚。"]'),
('91236680-5559-4f53-a7ac-c5f679e53240','謝紫微以畫鷺二軸爲寄','梅堯臣','宋','宋诗','song-poetry','','[]','白鷺畫雙素，粉毫幽趣多。',48,'全唐诗/poet.song.13000.json','["白鷺畫雙素，粉毫幽趣多。", "翹沙依折葦，刷羽對衰荷。", "浦思懸秋壁，江情憶釣蓑。", "因君遠相寄，詩詠對滄波。"]'),
('45a81fe4-95c5-4389-ba6b-40518584b37d','宿州河亭書事','梅堯臣','宋','宋诗','song-poetry','','[]','遠泛千里舟，暫向郊亭泊。',96,'全唐诗/poet.song.13000.json','["遠泛千里舟，暫向郊亭泊。", "觀物趣無窮，適情吟有託。", "林中鴉舅獰，席上蠅虎攫。", "雨久草苗盛，田蕪瓜蔓弱。", "香粳稚子慣，脫粟家人薄。", "少年都下來，聊問時所作。", "新衣尚穿束，舊服變襃博。", "我今貧且賤，短褐隨宜著。"]'),
('2824177e-cee8-4963-bf1a-08bb2c05f01a','晚泊觀鬬雞','梅堯臣','宋','宋诗','song-poetry','','[]','舟子抱雞來，雄雄跱高岸。',144,'全唐诗/poet.song.13000.json','["舟子抱雞來，雄雄跱高岸。", "側行初取勢，俯啄示無憚。", "先鳴氣益振，奮擊心非愞。", "勇頸毛逆張，怒目眥裂盰。", "血流何所爭，死鬭欲充玩。", "應當激猛毅，豈獨專晨旦。", "勝酒人自私，粒食誰爾喚。", "緬懷彼興魏，傍睨當衰漢。", "徒然驅國衆，曾靡救時難。", "羣雄自苦戰，九錫邀平亂。", "寶玉歸大姦，干戈託奇算。", "從來小資大，聊用一長歎。"]'),
('4bb47833-2590-4905-8e44-5e5600049aa2','聞表兄施先輩上第','梅堯臣','宋','宋诗','song-poetry','','[]','昔人事功名，五十未爲老。',60,'全唐诗/poet.song.13000.json','["昔人事功名，五十未爲老。", "而今君已及，得桂誠非早。", "所慰白頭親，且將黄綬好。", "吾始日夜心，望盡京關道。", "拜慶早歸來，莫變秋庭草。"]'),
('f3d2cbdc-21c7-400e-b4c5-1749eb0ec27c','雍丘逢錢寺丞載陽','梅堯臣','宋','宋诗','song-poetry','','[]','殷勤魏公子，落莫吳王孫。',24,'全唐诗/poet.song.13000.json','["殷勤魏公子，落莫吳王孫。", "下客獨垂淚，傷心思舊恩。"]'),
('b8fe34c2-b4c2-4b0c-8079-4ef02da15103','廟子灣辭','梅堯臣','宋','宋诗','song-poetry','','[]','我之東來兮過彼雍丘，舟師奏功兮濁水湍流。',181,'全唐诗/poet.song.13000.json','["我之東來兮過彼雍丘，舟師奏功兮濁水湍流。", "歷長灣兮勢曲鉤，傾高斗折兮若奔虬。", "潛伏怪物兮深幽幽，發作暴漲兮爲潮頭。", "土人立祠兮在彼沙洲，老木蒼蒼兮蟬噪啾啾。", "輸卒引繂兮蓬首裸體劇縲囚，赤日上煎兮膠津蹙氣塞咽喉。", "胸盪肩挨同軛牛，足進復退不得休。", "竟持紙幣挂廟陬，微風飄揚如喜收。", "我今語神神聽不，何不歸海事陽侯。", "穹魚大龜非爾儔，奚必區區此汴溝。", "驚愚駭俗得肴羞，去就當决何遲留。"]'),
('041904c4-8b2b-4bc9-8615-5fa61ca4a2d2','送蔡侍禁赴長沙','梅堯臣','宋','宋诗','song-poetry','','[]','寒葉下瀟湘，之官逐雁行。',48,'全唐诗/poet.song.13000.json','["寒葉下瀟湘，之官逐雁行。", "水經菱浦晚，船過橘洲香。", "二女竹林外，三閭楓葉傍。", "平時息戎律，物景助才章。"]'),
('7e6b2d9f-d3e3-4735-bfad-a855ffac5c8c','送馬廷評之餘姚','梅堯臣','宋','宋诗','song-poetry','','[]','越鄉知勝楚，君去莫辭遥。',48,'全唐诗/poet.song.13000.json','["越鄉知勝楚，君去莫辭遥。", "曉日魚蝦市，新霜橘柚橋。", "河流通海道，山井應江潮。", "近邑逢鷗鳥，先應避畫橈。"]'),
('5ac4f64c-71f3-43b0-8399-44ad06ea2827','送秀州海鹽知縣李寺丞','梅堯臣','宋','宋诗','song-poetry','','[]','吳帆千里去，邑屋富魚鹽。',48,'全唐诗/poet.song.13000.json','["吳帆千里去，邑屋富魚鹽。", "霜鶴亭臯唳，風烏海客占。", "滄凉朝日近，紫翠晚山尖。", "若過陸機宅，寒蕪應不嫌。"]'),
('cb5e4d17-27c1-495a-97a8-9385468fbd1d','送馬廷評知康州','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','南去晉康郡，風帆幾千里。',72,'全唐诗/poet.song.13000.json','["南去晉康郡，風帆幾千里。", "辭家上洞庭，落葉過湘水。", "瀧吏迎使君，壺漿出蠻壘。", "問俗言未通，觀風想先喜。", "曾非異方趣，頗與華人擬。", "期子寄梅花，無由問行李。"]'),
('2fe241f3-bbb5-4aad-866f-6fe1477ba08c','過鳴雁城','梅堯臣','宋','宋诗','song-poetry','','[]','九月過鳴雁，斜陽上廢臺。',48,'全唐诗/poet.song.13000.json','["九月過鳴雁，斜陽上廢臺。", "兵車千載會，桑柘萬疇開。", "代謝隨秋草，英靈化死灰。", "我來空詠古，寒鳥有餘哀。"]'),
('af796467-1000-4fda-a2c2-6ecab92b541c','送余駕部江州','梅堯臣','宋','宋诗','song-poetry','','[]','內史九江行，潦收波已清。',48,'全唐诗/poet.song.13000.json','["內史九江行，潦收波已清。", "何時鷁舟上，遠見爐峯迎。", "野色連葭菼，秋香薦橘橙。", "寒潮如特送，不肯過湓城。"]'),
('bd3f7f1d-ad29-4e80-9bbe-2179ea1057e7','依韻和陳秘校見寄','梅堯臣','宋','宋诗','song-poetry','','[]','鬰鬰東堂桂，常期接袂攀。',48,'全唐诗/poet.song.13000.json','["鬰鬰東堂桂，常期接袂攀。", "羽翰殊不及，蓬蓽却空還。", "江水幾經歲，鑑中無壯顔。", "音塵能見問，誰道隔雲山。"]'),
('e56f7acf-df88-4279-a5c7-d7e8498638ff','送張子野秘丞知鹿邑','梅堯臣','宋','宋诗','song-poetry','','[]','忽作五年別，相逢雙鬢疎。',48,'全唐诗/poet.song.13000.json','["忽作五年別，相逢雙鬢疎。", "不知從此去，當見復何如。", "公秫時爲酒，晨庖日有魚。", "沛譙風物美，聊以樂琴書。"]'),
('5ba2b6ee-b421-4ab6-978c-f507aa38d8a7','送王紫微北使','梅堯臣','宋','宋诗','song-poetry','','[]','天子命儒臣，遐方重專對。',72,'全唐诗/poet.song.13000.json','["天子命儒臣，遐方重專對。", "持書下西閣，擁節來窮塞。", "貂服紫蒙茸，虎旗光綵綷。", "將迎走氈騎，衛從羅金鎧。", "當宣漢恩德，便使胡欣戴。", "幾日過陰山，南飛雁相背。"]'),
('da80053b-7170-4e41-be64-dcce76e63b3b','九月都下對雪寄永叔師魯','梅堯臣','宋','宋诗','song-poetry','','[]','陰風中夜鳴，密雪逗曉積。',72,'全唐诗/poet.song.13000.json','["陰風中夜鳴，密雪逗曉積。", "誰言有蓬巷，但見鋪瑶席。", "忽憶在山中，開戶羣峯白。", "當時吟不厭，盡日坐巖石。", "徬徨懷故人，憔悴爲遷客。", "欲泛剡溪船，路長安可適。"]'),
('6b5cf844-acad-4700-8faf-478ecfdb4119','劉弟示詩一軸走筆答之','梅堯臣','宋','宋诗','song-poetry','','[]','昔與伯氏吟，青銅照人髮。',48,'全唐诗/poet.song.13000.json','["昔與伯氏吟，青銅照人髮。", "今又讀君詩，寒冰徹人骨。", "時時探古趣，往往到月窟。", "清濟流不休，終期至溟渤。"]'),
('8f262951-834c-451f-99ac-1f09fd39a441','劉十秀才見過尋以爲寄次韻和酬','梅堯臣','宋','宋诗','song-poetry','','[]','放言破崖岸，塵事盡磨刮。',48,'全唐诗/poet.song.13000.json','["放言破崖岸，塵事盡磨刮。", "況此氣澄明，幽襟亦軒豁。", "竟日坐衡茅，同心異胡越。", "吾道今不孤，長吟爲君發。"]'),
('9a7a9023-b86e-4f3a-9dab-114d2c8cff6a','依韻和劉敞秀才','梅堯臣','宋','宋诗','song-poetry','','[]','安得采虛名，師道欲吾廣。',144,'全唐诗/poet.song.13000.json','["安得采虛名，師道欲吾廣。", "雖然成術業，曾不計少長。", "孔孟久已亡，富貴得亦儻。", "後生不聞義，前輩懼爲黨。", "退之昔獨傳，力振功不賞。", "舌吻張洪鍾，小大扣必響。", "近世復泯滅，務覺多忽怳。", "今子誠有志，方駕已屢枉。", "自慙懷道淺，所得可下上。", "正如種青松，而欲託朽壤。", "典冊皆可尋，聖言皆可仰。", "幸無增我過，此語固不爽。"]'),
('fa903fb1-616d-4866-a005-4e0c73c1a880','依韻和劉十秋霖','梅堯臣','宋','宋诗','song-poetry','','[]','秋草更綠秋林衰，長安遊客未成衣。',32,'全唐诗/poet.song.13000.json','["秋草更綠秋林衰，長安遊客未成衣。", "凄凄斗欲變寒色，一夜獨語看燈輝。"]'),
('d6a86383-ad11-4de8-912e-7ee4e4e11cb6','送劉十往荆渚','梅堯臣','宋','宋诗','song-poetry','','[]','臨水一太息，解舟當落暉。',48,'全唐诗/poet.song.13000.json','["臨水一太息，解舟當落暉。", "上樓人已遠，極目鳥空飛。", "荆楚時方晏，江湖客未歸。", "定知吟憶處，林外月光微。"]'),
('100b0d6d-728e-4a74-8b4a-2f72699adf45','祫禮頌聖德詩','梅堯臣','宋','宋诗','song-poetry','','[]','溥哉孝享，將事于寧。',240,'全唐诗/poet.song.13000.json','["溥哉孝享，將事于寧。", "文武卿士，冠劍在庭。", "爰俟帝齋，風霰其零。", "風霰不已，鈎陳豹尾。", "龍旂太常，立列比比。", "帝居路寢，百辟就次。", "至于穀旦，漫漫翳翳。", "帝入靈宮，左撞黄鍾。", "陞階置玉，日氣曈鴻。", "鴻鴻杲杲，氛駁陰掃。", "宿于太宮，月星皓皓。", "侍祠之臣，鵠舉鷺振。", "或捧其匜，或進其巾。", "輔相夾導，俯僂鱗鱗。", "圭瓚以陳，登歌以均。", "東向虛位，發爵親親。", "平明帝還，紫宸序班。", "望帝之顔，穆穆閑閑。", "簷步廊廊，雪浮陽光。", "大楹爛爛，朱陛煌煌。", "稱祝萬壽，萬壽無疆。", "却登寶輿，以御端門。", "揭雞肆赦，雷動乾坤。", "于時都人，于時婦女。"]'),
('80850f90-3ddc-42db-9f87-f3653a34d656','祫享觀禮二十韻','梅堯臣','宋','宋诗','song-poetry','','[]','卜惟陽月吉，孝享禮方脩。',240,'全唐诗/poet.song.13000.json','["卜惟陽月吉，孝享禮方脩。", "齋幄嚴宮殿，羣臣奉冕旒。", "北風先集霰，夜雪競侵幬。", "羽仗天街立，龍笳象魏流。", "翌朝升寶輅，夾道列華輈。", "琳宇躬將款，珠塵密未收。", "撞鐘鈞奏合，奠玉日光浮。", "捧冊叨於左，觀儀得以周。", "帝來清廟下，月欲大刀頭。", "既祼還初次，更衣戴遠游。", "黄麾轉槐路，朱輦駕雲虬。", "武士羅金甲，中人著錦褠。", "千官入稱慶，萬國與同休。", "却出紫宸閣，俄登宣德樓。", "雞星傳巽令，鶴馭作天郵。", "肆赦通皇澤，深仁被九州。", "巍巍百世業，坦坦四夷柔。", "惠及高年叟，恩差五等侯。", "力田仍給復，有道俾旁求。", "何以歌堯美，茲同擊壤謳。"]'),
('479c5ae0-a771-4bee-a0a6-96102e3e594b','寶元聖德詩','梅堯臣','宋','宋诗','song-poetry','','[]','齋誠羽衛陳，庚戌推蓂莢。',144,'全唐诗/poet.song.13000.json','["齋誠羽衛陳，庚戌推蓂莢。", "靈宮容物備，清廟威儀攝。", "遲明導玉輿，出宿戒清堞。", "冥濛雲霧低，泱漭乾坤接。", "時雪凝九霄，金笳競三疊。", "來賓萬國會，受職百神協。", "中夜即壇壝，濃陰駁鱗鬣。", "及爾圭幣升，煥然星斗曄。", "華鍾帝樂張，法從天衢躡。", "端門清旭上，肆宥歡聲浹。", "寶圖增大號，元曆開皇刼。", "吉甫獨何人，詠歌揚聖業。"]'),
('2f3be010-afbe-4e8e-b013-4b046f01e210','送胡臣秀才','梅堯臣','宋','宋诗','song-poetry','','[]','汴水日夜淺，歸船不可留。',48,'全唐诗/poet.song.13000.json','["汴水日夜淺，歸船不可留。", "天高雲就嶺，地冷雁迴洲。", "江館魚堪食，家林橘已收。", "平生素業在，莫見里人羞。"]'),
('8bd1a89f-4349-4a85-8689-f9cc999fcd6e','送張秀才之淮南','梅堯臣','宋','宋诗','song-poetry','','[]','聊爲楚客唱，一送淮南行。',48,'全唐诗/poet.song.13000.json','["聊爲楚客唱，一送淮南行。", "出汴遠心喜，移舟孤岫橫。", "危帆將進浦，寒霧不分城。", "枚乘舊居處，向來秋草生。"]'),
('81244c72-975c-45a6-9ad0-b4be076c7406','還文雅師書帙','梅堯臣','宋','宋诗','song-poetry','','[]','編絕不加新，于今十二春。',48,'全唐诗/poet.song.13000.json','["編絕不加新，于今十二春。", "綠窗重展目，靜几勿生塵。", "豈愛吾廬日，終將道者親。", "莫嫌同刺字，漫滅看難真。"]'),
('28f7cb5c-99e8-41a2-801e-97e112bde1e6','依韻和徐元輿讀寄內詩戲成','梅堯臣','宋','宋诗','song-poetry','','[]','鴛鴦同白首，相得在中河。',24,'全唐诗/poet.song.13000.json','["鴛鴦同白首，相得在中河。", "水客莫驚笑，雲間比翼多。"]'),
('caeded4b-9fcb-4314-a9db-f12fb9eb0865','送賢良田太丞通判江寧','梅堯臣','宋','宋诗','song-poetry','','[]','世爲燕趙客，慷慨有奇才。',48,'全唐诗/poet.song.13000.json','["世爲燕趙客，慷慨有奇才。", "對策漢庭後，拜官江國來。", "舟從瓜步去，潮自蔣山回。", "心寄城頭月，相隨上古臺。"]'),
('9cf43451-406e-4958-bbc5-214f3e143cf5','送邵夢得永康軍判官','梅堯臣','宋','宋诗','song-poetry','','[]','言籬洛陽日，正值春風前。',48,'全唐诗/poet.song.13000.json','["言籬洛陽日，正值春風前。", "伊水矯白鷺，蜀山鳴杜鵑。", "輕袍游宦去，匹馬度關年。", "若過君平肆，窮通可問焉。"]'),
('10c4f2e3-54e6-4777-9d8d-ff0c2b2a5959','送蕭監丞濬宰臨邑','梅堯臣','宋','宋诗','song-poetry','','[]','羨君先拜邑，殘臘見登車。',48,'全唐诗/poet.song.13000.json','["羨君先拜邑，殘臘見登車。", "遠驛寒雲重，長郊積雪餘。", "行當勸民稼，始信带經鋤。", "還到濟南日，應傳古尚書。"]'),
('260a12d6-fbee-478b-be10-313ad7193dea','南鄰蕭寺丞夜話別','梅堯臣','宋','宋诗','song-poetry','','[]','憶昨偶相親，相親如舊友。',72,'全唐诗/poet.song.13000.json','["憶昨偶相親，相親如舊友。", "雖言我巷殊，正住君家後。", "壁裏射燈光，籬根分井口。", "來邀食有魚，屢過貧無酒。", "明日定徂征，聊茲酌升斗。", "宵長莫惜醉，路遠空迴首。"]'),
('a33a216b-9d58-4f00-beab-5629ce9baa79','讀司馬季主傳贈何山人','梅堯臣','宋','宋诗','song-poetry','','[]','長安新雨後，九陌少行人。',192,'全唐诗/poet.song.13000.json','["長安新雨後，九陌少行人。", "同輿有宋賈，游市懷隠淪。", "日聞古賢哲，必與醫卜鄰。", "來過季主室，再拜語逡巡。", "矍然悟辭貌，何爲居埃塵。", "捧腹乃大笑，吾道非爾臻。", "驥慙罷馿駟，鳳豈燕雀親。", "筮占聊助上，功利儻及民。", "大夫與博士，登車若喪神。", "今我見何遯，始驗太史真。", "順性誨善惡，不離義與仁。", "言孝諭爲子，言忠諭爲臣。", "又得蜀嚴比，寧將日者均。", "京都盛龜筴，坐肆如魚鱗。", "噤口不正言，唯能辨冬春。", "鴻冥復何慕，安得雞鶩馴。"]'),
('3eb30963-4e22-47af-b8df-cbcb3b761147','臘日雪','梅堯臣','宋','宋诗','song-poetry','','[]','風毛隨校臘，浩浩古原沙。',48,'全唐诗/poet.song.13000.json','["風毛隨校臘，浩浩古原沙。", "寒入弓聲健，陰藏兔徑賒。", "馬頭迷玉勒，鷹背落梅花。", "少壯心空在，悠然感歲華。"]'),
('bafe065c-f084-43b2-8b61-08713a822d14','依韻和雍丘尉王秘校見寄','梅堯臣','宋','宋诗','song-poetry','','[]','東瞻杞國城，半日鳥飛程。',48,'全唐诗/poet.song.13000.json','["東瞻杞國城，半日鳥飛程。", "度雁不曾下，新文誰寄評。", "舊年因使至，秀句欲人驚。", "聊效題齋壁，先賢亦以旌。"]'),
('da21ba6c-ed00-4f0e-982a-0f0b42c7940a','送新安張尉乞侍養歸淮甸','梅堯臣','宋','宋诗','song-poetry','','[]','天兵出塞日，西尉去官初。',48,'全唐诗/poet.song.13000.json','["天兵出塞日，西尉去官初。", "却衣老萊服，曾無梅福書。", "春郊欲迴雁，寒水正沉魚。", "任意歸舟駛，風煙亦自如。"]'),
('67c9287e-f163-445d-8113-662e3809915b','依韻和子聰見寄','梅堯臣','宋','宋诗','song-poetry','','[]','嘗念餞行舟，風蟬動去愁。',48,'全唐诗/poet.song.13000.json','["嘗念餞行舟，風蟬動去愁。", "獨登孤岸立，不見遠帆收。", "及送故人盡，亦嗟歸迹留。", "洛陽君更憶，寧復醉危樓。"]'),
('44421835-56f4-40fd-9b6f-2d78c53402d7','送何遯山人歸蜀','梅堯臣','宋','宋诗','song-poetry','','[]','春風入樹綠，童稚望柴扉。',48,'全唐诗/poet.song.13000.json','["春風入樹綠，童稚望柴扉。", "遠壑杜鵑響，前山蜀客歸。", "到家逢社燕，下馬澣征衣。", "終日自臨水，應知已息機。"]'),
('9dbbae19-22fd-480d-83e2-986b8818aee9','寄衡山福嚴長老','梅堯臣','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山幾千里，聞在湘川側。',48,'全唐诗/poet.song.13000.json','["衡山幾千里，聞在湘川側。", "雲霞不可到，峯壑無由識。", "方丈開其間，青松隠寒色。", "飛鴻尚莫過，況寄雙鳬翼。"]'),
('4d967419-db3f-49aa-a216-5d78d4446cc1','曲渚橋送張秘校赴慶州幕','梅堯臣','宋','宋诗','song-poetry','','[]','野客伐山桂，橫爲曲渚橋。',48,'全唐诗/poet.song.13000.json','["野客伐山桂，橫爲曲渚橋。", "勢危寧過馬，徑狹欲通樵。", "小艇何妨繫，離魂正此銷。", "想君迴首處，虹影在林椒。"]'),
('10cf43b6-6f88-4a69-be00-2986ea11b9f0','南陽謝公祈雨','梅堯臣','宋','宋诗','song-poetry','','[]','雲龍本職雨，不雨其失職。',96,'全唐诗/poet.song.13000.json','["雲龍本職雨，不雨其失職。", "萬草欲焚如，千疇幾赭色。", "刺史爲民憂，侵晨車競飭。", "朅來欵宮祠，豈不念黍稷。", "𩃗靄隨輪軒，霶𩃱徧畛域。", "孰謂雲龍愚，能成仁惠德。", "濯濯羣物新，葱葱衆苗殖。", "莫比邵父渠，初慙用人力。"]'),
('2627cceb-e033-4353-a4ab-bbd3ea1f3aaf','西禪院竹','梅堯臣','宋','宋诗','song-poetry','','[]','古寺带脩岡，青葱萬竿玉。',48,'全唐诗/poet.song.13000.json','["古寺带脩岡，青葱萬竿玉。", "春梢長舊林，夏雨濕新綠。", "幽禽嘯呼雜，晚照陰晴續。", "解带欲忘歸，壺觴歡自足。"]'),
('d8bc942d-ad2f-4a9d-8b89-e7b5030b1b8a','新霽望岐笠山','梅堯臣','宋','宋诗','song-poetry','','[]','北望直百里，峨峨千仞青。',48,'全唐诗/poet.song.13000.json','["北望直百里，峨峨千仞青。", "斷虹迎日盡，飛雨带龍腥。", "陰壑煙雲畜，陽崖草木靈。", "登臨終不厭，時許到茲亭。"]'),
('53a6d11f-363a-4e9b-8cec-3b7184219b39','師厚生日因以詩贈','梅堯臣','宋','宋诗','song-poetry','','[]','龍驥産龍駒，良金出良冶。',60,'全唐诗/poet.song.13000.json','["龍驥産龍駒，良金出良冶。", "良冶無頑礦，龍駒豈凡馬。", "致遠在御徒，作礪由工者。", "君子生慶門，詩書未嘗捨。", "進道期日隆，無愧金馬下。"]'),
('529ad307-f691-4532-b6a2-1d76cc547013','晝寢','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞晉高士，時偃北窗風。',48,'全唐诗/poet.song.13000.json','["嘗聞晉高士，時偃北窗風。", "及爾寂無慮，始知機盡空。", "便便嘲已解，栩栩夢何窮。", "一寤復一寐，百年消此中。"]'),
('28c76366-244c-4857-9367-14870f37d386','過白水','梅堯臣','宋','宋诗','song-poetry','','[]','下馬獨懷古，翛然臨渡風。',48,'全唐诗/poet.song.13000.json','["下馬獨懷古，翛然臨渡風。", "真人去來久，流水自無窮。", "雨闊沙痕漲，灣平野色通。", "曾興漢家業，今與百川同。"]'),
('d9a6960e-3b8d-4422-bf8c-e73faaa770d7','泛舟城隅呈永叔','梅堯臣','宋','宋诗','song-poetry','','[]','藤竹繞城陰，煙梢拂濠水。',48,'全唐诗/poet.song.13000.json','["藤竹繞城陰，煙梢拂濠水。", "山禽時一鳴，楚客孤舟裏。", "孤舟穿綠荷，獵獵雨新過。", "誰思暮江上，只尺採蓮歌。"]'),
('1204de88-761e-46fa-85a1-754777b4e9a4','送永叔歸乾德','梅堯臣','宋','宋诗','song-poetry','','[]','淵明節本高，曾不爲吏屈。',48,'全唐诗/poet.song.13000.json','["淵明節本高，曾不爲吏屈。", "斗酒從故人，籃輿傲華紱。", "悠然目遠空，曠爾遺羣物。", "飲罷即言歸，胸中寧鬰鬰。"]'),
('309dfc61-db48-4e48-9c63-30184178267c','代書寄歐陽永叔四十韻','梅堯臣','宋','宋诗','song-poetry','','[]','始謫夷陵日，當居建德年。',288,'全唐诗/poet.song.13000.json','["始謫夷陵日，當居建德年。", "一書冤逐客，四詠繼稱賢。", "自謂臨江徼，相逢莫我先。", "白醪封畫榼，素鯉養泓泉。", "戒吏收山栗，呼童惜沼蓮。", "只期東浦過，共醉小溪邊。", "日日占風勢，時時到水堧。", "安知貪挂席，不肯暫迴船。", "自爾皆無定，歸歟亦未然。", "指程幾一月，泝險歷三千。", "魚鳥都難問，音塵杳莫傳。", "因之走羸僕，試與訪南遷。", "比及過牛峽，還聞迎璧田。", "報言雖不獲，吉語喜多全。", "我解歸堯闕，君移近漢淵。", "問途曾未遠，命駕亦何緣。", "衰野今行矣，隆中有待焉。", "鄉亭瓜接軫，風化蟻同羶。", "即欲朋簪盍，翻爲俗事牽。", "愛嬰嬌啞啞，嗜寢復便便。", "雞黍煩爲具，輪轅豈得前。", "寄聲勤以謝，幸子恕而憐。", "來貺誠爲望，論情恐未捐。", "嘗親馬南郡，果謁謝臨川。"]'),
('0d272b64-cf87-44a8-8b53-9763b064508f','漸嘉樓望雨陪謝守','梅堯臣','宋','宋诗','song-poetry','','[]','冒雨上城頭，凄凄欲報秋。',48,'全唐诗/poet.song.13000.json','["冒雨上城頭，凄凄欲報秋。", "雲低密藏樹，風急暗侵樓。", "漸積荷珠重，新添沼鑑幽。", "憑欄未能去，公自念民疇。"]'),
('a24f460c-ee3b-42a2-a118-8c3066b0a630','和謝舍人洊震','梅堯臣','宋','宋诗','song-poetry','','[]','盛夏萬物當長養，驕陽不雨誰爲憂。',208,'全唐诗/poet.song.13000.json','["盛夏萬物當長養，驕陽不雨誰爲憂。", "天無纖雲野赬色，草木焦卷如經秋。", "南陽太守自引咎，不以天時爲怨尤。", "齋精潔慮祠望內，僚屬奔從無停輈。", "謾取詩言占離畢，徒依風俗驗鳴鳩。", "忽聞郡北直百里，岑岑岐笠藏靈湫。", "持牲遣吏詣其下，俎豆未徹升陰虬。", "電光劃劃遶巖壁，雷聲隠隠生山陬。", "擁雲馳雨自東上，西風斗猛雲還收。", "神龍蓄志未發泄，明日更與頑陽讎。", "黤靄陰黑若卷海，聯綿霹靂能破仇。", "沃然原隰洗妖氣，浩爾溝瀆揚平流。", "九穀有登百姓喜，蜿蜒歆祀神何羞。"]'),
('caa6c896-5e27-43ec-8d94-6a54bf8a6171','和謝舍人新秋','梅堯臣','宋','宋诗','song-poetry','','[]','西風一夕狂，古屋吹可恐。',48,'全唐诗/poet.song.13000.json','["西風一夕狂，古屋吹可恐。", "微變蜻蛚吟，斗摧蚊蚋勇。", "朝驚露墜梧，遠愛雲飛隴。", "還憶舊溪遊，水清漁箔壅。"]'),
('f57db46d-dbfc-4457-b0d8-d401ce678ee9','中秋新霽壕水初滿自城東隅泛舟迴謝公命賦','梅堯臣','宋','宋诗','song-poetry','','[]','齋舫談經後，官池載酒行。',48,'全唐诗/poet.song.13000.json','["齋舫談經後，官池載酒行。", "斜陽鳥外落，新月樹端生。", "演漾思江浦，夷猶繞郡城。", "東轅有遺恨，日日物華清。"]'),
('cf478bd8-f79e-4304-a12f-5660284925f5','陪謝紫微晚泛','梅堯臣','宋','宋诗','song-poetry','','[]','積雨漲秋壕，輕舟此共遨。',48,'全唐诗/poet.song.13000.json','["積雨漲秋壕，輕舟此共遨。", "菰蒲斂鋩鍔，蓮芡熟櫜韜。", "岸靜魚跳月，林喧鳥避篙。", "歸時興不淺，風物正蕭騷。"]'),
('f1fd980c-25c8-4ee1-9c77-0d104f74effb','奉陪覽秀亭拋堶','梅堯臣','宋','宋诗','song-poetry','','[]','聊爲飛礫戲，愈切愈紛如。',48,'全唐诗/poet.song.13000.json','["聊爲飛礫戲，愈切愈紛如。", "自是取勢闊，非關用意疎。", "悞驚花鳥起，亂破錦苔初。", "童指拾將禿，多慙賈勇餘。"]'),
('8bccb680-a475-4cb9-9b72-7f44470c4047','傷馬','梅堯臣','宋','宋诗','song-poetry','','[]','吾貧只一馬，昨日忽云喪。',48,'全唐诗/poet.song.13000.json','["吾貧只一馬，昨日忽云喪。", "庭樹齧無膚，秋郊誰復放。", "空傷駿骨埋，固乏弊帷葬。", "況本出天閑，因之重怊悵。"]'),
('d991ba06-4832-4c5d-92e1-4fcce02031df','一日曲','梅堯臣','宋','宋诗','song-poetry','','[]','妾家鄧侯國，肯愧邯鄲姝。',240,'全唐诗/poet.song.13000.json','["妾家鄧侯國，肯愧邯鄲姝。", "世本富繒綺，嬌愛比明珠。", "十五學組紃，未嘗開戶樞。", "十六失所適，姓名傾里閭。", "十七善歌舞，使君邀宴娛。", "自茲著樂府，不得同羅敷。", "凉溫忽荏苒，屢接朝大夫。", "相歡不及情，何異逢路衢。", "昨日一見郎，目色曾不渝。", "結愛從此篤，暫隔猶恐疎。", "如何遂從宦，去涉千里途。", "郎跨青驄馬，妾乘白雪駒。", "送郎郎未速，別妾妾仍孤。", "不如水中鱗，雙雙依綠蒲。", "不如雲間鵠，兩兩下平湖。", "魚鳥尚有託，妾今誰與俱。", "去去約春華，終朝怨日賒。", "一心思杏子，便擬見梅花。", "梅花幾時吐，頻掐欄竿數。", "東風若見郎，重爲歌金縷。"]'),
('355a0ccd-7166-4fab-b41f-42bd0ce46fd2','依韻和謝副閤寄新酒','梅堯臣','宋','宋诗','song-poetry','','[]','聞道芳洲景氣新，却輸鷗鷺日相親。',32,'全唐诗/poet.song.13000.json','["聞道芳洲景氣新，却輸鷗鷺日相親。", "小槽酒熟玻瓈色，誰憶高臺共賦人。"]'),
('7c263f24-f183-42af-be4b-244b5b4a22af','送劉子思殿丞宰巫山','梅堯臣','宋','宋诗','song-poetry','','[]','千里向巴東，青山不可窮。',48,'全唐诗/poet.song.13000.json','["千里向巴東，青山不可窮。", "峽猿初入聽，蠻語未全通。", "暮雪思梁國，朝雲識楚宮。", "吏人迎拜處，嘶馬入丹楓。"]'),
('d0b989b9-e4f0-43c7-8187-de3ae4cff8be','朔風寄永叔','梅堯臣','宋','宋诗','song-poetry','','[]','朔風嗥枯枝，遠雁不能起。',72,'全唐诗/poet.song.13000.json','["朔風嗥枯枝，遠雁不能起。", "日色寒無光，原野澹千里。", "所思在南國，遐路闊音旨。", "潛鱗亦安託，冰結長河水。", "峨峨既未泮，獵獵終不已。", "悠然傷我心，歷亂非可擬。"]'),
('18b54b4b-d3f7-491c-b499-d82b503aa0b6','襄城對雪  其一','梅堯臣','宋','宋诗','song-poetry','','[]','風急夜窗鳴，暗知庭下積。',48,'全唐诗/poet.song.13000.json','["風急夜窗鳴，暗知庭下積。", "曉幔忻以捲，虛堂睡成癖。", "飄颻初縈林，凌亂欲侵席。", "擁扉人莫掃，何似袁家宅。"]'),
('9f674c44-e3fa-4c39-a2cd-fd9e524ef8de','襄城對雪  其二','梅堯臣','宋','宋诗','song-poetry','','[]','登城望密雪，浩浩川野昏。',48,'全唐诗/poet.song.13000.json','["登城望密雪，浩浩川野昏。", "誰思五原下，甲色千里屯。", "凍禽立枯枝，饑獸齧陳根。", "念彼無衣褐，愧此貂裘溫。"]'),
('d3fe932c-bfa3-4dc0-8a55-bd56625bc643','雪夜留梁推官飲','梅堯臣','宋','宋诗','song-poetry','','[]','晝雪落旋消，夜雪寒易積。',72,'全唐诗/poet.song.13000.json','["晝雪落旋消，夜雪寒易積。", "燈清古屋深，爐凍殘煙碧。", "爲沽一斗酒，暫對千里客。", "酒薄意不淺，輕今須重昔。", "重昔是年華，飄飄猶過隙。", "一醉冒風歸，平明馬無跡。"]'),
('6410f9ac-f3b3-4115-ac61-05a8e70866e8','南陽謝紫微挽詞三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','忽驚南郊信，半夜雪中來。',48,'全唐诗/poet.song.13000.json','["忽驚南郊信，半夜雪中來。", "遂哭寢門外，始嗟梁木摧。", "文章千古盛，風韻故人哀。", "憶昨臨湍水，寧知隔夜臺。"]'),
('19711992-6ea9-42fb-b102-b6f6bb388234','南陽謝紫微挽詞三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','平昔聞嚴助，承明厭直廬。',48,'全唐诗/poet.song.13000.json','["平昔聞嚴助，承明厭直廬。", "請章來未久，捐館遽何如。", "無復淮南諭，曾成太史書。", "蒼蒼不可問，揮涕望輀車。"]'),
('4fef556b-07bd-4d62-bb14-ce750f8f2dfe','南陽謝紫微挽詞三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','自古豈無死，賢哉獨可悲。',48,'全唐诗/poet.song.13000.json','["自古豈無死，賢哉獨可悲。", "家貧留旅櫬，門慶有諸兒。", "里社當存祀，邦人定立碑。", "還同羊叔子，罷市見遺思。"]'),
('f3f22e14-a77a-4131-99c4-69d215b6482f','永叔自南陽至余郊迓焉首訪謝公奄然相與流涕作是詩以寫懷','梅堯臣','宋','宋诗','song-poetry','','[]','郭門臨汝水，鏡色入高衢。',96,'全唐诗/poet.song.13000.json','["郭門臨汝水，鏡色入高衢。", "鞍馬過其上，塵襟蕩已無。", "及郊逢故友，出涕各霑襦。", "神物喪頭角，空存尾與軀。", "溝木失匠斲，誰施藍與朱。", "並轡不能語，斯文其已夫。", "歸來授予館，自爲炊彫胡。", "且勿厭茲會，日月易以徂。"]'),
('77a26987-7c7d-4bc1-ba77-38480a273239','贈琴僧知白','梅堯臣','宋','宋诗','song-poetry','','[]','上人南方來，手抱伏犧器。',72,'全唐诗/poet.song.13000.json','["上人南方來，手抱伏犧器。", "頹然造我門，不顧門下吏。", "上堂弄金徽，深得太古意。", "清風蕭蕭生，脩竹摇晚翠。", "聲妙非可傳，彈罷不復記。", "明日告以行，徒興江海思。"]'),
('e663f8fe-30ae-41f1-a4e5-f64f5feeaae8','教授宋著作還','梅堯臣','宋','宋诗','song-poetry','','[]','何以擬君子，雲鴻肅羽儀。',48,'全唐诗/poet.song.13000.json','["何以擬君子，雲鴻肅羽儀。", "將過上林苑，先集孝王池。", "唼藻有餘樂，漸磐方得時。", "野塘歸莫晚，白水遠連陂。"]'),
('5102caa8-f326-4cf9-aa7a-7cd1d8d53645','夏日晚霽與崔子登周襄故城','梅堯臣','宋','宋诗','song-poetry','','[]','雨脚收不盡，斜陽半古城。',48,'全唐诗/poet.song.13000.json','["雨脚收不盡，斜陽半古城。", "獨携幽客步，閑閱老農耕。", "寶氣無人發，陰蟲入夜鳴。", "余非避喧者，坐愛遠風清。"]'),
('92655a71-7ff5-4b1d-bfc1-cb1af6c8c84d','永叔寄澄心堂紙二幅','梅堯臣','宋','宋诗','song-poetry','','[]','昨朝人自東郡來，古紙兩軸緘縢開。',224,'全唐诗/poet.song.13000.json','["昨朝人自東郡來，古紙兩軸緘縢開。", "滑如春冰密如蠒，把玩驚喜心徘徊。", "蜀牋蠹脆不禁久，剡楮薄慢還可咍。", "書言寄去當寶惜，慎勿亂與人翦裁。", "江南李氏有國日，百金不許市一枚。", "澄心堂中唯此物，靜几鋪寫無塵埃。", "當時國破何所有，帑藏空竭生莓苔。", "但存圖書及此紙，輦大都府非珍瓌。", "于今已踰六十載，棄置大屋牆角堆。", "幅狹不堪作詔命，聊備麤使供鸞臺。", "鸞臺天官或好事，持歸秘惜何嫌猜。", "君今轉遺重增愧，無君筆札無君才。", "心煩收拾乏匱櫝，日畏撦裂防嬰孩。", "不忍揮毫徒有思，依依還起子山哀。"]'),
('a5c2bd8c-b3ae-431a-8776-47720dc2a3da','聞尹師魯赴涇州幕','梅堯臣','宋','宋诗','song-poetry','','[]','胡騎犯邊來，漢兵皆死戰。',120,'全唐诗/poet.song.13000.json','["胡騎犯邊來，漢兵皆死戰。", "昨聞衛將軍，賢俊多所薦。", "知君慮不淺，求對未央殿。", "天子喜有言，軺車因召見。", "籌畫當冕旒，袍魚賜銀茜。", "曰臣豈身謀，而邀陛下睠。", "青衫出二崤，白馬如飛電。", "關山冒風露，兒女泣霜霰。", "軍客壯士多，劍藝匹夫衒。", "賈誼非俗儒，慎無輕寡變。"]'),
('227076d6-33ef-42b6-96de-3456c8345918','夏日陪提刑彭學士登周襄王故城','梅堯臣','宋','宋诗','song-poetry','','[]','聊隨漢使者，一上周王城。',48,'全唐诗/poet.song.13000.json','["聊隨漢使者，一上周王城。", "片雨北郊晦，殘陽西嶺明。", "野禽呼自別，香草問無名。", "誰復黍離詠，但興箕潁情。"]'),
('7f7a0382-a137-452d-bb88-74891d017277','王殿丞赴莫州日就余求釣竿數莖以往今因其使回戲贈','梅堯臣','宋','宋诗','song-poetry','','[]','去日覓釣竿，定能垂釣否。',24,'全唐诗/poet.song.13000.json','["去日覓釣竿，定能垂釣否。", "若不暇釣魚，釣竿當去取。"]'),
('0f9255f2-67ff-4afc-9bc6-727bacc6c90a','詠蜘蛛','梅堯臣','宋','宋诗','song-poetry','','[]','日結一尺網，知吐幾尺絲。',24,'全唐诗/poet.song.13000.json','["日結一尺網，知吐幾尺絲。", "百蟲爲爾食，九腹常苦饑。"]'),
('d9d8043e-50a5-466d-84da-68425472af49','宋著作寄鳳茶','梅堯臣','宋','宋诗','song-poetry','','[]','春雷未出地，南土物尚凍。',144,'全唐诗/poet.song.13000.json','["春雷未出地，南土物尚凍。", "呼譟助發生，萌穎强抽𦮎。", "團爲蒼玉璧，隠起雙飛鳳。", "獨應近臣頒，豈得常寮共。", "顧茲實賤貧，何以叨贈貢。", "石碾破微綠，山泉貯寒洞。", "味餘喉舌甘，色薄牛馬湩。", "陸氏經不經，周公夢不夢。", "雲脚俗所珍，鳥觜誇仍衆。", "常常濫盃甌，草草盈罌甕。", "寧知有奇品，圭角百金中。", "秘惜誰可邀，虛齋對禽哢。"]'),
('a4f30ebe-2b77-431d-a429-5d214ce6c7a0','觀水','梅堯臣','宋','宋诗','song-poetry','','[]','秋水漫長堤，郊原上下迷。',48,'全唐诗/poet.song.13000.json','["秋水漫長堤，郊原上下迷。", "孤城閉板築，高樹見巢棲。", "耳厭蛙聲極，漚生雨點齊。", "渚間牛不辨，誰爲掃陰霓。"]'),
('af13e7f4-ec9b-46f4-88eb-7c1627936c28','大水後城中壞廬舍千餘作詩自咎','梅堯臣','宋','宋诗','song-poetry','','[]','不如無道國，而水冒城郭。',48,'全唐诗/poet.song.13000.json','["不如無道國，而水冒城郭。", "豈敢問天災，但慙爲政惡。", "湍迴萬瓦裂，槎向千林閣。", "獨此懷百憂，思歸卧雲壑。"]'),
('8fa98ea5-5140-4cbe-a3a4-3d050e28c499','依韻和李君讀余注孫子','梅堯臣','宋','宋诗','song-poetry','','[]','我世本儒術，所談聖人篇。',168,'全唐诗/poet.song.13000.json','["我世本儒術，所談聖人篇。", "聖篇闢乎道，信謂天地根。", "衆賢發藴奧，授業稱專門。", "傳箋與注解，璨璨今猶存。", "始欲沿其學，陳跡不可言。", "唯餘兵家說，自昔罕所論。", "因暇聊發篋，故讀尚可溫。", "將爲文者備，豈必握武賁。", "終資仁義師，焉愧道德藩。", "揮毫試析理，已厭前輩繁。", "信有一日長，可壓千載魂。", "未涉勿言淺，尋流方見源。", "廟謀盛夔禼，正議滅烏孫。", "吾徒誠合進，尚念有親尊。"]'),
('34ed86a4-ce7a-4cdc-a35f-d68793b9d273','新霽登周王城','梅堯臣','宋','宋诗','song-poetry','','[]','行行古城頭，歷覽古城下。',48,'全唐诗/poet.song.13000.json','["行行古城頭，歷覽古城下。", "水鳥傍人煙，河流隔桑柘。", "秋山豁晴翠，野老親時稼。", "民訟今已稀，閑登厭官舍。"]'),
('ff6ae4da-8a5c-4997-8e4c-a0edeeb12ce4','依韻答李晉卿結交篇','梅堯臣','宋','宋诗','song-poetry','','[]','上交執正道，下交守奇節。',72,'全唐诗/poet.song.13000.json','["上交執正道，下交守奇節。", "當爲蘭死香，勿作竹枯裂。", "試看溫玉堅，何似春冰折。", "貴賤事乃見，古今情不別。", "平生相與親，晏歲誰可决。", "君能持此意，足以表風烈。"]'),
('3b85623e-e98d-42a1-b890-7c22ab8f1c7d','秋日屬疾','梅堯臣','宋','宋诗','song-poetry','','[]','體羸易生疾，況乃凌秋陰。',48,'全唐诗/poet.song.13000.json','["體羸易生疾，況乃凌秋陰。", "微寒薄膚腠，飲藥增衣衾。", "一日失所治，百骸將不任。", "當從華氏學，聊欲爲戲禽。"]'),
('a75f489e-fb52-4292-83f9-f20121206c93','田家','梅堯臣','宋','宋诗','song-poetry','','[]','高樹蔭柴扉，青苔照落暉。',48,'全唐诗/poet.song.13000.json','["高樹蔭柴扉，青苔照落暉。", "荷鋤山月上，尋徑野煙微。", "老叟扶童望，羸牛带犢歸。", "燈前飯何有，白薤露中肥。"]'),
('41f9937b-937d-4820-8185-ab5bf4fb5347','苦雨','梅堯臣','宋','宋诗','song-poetry','','[]','秋空幾旬雨，四海低鵬翮。',72,'全唐诗/poet.song.13000.json','["秋空幾旬雨，四海低鵬翮。", "晝不見日精，夜不見月魄。", "灑盡天漢流，蒸爛女媧石。", "塗潦將埋輪，牛馬困負軛。", "羣蟲無土蟄，百果就枝坼。", "安能誅陰虬，坐使天地闢。"]'),
('d229820d-bccc-4531-8885-33e20ba835df','聞永叔復館因以寄賀','梅堯臣','宋','宋诗','song-poetry','','[]','東方有鎩禽，已喜羽翰插。',48,'全唐诗/poet.song.13000.json','["東方有鎩禽，已喜羽翰插。", "重來金馬門，莫忘黄牛峽。", "黄牛無冬春，遠水生鱗甲。", "今非昔日憂，賀酒特新壓。"]'),
('ab603ef8-67a7-4851-ac5b-88951c0d9180','九月一日','梅堯臣','宋','宋诗','song-poetry','','[]','授衣念徂節，闔棺傷故人。',72,'全唐诗/poet.song.13000.json','["授衣念徂節，闔棺傷故人。", "故人昔送我，把酒湍水濱。", "只道後期易，豈知無會因。", "死生意不及，欲語鼻先辛。", "既乏羨門術，安得如松筠。", "寒暑更數十，應亦同埃塵。"]'),
('5f4cf837-cf27-4274-96a5-34893060ef3a','弔李膺辭','梅堯臣','宋','宋诗','song-poetry','','[]','陰蜺橫天，長劍欲抉，匣穎未露兮精鋼已折。',238,'全唐诗/poet.song.13000.json','["陰蜺橫天，長劍欲抉，匣穎未露兮精鋼已折。", "層冰塞川，猛炬方烈，凝氣未銷兮高焰已滅。", "雖忠毅之有志兮，當衰運之閉結。", "嗟身禍之不免兮，甘就死於縲絏。", "何賢者之景慕兮，或自表而謝絕。", "惟荀公之獲御兮，見顔間之氣悅。", "奚服媚之若茲兮，蓋操秉乎峻節。", "風裁獨高而罕接兮，號龍門而無凡轍。", "允簡亢不容於時兮，玉雖碎而猶潔。", "痛漢綱之頹圮兮，又何毀乎賢哲。", "歷千古而可悲兮，故余不得而面結。", "叨此邦而長民兮，過舊壠而增咽。", "嗟異代之有遇兮，若登履乎閫闑。", "對風樹之蕭蕭兮，想魂氣之未竭。", "聊感槩於斯兮，寫憂心之惙惙。"]'),
('e4c5fa17-74f9-4f9d-ad2a-1c558e7929bd','送李康伯赴武當都監','梅堯臣','宋','宋诗','song-poetry','','[]','城下漢江流，滄波照鬢秋。',48,'全唐诗/poet.song.13000.json','["城下漢江流，滄波照鬢秋。", "山川包楚塞，風物似荆州。", "試聽清砧發，何如畫角愁。", "遥知絕戎事，水味有槎頭。"]'),
('9a9a0ff2-4f43-4094-bd81-59f2811f0275','重送','梅堯臣','宋','宋诗','song-poetry','','[]','得朋如得寶，何恨相知晚。',48,'全唐诗/poet.song.13000.json','["得朋如得寶，何恨相知晚。", "舊友貴來疎，嗟君行復遠。", "秋城隔寒水，驛路入蒼巘。", "古情深不深，所祝加餐飯。"]'),
('154abea3-eeb7-4377-8e5d-4f682ae19bf6','田家語','梅堯臣','宋','宋诗','song-poetry','','[]','誰道田家樂，春稅秋未足。',168,'全唐诗/poet.song.13000.json','["誰道田家樂，春稅秋未足。", "里胥扣我門，日夕苦煎促。", "盛夏流潦多，白水高於屋。", "水既害我菽，蝗又食我粟。", "前月詔書來，生齒復板錄。", "三丁籍一壯，惡使操弓韣。", "州符今又嚴，老吏持鞭朴。", "搜索稚與艾，唯存跛無目。", "田閭敢怨嗟，父子各悲哭。", "南畝焉可事，買箭賣牛犢。", "愁氣變久雨，鐺缶空無粥。", "盲跛不能耕，死亡在遲速。", "我聞誠所慙，徒爾叨君祿。", "却詠歸去來，刈薪向深谷。"]'),
('678cc3a3-e46e-4056-bb40-aa8e3a3a4793','檢覆葉縣魯山田李晉卿餞於首山寺留別','梅堯臣','宋','宋诗','song-poetry','','[]','我本山水鄉，看山常不足。',120,'全唐诗/poet.song.13000.json','["我本山水鄉，看山常不足。", "自從到官來，塵事便拘束。", "嘗聞此山寺，法宇深雲木。", "無由一來過，夢想向巖谷。", "按田趨鄰疆，跨馬涉平陸。", "良友送我行，偶與賞心屬。", "禪庭鳴白雞，祖席歌黄鵠。", "野氣逼人寒，嵐光添酒綠。", "言離非遠離，但愛交情篤。", "重游應有期，君亦行車促。"]'),
('1091de0e-891c-4cf6-b17b-da648a009c75','卧羊山','梅堯臣','宋','宋诗','song-poetry','','[]','亂石若羣羊，緣崗卧斜日。',48,'全唐诗/poet.song.13000.json','["亂石若羣羊，緣崗卧斜日。", "曾非左慈化，更想初平叱。", "無羶穴蟻去，有乳寒泉出。", "誰憶灞陵原，纍纍冢傍質。"]'),
('ce4abd9f-321c-4284-8c12-8f87d44eb564','汝墳貧女','梅堯臣','宋','宋诗','song-poetry','','[]','汝墳貧家女，行哭音悽愴。',120,'全唐诗/poet.song.13000.json','["汝墳貧家女，行哭音悽愴。", "自言有老父，孤獨無丁壯。", "郡吏來何暴，縣官不敢抗。", "督遣勿稽留，龍鍾去携仗。", "勤勤囑四鄰，幸願相依傍。", "適聞閭里歸，問訊疑猶强。", "果然寒雨中，僵死壤河上。", "弱質無以託，橫尸無以葬。", "生女不如男，雖存何所當。", "拊膺呼蒼天，生死將奈向。"]'),
('e2d69230-e5f7-4afe-82f0-883f2b3a49ec','昆陽城','梅堯臣','宋','宋诗','song-poetry','','[]','試看昆陽下，白骨猶銜鏃。',24,'全唐诗/poet.song.13000.json','["試看昆陽下，白骨猶銜鏃。", "莫願隍水頭，更添新鬼哭。"]'),
('4f1ee9ee-ea6f-426d-b49f-0e8db1f12c0e','老牛陂','梅堯臣','宋','宋诗','song-poetry','','[]','吳牛行欲老，漢馬焉得肥。',24,'全唐诗/poet.song.13000.json','["吳牛行欲老，漢馬焉得肥。", "筋力不可恃，遊子當念歸。"]'),
('9f2a1864-0d6a-4f75-9645-d682c36ba72d','雙鳧觀','梅堯臣','宋','宋诗','song-poetry','','[]','山下溪流照城郭，幽庭柏子風自落。',32,'全唐诗/poet.song.13000.json','["山下溪流照城郭，幽庭柏子風自落。", "古壇蒼蘚少人行，不見雙鳬見黄雀。"]'),
('b61a9f7a-7cf2-478b-b6df-223104d73b53','葉公廟','梅堯臣','宋','宋诗','song-poetry','','[]','{上/貝}物還見驚，從來人所悼。',28,'全唐诗/poet.song.13000.json','["{上/貝}物還見驚，從來人所悼。", "今看古壁畫，應合當時好。"]'),
('577ab800-e034-4e6a-9efd-dfc2c2ba439f','己卯歲紫微謝公赴南陽過葉縣陪遊興慶精舍題名壁間而去庚辰歲余來按田因訪舊跡衋然於懷故作此謠以志其悲','梅堯臣','宋','宋诗','song-poetry','','[]','昔與南陽太守行，車騎休時訪庭柏。',48,'全唐诗/poet.song.13000.json','["昔與南陽太守行，車騎休時訪庭柏。", "今來重看壁間題，太守已爲泉下客。", "獨留清血是門人，怊悵便令生死隔。"]'),
('6ac3c80a-e2d1-4080-bd0e-efd5fee78363','觀扱兔','梅堯臣','宋','宋诗','song-poetry','','[]','莽莽蒿萊下，紛紛狡兔迷。',24,'全唐诗/poet.song.13000.json','["莽莽蒿萊下，紛紛狡兔迷。", "枯枝坐守者，若箇是忘歸。"]'),
('5478254c-4196-4677-8f99-24b8c5cde3ed','燈花','梅堯臣','宋','宋诗','song-poetry','','[]','灼灼生寒燼，終朝照席明。',24,'全唐诗/poet.song.13000.json','["灼灼生寒燼，終朝照席明。", "從教占有驗，燃滅本無情。"]'),
('275d0277-41ff-4aee-8bec-c606ca5ec96e','魯山山行','梅堯臣','宋','宋诗','song-poetry','','["\u767b\u5c71", "\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u5199\u666f", "\u521d\u4e2d\u53e4\u8bd7", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u6292\u6000"]','適與野情愜，千山高復低。',48,'全唐诗/poet.song.13000.json','["適與野情愜，千山高復低。", "好峯隨處改，幽徑獨行迷。", "霜落熊升樹，林空鹿飲溪。", "人家在何許，雲外一聲雞。"]'),
('ebc0ff44-e492-4c97-b984-884a6ea4b1bc','游元紫芝琴堂','梅堯臣','宋','宋诗','song-poetry','','[]','訪古歷荒城，城孤落日鳴。',24,'全唐诗/poet.song.13000.json','["訪古歷荒城，城孤落日鳴。", "人琴兩不見，破月高臺傾。"]'),
('203af1a7-7b89-48d3-9d6d-89200cc63894','至香山寺報秀叔','梅堯臣','宋','宋诗','song-poetry','','[]','家近心還速，川長馬易疲。',48,'全唐诗/poet.song.13000.json','["家近心還速，川長馬易疲。", "望山孤寺出，渡水夕陽遲。", "來向林間宿，歸須月上時。", "只應庭際鵲，已報汝先知。"]'),
('77b2ca2e-0750-4ca2-891a-bfc92d9b0e62','寒草','梅堯臣','宋','宋诗','song-poetry','','[]','寒草纔變枯，陳根已含綠。',24,'全唐诗/poet.song.13000.json','["寒草纔變枯，陳根已含綠。", "始知天地仁，誰道風霜酷。"]'),
('9e3d122c-ff5e-4145-b884-b3e5bab36ca5','送崔秀才  其一','梅堯臣','宋','宋诗','song-poetry','','[]','晨風無定巢，遠寄鷦鷯枝。',48,'全唐诗/poet.song.13000.json','["晨風無定巢，遠寄鷦鷯枝。", "天寒鼓翼健，粒食寧所窺。", "大澤多羣羽，翱翔各有時。", "今子振衣去，焉能久迍羈。"]'),
('77b6a8d2-fae0-496a-bbb5-a2a4eb81ecfb','送崔秀才  其二','梅堯臣','宋','宋诗','song-poetry','','[]','少年遊太學，著盡篋中衣。',48,'全唐诗/poet.song.13000.json','["少年遊太學，著盡篋中衣。", "獨劍自爲伴，無家何處歸。", "秋蓬隨野轉，寒鵲遶林飛。", "霄漢有知己，行行寧久微。"]'),
('3e276a5d-840f-41a0-ada7-44540ab1f239','思遠寄師厚','梅堯臣','宋','宋诗','song-poetry','','[]','馬蹄踐霜雪，不畏道路寒。',72,'全唐诗/poet.song.13000.json','["馬蹄踐霜雪，不畏道路寒。", "游子重衣裘，慈母懸心肝。", "懸心幾千里，冉冉歲已殘。", "大河今漸涸，遠目常不乾。", "度雁朝夕聞，尺書寄亦難。", "願同車輪復，勿比弦上丸。"]'),
('0a79c656-6e2a-4c03-ade8-d7a49de5d009','送師厚歸南陽會天大風遂宿高陽山寺明日同至姜店','梅堯臣','宋','宋诗','song-poetry','','[]','往日送子春風前，春風酣酣杏正妍。',320,'全唐诗/poet.song.13000.json','["往日送子春風前，春風酣酣杏正妍。", "今來送歸秋風後，秋風摵摵沙滿川。", "馬鬣斜傾毛瑟縮，馭吏噤唫足後先。", "弊裘吹裂寒入骨，枯株磨戛火欲燃。", "忽逢古寺出巖腹，與君下馬相留連。", "殿堂高下就山勢，松柏森聳侵雲巔。", "長廊落葉卷若掃，丈室垂幔翻如褰。", "像塑神母乳九子，抱携撫玩皆可憐。", "却令遠客自生念，欲見幼稚心煩煎。", "擁爐對坐日昏黑，龕燈共借僧榻眠。", "雖然覆衣冷如鐵，不及在家貧無氊。", "曲肱難寐要天曉，兩股凍痹仍筋攣。", "桹桹殘夜木魚響，起看昴畢傾西躔。", "怒號斗息東方白，童僕整肅吾將還。", "老僧掃壁持筆硯，請予强此題歲年。", "出門並轡至山店，茅屋揭盡餘尺椽。", "又據胡床一談笑，君不解飲聊開筵。", "程次都無五百里，篋中可乏一囊錢。", "拂衣頻起畏日昃，應恐慈母心懸懸。", "顧我便當江海去，却思此地何由緣。"]'),
('24d9c16c-f6bd-4820-8182-eac98b39eb2f','疲馬','梅堯臣','宋','宋诗','song-poetry','','[]','疲馬不畏鞭，暮途知幾千。',24,'全唐诗/poet.song.13000.json','["疲馬不畏鞭，暮途知幾千。", "當須量馬力，始得君馬全。"]'),
('405ea785-bc99-4251-bf51-406e02928326','依韻和永叔子履冬夕小齋聯句見寄','梅堯臣','宋','宋诗','song-poetry','','[]','遥知夜相過，對語冷無火。',120,'全唐诗/poet.song.13000.json','["遥知夜相過，對語冷無火。", "險辭鬭尖奇，凍地抽笋笴。", "唫成欲寄誰，談極唯思我。", "學術窮後先，文字少許可。", "敢將蠡測海，有似脂出輠。", "必餓嘗見憂，此病各又果。", "弊駕當還都，重門不須鏁。", "到時春怡怡，萬柳枝娜娜。", "定應人折贈，只恐絮已墮。", "行橐且不貧，明珠藏百顆。"]'),
('b4e28f7d-030c-4aa3-817e-01e0af788468','古冢','梅堯臣','宋','宋诗','song-poetry','','[]','南陽古原上，荒塚若魚鱗。',48,'全唐诗/poet.song.13000.json','["南陽古原上，荒塚若魚鱗。", "劍佩不爲土，衣冠應化塵。", "枯骸託魑魅，細草沒麒麟。", "何必問名氏，漢家多近親。"]'),
('0e5059c2-2a4e-463e-b8e9-b5dd6713ae7b','仲春同師直至壠山雪中宿穰亭','梅堯臣','宋','宋诗','song-poetry','','[]','與子乘羸馬，夜投山家宿。',48,'全唐诗/poet.song.13000.json','["與子乘羸馬，夜投山家宿。", "風雪滿綈裘，燈火深竹屋。", "烹雞頼主人，吠犬憎倦僕。", "明發到巖前，春荑凍雲木。"]'),
('42da6cea-1321-4b40-b1e2-344773a67ae2','依韻和師直仲春雪中馬上','梅堯臣','宋','宋诗','song-poetry','','[]','自倚春風暖，輕袍犯雪來。',48,'全唐诗/poet.song.13000.json','["自倚春風暖，輕袍犯雪來。", "過塘迷綠水，拂樹雜芳梅。", "山蔽峯難辨，樵通徑易開。", "野行方有味，緩轡不須催。"]'),
('b774aeab-f4e4-48f9-8e0d-77297269ec5b','和師直早春雪後五壠道中作','梅堯臣','宋','宋诗','song-poetry','','[]','來尋谷口春，正值陰雲結。',72,'全唐诗/poet.song.13000.json','["來尋谷口春，正值陰雲結。", "日暮冰霰繁，宿亭孤飯設。", "侵晨登壠去，始見羣峯列。", "草凍未抽心，松枯猶抱節。", "川傍認飛鷺，林上墜殘雪。", "何意待芳菲，遲留未堪折。"]'),
('2200a129-c20f-4c9e-8861-b58b5140fb9f','依韻和師直晚步徧覽五壠川','梅堯臣','宋','宋诗','song-poetry','','[]','窮覽川原勝，經行未厭頻。',48,'全唐诗/poet.song.13000.json','["窮覽川原勝，經行未厭頻。", "樵深但聞斧，谷暖自留春。", "臨水何妨坐，看雲忽滯人。", "誰家煙塢裏，竹樹遠相鄰。"]'),
('8310ccc0-77bd-466a-a9bf-92217d179310','暮春過洪氏汝曲小園','梅堯臣','宋','宋诗','song-poetry','','[]','三月花已休，閑來羨叢薄。',48,'全唐诗/poet.song.13000.json','["三月花已休，閑來羨叢薄。", "河回地勢偏，雨入灘聲惡。", "綠草旋抽心，青梅猶带萼。", "主人歸未歸，誰省曾遊樂。"]'),
('f5aca9e8-88d9-41a7-9a19-20d9714e61e6','雷秘校入闕擬官時將登舟過輦下','梅堯臣','宋','宋诗','song-poetry','','[]','與君先後發，同走向京華。',48,'全唐诗/poet.song.13000.json','["與君先後發，同走向京華。", "羨躍青驪去，將乘烏榜賒。", "著鞭辭宿雨，渡水踏春沙。", "聞道求爲縣，應當學種花。"]'),
('08ca70b5-cc78-4cb0-adc3-ada838498510','登許昌城望西湖','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','試望許西偏，湖光浸曉煙。',48,'全唐诗/poet.song.13000.json','["試望許西偏，湖光浸曉煙。", "岸痕添宿雨，草色際平田。", "夏木陰猶薄，朱荷出未圓。", "人閑綠波靜，幽鷺插頭眠。"]'),
('51a6278b-5e58-4f15-abc1-9ca90de1575d','孫主簿惠上黨寺壁胡霈然書墨迹一匣','梅堯臣','宋','宋诗','song-poetry','','[]','上黨佛祠何可觀，開元瑞物圖高閣。',192,'全唐诗/poet.song.13000.json','["上黨佛祠何可觀，開元瑞物圖高閣。", "又有長廊古壁上，復是名輩題丹雘。", "當時泥用絲作筋，意欲千載無剝落。", "書奇畫妙了不識，訛傳墨土能治瘧。", "寺僧不惜人掐取，筆畫遂缺如鳥啄。", "後來好事恐磨滅，寶刀裁剗泥如剝。", "取之龕置綠板匣，便寶箱楮同美璞。", "拂拭還看體勢生，盤屈蒼虬舞鸞鷟。", "在昔不畏屋壁壞，今也常恐兒童撲。", "夫君知我心所重，南歸贈以致誠慤。", "此時雖喜落吾手，老大腕硬無由學。", "但當拜貺不敢忘，莫爲報言曾未數。"]'),
('374b3217-a17f-4f94-8faa-1877b105419a','寄永興招討夏太尉','梅堯臣','宋','宋诗','song-poetry','','[]','寶元元年西夏叛，天子命將臨戎行。',320,'全唐诗/poet.song.13000.json','["寶元元年西夏叛，天子命將臨戎行。", "二年孟春果來寇，高奴城下皆氐羌。", "五原偏師急赴敵，晝夜不息趨戰場。", "馬煩人怠當勁虜，雖持利器安得强。", "二師覆敗乃自取，豈是廊廟謀不臧。", "朝廷又選益經略，三幙賢俊務所長。", "或取李悝備邊策，或欲五道出朔方。", "仲夏科民挾弓矢，季冬括馿齎道糧。", "官軍未進復犯塞，搴旗殺將何倡狂。", "遂令士卒愈沮氣，欲使乘障膽不張。", "我願助畫跡且遠，側身西望空淒涼。", "庶幾一言可裨益，臨風欲寄鳥翼翔。", "所宜畜銳保城壁，轉饋先在通行商。", "守而勿追彼自困，境上未免小奪攘。", "譬如蚊虻噆膚體，實於肌血無大傷。", "此言雖小可喻遠，幸公采用不我忘。", "誠知公慮若裴度，聖上聽用同憲皇。", "當時豈不歷歲月，猶且衆鎮未陸梁。", "況今鷹犬乏雄勇，便擬馳騁徒蒼惶。", "且緩須時勵犀卒，終期拉朽功莫當。"]'),
('5b2baa22-5109-4ecc-a784-263ae8f81587','桓妬妻','梅堯臣','宋','宋诗','song-poetry','','[]','昔聞桓司馬，娶妾貌甚都。',156,'全唐诗/poet.song.13000.json','["昔聞桓司馬，娶妾貌甚都。", "其妻南郡主，悍妬誰與俱。", "持刀擁羣婢，逕往將必屠。", "妾時在窗前，解鬟臨鏡梳。", "鬒髮雲垂地，瑩姿冰照壺。", "妾初見主來，綰髻下庭隅。", "斂手語出處，國破家已殂。", "無心來至此，豈願奉君娛。", "今日苟見殺，雖死生不殊。", "主乃擲刃前，抱持一長吁。", "曰我見猶憐，何況是老奴。", "盛怒反爲喜，哀矜非始圖。", "嫉忌尚服美，傷哉今亦無。"]'),
('93fd8d65-aca4-4e35-b5b7-8f8b39eab071','夏日晚晴登許昌西湖','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','新晴萬柳齊，鶑度水東西。',72,'全唐诗/poet.song.13000.json','["新晴萬柳齊，鶑度水東西。", "城上明殘照，雲間挂斷霓。", "煙蒲勻若翦，沙岸浄無泥。", "菓壓繁枝重，人乘小駟低。", "嵐光開翡翠，湖色浸玻瓈。", "只欠朱藤密，如過罨畫谿。"]'),
('eb6e9a82-82a0-4e3d-9f7a-c4670b0429c3','許昌晚晴陪從過西湖因詠謝希深蘋風詩愴然有懷','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','疎雲漏斜照，殘雨葉間明。',48,'全唐诗/poet.song.13000.json','["疎雲漏斜照，殘雨葉間明。", "飛蓋城頭去，澄湖水正平。", "荷盛鮫客淚，蔓濯野人纓。", "公獨思康樂，臨流誦句清。"]'),
('038ea9b5-5323-4a8b-8e31-22bfd3419f4f','故原戰','梅堯臣','宋','宋诗','song-poetry','','[]','落日探兵至，黄塵鈔騎多。',48,'全唐诗/poet.song.13000.json','["落日探兵至，黄塵鈔騎多。", "邀勳輕赴敵，轉戰背長河。", "大將中流矢，殘兵空負戈。", "散亡歸不得，掩抑泣山阿。"]'),
('92416275-54b3-4050-bbc4-2a9089beb7fe','故原有戰卒死而復蘇來說當時事','梅堯臣','宋','宋诗','song-poetry','','[]','縱橫尸暴積，萬殞少全生。',48,'全唐诗/poet.song.13000.json','["縱橫尸暴積，萬殞少全生。", "飲雨活胡地，脫身歸漢城。", "野貛穿廢竈，妖鵩嘯空營。", "侵骨劍瘡在，無人爲不驚。"]'),
('55aad386-680b-42f8-a603-53368d7f3787','西湖閑望','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夏景已多趣，湖邊日更佳。',48,'全唐诗/poet.song.13000.json','["夏景已多趣，湖邊日更佳。", "園葵雜紅紫，岸柳自欹斜。", "雨氣收林表，城陰接水涯。", "愛閑輸白鳥，盡日立汀沙。"]'),
('06df6f3c-28d4-44d1-a321-b37827684312','寄謝師直','梅堯臣','宋','宋诗','song-poetry','','[]','憶同仲春月，冒雨過穰亭。',240,'全唐诗/poet.song.13000.json','["憶同仲春月，冒雨過穰亭。", "聊酌山酒別，獨吟夜燈青。", "明朝上嶺路，羣岫張雲屏。", "忽入川谷秀，固非平生經。", "綠竹間紅萼，紫藤垂千扃。", "春塘水决决，野老髮星星。", "田父相與至，里言尚可聽。", "始聞丹砂岑，遂識五壠形。", "傍瞻禹湯迹，競信廟貌靈。", "邀我陟巉巉，宿霧方冥冥。", "暗霑衣裘濕，時襲草木馨。", "棟宇敞絕頂，牲酒列幽亭。", "竹杯占禍福，巫錦醉一嚀。", "日晏別雲外，月出至近坰。", "僕夫疲不進，鞭策無暫停。", "我馬忽顛墜，君心同鶺鴒。", "再駕體無傷，扣關燭已熒。", "自茲期莫逆，未契心所銘。", "怱怱操行袂，汎汎如水萍。", "今來各一方，安得同醉醒。"]'),
('b1a5797a-d580-4201-89fc-64fc5d3371c8','感二鳥','梅堯臣','宋','宋诗','song-poetry','','[]','雄雌雙好鳥，託棲空樹中。',96,'全唐诗/poet.song.13000.json','["雄雌雙好鳥，託棲空樹中。", "有蛇出傍穴，噴毒氣如虹。", "半夜此驚飛，瞥目隨西東。", "有喙不能達，啼雲復嘯風。", "迴翔隔歲月，老木高童童。", "眼生衆禽噪，雖近未由通。", "昨朝煙雨晦，並翼向幽叢。", "鷹鸇尚橫集，颺颺意無窮。"]'),
('a794e725-27bc-4c4b-a0d4-5de52174c147','古相思','梅堯臣','宋','宋诗','song-poetry','','[]','劈竹兩分張，情知無合理。',48,'全唐诗/poet.song.13000.json','["劈竹兩分張，情知無合理。", "織作雙紋簟，依然淚花紫。", "淚花雖復合，疑岫幾千里。", "欲識舜娥悲，無窮似湘水。"]'),
('a8d3ca1c-0bd2-46d0-8317-80e749a75580','舟次朱家曲寄許下故人','梅堯臣','宋','宋诗','song-poetry','','[]','藹藹桑柘岸，喧喧雞犬村。',48,'全唐诗/poet.song.13000.json','["藹藹桑柘岸，喧喧雞犬村。", "晚雲連雨黑，秋水带沙渾。", "稍聽鄰船語，初分異土言。", "雖嗟遠朋友，日喜近田園。"]'),
('b8ce8416-91a0-489e-be89-c086ab03f67a','送曇穎上人往廬山','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','潯陽幾千里，無不見爐峯。',72,'全唐诗/poet.song.13000.json','["潯陽幾千里，無不見爐峯。", "蒼翠入衆目，巖壑少行蹤。", "高僧忽獨往，杳杳懷遠公。", "嘗聞虎溪上，醉令或來同。", "而今競邀致，幾里聞松風。", "塵心古難洗，瀑布垂秋虹。"]'),
('d89a6a78-e357-46a9-9f17-eee83df166a8','弔石曼卿','梅堯臣','宋','宋诗','song-poetry','','[]','前時京師來，對馬嘗相揖。',144,'全唐诗/poet.song.13000.json','["前時京師來，對馬嘗相揖。", "埃塵正滿衢，笑語曾未及。", "雖然恨莫親，往往聞風什。", "星斗交垂光，昭昭不可挹。", "獨哦秋露中，豈顧衣裘溼。", "酒杯輕宇宙，天馬難羈縶。", "今朝我還都，但見交朋泣。", "借問泣者誰，曼卿魂已蟄。", "堂堂豪傑姿，遂爾一棺戢。", "君生寒月明，君沒寒月入。", "月入還復升，精魄寧未集。", "孤墳細草遍，翠碣嗟新立。"]'),
('a9da41ff-84fa-4c25-bab6-8c3a6a40a211','醉中留別永叔子履','梅堯臣','宋','宋诗','song-poetry','','["\u79bb\u522b", "\u6292\u6000", "\u53cb\u4eba", "\u5fe7\u56fd", "\u5b64\u5bc2"]','新霜未落汴水淺，輕舸惟恐東下遲。',256,'全唐诗/poet.song.13000.json','["新霜未落汴水淺，輕舸惟恐東下遲。", "遶城假得老病馬，一步一跛令人疲。", "到君官舍欲取別，君惜我去頻增嘻。", "便步髯奴呼子履，又令開席羅酒巵。", "逡巡陳子果亦至，共坐小室聊伸眉。", "烹雞庖兔下筯美，盤實飣餖栗與梨。", "蕭蕭細雨作寒色，厭厭盡醉安可辭。", "門前有客莫許報，我方劇飲冠幘欹。", "文章或論到淵奧，輕重曾不遺毫釐。", "間以辨謔每絕倒，豈顧明日無晨炊。", "六街禁夜猶未去，童僕竊訝吾儕癡。", "談兵究弊又何益，萬口不謂儒者知。", "酒酣耳熱試發泄，二子尚乃驚我爲。", "露才揚己古來惡，卷舌噤口南方馳。", "江湖秋老鱖鱸熟，歸奉甘旨誠其宜。", "但願音塵寄鳥翼，慎勿却效兒女悲。"]'),
('3eafdd52-80d6-4ab0-9935-5b06401fd05d','汴水斗減舟不能進因寄彥國舍人','梅堯臣','宋','宋诗','song-poetry','','[]','朝落幾寸水，暮長幾寸沙。',48,'全唐诗/poet.song.13000.json','["朝落幾寸水，暮長幾寸沙。", "深灘鼇背出，淺浪龍鱗斜。", "秋風忽又惡，越舫嗟初閣。", "坐想掖垣人，猶如在寥廓。"]'),
('781aa107-e97b-40c3-8365-14fb08e22665','陪淮南轉運魏兵部遊穎州女郎臺寺','梅堯臣','宋','宋诗','song-poetry','','[]','舊傳媯氏女，將適楚人時。',48,'全唐诗/poet.song.13000.json','["舊傳媯氏女，將適楚人時。", "築館自臨水，故臺空此基。", "因爲楚宮媵，來與使車期。", "樓上望湖上，煙林晚蔽虧。"]'),
('24c7c055-103e-46e5-88af-59bc33d093ef','望僊亭','梅堯臣','宋','宋诗','song-poetry','','[]','公來有餘樂，所樂爲郡間。',72,'全唐诗/poet.song.13000.json','["公來有餘樂，所樂爲郡間。", "訟稀聊自適，靜勝以紓顔。", "清軒開曉幔，歷歷見淮山。", "山色洗新雨，佳期如可攀。", "代異雞犬去，時平草木閑。", "試望天衢近，飛駕應此還。"]'),
('78cfc951-0ee5-4968-b6c7-8c9088e3b120','陪淮南轉運魏兵部遊濠上莊生臺','梅堯臣','宋','宋诗','song-poetry','','[]','周當戰國時，何爲守靜正。',96,'全唐诗/poet.song.13000.json','["周當戰國時，何爲守靜正。", "干戈既日尋，仁義固不競。", "天下皆跖徒，寧知聖爲聖。", "是將萬物齊，不顧千金聘。", "所以忘形骸，所以保性命。", "安能小仲尼，豈不識世病。", "我從魏公來，訪古停烏榜。", "聊識賢者心，吁嗟一長詠。"]'),
('17398a96-ecb0-464e-9a98-7bfe55cfe9eb','淮上雜詩六首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','宿雲未全斂，微雨入船疎。',48,'全唐诗/poet.song.13000.json','["宿雲未全斂，微雨入船疎。", "問伴失前後，暝行隨疾徐。", "相親沙上雁，自樂水中魚。", "亭午日光透，遠分林際居。"]'),
('06227409-3328-48b3-ac28-107dc5bc8d0c','淮上雜詩六首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','暗開淮水平，遠見孤城出。',48,'全唐诗/poet.song.13000.json','["暗開淮水平，遠見孤城出。", "出舟問舟子，遽對那能悉。", "始聞莊生臺，還想觀魚日。", "果得真隠心，魚鳥情非密。"]'),
('66270e66-525b-4a78-80c8-f06578752b89','淮上雜詩六首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','輕舟晚投處，聒聒渚禽嘶。',48,'全唐诗/poet.song.13000.json','["輕舟晚投處，聒聒渚禽嘶。", "橡子隨薪束，蔬科带土携。", "岸幽雲滿石，潮落蚌生泥。", "客思無憀極，唯將魯酒迷。"]'),
('49090791-da8b-4367-bc5e-07a8d2703014','淮上雜詩六首  其四','梅堯臣','宋','宋诗','song-poetry','','[]','野雁不知數，翳然川上鳴。',48,'全唐诗/poet.song.13000.json','["野雁不知數，翳然川上鳴。", "曾無設羅意，空自見船驚。", "渺渺拍波去，紛紛孤嶼盈。", "苦寒非塞外，霜落夜淮清。"]'),
('34bb6e9c-d03b-4113-8110-4361795480e4','淮上雜詩六首  其五','梅堯臣','宋','宋诗','song-poetry','','[]','漠漠晝煙披，縱橫見漁艇。',48,'全唐诗/poet.song.13000.json','["漠漠晝煙披，縱橫見漁艇。", "輕橈上急水，或與飛鴻並。", "魚大釣絲微，牽隨碧潭迥。", "向晚得志歸，浩歌山月靜。"]'),
('db203b0e-3f0a-4c66-9970-99246424ee19','淮上雜詩六首  其六','梅堯臣','宋','宋诗','song-poetry','','[]','舟閣下灘遲，蒼黄暮灘上。',48,'全唐诗/poet.song.13000.json','["舟閣下灘遲，蒼黄暮灘上。", "偏愁逆水風，更駕崩沙浪。", "落日看已昏，漁燈遠相向。", "夜闌天轉寒，坐待潮流漲。"]'),
('cffc1e54-8030-49be-8ba8-c4c53191260a','赴霅任君有詩相送仍懷舊賞因次其韻','梅堯臣','宋','宋诗','song-poetry','','[]','湖山饒邃處，曾省牧之遊。',48,'全唐诗/poet.song.13000.json','["湖山饒邃處，曾省牧之遊。", "雁落葑田闊，船過菱渚秋。", "野煙昏古寺，波影動危樓。", "到日尋題墨，猶應舊壁留。"]'),
('5c1c6ff0-1ae6-41b4-90ba-94fe79f991de','過揚州參政宋諫議遺白鵝','梅堯臣','宋','宋诗','song-poetry','','[]','曾遊鳳池上，曾食鳳池萍。',36,'全唐诗/poet.song.13000.json','["曾遊鳳池上，曾食鳳池萍。", "乞與江湖去，將期養素翎。", "不同王逸少，辛苦寫黄庭。"]'),
('89352781-6869-451e-a879-a8bb1e35033e','金山寺','梅堯臣','宋','宋诗','song-poetry','','[]','吳客獨來後，楚橈歸夕曛。',48,'全唐诗/poet.song.13000.json','["吳客獨來後，楚橈歸夕曛。", "山形無地接，寺界與波分。", "巢鶻寧窺物，馴鷗自作羣。", "老僧忘歲月，石上看江雲。"]'),
('cacbd21a-b068-4bf7-98f3-eea05dd4f0ee','瓜洲對雪欲再遊金山寺家人以風波相止','梅堯臣','宋','宋诗','song-poetry','','[]','臘月海風急，雪吹巖下窗。',48,'全唐诗/poet.song.13000.json','["臘月海風急，雪吹巖下窗。", "輕舟不畏浪，昨日過寒江。", "渡口復夕興，區中無與雙。", "忽牽兒女戀，空聽遠鐘撞。"]'),
('de8687bd-458e-41da-a0ac-0909d284459b','金山芷芝二僧携茗見訪','梅堯臣','宋','宋诗','song-poetry','','[]','一遊江山上，日日吟不足。',72,'全唐诗/poet.song.13000.json','["一遊江山上，日日吟不足。", "雙錫忽來過，衣霜带初旭。", "況能持茗具，向此烹新綠。", "中𤃩水若飴，北焙花如粟。", "還將塵慮滌，自愧冠纓束。", "何以報勤勤，馳奴扣雲谷。"]'),
('136a6adc-e4e1-4b5f-8090-3082915d6829','淮南遇梵才吉上人因悼謝南陽疇昔之遊','梅堯臣','宋','宋诗','song-poetry','','[]','久已厭宦旅，故茲歸江南。',120,'全唐诗/poet.song.13000.json','["久已厭宦旅，故茲歸江南。", "始時遽辭邑，不及事春蠶。", "殘臘猶在道，險阻固所諳。", "扁舟次淮海，喜遇釋子談。", "契闊十五年，尚謂卧巖庵。", "偶見如夙期，淹留良亦甘。", "歎逝獨泫然，懷悲情豈堪。", "班班雲中鳥，共看投夕嵐。", "曷不念舊隠，山水唯素耽。", "我從湖上去，微爵輕子男。"]'),
('78c024f9-4853-47ab-8e99-c877c212533d','送櫟陽宰朱表臣','梅堯臣','宋','宋诗','song-poetry','','[]','塞上備胡羌，關中調兵食。',96,'全唐诗/poet.song.13000.json','["塞上備胡羌，關中調兵食。", "秦民尚苦輸，漢吏勤求職。", "君今喜懷詔，馳騎寧暇息。", "其邑嘗雨金，於時豈能得。", "行當經灞上，故事猶可憶。", "前代多戰爭，鬼火弄陰黑。", "蒼蒼路傍草，憔悴希春色。", "縣塗誠有政，威惠爲令德。"]'),
('6fb07a65-3160-458d-b269-20ef2a7cca30','次韻和長吉上人淮甸相遇','梅堯臣','宋','宋诗','song-poetry','','[]','淮上一相遇，憶在京都時。',288,'全唐诗/poet.song.13000.json','["淮上一相遇，憶在京都時。", "雖驚歲月換，未改松桂姿。", "童侍兩三人，瓶錫相與隨。", "自言東越來，篋中多好詩。", "文字皆妥帖，業術無傾欹。", "前輩嘗有言，清氣散人脾。", "語妙見情性，說之聊解頤。", "始推杼山學，得非素所師。", "此固有深趣，吾心久已知。", "橫琴乃玄悟，豈必弄鳴絲。", "古樂衆少聽，誰知彼吹箎。", "師曠沒世後，伯牙衆身悲。", "願同黄鵠舉，遠歸滄海涯。", "老驥雖不病，長坂安可馳。", "天台況奇勝，日夕勞夢思。", "尚忝齒纓綬，終年趨路岐。", "俯愧淵中魚，游泳水之湄。", "仰羨雲間鷙，凌厲辭縶維。", "居嘗起斯念，未去情不怡。", "今朝更道舊，感愴各嚬眉。", "同遊謝公門，遠想袂霑洟。", "惜哉胡不仁，碎彼東方琪。", "又出數紙書，手澤尚可披。", "眷眷疇昔意，於今當語誰。"]'),
('0c6457b0-0cdf-4dd2-a0f1-80c1a1f1c0e6','歲日旅泊家人相與爲壽','梅堯臣','宋','宋诗','song-poetry','','[]','舟中逢獻歲，風雨送餘寒。',120,'全唐诗/poet.song.13000.json','["舟中逢獻歲，風雨送餘寒。", "推年增漸老，永懷殊鮮歡。", "江邊無車馬，鑑裏對衣冠。", "孺人相慶拜，共坐列杯盤。", "盤中多橘柚，未咀齒已酸。", "飲酒復先醉，頗覺量不寬。", "岸梅欲破萼，野水微生瀾。", "來者即爲新，過者故爲殘。", "何言昨日趣，乃作去年觀。", "時節未變易，人世良可歎。"]'),
('e71dfb3c-e8e9-4d83-bf0e-18271f7c2cd3','寄題梵才大士台州安隠堂','梅堯臣','宋','宋诗','song-poetry','','[]','巢禽託靜林，潛魚戀深壑。',96,'全唐诗/poet.song.13000.json','["巢禽託靜林，潛魚戀深壑。", "豈不能自安，翔泳得所樂。", "達士遠紛華，於茲守沖漠。", "堂前鳴松風，堂後馥花萼。", "好鳥時一呼，澄明望寥廓。", "詩興猶不忘，禪心詎云著。", "所以得自然，寧必萬緣縛。", "未能與之游，懷慕徒有作。"]'),
('6cb25df0-393d-4bba-8f01-a41c3874d2c3','農難','梅堯臣','宋','宋诗','song-poetry','','[]','稂莠非所殖，嘉禾共一田。',60,'全唐诗/poet.song.13000.json','["稂莠非所殖，嘉禾共一田。", "老農實惡之，豈共時稼捐。", "管蔡與盜跖，同氣詎能遷。", "周公不妨聖，柳惠不妨賢。", "賢哉彼薅矣，取舍得其然。"]'),
('81d5cfe0-26d2-49af-be9d-f06a46cc0700','舟中值雨裴刁二君相與見過','梅堯臣','宋','宋诗','song-poetry','','[]','江上渰淒淒，天形接野低。',48,'全唐诗/poet.song.13000.json','["江上渰淒淒，天形接野低。", "岸痕生舊水，馬跡踏春泥。", "風急侵衣重，山昏卷幔迷。", "誰驚二客論，不愧巨源妻。"]'),
('0a072a5b-495e-4bca-ae88-ee67b95b1b10','題刁經臣山居時已應辟西幕','梅堯臣','宋','宋诗','song-poetry','','[]','向不樂郡府，遂云歸田園。',120,'全唐诗/poet.song.13000.json','["向不樂郡府，遂云歸田園。", "結廬復種蓺，草樹日已繁。", "散帙理舊學，了然無俗喧。", "春雨一迴過，覽耕登古原。", "青山每自愛，霽色當衡門。", "故人苟來往，名宦未嘗言。", "趣適已不淺，道心良亦存。", "忽聞辟書至，便令驅犢轅。", "豈期同瓠瓜，長繫蒿萊根。", "始知古君子，出處惟義敦。"]'),
('d7e883f4-4086-4894-aa3e-9466ba94c69f','前者裴君雨中見過因以詩謝復承來章輒依韻奉和','梅堯臣','宋','宋诗','song-poetry','','[]','主人門下客，寂寞在江涘。',84,'全唐诗/poet.song.13000.json','["主人門下客，寂寞在江涘。", "我昨謝銅章，解組猶脫屣。", "前日至朱方，正值春雨起。", "君時冒雨來，曾不避泥滓。", "林枝滴衣襟，沙岸平履齒。", "相歡了無間，偶論通遠旨。", "去逢交親問，爲報心如水。"]'),
('c4d85979-c098-434e-aa74-86094733aaba','甘露寺','梅堯臣','宋','宋诗','song-poetry','','[]','曾非遠城郭，寂爾隔囂氛。',48,'全唐诗/poet.song.13000.json','["曾非遠城郭，寂爾隔囂氛。", "尚有南朝樹，能留北固雲。", "川濤觀海若，霜磬入江濆。", "衛國丹青在，孤堂綠桂薰。"]'),
('29e9064b-f7cc-4173-b50d-780fbdfe5958','依韻和刁經臣讀李衛公平泉山居詩碑有感','梅堯臣','宋','宋诗','song-poetry','','[]','當時植珍木，豈是昧前規。',48,'全唐诗/poet.song.13000.json','["當時植珍木，豈是昧前規。", "廢宅長春草，故山存舊碑。", "已嗟良璧毀，安識古松姿。", "叔子每懷慕，此心空自知。"]'),
('8669bb20-4391-4fdc-b294-03e815886360','春日舟中對雪寄刁經臣','梅堯臣','宋','宋诗','song-poetry','','[]','誰道江南暖，新春見雪飛。',48,'全唐诗/poet.song.13000.json','["誰道江南暖，新春見雪飛。", "鷗來親客艇，花亂上人衣。", "古郡地偏寂，野窗寒入微。", "戴家人不遠，欲去未能歸。"]'),
('882ab9ff-0b12-4150-a5f7-b3c9277f5ee0','依韻和達觀禪師春日雪中見寄','梅堯臣','宋','宋诗','song-poetry','','[]','密霰來新歲，春陽氣漸微。',48,'全唐诗/poet.song.13000.json','["密霰來新歲，春陽氣漸微。", "侵庭草芽凍，紛雜雁行飛。", "江寺誰開逕，湖山我欲歸。", "雨花無六出，休怪著人衣。"]'),
('5e0a1545-999f-446e-9307-e77abf406adc','和刁太博新墅十題 靜舍','梅堯臣','宋','宋诗','song-poetry','','[]','野木扶疎重復重，塘蒲涵水綠茸茸。',32,'全唐诗/poet.song.13000.json','["野木扶疎重復重，塘蒲涵水綠茸茸。", "琴書尤古得爲樂，休問前山有戴顒。"]'),
('9a86d223-527a-40ec-be4c-291c3f684403','和刁太博新墅十題 西齋','梅堯臣','宋','宋诗','song-poetry','','[]','靜節歸來自結廬，稚川閑去亦多書。',32,'全唐诗/poet.song.13000.json','["靜節歸來自結廬，稚川閑去亦多書。", "請君架上添芸草，莫遣中間有蠹魚。"]'),
('0ddfce6c-f44c-4cbc-8253-334ba35afa49','和刁太博新墅十題 北軒','梅堯臣','宋','宋诗','song-poetry','','[]','冬日迎喧此未宜，苦吟那對朔風時。',32,'全唐诗/poet.song.13000.json','["冬日迎喧此未宜，苦吟那對朔風時。", "祇誇砌下留殘雪，不看簷間斗柄垂。"]'),
('d5ba2952-45d4-4e9f-ac4e-de73a03c9dec','和刁太博新墅十題 叢杉','梅堯臣','宋','宋诗','song-poetry','','[]','植幹森然美在庭，更憐相倚自青青。',32,'全唐诗/poet.song.13000.json','["植幹森然美在庭，更憐相倚自青青。", "翠姿且有干雲勢，豈是孤生向遠坰。"]'),
('7dbc06fb-2e76-47fd-9197-d40a06ccfbe3','和刁太博新墅十題 松阜','梅堯臣','宋','宋诗','song-poetry','','[]','勾引風聲已可聽，高陰仍更接崗形。',32,'全唐诗/poet.song.13000.json','["勾引風聲已可聽，高陰仍更接崗形。", "知君久欲平心氣，早晚根傍長茯苓。"]'),
('04c2404a-3580-40d2-a112-a1632a68066e','和刁太博新墅十題 小舫','梅堯臣','宋','宋诗','song-poetry','','[]','小舫閑撐莫厭遲，比於刳艇劣相宜。',32,'全唐诗/poet.song.13000.json','["小舫閑撐莫厭遲，比於刳艇劣相宜。", "漕河有處通陂水，深入荷花人不知。"]'),
('2ad10e86-f6c6-4523-97fd-82d93c542db7','和刁太博新墅十題 移竹','梅堯臣','宋','宋诗','song-poetry','','[]','遠愛檀欒碧逕開，荷鋤乘雨破秋苔。',32,'全唐诗/poet.song.13000.json','["遠愛檀欒碧逕開，荷鋤乘雨破秋苔。", "直須探作阮家趣，更向煙林缺處栽。"]'),
('915f7ddc-6882-42ff-a5b6-fce672990585','和刁太博新墅十題 花塢','梅堯臣','宋','宋诗','song-poetry','','[]','雜芳春發淺深叢，曲塢逶迤紫間紅。',32,'全唐诗/poet.song.13000.json','["雜芳春發淺深叢，曲塢逶迤紫間紅。", "色賤格微應不數，少添蘭菊待秋風。"]'),
('d2005eff-30a4-4cb5-bed1-dac777907a8e','和刁太博新墅十題 綿檜','梅堯臣','宋','宋诗','song-poetry','','[]','翠色凌寒豈易衰，柔條堪結更葳蕤。',32,'全唐诗/poet.song.13000.json','["翠色凌寒豈易衰，柔條堪結更葳蕤。", "松身柏葉能相似，勁拔緣何不自持。"]'),
('c35cd1e8-23ca-4a4a-a1ab-73b77ef4c16d','和刁太博新墅十題 新井','梅堯臣','宋','宋诗','song-poetry','','[]','淺淺清泉自鑑開，鱗鱗寒甃未生苔。',32,'全唐诗/poet.song.13000.json','["淺淺清泉自鑑開，鱗鱗寒甃未生苔。", "山中亭午野禽渴，不畏人驚欲下來。"]'),
('1c3f02f0-cd2d-457e-aa0c-1a7c5ebd1ac2','發陶莊却寄刁經臣裴如晦','梅堯臣','宋','宋诗','song-poetry','','[]','方看梅柳春，共別川河上。',48,'全唐诗/poet.song.13000.json','["方看梅柳春，共別川河上。", "移舟人已歸，迴首竹林望。", "水渾不照影，山遠猶相向。", "聞道欲西游，漢家今尚壯。"]'),
('51d3664b-0aa1-4d2b-b46d-61e95783bcb4','發丹陽後寄徐元輿','梅堯臣','宋','宋诗','song-poetry','','[]','別君忽五年，相望非一日。',96,'全唐诗/poet.song.13000.json','["別君忽五年，相望非一日。", "會合如夢寐，欣喜對形質。", "是時春已仲，臨水柳未密。", "載酒相與游，輕舠劣容膝。", "禪扃竹下過，乳井松間出。", "烹茶覺暫醒，岸幘情彌逸。", "興闌乘月歸，及旦解行繂。", "離懷更宿酲，遠想都如失。"]'),
('57ad085d-73c5-448a-846f-ddbf09d7b39f','胡武平遺牡丹一盤','梅堯臣','宋','宋诗','song-poetry','','[]','疇昔居洛陽，看盡名園花。',96,'全唐诗/poet.song.13000.json','["疇昔居洛陽，看盡名園花。", "臨水復蔭竹，豔色照彤霞。", "良友相與至，競飲歡無涯。", "而今猶老翁，鬢髮但未華。", "昨日到湖上，碧水涵蒲芽。", "此情頗已愜，薄宦非初嗟。", "况乃蒙見憐，带雨摘春葩。", "雖無向時樂，惠好仍有加。"]'),
('a089ec46-3dd9-4a17-b165-d70b91c43986','題滕學士九華山書堂','梅堯臣','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','處山方畏淺，曾慕結深廬。',48,'全唐诗/poet.song.13000.json','["處山方畏淺，曾慕結深廬。", "要與雲峯近，寧將野客疎。", "澗苗來入俎，林鳥或窺書。", "何事輕茲樂，而從出塞車。"]'),
('935d0227-21d7-416e-883c-379af49b0f36','送劉成伯還都','梅堯臣','宋','宋诗','song-poetry','','[]','余昔困川途，今非羨行者。',48,'全唐诗/poet.song.13000.json','["余昔困川途，今非羨行者。", "離心寄南風，相送過平野。", "既吹蓮葉舟，更逐桂條馬。", "中州多故人，懷抱幸君寫。"]'),
('8beab276-bd80-4532-a5c0-db0987150008','送舍弟正臣赴都','梅堯臣','宋','宋诗','song-poetry','','[]','吳兒能刺舟，其駛劇飛鳥。',48,'全唐诗/poet.song.13000.json','["吳兒能刺舟，其駛劇飛鳥。", "行行固莫留，望進前山小。", "家貧吾不憂，身計爾自了。", "何當還里門，拜慶期秋杪。"]'),
('be297eb6-f49b-43a5-b5ae-c56f28dbb66b','訪報本簡長老','梅堯臣','宋','宋诗','song-poetry','','[]','比泛苕溪來，初逢卞山雨。',48,'全唐诗/poet.song.13000.json','["比泛苕溪來，初逢卞山雨。", "雨收精舍出，喜與高僧語。", "門臨水若鑑，萬象皆可覩。", "清浄欲誰鄰，野蓮無處所。"]'),
('5c815b11-5897-4d7f-921a-f1d1ad7abe1b','依韻答淮南祝秘校初春見寄','梅堯臣','宋','宋诗','song-poetry','','[]','客有袖中書，初憑春燕寄。',36,'全唐诗/poet.song.13000.json','["客有袖中書，初憑春燕寄。", "春燕不時來，秋鴻今始至。", "水落蒲藻寒，悠悠江浦意。"]'),
('756a57f8-f91c-4e70-ac03-6eedd4dd3b3d','依韻和胡武平懷京下游好','梅堯臣','宋','宋诗','song-poetry','','[]','南國易悲愁，西風起高樹。',240,'全唐诗/poet.song.13000.json','["南國易悲愁，西風起高樹。", "枯荷復送雨，度雁寧知數。", "欲問北來音，繫書復若故。", "冥飛杳無跡，弋者徒有慕。", "况在白蘋洲，而懷石渠署。", "石渠多故人，鵷鵠方騫翥。", "鏘鳴尚可希，綷翼何由附。", "主人頼知己，未變疇昔顧。", "乘桴豈仲尼，好勇非季路。", "幸依南郡帳，不學邯鄲步。", "自守終日愚，都忘向時慮。", "睠戀此江湖，親年當喜懼。", "既獲庭闈近，又多山水趣。", "邇來對明月，千里猶會晤。", "長橋人絕聲，舉酒逢秋露。", "迥聞孤舟笛，煙水在何處。", "俯檻意無涯，跳波魚夜乳。", "頗得真隠情，奚須慕巢許。", "思寄梅枝香，遠隔蘭溪渡。", "緘之付好風，精爽亦隨去。"]'),
('c48b42a6-532f-477a-b188-b78154293a3d','依韻和武平九月十五日夜北樓望太湖','梅堯臣','宋','宋诗','song-poetry','','["\u592a\u6e56"]','東吳臨海若，看月上青冥。',48,'全唐诗/poet.song.13000.json','["東吳臨海若，看月上青冥。", "河漢微分練，星辰淡布螢。", "細煙沉遠水，重露裛空庭。", "孤坐饒清興，惟將影對形。"]'),
('482c5808-0329-4dc7-bb86-3e9189ffc494','依韻武平憶玉晨觀','梅堯臣','宋','宋诗','song-poetry','','[]','世路多氛垢，人間浪逐名。',48,'全唐诗/poet.song.13000.json','["世路多氛垢，人間浪逐名。", "是非還自喻，寵辱固堪驚。", "薄宦真何戀，丹砂儻可成。", "終尋谷口隠，鄭子豈其卿。"]'),
('9bb26c6f-4221-435b-87d6-a06ad531e012','凝碧堂','梅堯臣','宋','宋诗','song-poetry','','[]','始至荷芰生，田田湖上密。',72,'全唐诗/poet.song.13000.json','["始至荷芰生，田田湖上密。", "復當花競時，豔色凌朝日。", "今來蓮已枯，碧水墮秋實。", "更待雪中過，羣峯應互出。", "樽有綠蟻醅，俎有赬壺橘。", "可以持蟹螯，逍遥此居室。"]'),
('23012554-c38d-42e8-b23a-e4ec1fe70747','送劉成伯著作赴弋陽宰','梅堯臣','宋','宋诗','song-poetry','','[]','我昨之官來，值君爲郡掾。',180,'全唐诗/poet.song.13000.json','["我昨之官來，值君爲郡掾。", "當年已知名，是日纔識面。", "未久嗟還都，始應羣公薦。", "遂除芸省郎，出治江上縣。", "縣劇素所聞，其俗到可見。", "水精製盤盂，冰瑩産郊甸。", "鳴箏斲桐梓，雕飾雜寶絢。", "有藥化銅鉛，方士多伏鍊。", "君今齒尚壯，好學常不倦。", "二者定非惑，吾言亦狂狷。", "絃歌將有餘，幸可窮經傳。", "歸來期著書，篋楮盈百卷。", "莫學此疎慵，無能守貧賤。", "明朝君當行，勉勉自出餞。", "豈無一壺酒，豈無一鼎饌。"]'),
('3fa57c7a-b32f-4784-8b4a-66f968bfd86d','冬雷','梅堯臣','宋','宋诗','song-poetry','','[]','上帝設號令，隠其南山下。',240,'全唐诗/poet.song.13000.json','["上帝設號令，隠其南山下。", "震發固有時，曷常事憑怒。", "春以動含生，夏以奮風雨。", "冬其息不用，藏在黄厚土。", "我今來江南，歲曆惟建午。", "如何小雪前，向曉疑鳴釜。", "蛟蛇龜蟲厄，鱗裂口塊吐。", "蝦蟆不食月，深窟僵兩股。", "天公豈物欺，若此汩時序。", "或言非天公，實乃陰怪主。", "嘗觀古祠畫，牛首椎連鼓。", "黑雲雜狂飇，相與爲肺腑。", "是不由昊穹，安能順寒暑。", "吾因考厥事，復以驗莽鹵。", "市井欺量衡，定知不活汝。", "元惡逆大倫，勿加霹靂斧。", "此豈曰無私，故予未所取。", "必恐竊天威，似將文法侮。", "焉顧五行錯，詎畏萬物覩。", "欲扣九門陳，恨身無鳥羽。"]'),
('3222674b-ee1f-402c-a21b-d29e232de117','劉成伯遺建州小片的乳茶十枚因以爲答','梅堯臣','宋','宋诗','song-poetry','','[]','玉斧裁雲片，形如阿井膠。',48,'全唐诗/poet.song.13000.json','["玉斧裁雲片，形如阿井膠。", "春谿鬭新色，寒籜見重包。", "價劣萬金敵，名將紫筍拋。", "桓公不知味，空問楚人茅。"]'),
('b6bf9f35-d559-4f01-8068-e85c09c810f9','冬日送暹上人','梅堯臣','宋','宋诗','song-poetry','','[]','霜風刮地如刀鎌，鳥不遠飛魚已潛。',64,'全唐诗/poet.song.13000.json','["霜風刮地如刀鎌，鳥不遠飛魚已潛。", "何况削髮冷入骨，草屨不畏冰雪霑。", "緣山涉水去幾里，晝鉢野飯誰來添。", "毘陵舊寺苦欲到，索我贈行無久淹。"]'),
('5145a089-d0bf-4f17-b3a6-c5478ecbf96b','和壽州宋待制九題 熙熙閣','梅堯臣','宋','宋诗','song-poetry','','[]','初日照城樓，流暉及菌閣。',48,'全唐诗/poet.song.13000.json','["初日照城樓，流暉及菌閣。", "上收花霧紅，下見春煙薄。", "信美是殊邦，而淹佐時略。", "自慙江外人，敢慕淮南作。"]'),
('3174530a-750c-442b-80b8-0e35d0d40775','和壽州宋待制九題 春暉亭','梅堯臣','宋','宋诗','song-poetry','','[]','卉木日以發，中圃日以嘉。',48,'全唐诗/poet.song.13000.json','["卉木日以發，中圃日以嘉。", "歡言樂和景，及此鬢未華。", "春風實無幾，凌亂枝上花。", "山陰况暮月，俯仰誠可嗟。"]'),
('43b670bc-22b5-4bfb-8a10-8a408723fc87','和壽州宋待制九題 白蓮堂','梅堯臣','宋','宋诗','song-poetry','','[]','蟋蟀在秋堂，芙蕖出深水。',48,'全唐诗/poet.song.13000.json','["蟋蟀在秋堂，芙蕖出深水。", "浩露同一色，澄澈寒鑑裏。", "佳人恥施朱，欲與天真比。", "沙鳥閑且都，誰將擬公子。"]'),
('ab27d990-eed0-44cc-b14a-9732c5a13fa4','和壽州宋待制九題 式宴亭','梅堯臣','宋','宋诗','song-poetry','','[]','從事誰獨賢，而來均宴喜。',48,'全唐诗/poet.song.13000.json','["從事誰獨賢，而來均宴喜。", "幽禽雜嘯呼，珍木竟叢倚。", "興將物色俱，閑厭簫鼓美。", "寧同不聞問，訟息時遊此。"]'),
('3bcd5f76-c9d8-4283-84e0-ff3146bba0e1','和壽州宋待制九題 秋香亭','梅堯臣','宋','宋诗','song-poetry','','[]','高軒盛叢菊，可以泛綠罇。',48,'全唐诗/poet.song.13000.json','["高軒盛叢菊，可以泛綠罇。", "餘甘自同薺，忘憂寧用萱。", "有木皆剝實，何草不陳根。", "獨此冒霜豔，芬郁滿中園。"]'),
('36920f05-5b74-4f18-ab4d-8a449a05bdcb','和壽州宋待制九題 狎鷗亭','梅堯臣','宋','宋诗','song-poetry','','[]','羣生自知機，不可欺以異。',48,'全唐诗/poet.song.13000.json','["羣生自知機，不可欺以異。", "此雖鷗與馴，鷗亦魚所避。", "坐熊臨碧水，安得同一致。", "然此海客心，還應無有愧。"]'),
('97dd94bf-a93d-45cf-bc3b-385e439d63f5','和壽州宋待制九題 齊雲亭','梅堯臣','宋','宋诗','song-poetry','','[]','城隅結危棟，髣髴凌煙霓。',48,'全唐诗/poet.song.13000.json','["城隅結危棟，髣髴凌煙霓。", "平觀飛雨來，俯窺巢禽棲。", "浩蕩孤思發，冪歷蔓草齊。", "長安去不遠，何言西北迷。"]'),
('91385a1f-a2d7-4af6-ae28-c87a76de4d6d','和壽州宋待制九題 美蔭亭','梅堯臣','宋','宋诗','song-poetry','','[]','野村仍翦茅，當此茂林下。',48,'全唐诗/poet.song.13000.json','["野村仍翦茅，當此茂林下。", "晴暉葉上明，翠影杯中瀉。", "鮮風時颼飀，輕裾自蕭灑。", "固殊嵇生鍛，曷慕巖栖者。"]'),
('8c45b40d-9dcb-4c8f-a4d8-490b191c08c8','和壽州宋待制九題 望僊亭','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞淮南王，雞犬從此去。',48,'全唐诗/poet.song.13000.json','["嘗聞淮南王，雞犬從此去。", "至今山頭石，馬跡尚有處。", "使君辭從官，終日絕塵慮。", "望望雲漢間，想見賓天馭。"]'),
('3471d2a6-9294-467b-8ae0-cc439bdce36e','依韻和僧說上人見訪','梅堯臣','宋','宋诗','song-poetry','','[]','客從東國來，山雲猶在屨。',48,'全唐诗/poet.song.13000.json','["客從東國來，山雲猶在屨。", "是時正窮臘，雁落溪陰暮。", "投宿古城隅，雪迷松下路。", "衣楮足蘭荃，相過寧厭屢。"]'),
('bf59b76b-d719-4918-bbe3-dc75c8d368c9','立春前一日雪中訪烏程宰李君俞尋有詩見貺依韻和答','梅堯臣','宋','宋诗','song-poetry','','[]','粉絮先春拂面翔，臨風躍馬到君堂。',64,'全唐诗/poet.song.13000.json','["粉絮先春拂面翔，臨風躍馬到君堂。", "縣民將喜土膏起，令尹未驚農事忙。", "疾呼小吏具山酌，便欲盡醉爲詩狂。", "我牽塵俗不得久，何意更煩投夜光。"]'),
('627cc35f-4701-4a1e-819e-7bd8dea67818','送劉比部','梅堯臣','宋','宋诗','song-poetry','','[]','青山夜來雨，溪水已潺湲。',48,'全唐诗/poet.song.13000.json','["青山夜來雨，溪水已潺湲。", "侵曉桂旗動，傷離蘋渚前。", "百壺臨祖道，兩槳破春煙。", "舊業西河上，歸心向日邊。"]'),
('dd62fffa-4265-4b2d-86d4-dc94d33b3f6d','贈月上人彈琴','梅堯臣','宋','宋诗','song-poetry','','[]','人閑溪上橫刳木，素琴寒倚一枝玉。',32,'全唐诗/poet.song.13000.json','["人閑溪上橫刳木，素琴寒倚一枝玉。", "吳王城畔鏁深房，月下空彈孤雁曲。"]'),
('77e45db8-7650-4564-bc0c-bf7b909c85c8','冬日陪胡武平遊西余精舍','梅堯臣','宋','宋诗','song-poetry','','[]','侵晨霜氣嚴，溪口冰已合。',48,'全唐诗/poet.song.13000.json','["侵晨霜氣嚴，溪口冰已合。", "烏榜將進遲，寒篙旋摧拉。", "遥看松竹深，雪屋藏山衲。", "登臨興都盡，薄暮沿清霅。"]'),
('9f142436-30cb-45f2-9bb7-a49383d16a30','依韻和武平苕霅二水','梅堯臣','宋','宋诗','song-poetry','','[]','昔愛伊與洛，今逢苕與霅。',48,'全唐诗/poet.song.13000.json','["昔愛伊與洛，今逢苕與霅。", "南郭復西城，曉色明於甲。", "塵纓庶可濯，白鳥誰來狎。", "落日潭上歸，魚歌自相答。"]'),
('708b16dc-6b40-40b5-90f5-4f86fcbb22b9','依韻和武平昇卞二山','梅堯臣','宋','宋诗','song-poetry','','[]','北峯壓城蒼，南岫緣溪綠。',48,'全唐诗/poet.song.13000.json','["北峯壓城蒼，南岫緣溪綠。", "誰知昔人遊，尚想叢桂馥。", "鳥獸安可羣，呼鳴自爲族。", "儻聞羨門術，一躡塵外躅。"]'),
('d758572d-dbb9-4cb8-9fda-97d099a00d71','送崔主簿赴睦州清溪','梅堯臣','宋','宋诗','song-poetry','','[]','舟輕不畏險，逆上子陵灘。',48,'全唐诗/poet.song.13000.json','["舟輕不畏險，逆上子陵灘。", "七里峽天翠，千里雲木寒。", "古祠鳴野鳥，亂石激春湍。", "正與高懷愜，寧歌行路難。"]'),
('8ac0b0b3-c383-4a56-bd70-4b80fcc7f113','依韻和劉比部留別','梅堯臣','宋','宋诗','song-poetry','','[]','春雲已泊簾，濃淡半晴天。',48,'全唐诗/poet.song.13000.json','["春雲已泊簾，濃淡半晴天。", "沙草微抽綠，林枝遠带煙。", "况茲逢晚景，那更送歸船。", "苦酒聊爲酌，無勞辨聖賢。"]'),
('543d5a44-3235-4972-97b7-0ffbc82a0c00','送潘供奉承勛','梅堯臣','宋','宋诗','song-poetry','','[]','與君迹熟情已親，欲將行邁聊感人。',96,'全唐诗/poet.song.13000.json','["與君迹熟情已親，欲將行邁聊感人。", "舉酒不能效時俗，半醉苦語資立身。", "長大實好带弓劍，何不往助清邊塵。", "門戟雖高豈自有，當思乃祖爲功臣。", "所宜踴躍發奇策，嘉名定體庶得真。", "儻以斯言作狂說，乘肥食脆任青春。"]'),
('ba34aa5f-cd52-4e6b-8914-bf99eff780bd','答新長老詩編','梅堯臣','宋','宋诗','song-poetry','','[]','江東釋子多能詩，窗前樹下如蟬嘶。',64,'全唐诗/poet.song.13000.json','["江東釋子多能詩，窗前樹下如蟬嘶。", "朝風暮月只自老，建安舊體誰攀躋。", "唯師獨慕陶彭澤，奇蹟仍收王會稽。", "此焉趣尚已不淺，更在措意摩雲霓。"]'),
('6bded5d4-326c-4fa1-98d0-5f889a5bae6d','題劉道士奉真亭','梅堯臣','宋','宋诗','song-poetry','','[]','降真沉水生爐煙，扣齒曉漱華池泉。',64,'全唐诗/poet.song.13000.json','["降真沉水生爐煙，扣齒曉漱華池泉。", "心存崑閬未可到，夜瞻北斗何聯聯。", "顧茲虛室如有遲，一草一石幽且妍。", "芝蓋雲軿杳無至，不知誰更似楊權。"]'),
('8ad6914b-ce2c-44e2-bf99-915883506aef','依韻和烏程李著作四首 縣署西園','梅堯臣','宋','宋诗','song-poetry','','[]','春入西園何苦誇，我曾狂醉洛城花。',32,'全唐诗/poet.song.13000.json','["春入西園何苦誇，我曾狂醉洛城花。", "如今老大都無興，獨坐晴軒看落霞。"]'),
('557e7558-dc32-41e3-aac2-e2c3de23c10e','依韻和烏程李著作四首 霅上二首 其一','梅堯臣','宋','宋诗','song-poetry','','[]','共愛霅溪風物美，春來清可鑑鬚眉。',64,'全唐诗/poet.song.13000.json','["共愛霅溪風物美，春來清可鑑鬚眉。", "蘋生楚客將歸日，花暖吳蠶始浴時。", "臨水竹樓通市陌，跨橋雲屋接川湄。", "畫船載酒期君醉，已是無謀助翦夷。"]'),
('3795fab3-1585-4e91-b8ed-58989c05a442','依韻和烏程李著作四首 霅上二首 其二','梅堯臣','宋','宋诗','song-poetry','','[]','靚粧豔服遊川上，簫鼓聲中俗自歡。',32,'全唐诗/poet.song.13000.json','["靚粧豔服遊川上，簫鼓聲中俗自歡。", "寄語春風休用惡，恐教潭水起波瀾。"]'),
('7597a0d5-3921-4e3c-ab9f-e2d8d5e2fc95','依韻和烏程李著作四首 早春遊南園','梅堯臣','宋','宋诗','song-poetry','','[]','東國春歸早，南園百卉宜。',48,'全唐诗/poet.song.13000.json','["東國春歸早，南園百卉宜。", "萱芽開翠穎，杏萼破煙姿。", "青壠將鳴雉，喬林未囀鸝。", "石尤風莫起，芳物畏君吹。"]'),
('e39cfc3b-303d-4d4f-9608-92f88d89ac41','送簽判張祕丞赴秀州','梅堯臣','宋','宋诗','song-poetry','','[]','江燕歸時君亦歸，燕巢未暖君還去。',96,'全唐诗/poet.song.13000.json','["江燕歸時君亦歸，燕巢未暖君還去。", "去去溪邊楊柳多，正值清明欲飛絮。", "競折贈行何所益，時當長養傷嘉樹。", "不如舉酒對青山，酒罷移舟須薄暮。", "嘉禾主人余久知，跡冗不擬强攀附。", "儻或無忘問姓名，爲言懶拙皆如故。"]'),
('dbe23335-acfd-48f5-87a4-97ded1dcc144','送弟赴和州幕','梅堯臣','宋','宋诗','song-poetry','','[]','夾河爲郡不如古，江北江南作冗官。',64,'全唐诗/poet.song.13000.json','["夾河爲郡不如古，江北江南作冗官。", "須記長傳一經訓，雖貧莫改飲瓢歡。", "歷陽况與吾廬近，春穀休言問膳難。", "此日停舟聊舉酌，明當水驛自加餐。"]'),
('af1bd5c1-a4de-4bc4-a4d2-02f64e5fb24f','寄題徐都官新居假山','梅堯臣','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖萬穴古山骨，人結峯嵐勢不孤。',64,'全唐诗/poet.song.13000.json','["太湖萬穴古山骨，人結峯嵐勢不孤。", "苔徑三層平木末，河流一道接牆隅。", "已知谷口多花藥，祇欠林間落狖鼯。", "誰侍巾鞲此遊樂，里中遺老肯相呼。"]'),
('07372f30-0852-4bf3-9cd3-3ce0746b80e5','送梵才吉上人歸天台','梅堯臣','宋','宋诗','song-poetry','','[]','頃余遊鞏洛，值子入天台。',144,'全唐诗/poet.song.13000.json','["頃余遊鞏洛，值子入天台。", "當時羣卿士，共羨出氛埃。", "荏苒逾一紀，却向人間來。", "問子何爲爾，言興般若臺。", "雖將發愚闇，般若安在哉。", "此教久已熾，增海非一杯。", "我言亦爝火，豈使萬木灰。", "蓋欲守中道，焉能力損裁。", "子勿疑我言，遂以爲嫌猜。", "忽聞携錫杖，思向石橋迴。", "城霞與琪樹，璨璨助詩才。", "嘉辭徧入口，幸足息巖隈。"]'),
('9fd9ed54-b08e-474a-b9ad-7c73c55754b3','公度以余嘗語洛中花品而此邦之人多不敢言花於余今又風雨經時花期遂過作詩以見貽故次其韻','梅堯臣','宋','宋诗','song-poetry','','[]','去年三月來吳中，欲擬看花無與從。',96,'全唐诗/poet.song.13000.json','["去年三月來吳中，欲擬看花無與從。", "今年二月花偏早，發作無節雨與風。", "前時晴明要尋賞，謂夸洛陽多不容。", "我心豈是限南北，美好未必須深紅。", "姚黄魏品若盡有，春色定應天下空。", "因君見贈又及此，莫怪還思澗水東。"]'),
('0a8b9059-f2cb-4c5e-8dff-830fc81c0689','留題可及明心堂','梅堯臣','宋','宋诗','song-poetry','','[]','秭雉已先嘷，卉木萼漸歇。',48,'全唐诗/poet.song.13000.json','["秭雉已先嘷，卉木萼漸歇。", "俯檻弄條枚，因心悟生滅。", "上人本高胄，季父踐清列。", "而能厭紛華，樂彼方外說。"]'),
('aaf8cfd5-f946-4316-9ea6-834249266d0f','陪武平游雅上人房卞峯亭','梅堯臣','宋','宋诗','song-poetry','','[]','晚愛池上清，羣峯對簷隙。',48,'全唐诗/poet.song.13000.json','["晚愛池上清，羣峯對簷隙。", "常恐雲氣生，坐令蒼翠隔。", "復繞曲塘陰，映實孤花拆。", "誰知禪者居，來伴使君適。"]'),
('5a8f121d-e005-41c4-9bfe-31b20127a151','送張舍人自安吉移宰同安','梅堯臣','宋','宋诗','song-poetry','','[]','遠辭湖上山，徙治海邊邑。',48,'全唐诗/poet.song.13000.json','["遠辭湖上山，徙治海邊邑。", "機杼吳俗饒，魚蝦越人給。", "操琴在更張，殊土宜順襲。", "何以贈勤勤，薄言茲所及。"]'),
('350cdb12-23b2-49c0-b693-c94a5dfd3d6e','劉彝秀才歸江南','梅堯臣','宋','宋诗','song-poetry','','[]','鳳鳥不受笯，麒麟寧受靽。',36,'全唐诗/poet.song.13000.json','["鳳鳥不受笯，麒麟寧受靽。", "君思此二物，中夜忽興歎。", "况值南風來，襲蘭歸楚岸。"]'),
('1b564e41-ece5-49f5-a5eb-d0e3849f34d5','送胡武平','梅堯臣','宋','宋诗','song-poetry','','[]','來見江南昏，使君詠汀蘋。',120,'全唐诗/poet.song.13000.json','["來見江南昏，使君詠汀蘋。", "再看蘋葉老，汀畔送歸人。", "人歸多慕戀，遺惠在茲民。", "始時繞郊郭，水不通蹄輪。", "公來作新塘，直抵吳松垠。", "新塘建輿梁，濟越脫輈仁。", "言度新塘去，隨跡如魚鱗。", "從今新塘樹，便與蔽芾均。", "我雖備僚屬，筆舌敢妄陳。", "因行錄所美，願與國風振。"]'),
('4c347db0-bd2c-495c-b168-8deee07c2b7f','迴陳郎中詩集','梅堯臣','宋','宋诗','song-poetry','','[]','嘗觀陳伯玉，感遇三十篇。',120,'全唐诗/poet.song.13000.json','["嘗觀陳伯玉，感遇三十篇。", "矯矯追古道，粲爾日星懸。", "今公豈其後，佳詠久已傳。", "憶爲童子日，早誦錦繡妍。", "茲來預官屬，而許玩奇編。", "明珠三百琲，一一徑寸圓。", "他人握中有，未獲毫髮焉。", "家貧敢懷寶，况近驪龍淵。", "又畏風雨作，神物不得全。", "再拜捧明月，長跪還席前。"]'),
('047a36dc-3810-4018-90ad-3b04ce32697f','依韻和武平別後見寄','梅堯臣','宋','宋诗','song-poetry','','[]','溪遠檣危一望遥，此焉悽絕府中僚。',64,'全唐诗/poet.song.13000.json','["溪遠檣危一望遥，此焉悽絕府中僚。", "已同雁鶩依清淺，共看鸞皇上泬寥。", "別岸無端縈細柳，迴舟不忍過新橋。", "醉來事事能生感，誰道愁腸酒易銷。"]'),
('2e8a83fa-6c72-4a2e-a59c-3a1a8eeccce6','蘄州廣濟劉主簿','梅堯臣','宋','宋诗','song-poetry','','[]','相識雖非久，相親似舊年。',48,'全唐诗/poet.song.13000.json','["相識雖非久，相親似舊年。", "論文君豈後，尚齒我慙先。", "慣狎吳兒水，將浮楚客船。", "安知不離恨，高柳正鳴蟬。"]'),
('470dabe1-a7dd-4aa8-bed4-19e3b078aff0','依韻和僧說夏日閑居見寄','梅堯臣','宋','宋诗','song-poetry','','[]','城郭非清凉，山僧抱微疾。',48,'全唐诗/poet.song.13000.json','["城郭非清凉，山僧抱微疾。", "又况三伏時，當茲一禪室。", "炎飆正爍爍，溪水徒瑟瑟。", "唯詠冰雪辭，可以銷夏日。"]'),
('50187e3e-972d-4b92-a9ae-b54c83484170','依韻和李宰秋思','梅堯臣','宋','宋诗','song-poetry','','[]','一葉與風舞，已知天地情。',48,'全唐诗/poet.song.13000.json','["一葉與風舞，已知天地情。", "將令百果實，競振羣蟲聲。", "陶令欲收秫，豳人思誓觥。", "更吟君麗句，誰爲寫鍾評。"]'),
('32c4afbd-4544-41c9-ab5d-aa0d23eadf74','送儲令赴韶州樂昌','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞韶石下，虞舜古祠深。',36,'全唐诗/poet.song.13000.json','["嘗聞韶石下，虞舜古祠深。", "至樂久已寂，况持陶令琴。", "炎方不道遠，一去值秋霖。"]'),
('1508265b-b2ae-49c9-a0f8-85c0b5f085dd','隠真亭','梅堯臣','宋','宋诗','song-poetry','','[]','作尉慕吾祖，吾祖非得時。',48,'全唐诗/poet.song.13000.json','["作尉慕吾祖，吾祖非得時。", "誰似芙蓉國，日見芙蓉披。", "凉雨隨風來，清香入酒巵。", "自得真隠趣，不慙吳市爲。"]'),
('de1042c0-ad4e-4360-9735-2e6b4b5f7ce9','說上人遊廬山','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夙懷高世趣，固足林壑情。',72,'全唐诗/poet.song.13000.json','["夙懷高世趣，固足林壑情。", "欲遊名山徧，遂爲廬岳行。", "又訪遠公蹟，東林氣象清。", "瀑布秋影落，香爐曉煙生。", "洗蕩萬古慮，薰蒸千載名。", "我今滯孤宦，空羨瓶錫輕。"]'),
('3a50eb71-b047-4838-9e8b-2e9dd42ae87b','和元之述夢見寄','梅堯臣','宋','宋诗','song-poetry','','[]','高秋枕席凉，晝寢還清曠。',168,'全唐诗/poet.song.13000.json','["高秋枕席凉，晝寢還清曠。", "不嘲君腹便，獨夢予爾訪。", "豈忘相規言，仍記羣小謗。", "始知端正心，寐語尚不誑。", "惝怳何讒人，告子亦孟浪。", "吾聞有尸蟲，伺惡多相尚。", "耽睡受其惑，子心恐成恙。", "勉子守庾曹，勿使茲物王。", "魂交昧聰明，寤後成清唱。", "誦玩自省循，徒爾增怊悵。", "不能檢細微，遂使言屢貺。", "雖然甚頑鄙，內顧無過當。", "仲尼稱天厭，季路猶行行。", "何當謝勤誠，爲子傾嘉釀。"]'),
('57bf09fa-9536-4fbd-9bb2-f8113c7ccd0e','秋日卧疾恭上人來過不及見因以詩答','梅堯臣','宋','宋诗','song-poetry','','[]','溪上秋霧多，溪居曉寒入。',96,'全唐诗/poet.song.13000.json','["溪上秋霧多，溪居曉寒入。", "呼吸遂生痾，嘔泄不下粒。", "素居江南地，大率皆卑溼。", "久從吳土居，氣候非所襲。", "伏枕欲經旬，冠带拈已澀。", "女奚特扣關，問疾提山笠。", "我非金粟身，寄謝何暇揖。", "屈性茲不能，他時冀來及。"]'),
('cd712293-e4ac-4f0f-9814-81e5462ac6ce','依韻和守賢上人晚秋書事','梅堯臣','宋','宋诗','song-poetry','','[]','秋霧鬰不開，曚曨夾溪樹。',72,'全唐诗/poet.song.13000.json','["秋霧鬰不開，曚曨夾溪樹。", "深枝尚宿禽，寒葉時驚露。", "我居溪之陰，早景誠所慕。", "開谿吐初陽，獨吟神與晤。", "豈意方袍人，而懷此焉趣。", "忽枉瓊玖章，無慙惠休句。"]'),
('a6721d71-34a4-4e28-b511-30a1d5ac8e6e','臧子文剡縣主簿','梅堯臣','宋','宋诗','song-poetry','','[]','剡水無淺深，歷歷能見底。',48,'全唐诗/poet.song.13000.json','["剡水無淺深，歷歷能見底。", "潛鱗莫見窺，塵紱聊堪洗。", "古木潭上陰，遺祠巖下啟。", "應識道傍碑，因風奠醪醴。"]'),
('c57c01b4-5288-4fc3-b391-8b37aa44ce1a','余令之會稽新昌','梅堯臣','宋','宋诗','song-poetry','','[]','越舸將渡西陵時，臘雪欲作陰雲垂。',64,'全唐诗/poet.song.13000.json','["越舸將渡西陵時，臘雪欲作陰雲垂。", "古岸潮迴夜冰閣，冰上鯉魚紅尾鬐。", "知君奉親聊自得，窮冬涉險仍熙熙。", "縣民但可觀此意，休羨江邊孝女碑。"]'),
('47202a1a-e6af-416d-8f46-d63d698f084d','傳神悅躬上人','梅堯臣','宋','宋诗','song-poetry','','[]','握中一寸毫，寶匣百鍊金。',72,'全唐诗/poet.song.13000.json','["握中一寸毫，寶匣百鍊金。", "鑑貌不鑑道，寫形寧寫心。", "古人固不識，今人或所欽。", "依然見其質，儼爾恨無音。", "子誠丹青妙，巧奮造化深。", "妍媸必盡得，幻妄恐交侵。"]'),
('ffc0bcea-bbf2-465e-a6a7-fe8269bdb876','文曜師之南徐','梅堯臣','宋','宋诗','song-poetry','','[]','班班上川羽，薄暮未安巢。',48,'全唐诗/poet.song.13000.json','["班班上川羽，薄暮未安巢。", "擾擾方外士，歲晏遊遠郊。", "正值風霜急，晚冰隨處敲。", "何時居巖下，都把塵事拋。"]'),
('7ebe6e77-33a7-4f10-9420-ba4ab456a0f0','茂芝上人歸姑蘇','梅堯臣','宋','宋诗','song-poetry','','[]','身衣竺乾服，手援犧氏琴。',48,'全唐诗/poet.song.13000.json','["身衣竺乾服，手援犧氏琴。", "繁聲不願奏，古意一何深。", "晏景託孤艇，倦飛還舊林。", "闔閭城下寺，幾里認鐘音。"]'),
('a51c45ef-8ff7-41e0-b40e-270b127a980e','唐寺丞知南雄州','梅堯臣','宋','宋诗','song-poetry','','[]','前林尚含凍，南國使君行。',48,'全唐诗/poet.song.13000.json','["前林尚含凍，南國使君行。", "逆水春風峭，孤舟桂席輕。", "踏歌聞舊俗，信鬼有頹氓。", "當識朱衣貴，壺漿擁道迎。"]'),
('fbc82733-f487-485c-a3de-d833aade3a66','依韻和孫秀才朱長官見寄  其一','梅堯臣','宋','宋诗','song-poetry','','[]','古來富貴蹈危機，樂性安貧莫謂非。',32,'全唐诗/poet.song.13000.json','["古來富貴蹈危機，樂性安貧莫謂非。", "未及功名蒼鬢改，欲從疎懶五湖歸。"]'),
('71f8c049-c635-4f2b-a2b6-46ef0a080e1b','依韻和孫秀才朱長官見寄  其二','梅堯臣','宋','宋诗','song-poetry','','[]','昔年同志逢時盡，今日相親似子稀。',32,'全唐诗/poet.song.13000.json','["昔年同志逢時盡，今日相親似子稀。", "犀僕忽辭雲海上，遠持雙璧扣吾扉。"]'),
('4a45c30b-a3f0-4541-905d-3371c3e47aff','謝尉西歸','梅堯臣','宋','宋诗','song-poetry','','[]','曾爲洛陽客，喜見洛陽人。',72,'全唐诗/poet.song.13000.json','["曾爲洛陽客，喜見洛陽人。", "每憶舊遊處，相逢借問頻。", "當時伊水上，醉弄巖花春。", "而今絕茲樂，欲語已酸辛。", "明朝君當去，又復與誰親。", "唯應有素月，相照寒溪濱。"]'),
('eedb2e80-fde6-4ac7-867a-728e224d7f97','陳浩赴福州幕','梅堯臣','宋','宋诗','song-poetry','','[]','梅殘杏將坼，楊柳都未堪。',48,'全唐诗/poet.song.13000.json','["梅殘杏將坼，楊柳都未堪。", "欲贈無所贈，春風吹酒酣。", "遠山猶带雪，野水已如藍。", "羽檄不應有，詩書自可躭。"]'),
('7fb3c58d-c9e3-4253-8ad8-c711b168efc9','示沈生','梅堯臣','宋','宋诗','song-poetry','','[]','稚子每多疾，始與藥物親。',48,'全唐诗/poet.song.13000.json','["稚子每多疾，始與藥物親。", "由茲沈生跡，遂歷吾門頻。", "我居無鳥鼠，乃知屋室貧。", "舉世競趨利，爾非閭井人。"]'),
('919a2dcf-7bc8-4082-af44-ae9e3a6b8179','和潘叔治早春遊何山','梅堯臣','宋','宋诗','song-poetry','','[]','泛泛寒溪流，縈紆向山去。',48,'全唐诗/poet.song.13000.json','["泛泛寒溪流，縈紆向山去。", "淺石長蒲茸，朝煙暖巖樹。", "捨舟當禪扉，踏蘚污野屨。", "誰愛鮑參軍，登臨多秀句。"]'),
('313be136-ef44-424c-a798-ae6768c4d1d6','張法曹歸闕','梅堯臣','宋','宋诗','song-poetry','','[]','海底日未上，屋頭羣雀喧。',48,'全唐诗/poet.song.13000.json','["海底日未上，屋頭羣雀喧。", "晨興溪館迥，坐聽櫓聲煩。", "出戶望行舸，羨心如野猿。", "暮春余亦去，爲見故人言。"]'),
('2b5aa135-4471-4df0-87f8-3cbeab90e393','送張叔展北歸','梅堯臣','宋','宋诗','song-poetry','','[]','江南春候早，水暖野芹生。',48,'全唐诗/poet.song.13000.json','["江南春候早，水暖野芹生。", "北客欲歸日，故人持贈行。", "莫嫌爲物薄，言采幽蘭并。", "休惜臨流醉，高帆去棹輕。"]'),
('745ada15-f753-41a6-a53c-a7501a909c45','依韻和叔治晚春梅花','梅堯臣','宋','宋诗','song-poetry','','[]','楚人住處將爲援，越使傳時合有詩。',64,'全唐诗/poet.song.13000.json','["楚人住處將爲援，越使傳時合有詩。", "常是臘前混雪色，却驚春半見瓊姿。", "笛吹遠曲還多怨，風送清香似可期。", "我欲細看持在手，誰能爲折向南枝。"]'),
('42052d1b-1775-482a-9fbe-5a2b1bda9d83','僧元復院枕流軒','梅堯臣','宋','宋诗','song-poetry','','[]','寺外寒流駛，開軒靜者棲。',48,'全唐诗/poet.song.13000.json','["寺外寒流駛，開軒靜者棲。", "淺深看藻荇，出沒愛鳧鷖。", "一悟此中趣，萬緣皆可齊。", "誰來驚節物，岸木長春荑。"]'),
('3331c6b6-4bb0-4581-874c-18acba029da7','惱儂','梅堯臣','宋','宋诗','song-poetry','','[]','期我以踏青，花間儻相遇。',72,'全唐诗/poet.song.13000.json','["期我以踏青，花間儻相遇。", "果然南陌頭，翩若驚鴻度。", "不語强躊躕，羞人映芳樹。", "兩心常自憐，兩目空相注。", "依依不得親，薄暮還愁去。", "記取似丹葩，知開向何處。"]'),
('484ff4cf-6e76-40e0-86da-a3618e249838','相逢','梅堯臣','宋','宋诗','song-poetry','','[]','晚日南城歸，橋邊見郎去。',72,'全唐诗/poet.song.13000.json','["晚日南城歸，橋邊見郎去。", "遠遠逐郎迴，羅衣汗微污。", "不惜污羅衣，要與郎相顧。", "留連芳苑中，肯謝花夭嫭。", "傍欄思晤言，羞畏情誰諭。", "草草各還家，幽懷是飛絮。"]'),
('7d7d5d3e-e32d-4bde-9c9f-b23b41e4b6ee','檣烏','梅堯臣','宋','宋诗','song-poetry','','[]','檣頭飛去烏，夜夜啼聲碎。',48,'全唐诗/poet.song.13000.json','["檣頭飛去烏，夜夜啼聲碎。", "猶不如水禽，雙棲向煙外。", "煙外少分張，渚間多翳薈。", "休同八九子，反哺人誰愛。"]'),
('87827d37-df4a-497d-860b-a17ce3238888','過華亭','梅堯臣','宋','宋诗','song-poetry','','[]','晴雲嘷鶴幾千隻，隔水野梅三四株。',32,'全唐诗/poet.song.13000.json','["晴雲嘷鶴幾千隻，隔水野梅三四株。", "欲問陸機當日宅，而今何處不荒蕪。"]'),
('5423d3d4-b9fc-4901-be39-428aaf9da4ed','月暈','梅堯臣','宋','宋诗','song-poetry','','[]','月暈已知風，燈花先作喜。',24,'全唐诗/poet.song.13000.json','["月暈已知風，燈花先作喜。", "明日挂帆歸，春湖能幾里。"]'),
('8999aea4-c2d6-4463-b1f1-259f6598c1e1','逢謝師直','梅堯臣','宋','宋诗','song-poetry','','[]','昔歲南陽道中別，今向華亭水上逢。',32,'全唐诗/poet.song.13000.json','["昔歲南陽道中別，今向華亭水上逢。", "把酒語君悲且喜，流光冉冉去無蹤。"]'),
('06a53eb7-cd95-49c0-91c6-e9f42936188b','迴自青龍呈謝師直','梅堯臣','宋','宋诗','song-poetry','','[]','共君相別三四年，巖巖瘦骨還依然。',192,'全唐诗/poet.song.13000.json','["共君相別三四年，巖巖瘦骨還依然。", "唯髭比舊多且黑，學術久已不可肩。", "嗟余老大無所用，白髮冉冉將侵顛。", "文章自是與時背，妻餓兒啼無一錢。", "幸得詩書銷白日，豈顧富貴摩青天。", "而今飲酒亦復少，未及再酌腸如煎。", "前夕與君歡且飲，飲纔數盞我已眠。", "雞鳴犬吠似聒耳，舉頭屋室皆左旋。", "起來整巾不稱意，挂帆直走滄海邊。", "便欲騎鯨去萬里，列缺不借霹靂鞭。", "氣沮心衰計欲睡，夢想先到蘋渚前。", "與君無復更留醉，醉死誰能如謫僊。"]'),
('56c75804-bc67-4944-bdf5-e4f8015064a4','青龍海上觀潮','梅堯臣','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','百川倒蹙水欲立，不久却迴如鼻吸。',96,'全唐诗/poet.song.13000.json','["百川倒蹙水欲立，不久却迴如鼻吸。", "老魚無守隨上下，閣向滄洲空怨泣。", "推鱗伐肉走千艘，骨節專車無大及。", "幾年養此膏血軀，一旦翻爲漁者給。", "無情之水誰可憑，將作尋常自輕入。", "何時更看弄潮兒，頭戴火盆來就溼。"]'),
('5575da8e-3712-4733-83b1-6694e3f949ef','社前','梅堯臣','宋','宋诗','song-poetry','','[]','欲社先知雨，將歸未見花。',24,'全唐诗/poet.song.13000.json','["欲社先知雨，將歸未見花。", "那能長作客，夜夜夢還家。"]'),
('50d78c99-eaf1-4a7f-a656-e81d88256f5c','水次髑髏','梅堯臣','宋','宋诗','song-poetry','','[]','不知誰氏子，枯首在沙洲。',48,'全唐诗/poet.song.13000.json','["不知誰氏子，枯首在沙洲。", "肉化烏鳶腹，肢殘波浪頭。", "曾聞南面樂，寧有九原愁。", "厚葬不爲貴，漢官其登丘。"]'),
('52c01283-1b48-4bdc-ac37-67a0a698cb6c','葉大卿挽詞  其一','梅堯臣','宋','宋诗','song-poetry','','[]','位列名卿重，年躋賜几尊。',48,'全唐诗/poet.song.13000.json','["位列名卿重，年躋賜几尊。", "臧孫宜有後，定國已高門。", "舊族聲華遠，名藩治行存。", "秋風簫吹咽，隴隧起雲根。"]'),
('73b0696b-6501-43d6-98b7-1feb12024427','葉大卿挽詞  其二','梅堯臣','宋','宋诗','song-poetry','','[]','自古賢才少，滔滔豈足云。',48,'全唐诗/poet.song.13000.json','["自古賢才少，滔滔豈足云。", "善人安得見，清譽久來聞。", "器隕龍文鼎，魂歸馬鬣墳。", "豐碑幾當立，籍甚著遺芬。"]'),
('be1041ef-64a9-4a45-afbe-a30356c03e69','葉大卿挽詞  其三','梅堯臣','宋','宋诗','song-poetry','','[]','終始爲全德，生榮沒亦榮。',48,'全唐诗/poet.song.13000.json','["終始爲全德，生榮沒亦榮。", "里人悲畫翣，郡吏拜銘旌。", "石馬天麟肖，松枝國棟成。", "更看追孝意，捧土作新塋。"]'),
('5259652e-c6ae-4133-be24-6a2922abe91c','湖州寒食陪太守南園宴','梅堯臣','宋','宋诗','song-poetry','','[]','寒食二月三月交，紅桃破纇柳染梢。',160,'全唐诗/poet.song.13000.json','["寒食二月三月交，紅桃破纇柳染梢。", "陰晴不定野雲密，黕黕鼓聲湖岸坳。", "使君千騎出南圃，歌吹前導後鳴鐃。", "是時輒預車馬末，傾市競觀民業拋。", "竹亭臨水美可愛，嗑咂草木皆吐苞。", "遊人春服靚粧出，笑踏俚歌相與嘲。", "使君白髮體尤健，自晨及暮奏酒肴。", "爾輩少年翻易倦，倚席欠伸誰得教。", "公雖不責以正禮，我意未容誠斗筲。", "逡巡秉燭各分散，小人爭路何呶呶。"]'),
('6c99f0f1-4ff2-42dc-aa18-01cefc83ea0e','牡丹','梅堯臣','宋','宋诗','song-poetry','','[]','洛陽牡丹名品多，自謂天下無能過。',96,'全唐诗/poet.song.13000.json','["洛陽牡丹名品多，自謂天下無能過。", "及來江南花亦好，絳紫淺紅如舞娥。", "竹陰水照增顔色，春服帖妥裁輕羅。", "時結游朋去尋玩，香吹酒面生紅波。", "粉英不忿付狂蝶，白髮强插成悲歌。", "明年更開余已去，風雨吹殘可奈何。"]'),
('f4fd24c6-cb5f-4010-b1b1-d9ad3eb34d98','惜春三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','九十日春無幾日，不堪風雨競吹花。',32,'全唐诗/poet.song.13000.json','["九十日春無幾日，不堪風雨競吹花。", "舞英逐水向何處，泛泛斜溪伴晚霞。"]'),
('507f831b-41a7-490b-a7e0-4af1e8cb4eaa','惜春三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','前日看花心未足，狂風暴雨忽無憑。',32,'全唐诗/poet.song.13000.json','["前日看花心未足，狂風暴雨忽無憑。", "此身不及深溪水，隨得殘紅出武陵。"]'),
('9abc4a8a-77cb-4f52-b46d-5f7b26f72d9c','惜春三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','春色斗空花亦休，綠園深鎖更誰遊。',32,'全唐诗/poet.song.13000.json','["春色斗空花亦休，綠園深鎖更誰遊。", "殘枝遺萼不中看，暮雨霏霏起暗愁。"]'),
('8b21a174-7a43-4d30-858d-b4231f79c3d0','花娘歌','梅堯臣','宋','宋诗','song-poetry','','[]','花娘十二能歌舞，籍甚聲名居樂府。',320,'全唐诗/poet.song.13000.json','["花娘十二能歌舞，籍甚聲名居樂府。", "荏苒其間十四年，朝作行雲暮行雨。", "格夫氣俊能動人，人能動之無幾許。", "前歲適從江國來，時因醼席相微語。", "雖有幽情未得傳，暗結殷勤度寒暑。", "去春送客出東城，舟中接膝已心傾。", "自茲稍稍有期約，五月連航並釣行。", "曲堤別浦無人處，始笑鴛鴦浪得名。", "爾後頻逢殊嬿婉，各恨從來相見晚。", "月下花前不暫離，暫離已抵銀河遠。", "青鳥傳音日幾迴，雞鳴歸去暮還來。", "經秋度臘無纖失，愛極情專易得猜。", "前時南圃尋芳卉，小忿不勝投袂起。", "官私乘釁作威稜，督促倉惶去閭里。", "蕭蕭風雨滿長溪，一舸翩然逐流水。", "忽逢小史向城來，泣淚寄言心欲死。", "願郎日日致青雲，妾已長甘在泥滓。", "更悲恩意不得終，世事難憑何若此。", "郎聞茲語痛莫深，天地無窮恨無已。", "我今爲爾偶成章，便欲緘之託雙鯉。"]'),
('0aa5fb22-0a61-4826-9474-c41a21d91b26','程山人歸歙州','梅堯臣','宋','宋诗','song-poetry','','[]','新安固與吾鄉鄰，山水清絕殊可擬。',32,'全唐诗/poet.song.13000.json','["新安固與吾鄉鄰，山水清絕殊可擬。", "我今暫來子亦歸，空聽杜鵑雲樹裏。"]'),
('4a8ccaa5-3d89-4b5a-b930-498691959c1c','重過南園','梅堯臣','宋','宋诗','song-poetry','','[]','誰作此園爲宴喜，而今樂事已難并。',32,'全唐诗/poet.song.13000.json','["誰作此園爲宴喜，而今樂事已難并。", "佳人去後門長鏁，蔓草離離上古城。"]'),
('4d10d551-66fb-47f4-8861-93fc0a99461a','送滕監簿歸寧岳陽','梅堯臣','宋','宋诗','song-poetry','','[]','乃翁守西鄙，胡騎敢憑陵。',84,'全唐诗/poet.song.13000.json','["乃翁守西鄙，胡騎敢憑陵。", "撫士無餘貨，吏以文結繩。", "向聞來三堂，今復走巴陵。", "泝流幾千里，雲夢苦炎蒸。", "風檣易陣馬，猶使勇氣增。", "子今遠寄省，寄謝余豈能。", "江山可留詠，燕許昔嘗曾。"]'),
('ff79c728-75e1-408c-8588-1f88000859bd','寄題千步院兼示諲上人','梅堯臣','宋','宋诗','song-poetry','','[]','郊郭山林有美處，皆爲釋子所棲託。',48,'全唐诗/poet.song.13000.json','["郊郭山林有美處，皆爲釋子所棲託。", "高閑不與時俗侵，寂靜豈唯魚鳥樂。", "朝望平田插稻苗，暮看西村收雨脚。"]'),
('c4f28ea5-2958-4258-8faf-a77730c02ee1','早夏陪知府學士登疊嶂樓','梅堯臣','宋','宋诗','song-poetry','','[]','高陵自可眺，況復更層樓。',120,'全唐诗/poet.song.13000.json','["高陵自可眺，況復更層樓。", "峨峨衆山翠，活活寒溪流。", "新篁未掃籜，緣險已脩脩。", "曲道出林杪，飛宇跨城頭。", "春餘衆芳歇，子結纍蔓抽。", "庭空野鼠竄，日暝啼禽留。", "誰知郡府趣，適有林壑幽。", "主人易吾土，惟襲是瀛洲。", "伊我去閭井，爾來三十秋。", "昔望白雲下，今從輕軒游。"]'),
('c041a792-b0f1-47b6-921b-5becae8c2f23','得孫仲方畫美人一軸','梅堯臣','宋','宋诗','song-poetry','','[]','駿駒少馴良，美女少賢德。',48,'全唐诗/poet.song.13000.json','["駿駒少馴良，美女少賢德。", "嘗聞敗君駕，亦以傾人國。", "因觀壁間畫，筆妙仍奇色。", "持歸非奪好，來者恐爲惑。"]'),
('20f49f0f-bc67-4940-a9c7-06c7bf91061f','涂次寄羅道濟','梅堯臣','宋','宋诗','song-poetry','','[]','去年五月君到官，紅渠正開湖水寬。',96,'全唐诗/poet.song.13000.json','["去年五月君到官，紅渠正開湖水寬。", "共酌汀洲不知暮，扣舷月露霑衣寒。", "今年我罷欲歸去，朋酒久來無此歡。", "移舟不忍便爲別，競挈杯肴情未闌。", "城堙欲閉各分散，溪雲暗澹生悲端。", "明日抱酲風雨急，野蓮空看寄君難。"]'),
('a4ab18b7-7f11-4fa1-9431-4ed701e52fd2','和潘叔治題劉道士房畫薛稷六鶴圖六首 啄食','梅堯臣','宋','宋诗','song-poetry','','[]','窮年見俛啄，但有饑乏意。',36,'全唐诗/poet.song.13000.json','["窮年見俛啄，但有饑乏意。", "雖存玉山禾，不入丹青喙。", "因思方朔嘲，此豈優諧類。"]'),
('5eaac609-e0d4-4f14-bf1f-011072a8a295','和潘叔治題劉道士房畫薛稷六鶴圖六首 顧步','梅堯臣','宋','宋诗','song-poetry','','[]','舉足徒有勢，行沙遂無蹤。',36,'全唐诗/poet.song.13000.json','["舉足徒有勢，行沙遂無蹤。", "迴頸誠已久，未知竟何從。", "安能見儔侶，顧望自顒顒。"]'),
('33014a5a-3f05-4c05-804f-260b86c1c72d','和潘叔治題劉道士房畫薛稷六鶴圖六首 唳天','梅堯臣','宋','宋诗','song-poetry','','[]','引吭向層霄，聲聞期在耳。',36,'全唐诗/poet.song.13000.json','["引吭向層霄，聲聞期在耳。", "鼓吻意豈疎，知音何已矣。", "安得九臯同，流響入萬里。"]'),
('28ce9719-e4f5-4523-ab3e-6147a94b5ec8','和潘叔治題劉道士房畫薛稷六鶴圖六首 舞風','梅堯臣','宋','宋诗','song-poetry','','[]','如逢僊圃風，飄颻奮雙翅。',36,'全唐诗/poet.song.13000.json','["如逢僊圃風，飄颻奮雙翅。", "拊節余欲助，和歌誰爾類。", "但看矯然姿，固於流雪異。"]'),
('2211eabb-4c67-48cd-a9bd-0336ad58e2ca','和潘叔治題劉道士房畫薛稷六鶴圖六首 警露','梅堯臣','宋','宋诗','song-poetry','','[]','孤標近僊壇，依約聞墜露。',36,'全唐诗/poet.song.13000.json','["孤標近僊壇，依約聞墜露。", "儼如舉止揚，稍見神爽悟。", "曉月坐清軒，寒添壁間素。"]'),
('afbbf523-75be-4952-a3e4-e562925678ca','和潘叔治題劉道士房畫薛稷六鶴圖六首 理毛','梅堯臣','宋','宋诗','song-poetry','','[]','六鶴皆不同，初生薛公筆。',36,'全唐诗/poet.song.13000.json','["六鶴皆不同，初生薛公筆。", "況茲刷羽者，奮迅如天質。", "墨客懷賞心，題詩仍我率。"]'),
('7c3c5836-7390-4d97-bedc-1c70a4c13964','留題毘陵潘氏宅假山','梅堯臣','宋','宋诗','song-poetry','','[]','人心本好靜，世事方擾擾。',48,'全唐诗/poet.song.13000.json','["人心本好靜，世事方擾擾。", "丘壑未去時，庭中結山小。", "長欲見蒼翠，何須聽猿鳥。", "有志同尚平，當期婚嫁了。"]'),
('9f9e90ad-cfb0-46e9-b4e8-f10d28236aec','觀居寧畫草蟲','梅堯臣','宋','宋诗','song-poetry','','[]','古人畫虎鵠，尚類狗與鶩。',120,'全唐诗/poet.song.13000.json','["古人畫虎鵠，尚類狗與鶩。", "今看畫羽蟲，形意兩俱足。", "行者勢若去，飛者翻若逐。", "拒者如舉臂，鳴者如動腹。", "躍者趯其股，顧者注其目。", "乃知造物靈，未抵毫端速。", "毗陵多畫工，圖寫空盈輻。", "寧公實神授，坐使羣輩伏。", "草根有纖意，醉墨得已熟。", "權豪不可致，節行今仍獨。"]'),
('4c79c166-8cf8-4796-abd5-7875984cbe32','和穎上人南徐十詠 鐵甕城','梅堯臣','宋','宋诗','song-poetry','','[]','塹江以爲池，增山以爲壁。',48,'全唐诗/poet.song.13000.json','["塹江以爲池，增山以爲壁。", "鐵甕喻其堅，金城非所敵。", "前朝經喪亂，曾是輕鋒鏑。", "覽古一徜徉，空聽漁浦笛。"]'),
('d0520a87-a3f0-417a-a914-c621dd5fe2ca','和穎上人南徐十詠 北固山','梅堯臣','宋','宋诗','song-poetry','','[]','山勢自北來，高城倚爲固。',48,'全唐诗/poet.song.13000.json','["山勢自北來，高城倚爲固。", "當時偶登臨，邇者遂淪誤。", "微雲思作雨，古樹嘗霑露。", "今非恃險艱，草木藏狐兔。"]'),
('9cf3ff20-1811-48c6-90c5-7b3181f4b306','和穎上人南徐十詠 京口水','梅堯臣','宋','宋诗','song-poetry','','[]','江頭潮正平，日照土山口。',48,'全唐诗/poet.song.13000.json','["江頭潮正平，日照土山口。", "坐見遠來舟，高帆忽前後。", "將隨入浦風，稍度遥圻柳。", "客無南北虞，信是承平久。"]'),
('7c8658a6-0764-40c7-9cf0-28430d94249d','和穎上人南徐十詠 金山寺','梅堯臣','宋','宋诗','song-poetry','','[]','山與衆山殊，寺非諸寺擬。',48,'全唐诗/poet.song.13000.json','["山與衆山殊，寺非諸寺擬。", "無面不當江，有林皆照水。", "南泠隔吳會，北渡通揚子。", "還看上下帆，日日何常已。"]'),
('84f9ea94-4af1-48fe-96b0-2defcd0d8269','和穎上人南徐十詠 望海樓','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞觀蹄涔，詎識海水大。',48,'全唐诗/poet.song.13000.json','["嘗聞觀蹄涔，詎識海水大。", "浩浩與天同，滔滔衆流會。", "平吞江作練，遠瀉河如带。", "終日郡樓間，欲取長鯨鱠。"]'),
('cc1abf6e-e29f-440a-8aa2-df885b24e98d','和穎上人南徐十詠 季子廟','梅堯臣','宋','宋诗','song-poetry','','[]','信如季子賢，自昔知能幾。',48,'全唐诗/poet.song.13000.json','["信如季子賢，自昔知能幾。", "依約有荒祠，寂寥無奠篚。", "壞梁生濕菌，古木憑山鬼。", "英靈豈顧茲，青史辭亹亹。"]'),
('45f5afd9-a030-4082-8435-cf1f279d181b','和穎上人南徐十詠 鶴林寺','梅堯臣','宋','宋诗','song-poetry','','[]','松竹暗山門，颼飀給青吹。',48,'全唐诗/poet.song.13000.json','["松竹暗山門，颼飀給青吹。", "傳聞宋高祖，舊宅爲茲寺。", "地以黑龍升，經因白馬至。", "何必問興亡，山川應可記。"]'),
('a0a8f5d3-eabf-4693-9a29-3824021f3690','和穎上人南徐十詠 夫子篆','梅堯臣','宋','宋诗','song-poetry','','[]','季札墓傍碑，古稱尼父篆。',48,'全唐诗/poet.song.13000.json','["季札墓傍碑，古稱尼父篆。", "始沿春秋義，十字固莫淺。", "磨敲任牧童，侵剝因野蘚。", "嗟爾後之人，萬言書不顯。"]'),
('2b43fc07-76cb-4db1-a830-f0330b125d1b','和穎上人南徐十詠 甘露寺','梅堯臣','宋','宋诗','song-poetry','','[]','山頭百畝宮，庭下千年樹。',48,'全唐诗/poet.song.13000.json','["山頭百畝宮，庭下千年樹。", "在昔甘露霏，嘗疑神物護。", "陰連殿閣寒，聲撼雷霆怒。", "瞻影衛公堂，英魂想來去。"]'),
('4d5c8fa2-b2e9-4864-b6ea-3a8bb0c8692d','和穎上人南徐十詠 范公橋','梅堯臣','宋','宋诗','song-poetry','','[]','謂公天下才，非專一方惠。',48,'全唐诗/poet.song.13000.json','["謂公天下才，非專一方惠。", "及此作輿梁，力行無鉅細。", "既異國僑爲，將同傅巖濟。", "礱石亙長川，寧須伐山桂。"]'),
('a8988de5-3fa3-48ad-8c10-a97d3b48355f','邵伯堰下王君玉餞王仲儀赴渭州經略席上命賦','梅堯臣','宋','宋诗','song-poetry','','[]','未破河西寇，朝廷尚有憂。',48,'全唐诗/poet.song.13000.json','["未破河西寇，朝廷尚有憂。", "淮南命儒帥，塞上足封侯。", "莫擐黄金甲，須存百勝謀。", "昔嘗經黠虜，今去正防秋。"]'),
('cfd8ee56-8dba-4ca7-9286-1135f29bc841','悼亡三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','結髮爲夫婦，於今十七年。',48,'全唐诗/poet.song.13000.json','["結髮爲夫婦，於今十七年。", "相看猶不足，何況是長捐。", "我鬢已多白，此身寧久全。", "終當與同穴，未死淚漣漣。"]'),
('b3473986-6368-46a4-ab59-f0a7957dc294','悼亡三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','每出身如夢，逢人强意多。',48,'全唐诗/poet.song.13000.json','["每出身如夢，逢人强意多。", "歸來仍寂寞，欲語向誰何。", "窗冷孤螢入，宵長一雁過。", "世間無最苦，精爽此銷磨。"]'),
('75ba7393-81c7-43f1-9044-8c7ab8acf917','悼亡三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','從來有脩短，豈敢問蒼天。',48,'全唐诗/poet.song.13000.json','["從來有脩短，豈敢問蒼天。", "見盡人間婦，無如美且賢。", "譬令愚者壽，何不假其年。", "忍此連城寶，沉埋向九泉。"]'),
('dc214e6c-02b2-49ea-afd8-9f3b7556da3b','淚','梅堯臣','宋','宋诗','song-poetry','','[]','平生眼中血，日夜自涓涓。',48,'全唐诗/poet.song.13000.json','["平生眼中血，日夜自涓涓。", "瀉出愁腸苦，深於浸沸泉。", "紅顔將洗盡，白髮亦根連。", "此恨古皆有，不須愚與賢。"]'),
('f4637072-27ef-4e82-9bc7-68ec9f0348c0','秋日舟中有感','梅堯臣','宋','宋诗','song-poetry','','[]','天乎余困甚，失偶淚滂沱。',96,'全唐诗/poet.song.13000.json','["天乎余困甚，失偶淚滂沱。", "世事隨時遠，秋風順水多。", "鰥魚空戀穴，獨鳥未離柯。", "歲月都無幾，存亡可奈何。", "兒嬌從自哭，婢騃不能呵。", "已覺愁容改，休將舊鑑磨。", "弊衣留暗垢，殘藥恨沉痾。", "斗厭驅驅役，終期老薜蘿。"]'),
('d3f8f978-6de6-46b2-9d74-94f26b333ea4','書哀','梅堯臣','宋','宋诗','song-poetry','','[]','天既喪我妻，又復喪我子。',72,'全唐诗/poet.song.13000.json','["天既喪我妻，又復喪我子。", "兩眼雖未枯，片心將欲死。", "雨落入地中，珠沉入海底。", "赴海可見珠，掘地可見水。", "唯人歸泉下，萬古知已矣。", "拊膺當問誰，憔悴鑑中鬼。"]'),
('4bf88c37-e468-4cd8-bc2e-108235c6fc34','謁雙廟','梅堯臣','宋','宋诗','song-poetry','','[]','八月過宋都，泊舟雙廟側。',120,'全唐诗/poet.song.13000.json','["八月過宋都，泊舟雙廟側。", "永懷此忠良，遺烈傳碑刻。", "五位儼朝裾，千年同血食。", "當時多苟生，貴爵曾誰識。", "縱今有丘墳，都已荒荆棘。", "古人非輕死，於義實罕得。", "英骨化埃塵，令名同鳥翼。", "飛翔出後世，景慕無終極。", "豈若目前榮，未歿聲已息。", "西登孝王城，王氣由邦國。"]'),
('d73f09f6-e488-4ffe-af77-0e8c1af981ab','送弟禹臣赴官江南','梅堯臣','宋','宋诗','song-poetry','','[]','昔與子同歸，夜向瓜洲泊。',48,'全唐诗/poet.song.13000.json','["昔與子同歸，夜向瓜洲泊。", "持杯月正清，遄水平如削。", "爾來蘆岸深，須防虎潛搏。", "行行無朋友，遇事自斟酌。"]'),
('8e09b422-560b-4c9a-999d-37a41b5cd3aa','和永叔晉祠詩','梅堯臣','宋','宋诗','song-poetry','','[]','并州古來稱近胡，山雄氣壯民足儲。',160,'全唐诗/poet.song.13000.json','["并州古來稱近胡，山雄氣壯民足儲。", "山根晉水發源處，平若皎鑑潛决疎。", "漸流漸急不可測，以至𤂆𤂆鳴清渠。", "豈惟俯可見毛髮，況乃了了看龜魚。", "下溉平田幾百頃，稻苗𥝧䅉曾不枯。", "興亡莫問隨水遠，廟深草樹空扶疎。", "伊君持節過其下，愛此佳趣聊停車。", "北望故城無舊物，泱漭野色連丘墟。", "已向風前聽好鳥，只畏落日聞蒼狐。", "晉人須識漢使美，冉冉青髯似綠蒲。"]'),
('e1cc7e1f-6445-48c7-a933-eb379ed0867b','得李殿丞端州硯','梅堯臣','宋','宋诗','song-poetry','','[]','鮫龍所窟處，其石美且堅。',48,'全唐诗/poet.song.13000.json','["鮫龍所窟處，其石美且堅。", "蠻匠斲爲硯，漢官求費錢。", "持歸向都邑，爭乞如瓦磚。", "豈識萬里險，謬竊好事傳。"]'),
('e2aa60b1-0c78-48db-92b4-e26e8e6df0a1','書謝師厚至','梅堯臣','宋','宋诗','song-poetry','','[]','爾來器爾姑，清淚滴塵几。',48,'全唐诗/poet.song.13000.json','["爾來器爾姑，清淚滴塵几。", "一聞在目言，不謂今則死。", "而猶意遠行，所念當至止。", "秋風忽助嚎，萬木欲摧毀。"]'),
('1daa1122-3127-4737-838b-ebeed4c08d23','詠蘇子美庭中千葉菊樹子','梅堯臣','宋','宋诗','song-poetry','','[]','生與衆草生，不與衆草榮。',96,'全唐诗/poet.song.13000.json','["生與衆草生，不與衆草榮。", "彼皆春爭葩，茲獨秋吐英。", "千葉共一萼，百蔕共一莖。", "幽亭聳扶疎，獨本非搘撐。", "吾友蘇子美，有酒對自傾。", "香隨青陵蝶，色映黄金鶑。", "昨日偶來過，頗興陶令情。", "豈敢復言詩，君家有子卿。"]'),
('9d72006b-0deb-4f27-8d5e-30fc268004f4','新冬傷逝呈李殿丞','梅堯臣','宋','宋诗','song-poetry','','[]','惡老今逼衰，孤寂仍足悲。',72,'全唐诗/poet.song.13000.json','["惡老今逼衰，孤寂仍足悲。", "寒風一夜起，曩事無不思。", "手澤在故物，默歷非故時。", "夢寐猶平常，反悟恨莫追。", "人生苦情累，安得木石爲。", "頼有同舍郎，相語强解頤。"]'),
('87f4cb4e-10f4-4b11-b5d4-df95f099eea7','送趙升卿之韶幕','梅堯臣','宋','宋诗','song-poetry','','[]','舟車歷盡險，風物乃還君。',48,'全唐诗/poet.song.13000.json','["舟車歷盡險，風物乃還君。", "俎肉應多味，虞韶不復聞。", "林鳴異音鳥，山冒欲晴雲。", "若弔張丞相，空祠舊近墳。"]'),
('c89e7546-451e-43fd-b4fa-c915057a4dcb','蘇子美竹軒和王勝之','梅堯臣','宋','宋诗','song-poetry','','[]','庭無十步廣，有竹纔百個。',96,'全唐诗/poet.song.13000.json','["庭無十步廣，有竹纔百個。", "子時哦其間，賓友或來和。", "琴壺置於傍，圖籍亦在左。", "誰憐脩脩影，只畏寒日過。", "誰憐青青枝，下有暗葉墮。", "我期霰雪時，來聽幽聲卧。", "應當爲設榻，勿使賞心剉。", "持以報主人，此興不可破。"]'),
('e1f61182-4073-424e-b9de-7dd8af1568cb','偶書寄蘇子美','梅堯臣','宋','宋诗','song-poetry','','[]','君詩壯且奇，君筆工復妙。',120,'全唐诗/poet.song.13000.json','["君詩壯且奇，君筆工復妙。", "二者世共寶，一得亦難料。", "我今或盈軸，體逸思益峭。", "有如秋空鷹，氣壓城雀鷂。", "又如飲巨鍾，一舉不能釂。", "既釂心已醉，顛倒視兩曜。", "吾交有永叔，勁正語多要。", "嘗評吾二人，放檢不同調。", "其於文字間，苦硬與惡少。", "雖然趣尚殊，握手幸相笑。"]'),
('5f7c57dc-efaf-42e7-970e-617f90e4f7ff','寄題洪州李氏涵虛閣','梅堯臣','宋','宋诗','song-poetry','','[]','耳熟滕閣美，未爲豫章遊。',72,'全唐诗/poet.song.13000.json','["耳熟滕閣美，未爲豫章遊。", "近聞東湖上，可見西山頭。", "朝愛雲氣生，暮數鳥行幽。", "主人趣向遠，登覽日不休。", "父兄已三人，挂冠此遲留。", "他年儻一往，風物詠可周。"]'),
('0634b5b3-278a-470b-b97e-1282a760c963','送蕭秘校','梅堯臣','宋','宋诗','song-poetry','','[]','比從江南來，又從江南去。',48,'全唐诗/poet.song.13000.json','["比從江南來，又從江南去。", "孤舟隨雁羣，晚泊定何處。", "霜橙可爲齏，冰鱠思下筯。", "此興吾不知，薄言聊所慕。"]'),
('1aa3eefd-84af-4a47-b251-d1921a882790','送李殿丞通判處州','梅堯臣','宋','宋诗','song-poetry','','[]','拜官將近親，不畏千里險。',96,'全唐诗/poet.song.13000.json','["拜官將近親，不畏千里險。", "泝流上贛水，石亂波驚颭。", "舟人素已諳，曲折就迴閃。", "豈虞失便利，倚慣憂亦掩。", "昔余從平流，悸夢尚成魘。", "今逢子方去，青䋏絲新染。", "沙頭有堠吏，惴立板方斂。", "鴻雁正來翔，競看朱服儼。"]'),
('a4179129-bc71-4cab-9611-e232bacc7bdc','古劍篇送蔡君謨自諫省出守福唐','梅堯臣','宋','宋诗','song-poetry','','[]','生銅夜夜鳴，剉鐵未嘗缺。',48,'全唐诗/poet.song.13000.json','["生銅夜夜鳴，剉鐵未嘗缺。", "主人久提携，何事贈離別。", "借問豈酬恩，請看鐔上血。", "休慙補履功，出處異施設。"]'),
('61415a6b-35d4-4d39-b879-5cc908bf864a','雜興','梅堯臣','宋','宋诗','song-poetry','','[]','主人有十客，共食一鼎珍。',60,'全唐诗/poet.song.13000.json','["主人有十客，共食一鼎珍。", "一客不得食，覆鼎傷衆賓。", "雖云九客沮，未足一客嗔。", "古有弒君者，羊羹爲不均。", "莫以天下士，而比首陽人。"]'),
('a4c3d8d5-f707-4f70-bdb6-ad1f20c09643','送逐客王勝之不及遂至屠兒原','梅堯臣','宋','宋诗','song-poetry','','[]','犯霜出國門，送客客已去。',72,'全唐诗/poet.song.13000.json','["犯霜出國門，送客客已去。", "猶意行未遠，策馬過寒戍。", "川長不見人，沙沒前崗路。", "始聞雲木深，忽逢朱亥墓。", "金鎚一報恩，義烈垂竹素。", "何須文學爲，寄語長沙傅。"]'),
('f8058958-8dfa-49bd-9569-3fdfb3fd6b2d','送周仲章太博之鉅野','梅堯臣','宋','宋诗','song-poetry','','[]','仲月霜氣嚴，朝來厚如雪。',48,'全唐诗/poet.song.13000.json','["仲月霜氣嚴，朝來厚如雪。", "鴻雁各南飛，羽毛將恐折。", "征途履以足，侵骨寒於鐵。", "得罪此爲輕，君恩大歡悅。"]'),
('af6f43bd-141a-403a-a8a5-8de0b38b3535','鄴中行','梅堯臣','宋','宋诗','song-poetry','','[]','武帝初起銅雀臺，丕又建閣延七子。',144,'全唐诗/poet.song.13000.json','["武帝初起銅雀臺，丕又建閣延七子。", "日日臺上羣烏饑，峨峨七子宴且喜。", "是時閣嚴人不通，雖有層梯誰可履。", "公幹才俊或欺事，平視美人曾不起。", "五官褊急猶且容，意使忿怒如有鬼。", "自茲不得爲故人，輸作左校濱於死。", "其餘數子安可存，紛然射去如流矢。", "鳥烏聲樂臺轉高，各自畢逋誇疐尾。", "而今撫卷跡已陳，唯有漳河舊流水。"]'),
('7e677aa1-048b-4441-ab4e-4a2cee4f29fa','親郊前三日大慶殿雪中皇帝率羣臣發章聖五后冊','梅堯臣','宋','宋诗','song-poetry','','[]','將郊先奉冊，拜立未央庭。',72,'全唐诗/poet.song.13000.json','["將郊先奉冊，拜立未央庭。", "天表君心孝，人驚曉雪零。", "冕旒紛點綴，劍佩濕晶熒。", "曲蓋曾無用，羣臣敢自寧。", "鑪煙靜齋幄，井氣凍宮缾。", "明日來壇下，中宵已見星。"]'),
('caf66fe2-3b78-4dbf-8de4-751a91f47d58','忠上人携王生古硯誇余云是定州漢祖廟上瓦爲之因作詩以答','梅堯臣','宋','宋诗','song-poetry','','[]','硯取漢廟瓦，誰恤漢廟隳。',36,'全唐诗/poet.song.13000.json','["硯取漢廟瓦，誰恤漢廟隳。", "重古一如此，吾今對之悲。", "既寶若圭璧，未知爲用時。"]'),
('1184b823-b53b-4266-8b7f-ba1fc0f3187c','讀後漢書列傳','梅堯臣','宋','宋诗','song-poetry','','[]','漢家誅黨人，誰與李杜死。',36,'全唐诗/poet.song.13000.json','["漢家誅黨人，誰與李杜死。", "死者有范滂，其母爲之喜。", "喜死名愈彰，生榮同犬豕。"]'),
('87e7ae3f-bea2-45c5-8029-cac2b8539d61','異同','梅堯臣','宋','宋诗','song-poetry','','[]','吾聞聖賢心，不限親與疎。',96,'全唐诗/poet.song.13000.json','["吾聞聖賢心，不限親與疎。", "義殊目前乖，道同異代俱。", "堯舜及周孔，千載趨一途。", "盜跖誚孔氏，弟子將黨歟。", "蹠自驅其衆，日念殺不辜。", "河濱捧土人，海畔逐臭夫。", "塞川豈量力，同趣即爾徒。", "爾既不自過，反以此爲紆。"]'),
('53110c17-de10-4d30-b7ed-bebc43f3875d','蔡仲謀遺鯽魚十六尾余憶在襄城時獲此魚留以遺歐陽永叔','梅堯臣','宋','宋诗','song-poetry','','[]','昔嘗得圓鯽，留待故人食。',48,'全唐诗/poet.song.13000.json','["昔嘗得圓鯽，留待故人食。", "今君遠贈之，故人大河北。", "欲膾無庖人，欲寄無鳥翼。", "放之已不活，烹煮費薪棘。"]'),
('44df7224-63be-4b57-b1c5-b1c337afbc92','雜擬','梅堯臣','宋','宋诗','song-poetry','','[]','忽聞胡騎渡河水，月魄夜脅陰貂寒。',32,'全唐诗/poet.song.13000.json','["忽聞胡騎渡河水，月魄夜脅陰貂寒。", "獨侍金輿立城角，龍蛇不展繞旗竿。"]'),
('68906ca5-cef3-40c5-aa46-0ac2ff2abda3','答中上人卷','梅堯臣','宋','宋诗','song-poetry','','[]','吹笛皆學龍，吹笙皆學鳳。',60,'全唐诗/poet.song.13000.json','["吹笛皆學龍，吹笙皆學鳳。", "又於笙笛間，高下不相中。", "得其精者稀，得其麤者衆。", "況於真出音，千歲不復夢。", "爾爲學笙歟，頗已臻妙弄。"]'),
('e8b13d8f-b88d-4307-a4fa-81ef562a92bb','送蘇子美','梅堯臣','宋','宋诗','song-poetry','','[]','勇爲江海行，風波曾不懼。',192,'全唐诗/poet.song.13000.json','["勇爲江海行，風波曾不懼。", "但欲尋名山，扁舟無定處。", "南有鵬若鴞，嶮有石若鋸。", "毒草見人摇，短狐逢影怒。", "不遐尚苦乖，更遠饒瘴霧。", "東土乃濱海，蜃鼉仍可怖。", "殻物怪瑣屑，蠃蜆固無數。", "鹹腥損齒牙，日月復易飫。", "二方既若此，往矣無久駐。", "竟當西北來，醇酎炙肥羜。", "夏不厭漿酪，冬不厭雉兔。", "勿言專口腹，口腹人所務。", "天台信奇偉，石橋非坦步。", "廬岳趣最幽，饑腸看瀑布。", "此致雖爲高，實亦難久慕。", "君行聽我言，不聽到應悟。"]'),
('981f60af-0006-4116-a5f3-55e4d2db94e2','晚歸聞李殿丞訪別言己屢來不遇','梅堯臣','宋','宋诗','song-poetry','','[]','蕭條一陋巷，頻日見馬蹄。',144,'全唐诗/poet.song.13000.json','["蕭條一陋巷，頻日見馬蹄。", "歸來稚子告，有客云將暌。", "始知君其南，復歎我向西。", "豈不懷念慕，吾親書新齎。", "曰吾五男子，愛惜無不齊。", "所要立門戶，安用同犬雞。", "齪齪守此客，馴馴戀此棲。", "二季留左右，足以共挈携。", "身許遠就祿，幸又奉阿㜷。", "今年還都下，路喪子與妻。", "囊罄厭外役，進退類藩羝。", "終當改江邑，儻得致音題。"]'),
('e82071c7-6d45-4449-8d13-1f78cfb5aedc','刁景純將之海陵與二三子送於都門外遂宿舟中明日留饌膾','梅堯臣','宋','宋诗','song-poetry','','[]','人言汴水駛，奈何已冬乾。',72,'全唐诗/poet.song.13000.json','["人言汴水駛，奈何已冬乾。", "蔡雖平且慢，臘月行亦難。", "唯聽夜冰合，爲君愁苦寒。", "暫維青絲䋏，邀膾白玉盤。", "行人反飫我，於理殊未安。", "所忻能自養，不復道加餐。"]'),
('7d333406-a6b3-459c-b821-b7fa44d9c6ba','寄洪州致仕李國博','梅堯臣','宋','宋诗','song-poetry','','[]','湖上悠然度幾春，勇拋榮祿遂天真。',64,'全唐诗/poet.song.13000.json','["湖上悠然度幾春，勇拋榮祿遂天真。", "青蒲翠竹圍華屋，白酒黄雞命里人。", "果下有時乘小駟，兒曹方見擁朱輪。", "田園歲入千鍾美，肯似疎家苦畏貧。"]'),
('113f4f89-8206-4154-96ce-26f21d794c04','同謝師厚宿胥氏書齋聞鼠甚患之','梅堯臣','宋','宋诗','song-poetry','','[]','燈青人已眠，饑鼠稍出穴。',48,'全唐诗/poet.song.13000.json','["燈青人已眠，饑鼠稍出穴。", "掀翻盤盂響，驚聒夢寐輟。", "唯愁几硯撲，又恐架書齧。", "癡兒效貓鳴，此計誠已拙。"]'),
('7dc02123-462a-4431-a5f0-56f660c72050','聞子美次道師厚登天清寺塔','梅堯臣','宋','宋诗','song-poetry','','[]','二三君少壯，走上浮圖巔。',60,'全唐诗/poet.song.13000.json','["二三君少壯，走上浮圖巔。", "何爲苦思我，平步猶不前。", "苟得從而登，兩股應已攣。", "復想下時險，喘汗頭目旋。", "不如且安坐，休用窺雲煙。"]'),
('6dcfa1b8-1208-4412-a7fd-0e3e41f03fcc','謝師厚歸南陽效阮步兵','梅堯臣','宋','宋诗','song-poetry','','[]','一日復一朝，一暮復一旦。',120,'全唐诗/poet.song.13000.json','["一日復一朝，一暮復一旦。", "與子相經過，少會不言散。", "我心終未極，歲月忽云晏。", "嘶馬思長道，孤鳥逐前伴。", "駕言慕儔侶，懷抱若冰炭。", "南臨白水湄，風雪振高岸。", "意恐慈母念，疾馳節已換。", "解劍登北堂，幼婦笑粲粲。", "弊裘一以縫，征塵一以澣。", "而我客大梁，衣垢自悲歎。"]'),
('6c239f01-78bd-4821-9aed-868ab66f5421','師厚明日歸南陽夜坐有懷','梅堯臣','宋','宋诗','song-poetry','','[]','明朝子當去，我若雲失龍。',60,'全唐诗/poet.song.13000.json','["明朝子當去，我若雲失龍。", "龍歸雲未歸，索莫將安從。", "半夜出戶望，參畢已正中。", "倏然變陰黑，烈烈鳴窗風。", "窗鳴不得寐，擁被一悲翁。"]'),
('3a78eca0-c627-4a38-832f-59e1b2f7ec09','永叔贈酒','梅堯臣','宋','宋诗','song-poetry','','[]','大門多奇醖，一斗市錢千。',240,'全唐诗/poet.song.13000.json','["大門多奇醖，一斗市錢千。", "貧食尚不足，欲飲將何緣。", "豈能以口腹，屈節事豪權。", "閉戶飽於齏，作詩湧如泉。", "一日復一夕，醒目常不眠。", "窮臘忽可怪，雙壺故人傳。", "呼兒欲自酌，瓦盞無完全。", "其能饔甘脆，而況侑夭妍。", "却令情懷惡，分與富貴偏。", "收拾不復嘗，排置屋角邊。", "儻有嘉客至，傾倒相與顛。", "何暇問濃薄，但覺窗扉旋。", "誰識我爲我，賓主各頹然。", "始得語且橫，既醉論益堅。", "曾不究世務，閑氣爭古先。", "畢竟兩未决，辨吻空流涎。", "嗟我儒者飲，聒耳無管絃。", "雖云暫歡適，終久還愁煎。", "自甘不偶死，寧慕金印懸。", "願頻致此物，勿恤瘡檐肩。"]'),
('9b866658-1f74-431f-8bee-e81698d75dee','得山雨','梅堯臣','宋','宋诗','song-poetry','','[]','急雨射蒼壁，濺林跳萬珠。',24,'全唐诗/poet.song.13000.json','["急雨射蒼壁，濺林跳萬珠。", "山根水壅壑，漫竅若注壺。"]'),
('c34635a7-51d2-4ac9-b9e3-6cb0c6b4aea8','范殿丞通判秦州','梅堯臣','宋','宋诗','song-poetry','','[]','天水出名馬，多稱黄金羈。',72,'全唐诗/poet.song.13000.json','["天水出名馬，多稱黄金羈。", "正值羌已和，邊草復離離。", "乘肥固未失，所藴不得施。", "主人本燕客，寧獨事書詩。", "志尚功名間，管樂猶一時。", "去去勿復道，磊落爲男兒。"]'),
('b1221305-d69b-4143-92c8-f79e657d65a1','陳繹越州從事','梅堯臣','宋','宋诗','song-poetry','','[]','母夫人老母兄黜，夫人從爾之會稽。',64,'全唐诗/poet.song.13000.json','["母夫人老母兄黜，夫人從爾之會稽。", "恐傷爾心不敢泣，春崗細雨聞竹雞。", "時亦藏淚未出臉，奈何相與頭傾低。", "誠知就祿非獲己，應欲退耕無舊畦。"]'),
('e1db8448-e552-469f-9a99-beab066deb92','辛著作知西京永寧','梅堯臣','宋','宋诗','song-poetry','','[]','躍馬西畿令，家塋在洛陽。',48,'全唐诗/poet.song.13000.json','["躍馬西畿令，家塋在洛陽。", "衣霑寒食雨，花發故宮牆。", "冷淡鳩鳴屋，寬閑水滿塘。", "送君悲漸老，空憶釣伊魴。"]'),
('0d3f6953-5036-443f-bda7-ff66be3876e0','依韻和師厚別後寄','梅堯臣','宋','宋诗','song-poetry','','[]','吾與爾別未及旬，吾家依舊甑生塵。',72,'全唐诗/poet.song.13000.json','["吾與爾別未及旬，吾家依舊甑生塵。", "閉門不出將誰親，自持介獨輕貨珍。", "盤餐豈有鹹酸辛，苦吟輟寢昏繼晨。", "夜光忽怪來何頻，採拾若在滄海垠。", "和者彌寡唯陽春。"]'),
('51867512-aad7-41bc-b836-a9b0b9dfcaef','普凈院佛閣上孤鶻','梅堯臣','宋','宋诗','song-poetry','','[]','我新稅居見寺閣，金碧照我破屋前。',176,'全唐诗/poet.song.13000.json','["我新稅居見寺閣，金碧照我破屋前。", "目看閣上聚鳩鴿，巢棲飲哺忘窮年。", "雕簷畫壁屎污徧，以及像塑頭與肩。", "寺僧不敢施彈射，忽有蒼鶻張毒拳。", "鴉鳴鵲噪鸜鵒叫，怒鶻來此窺腥羶。", "鶻心决裂不畏衆，瞥碎一腦驚後先。", "死鳥墮空未及地，返翅下取如風旋。", "獨當屋脊恣撦磔，啄肉披肝腸棄捐。", "老鴟無藝又狠怯，盤飛欲近饑目穿。", "逡巡鶻飽自飛去，爭殘不辨烏與鳶。", "羣兒指點路人笑，我方吟憶秋江邊。"]'),
('91d5c6ce-984f-47d4-9829-5a3f38f714a6','蜂','梅堯臣','宋','宋诗','song-poetry','','[]','春風無主撩亂時，分羣養子各守脾。',80,'全唐诗/poet.song.13000.json','["春風無主撩亂時，分羣養子各守脾。", "爭掇花腴爲蠟蜜，年年共割不我稽。", "俄逢主人若過慮，畏爾有蠆成噬臍。", "密將惡物毒爾族，爾曾不得同醯雞。", "王雖爾名爾何補，造甘爲利乃自取。"]'),
('9acb1886-5ba5-402f-a41a-007e9dd676a2','並遊','梅堯臣','宋','宋诗','song-poetry','','[]','並出慙羸駕，康衢懶著鞭。',48,'全唐诗/poet.song.13000.json','["並出慙羸駕，康衢懶著鞭。", "蹇馿能勝馬，擘道去如煙。", "何用嗟遲疾，從來有後先。", "所期皆一至，我到爾應還。"]'),
('f2d43da2-7028-45be-8394-3e64398ad8e2','寄宣州可真上人','梅堯臣','宋','宋诗','song-poetry','','[]','昭亭山色無纖塵，昭亭潭水見游鱗。',32,'全唐诗/poet.song.13000.json','["昭亭山色無纖塵，昭亭潭水見游鱗。", "長松碧篠入古寺，石上高僧度幾春。"]'),
('fef472b7-7149-480f-846d-901ef726263c','冬夕會飲聯句','梅堯臣','宋','宋诗','song-poetry','','[]','與君數夜飲，唯恐酒盞空。',293,'全唐诗/poet.song.13000.json','["與君數夜飲，唯恐酒盞空。", "今我苦欲淺，語志難此同。", "陳編侑歡適，間謔何魁雄。", "婢子寒且倦，主人哦不窮。", "燈青屢結花，煎響時鳴蟲。", "穴鼠暗出沒，風雁高雍容。", "冰霜覆瓦屋，貂狐輸貴翁。", "孤床乏暖質，苦語有淡工。", "咀嚼患{炙火=肉}小，煨炮驚殻紅。", "落蟾斜入竅，遠漏微遞風。", "醉心欺睡魄，細書刺昏瞳。", "吽呀聞爭犬，哮吼厭啼𩦺。", "撥火亂赬豆，附炙雙彎弓。", "乾果硬迸齒，寒齏酸滿胸。", "枯蛤擘無肉，淡脯燒可饔。", "語必造聖賢，樂已過鼓鍾。", "紙窗幸未曙，絮被令旋縫。", "凍痺兩股鐵，跑抓雙鬢蓬。", "脬尿既懶溺，裩虱唯欲烘。", "器皿足缺齾，捧執無夭穠。", "兒女寒不寢，僮僕困欲瞢。", "豈無貴富徒，笑此饑寒蹤。", "丈夫固有負，道義久已充。", "墨子不黔突，齒輩且得封。"]'),
('94eae315-5177-43cf-bac5-aadeca4a47a1','元夕同次道中道平叔如晦賦詩得閑字','梅堯臣','宋','宋诗','song-poetry','','[]','金輿在閶闔，簫吹滿人寰。',48,'全唐诗/poet.song.13000.json','["金輿在閶闔，簫吹滿人寰。", "九陌行如晝，千門夜不關。", "星通河漢上，珠亂里閭間。", "誰與聯輕騎，宵長月正閑。"]'),
('7253c752-eefe-4947-aa11-853fc378c727','正月十五夜出迴','梅堯臣','宋','宋诗','song-poetry','','[]','不出只愁感，出遊將自寬。',96,'全唐诗/poet.song.13000.json','["不出只愁感，出遊將自寬。", "貴賤依儔匹，心復殊不歡。", "漸老情易厭，欲之意先闌。", "却還見兒女，不語鼻辛酸。", "去年與母出，學母施朱丹。", "今母歸下泉，垢面衣少完。", "念爾各尚幼，藏淚不忍看。", "推燈向壁卧，肺腑百憂攢。"]'),
('86d61287-ec21-400b-82e9-65a32f8fdabc','同次道遊相國寺買得翠玉罌一枚','梅堯臣','宋','宋诗','song-poetry','','[]','古寺老柏下，叟貨翠玉罌。',72,'全唐诗/poet.song.13000.json','["古寺老柏下，叟貨翠玉罌。", "獸足面以立，瓜腹肩而平。", "虛能一勺容，色與藍水并。", "我獨何爲者，忽見目以驚。", "家無半鍾畜，不吝百金輕。", "都人莫識寶，白日雙眼盲。"]'),
('e914b6af-8639-4a75-86d4-adc7433d7f25','送惠懃上人','梅堯臣','宋','宋诗','song-poetry','','[]','遽告我行何所之，東南爾土爾自知。',80,'全唐诗/poet.song.13000.json','["遽告我行何所之，東南爾土爾自知。", "山水佛事不暇說，去何速兮來何爲。", "公卿貴人見爾喜，爲爾買屋丐爾資。", "王城幸可樂歲月，野鶴終是思陂池。", "去去雲霞不容侶，却應來此如前時。"]'),
('a8622b97-6cbb-412f-8a51-3458c5d7410d','聞賣韭黄蓼甲','梅堯臣','宋','宋诗','song-poetry','','[]','百物凍未活，初逢賣菜人。',48,'全唐诗/poet.song.13000.json','["百物凍未活，初逢賣菜人。", "乃知糞土暖，能發萌芽春。", "柔美已先薦，陽和非不均。", "芹根守天性，憔悴澗之濱。"]'),
('251498fe-0787-457b-a6ea-b23639f4fbd1','董著作嘗爲參謀歸話西事','梅堯臣','宋','宋诗','song-poetry','','[]','子說頗驍勇，築城收漢疆。',48,'全唐诗/poet.song.13000.json','["子說頗驍勇，築城收漢疆。", "提兵無百騎，偷路執生羌。", "大將罪專輒，舉軍皆感傷。", "歸來出萬死，羸馬亦摧藏。"]'),
('f78c0df3-28e8-4f46-bc37-25c824097886','戲寄師厚生女','梅堯臣','宋','宋诗','song-poetry','','[]','生男衆所喜，生女衆所醜。',48,'全唐诗/poet.song.13000.json','["生男衆所喜，生女衆所醜。", "生男走四鄰，生女各張口。", "男大守詩書，女大逐雞狗。", "何時某氏郎，堂上拜媼叟。"]'),
('6d9ff297-064c-4d5a-8cea-33a771e6dfc7','薛中舍宰聞喜','梅堯臣','宋','宋诗','song-poetry','','[]','秦人宦於秦，百事順耳目。',48,'全唐诗/poet.song.13000.json','["秦人宦於秦，百事順耳目。", "山川我已疎，風物子所熟。", "維美行邁時，親賓祖車轂。", "空將離別心，欲出無僮僕。"]'),
('37436a4f-3582-452f-afea-7d2c83c3bd7d','郭之美忽過云往河北謁歐陽永叔沈子山','梅堯臣','宋','宋诗','song-poetry','','[]','春風無行迹，似與草木期。',84,'全唐诗/poet.song.13000.json','["春風無行迹，似與草木期。", "高低新萌芽，閉戶我未知。", "忽聞人扣門，手把蟠桃枝。", "問我此蟠桃，緣何結子遲。", "但笑不復答，問者當自推。", "振衣向河朔，河朔人偉奇。", "以茲不答意，遲子北歸時。"]'),
('dc8d5fd5-a3f0-4d7e-9d7d-2a82645f769b','孫司諫知鄧州','梅堯臣','宋','宋诗','song-poetry','','[]','南陽漢名都，其俗尚敦樸。',72,'全唐诗/poet.song.13000.json','["南陽漢名都，其俗尚敦樸。", "亡徒頃爲盜，刺史安與角。", "田野遂焦熬，蒿萊思沃濯。", "茲雖得甘露，向已苦風雹。", "更張固所重，下令未宜數。", "且觀道傍碑，文字今已剝。"]'),
('71eb93c3-88d8-401f-b39e-f757a9d5b900','史尉還烏程','梅堯臣','宋','宋诗','song-poetry','','[]','與君去年別，君來竟悲喜。',216,'全唐诗/poet.song.13000.json','["與君去年別，君來竟悲喜。", "乘馬夜訪君，備陳昔行李。", "五月辭吳中，六月渡揚子。", "七月行喪妻，是月子又死。", "買棺無橐金，助貸頼知己。", "嬌兒晝夜啼，幼女飲食止。", "行路况炎蒸，悲哀滿心耳。", "青銅不忍照，憔悴鄰於鬼。", "八月至都下，少長疾未已。", "一婢復嗑然，老媼幾不起。", "君門日預朝，僕乘貧可恥。", "十月補王畿，受代隔歲紀。", "閉門陋巷中，悶默閱書史。", "初聞君至之，如見湖山美。", "今聞君復還，爲我謝雲水。", "故交儻相問，懷抱今如此。", "豈乏南飛雁，豈無東下鯉。", "自同嵇康懶，作書愁把紙。"]'),
('ab8c1753-8e1b-46ec-91ea-2a544eff86b5','薛九宅觀雕狐圖','梅堯臣','宋','宋诗','song-poetry','','[]','蜀中處士李懷衮，手畫皂雕擒赤狐。',80,'全唐诗/poet.song.13000.json','["蜀中處士李懷衮，手畫皂雕擒赤狐。", "猛爪入頰觜迸血，短尾㒔㑛窮蹄鋪。", "雕爭怒力狐爭死，二物形意無纖殊。", "一禽一獸固已別，硬羽軟毛非筆模。", "入君此室見此圖，如在原野從馳驅。"]'),
('27961abf-5b1a-4435-8ca4-80e7c2edac3c','寄汶上','梅堯臣','宋','宋诗','song-poetry','','[]','大第未嘗身一至，人猜巧宦我應非。',64,'全唐诗/poet.song.13000.json','["大第未嘗身一至，人猜巧宦我應非。", "彈冠不讀先賢傳，說劍休更短後衣。", "瘦馬青袍三十載，故人朱轂幾多違。", "功名富貴無能取，亂石清泉自憶歸。"]'),
('48f58b83-2036-4a23-baea-758dc4049993','蕭著作宰豐城','梅堯臣','宋','宋诗','song-poetry','','[]','王都二月花正開，社雨作陰迎燕子。',64,'全唐诗/poet.song.13000.json','["王都二月花正開，社雨作陰迎燕子。", "人先春色向江南，江南春色歸春水。", "拍岸綠波生荻芽，晨羞聊可助甘旨。", "縣涂爲政子所諳，不敢贈言言日鄙。"]'),
('f521c803-2b8a-4719-8933-924d5873b642','董安員外之信州鉛山簿','梅堯臣','宋','宋诗','song-poetry','','[]','古岸綠蒲老，春帆逆水輕。',48,'全唐诗/poet.song.13000.json','["古岸綠蒲老，春帆逆水輕。", "烹鮮聊以芼，泝險復兼程。", "可用茲時樂，無將遠道驚。", "曾爲江上客，因贈北行人。"]'),
('3c2474f0-537f-4926-8804-563a29cff6b7','弟得臣殿丞簽判越州','梅堯臣','宋','宋诗','song-poetry','','[]','再爲會稽行，聊問會稽美。',120,'全唐诗/poet.song.13000.json','["再爲會稽行，聊問會稽美。", "禹穴遷所探，秦望斯所紀。", "年代已浸深，書碑必亡矣。", "剡溪有樵風，其事恐非是。", "買臣千載後，得無負薪子。", "黄庭昔換鵝，道士儻不死。", "行當訪其真，願以鵝報爾。", "慎勿笑我癡，萬事難可擬。", "摘筍復盈檐，緡魚新出水。", "此又食之珍，因書悉條理。"]'),
('2ab53f61-d1ee-404b-95bd-3d44ec991fca','李舍人淮南提刑','梅堯臣','宋','宋诗','song-poetry','','[]','啄木欲除蠹，蠹去樹亦撓。',48,'全唐诗/poet.song.13000.json','["啄木欲除蠹，蠹去樹亦撓。", "何須食微蟲，爾腹豈不飽。", "天下本無事，自爲庸人擾。", "君實知古深，終慙用傾巧。"]'),
('149e9e6e-5fe8-4839-80d1-e1b06fe7db7d','吳殿丞代州通判','梅堯臣','宋','宋诗','song-poetry','','[]','舉才不避勢，必也知其長。',48,'全唐诗/poet.song.13000.json','["舉才不避勢，必也知其長。", "王官誠濟濟，豈得佐邊疆。", "代郡實雄要，昔已選帥良。", "功名乃欲取，叱馭登太行。"]'),
('248f4119-a0c0-490f-aa1c-5e4216a918ca','和人喜雨','梅堯臣','宋','宋诗','song-poetry','','[]','仲冬至仲春，陰隔久不雨。',108,'全唐诗/poet.song.13000.json','["仲冬至仲春，陰隔久不雨。", "耕農將失時，萌穎未出土。", "帝心實焦勞，日夜不安處。", "禱祠煩駿奔，肸饗杳無補。", "帝時降金輿，徧款靈真宇。", "百姓知帝勤，變愁爲鼓舞。", "和氣能致祥，是日雲蔽午。", "夕風不鳴條，甘潤忽周普。", "已見堯爲君，安問誰爲輔。"]'),
('a2c6e179-1e6f-422a-82c0-65c15fc5ec2f','胥員外之復州景陵尉','梅堯臣','宋','宋诗','song-poetry','','[]','城隅漢水闊，正足槎頭鯿。',48,'全唐诗/poet.song.13000.json','["城隅漢水闊，正足槎頭鯿。", "采荇兼登俎，施罛不貴錢。", "江帆風勢美，竹屋雨聲連。", "必有蒼苔碣，留爲好事傳。"]'),
('7340d8ee-db77-4ec7-a70b-40794cb7e7a3','李審言歸鄭州','梅堯臣','宋','宋诗','song-poetry','','[]','嘗從京索間，躍馬望春山。',48,'全唐诗/poet.song.13000.json','["嘗從京索間，躍馬望春山。", "氣象歸王國，丘陵接漢關。", "長榆啼鳥亂，細草牧陂閒。", "老厭行涂路，因歌送子還。"]'),
('820e4678-3cdd-45fb-b93d-7e0e1ed51a5a','李舍人見過','梅堯臣','宋','宋诗','song-poetry','','[]','春泥無處所，窮巷少人行。',48,'全唐诗/poet.song.13000.json','["春泥無處所，窮巷少人行。", "忽枉青絲騎，曾非白面生。", "笑言聊與適，雞黍未嘗烹。", "莫歎余貧甚，吾儕業本清。"]'),
('d1df855d-6a9c-460a-ac02-1618de438bc7','春鶻謠','梅堯臣','宋','宋诗','song-poetry','','[]','春巢纍纍，衆鳥哺兒。',83,'全唐诗/poet.song.13000.json','["春巢纍纍，衆鳥哺兒。", "衆鳥不出巢，羣雛嗷嗷腹甚饑。", "不出巢，其謂何，上有蒼鶻窺其窠。", "問鶻何仇，鶻不我顧。", "我巢有雛，開口待哺。", "一日不擊，巢雛不食。", "爾憂爾雛，衆鳥號呼又可吁。"]'),
('dced9e10-ccd9-4ee1-bc9f-ad63a58a3185','來夢','梅堯臣','宋','宋诗','song-poetry','','[]','忽來夢我，于水之左，不語而坐。',75,'全唐诗/poet.song.13000.json','["忽來夢我，于水之左，不語而坐。", "忽來夢余，于山之隅，不語而居。", "水果水乎，不見其逝。", "山果山乎，不見其途。", "爾果爾乎，不見其徂。", "覺而無物，泣涕漣如，是歟非歟。"]'),
('a5a99ba3-7a32-4be5-b5a0-e6ae88d4d3bc','汴之水三章送淮南提刑李舍人  其一','梅堯臣','宋','宋诗','song-poetry','','[]','汴之水，分于河，黄流濁濁激春波。',63,'全唐诗/poet.song.13000.json','["汴之水，分于河，黄流濁濁激春波。", "昨日初觀水東下，千人走喜兮萬人歌。", "歌謂何，大船來兮小船過。", "百貨將集玉都那，君則揚舲兮以糺刑科。"]'),
('5369230a-4494-42e2-87cb-ae9fe50b4f1d','汴之水三章送淮南提刑李舍人  其二','梅堯臣','宋','宋诗','song-poetry','','[]','汴之水，入于泗，黄流清淮爲一致。',49,'全唐诗/poet.song.13000.json','["汴之水，入于泗，黄流清淮爲一致。", "上牽下櫓日夜來，千人同濟兮萬人利。", "利何謂，國之漕，商之貨，實所寄。"]'),
('4bc5cd5f-b3a5-4699-bba8-692d092301da','汴之水三章送淮南提刑李舍人  其三','梅堯臣','宋','宋诗','song-poetry','','[]','我送行舟，于水之次。',34,'全唐诗/poet.song.13000.json','["我送行舟，于水之次。", "春風吹兩旗，君作天王使。", "罟客自求魚，清江莫相避。"]'),
('8bb2e1a3-3f45-47ad-baae-a96d802657e9','宋次道一百五日往鄭拜墓','梅堯臣','宋','宋诗','song-poetry','','[]','去不避風雨，泣望松柏門。',48,'全唐诗/poet.song.13000.json','["去不避風雨，泣望松柏門。", "颯然風悲響，如感泉下魂。", "沃酹向墳土，空濕陳草根。", "人歸夜月冷，石馬在九原。"]'),
('fe4da89c-d9ee-4cf4-8e0c-87a3edc80ea5','孫太祝亳州簽判','梅堯臣','宋','宋诗','song-poetry','','[]','微風起船尾，雨氣生日脚。',48,'全唐诗/poet.song.13000.json','["微風起船尾，雨氣生日脚。", "不愁春路泥，正泛春波樂。", "順去疾鳥飛，問程殊我度。", "才名留守家，更入尚書幙。"]'),
('de301636-75cc-44b7-a9f9-fcb536aa3710','寄靈隠通教僧','梅堯臣','宋','宋诗','song-poetry','','[]','奇山若洗青，草木生石上。',48,'全唐诗/poet.song.13000.json','["奇山若洗青，草木生石上。", "根萌不可窮，條蔓自增王。", "其陰有高僧，日食惟一盎。", "世人久已疎，猿鳥應相向。"]'),
('d9612090-5e9f-4b4c-b78e-55ce33e32a92','李少傅鄭圃佚老亭','梅堯臣','宋','宋诗','song-poetry','','[]','莊生述天理，老固當念佚。',96,'全唐诗/poet.song.13000.json','["莊生述天理，老固當念佚。", "舉世用自勞，誰能以爲必。", "我公謝鼎司，嗣子都華秩。", "代言輟帝右，作藩輔王室。", "承顔向茲地，園宇樂永日。", "佳樹發已繁，脩竹移未密。", "春禽時弄吭，清景付吟筆。", "朱金待金構，榮美安與匹。"]'),
('f1a67cba-e2bf-4233-a48a-8bb4467d2b9a','令狐秘丞守彭州','梅堯臣','宋','宋诗','song-poetry','','[]','前時草草別，渺漫二十年。',108,'全唐诗/poet.song.13000.json','["前時草草別，渺漫二十年。", "從宦各所適，非爲道路偏。", "今始一相遇，言愧少壯前。", "子有萬里翮，尚不飛雲煙。", "而復走隴蜀，欲以條教宣。", "將西過危棧，葉暗聞杜鵑。", "未知爲郡樂，預已抱愁煎。", "再來與子辭，當去復留連。", "且念前期遠，歲月實易遷。"]'),
('f25a385d-609b-46b9-9e85-c64431447361','依韻和李舍人旅中寒食感事','梅堯臣','宋','宋诗','song-poetry','','[]','一百五日風雨急，斜飄細濕春郊衣。',64,'全唐诗/poet.song.13000.json','["一百五日風雨急，斜飄細濕春郊衣。", "梨花半殘意思少，客子漸老尋游非。", "戢戢車徒九門盛，寥寥煙火萬家微。", "今朝甘自居窮巷，無恨墦間得醉歸。"]'),
('2a0b50b7-3771-4770-95c6-a4fe80a362b9','依韻和張應之見贈','梅堯臣','宋','宋诗','song-poetry','','[]','京洛多游好，相與歲月深。',48,'全唐诗/poet.song.13000.json','["京洛多游好，相與歲月深。", "雖同執一籥，吹曲各異音。", "自微衆音響，安感萬物心。", "我窮子來唁，慷慨發長吟。"]'),
('43af0953-eeb5-42df-bcc7-f0b4d5c2ca8c','哭尹子漸','梅堯臣','宋','宋诗','song-poetry','','[]','故人河內守，昨日報已亡。',48,'全唐诗/poet.song.13000.json','["故人河內守，昨日報已亡。", "同氣泣上黨，悲風生太行。", "曩爲衆所惜，今復人共傷。", "阮籍本真率，感慨壽不長。"]'),
('0f7d7d79-3b92-4f53-9e9e-26fe9c22e887','次道約食後同敏叔中道平叔如晦詣景德浴以風埃遂止','梅堯臣','宋','宋诗','song-poetry','','[]','昔思春服成，浴乎沂水上。',72,'全唐诗/poet.song.13000.json','["昔思春服成，浴乎沂水上。", "仲尼亦所志，語此雖未向。", "子今當是時，有意同我尚。", "已邀二三友，欲往期畢餉。", "倏然風滿途，塵土阻清曠。", "安得一振衣，徒希舞雩唱。"]'),
('58b279d5-ee1c-45bb-8a5f-2d2b50cd1ace','陳經秘校之信州幕','梅堯臣','宋','宋诗','song-poetry','','[]','東吳海物錯，南楚江味多。',48,'全唐诗/poet.song.13000.json','["東吳海物錯，南楚江味多。", "家吳而宦彼，風土去幾何。", "既得風土樂，可贊政治和。", "歸來識香草，爲綴楚人歌。"]'),
('8350eb2c-f7c7-4fa0-803a-cca7b0582591','朱武太博通判常州兼寄胡武平','梅堯臣','宋','宋诗','song-poetry','','[]','昔我陽夏公，嘗茲同郡治。',72,'全唐诗/poet.song.13000.json','["昔我陽夏公，嘗茲同郡治。", "政餘作東園，草木尚有意。", "豈不務安養，斯民歌樂易。", "是時有賢才，鄉舉堪皇器。", "今方居冢廬，試質當時事。", "願君思前人，文雅庶未墜。"]'),
('33e18259-3cbf-4812-ba9c-c052f3ec6055','師厚云蝨古未有詩邀予賦之','梅堯臣','宋','宋诗','song-poetry','','[]','貧衣弊易垢，易垢少蝨難。',48,'全唐诗/poet.song.13000.json','["貧衣弊易垢，易垢少蝨難。", "羣處裳带中，旅升裘領端。", "藏跡詎可索，食血以自安。", "人世猶俯仰，爾生何足觀。"]'),
('080aa99d-ad35-416c-bceb-17cc95fb6e6f','依韻和中道寶相花','梅堯臣','宋','宋诗','song-poetry','','[]','嘉卉得所託，植君之寢陽。',48,'全唐诗/poet.song.13000.json','["嘉卉得所託，植君之寢陽。", "開榮同此春，淡豔自生光。", "不爲露益色，不爲風盡香。", "節換葉已密，尚可見餘芳。"]'),
('9d059126-e0df-46cb-b1e5-a7c497765103','擬陶體三首 手問足','梅堯臣','宋','宋诗','song-poetry','','[]','共生一體中，出處常相并。',48,'全唐诗/poet.song.13000.json','["共生一體中，出處常相并。", "所動輒有跡，何不擇地行。", "履舄雖可蔽，步武豈無聲。", "嘗思汝爲玉，請刖見直誠。"]'),
('f9ad312f-dcef-452f-b3b6-be89413ef564','擬陶體三首 足答手','梅堯臣','宋','宋诗','song-poetry','','[]','上下各有分，同質實異支。',48,'全唐诗/poet.song.13000.json','["上下各有分，同質實異支。", "要用固爾先，當念扶我危。", "我刖爾獨安，何以幸華夷。", "且願縮袖間，操執自有時。"]'),
('855d2db8-4d7a-432b-b972-6cd9d460911d','擬陶體三首 目釋','梅堯臣','宋','宋诗','song-poetry','','[]','我居元首間，分並日月光。',60,'全唐诗/poet.song.13000.json','["我居元首間，分並日月光。", "左右各照曜，盲一豈相妨。", "尚恐有所翳，獨見不能强。", "嗟爾手與足，何爲欲競傷。", "捉馳自有職，勿使心悲凉。"]'),
('afc28a94-0f22-4d75-84c3-2544827f4cf2','贈葉山人','梅堯臣','宋','宋诗','song-poetry','','[]','傾珍奉賓客，傲物去珥貂。',48,'全唐诗/poet.song.13000.json','["傾珍奉賓客，傲物去珥貂。", "貴來不以屈，飲酒且逍遥。", "黄金百鎰盡，左右無纖腰。", "但存丹砂術，有道在一瓢。"]'),
('5c5bf395-2267-478a-a977-60618be70014','李廷臣通判蔡州','梅堯臣','宋','宋诗','song-poetry','','[]','夾路青青草，隨君去未休。',48,'全唐诗/poet.song.13000.json','["夾路青青草，隨君去未休。", "亦將離思遠，還共翠心抽。", "細藉車輪穩，薰牽野蔓柔。", "王孫歸不久，冉冉莫經秋。"]'),
('66987b30-4bac-4be2-a99a-f17285635cba','朱櫻','梅堯臣','宋','宋诗','song-poetry','','[]','明珠摘木末，紅露貯金盤。',48,'全唐诗/poet.song.13000.json','["明珠摘木末，紅露貯金盤。", "始見侍臣賜，已爲黄雀殘。", "味兼羊酪美，食厭楚梅酸。", "苑囿東周盛，纍纍映葉丹。"]'),
('93b2d5ad-798c-47e9-8c9e-826b7c4afb81','悼子','梅堯臣','宋','宋诗','song-poetry','','[]','舟行次符離，我子死阿十。',108,'全唐诗/poet.song.13000.json','["舟行次符離，我子死阿十。", "臨之但驚迷，至傷反無泣。", "款定始懷念，內若湯火集。", "前時喪爾母，追恨尚無及。", "邇來朝哭妻，淚落襟袖濕。", "又復夜哭子，痛併肝腸入。", "吾將仰問天，此理豈所執。", "我惟兩男子，奪一何太急。", "春鳥獨蔓延，哺巢首戢戢。"]'),
('adb85541-b764-4056-906b-2cdeaf2f923b','懷悲','梅堯臣','宋','宋诗','song-poetry','','[]','自爾歸我家，未嘗厭貧窶。',84,'全唐诗/poet.song.13000.json','["自爾歸我家，未嘗厭貧窶。", "夜縫每至子，朝飯輒過午。", "十日九食齏，一日儻有脯。", "東西十八年，相與同甘苦。", "本期百歲恩，豈料一夕去。", "尚念臨終時，拊我不能語。", "此身今雖存，竟當共爲土。"]'),
('a430bc61-7cb7-42df-8931-c0756d798590','和中道雨樹','梅堯臣','宋','宋诗','song-poetry','','[]','一旬苟不雨，萬木昏蒼蒼。',48,'全唐诗/poet.song.13000.json','["一旬苟不雨，萬木昏蒼蒼。", "朝見洗林葉，動摇生輝光。", "晚逢開疏陰，枝上漏微陽。", "翠色固以好，安得無秋霜。"]'),
('a8021344-82a2-463f-a640-b0f3aa7c8513','永叔寄詩八首并祭子漸文一首因采八詩之意警以爲答','梅堯臣','宋','宋诗','song-poetry','','[]','昔聞退之與東野，相與結交賤微時。',224,'全唐诗/poet.song.13000.json','["昔聞退之與東野，相與結交賤微時。", "孟不改貧韓漸貴，二人情契都不移。", "韓無驕矜孟無靦，直以道義爲己知。", "我今與子亦似此，子亦不愧前人爲。", "北都健兒昨日至，扣門乃是所遺詩。", "上言病中初有寄，下言我詠蟠桃枝。", "盛衰開落感殘杏，暮春無事羨游絲。", "班班鳩鳴忽懷念，一掃十幅無閒辭。", "洛川花圖多品目，鬭新爭巧始可疑。", "讀書又憶石夫子，似蠶作繭誠有之。", "鎮陽歸夢北潭北，吟此八章誰謂癡。", "最後有文弔尹子，壽夭難問信所悲。", "共書大軸許傳玩，一日百展曾忘疲。", "報君亦欲齎滿軸，恐費紙墨令人嗤。"]'),
('d9530123-4b94-488c-9164-16fe921b7550','黄敏復尉新城','梅堯臣','宋','宋诗','song-poetry','','[]','新城接桐廬，山茗久所利。',48,'全唐诗/poet.song.13000.json','["新城接桐廬，山茗久所利。", "江東亡命兒，販不畏黥劓。", "堂上千金子，捕以操兇器。", "恐非吾徒爲，勇少乃可避。"]'),
('4e114dfa-7f7b-4e59-9c46-cbec9c86a4a7','寄永叔','梅堯臣','宋','宋诗','song-poetry','','[]','夏日永以靜，渴鳥方在枝。',72,'全唐诗/poet.song.13000.json','["夏日永以靜，渴鳥方在枝。", "張口不能言，翕翕兩翅披。", "庭中有井泉，井深無綆縻。", "欲汲假其鄰，鄰且非我知。", "鴻鷗矯河上，比爾得所宜。", "得宜豈不樂，胡然我念之。"]'),
('16f5129f-1258-4311-bc86-a47a88569c16','丞相二章  其一','梅堯臣','宋','宋诗','song-poetry','','[]','丞相之拜，冠弁旅至。',40,'全唐诗/poet.song.13000.json','["丞相之拜，冠弁旅至。", "乘馬載驅，如彼鉅潴。", "有鴈有鶩，有龜有魚。", "烝然來萃，翔泳嘯呼。"]'),
('77cb14e2-fcce-41f1-a799-a2a0f8c98f00','丞相二章  其二','梅堯臣','宋','宋诗','song-poetry','','[]','丞相之去，乃還印綬。',40,'全唐诗/poet.song.13000.json','["丞相之去，乃還印綬。", "乃飭車輪，如彼涸津。", "時靡翔羽，時靡游鱗。", "寂兮寂兮，豈有嘉賓。"]'),
('92a889b8-ec38-453d-bbb6-8c3a6827d1b7','閔讒狡  其一','梅堯臣','宋','宋诗','song-poetry','','[]','矯有讒狡，讒以戕類。',43,'全唐诗/poet.song.13000.json','["矯有讒狡，讒以戕類。", "狡以媚其貴，謂不騫不墜。", "謂人莫爾制，而死制之。", "誰謂無鬼，孰制之死。"]'),
('c3965cf4-576d-412d-9b72-350363e40f63','閔讒狡  其二','梅堯臣','宋','宋诗','song-poetry','','[]','彼狡之將死，若有以見。',43,'全唐诗/poet.song.13000.json','["彼狡之將死，若有以見。", "既見既惡之，引袂蒙面。", "謂人莫爾辨，而自辨之。", "誰謂無鬼，孰俾之譴。"]'),
('e766e32a-650e-47c3-b8ba-e1504a4a22a9','薛八殿丞有遺','梅堯臣','宋','宋诗','song-poetry','','[]','未嘗營貨貝，貨貝寧爲來。',48,'全唐诗/poet.song.13000.json','["未嘗營貨貝，貨貝寧爲來。", "俸苦月不足，貧死口肯開。", "好事忽我恤，十千助晨杯。", "薪水已過豐，不得如顔回。"]'),
('c02a791d-4478-4214-8ee1-4f5b6e1f4924','師厚與胥氏婦來奠其姑','梅堯臣','宋','宋诗','song-poetry','','[]','雙裾來此室，慟器拜靈牀。',48,'全唐诗/poet.song.13000.json','["雙裾來此室，慟器拜靈牀。", "魂衣想髣髴，薄酒湛其觴。", "含悽撫孤稚，拭淚問平常。", "我生都無如，仰看燕在梁。"]'),
('494ce9ce-3d74-4cb6-8913-04a2438bac9c','諭烏','梅堯臣','宋','宋诗','song-poetry','','[]','百鳥共戴鳳，惟欲鳳德昌。',240,'全唐诗/poet.song.13000.json','["百鳥共戴鳳，惟欲鳳德昌。", "願鳳得其輔，咨爾孰可當。", "百鳥告爾間，惟烏最靈長。", "乃呼鳥與鵲，將政庶鳥康。", "烏時來佐鳳，署置且非良。", "咸用所附己，欲同助翱翔。", "以燕代鴻鴈，傳書識暄凉。", "鸜鴿代鸚鵡，剝舌說語詳。", "禿鶬代老鶴，乘軒事昂藏。", "野鶉代雄雞，爪觜稱擅場。", "雀豹代雕鶚，搏擊肅秋霜。", "蝙蝠嘗入幙，捕蚊夜何忙。", "老鴟啄臭腐，盤飛使游揚。", "鵂鶹與梟鵩，待以爲非常。", "一朝百鳥厭，讒烏出遠方。", "烏伎亦止此，不敢戀鳳傍。", "養子頗似父，又貪噪豺狼。", "爲鳥鳥不伏，獸肯爲爾戕。", "莫如且斂翮，休用苦不量。", "吉凶豈自了，人事亦交相。"]'),
('ed87d5ee-9d04-4f8f-84d8-44be9637811d','弔裴易進士','梅堯臣','宋','宋诗','song-poetry','','[]','力學未及仕，口中已含珠。',48,'全唐诗/poet.song.13000.json','["力學未及仕，口中已含珠。", "賦命固所負，讀書非所辜。", "斂送有兄弟，哭泣無妻孥。", "惟此靡薄厚，必竟同一途。"]'),
('80eefe87-7f7c-40e4-8cd0-fc740122dc86','閒詠寄呈次道','梅堯臣','宋','宋诗','song-poetry','','[]','我閒日貧縛，子閒數疾纏。',48,'全唐诗/poet.song.13000.json','["我閒日貧縛，子閒數疾纏。", "閒固不可常，吾觀與子然。", "吾與子嗜學，豈獨閒窮年。", "安安者誰歟，分亦似所偏。"]'),
('45b92426-288f-4da5-9296-604e4a2b8f45','寄楚州呂濟叔','梅堯臣','宋','宋诗','song-poetry','','[]','亭午鳥不下，誰復過我廬。',84,'全唐诗/poet.song.13000.json','["亭午鳥不下，誰復過我廬。", "忽聞扣門者，偶出問何如。", "云是山陽吏，太守遣置書。", "自惟久窮困，游子安念予。", "淮陰况要津，賓館無暫虛。", "豈意有所逮，委曲情未疎。", "報言愧不靦，聊以謝興居。"]'),
('ffb75867-43e2-4fc7-8557-eb6e72ebb5e3','答中道小疾見寄','梅堯臣','宋','宋诗','song-poetry','','[]','嵇康性彌嬾，曾不廢養生。',120,'全唐诗/poet.song.13000.json','["嵇康性彌嬾，曾不廢養生。", "子姑當妙年，何乃勞其精。", "老聃有至論，身孰親於名。", "詩本道情性，不須大厥聲。", "方聞理平淡，昏曉在淵明。", "寢欲來於夢，食欲來於羹。", "淵明儻有靈，爲子氣不平。", "其人實傲佚，不喜子纏縈。", "吾今敢告子，幸願少適情。", "時能與子飲，莫惜倒缾罌。"]'),
('be1be815-247d-4a23-a169-38f973054015','五月五日','梅堯臣','宋','宋诗','song-poetry','','[]','屈氏已沉死，楚人哀不容。',48,'全唐诗/poet.song.13000.json','["屈氏已沉死，楚人哀不容。", "何嘗奈讒謗，徒欲却蛟龍。", "未泯生前恨，而追沒後蹤。", "沅湘碧潭水，應自照千峯。"]'),
('ab230ac2-3684-46a0-a2c1-87d5dee5b712','送可教僧歸越','梅堯臣','宋','宋诗','song-poetry','','[]','萬事厭尋常，羨慕每不足。',48,'全唐诗/poet.song.13000.json','["萬事厭尋常，羨慕每不足。", "居南多北思，在遠慙近俗。", "既來橘變枳，但見空條綠。", "氣味誰復論，孤根逗巖曲。"]'),
('a55b3023-9205-4e7d-9c93-0ca06e6e8328','和裴如晦雨中過其亡兄易居','梅堯臣','宋','宋诗','song-poetry','','[]','人亡雨館寂，車馬偶來臨。',48,'全唐诗/poet.song.13000.json','["人亡雨館寂，車馬偶來臨。", "濕衣添新淚，故物傷夙心。", "淒淒庭下樹，萬葉起哀音。", "此地嘗對語，在昔豈知今。"]'),
('a1380e0e-5e5a-4fda-8cb6-08c29226e3b0','雨中宿謝胥裴三君書堂','梅堯臣','宋','宋诗','song-poetry','','[]','急雨射窗鳴，燈殘我正寢。',48,'全唐诗/poet.song.13000.json','["急雨射窗鳴，燈殘我正寢。", "穴蚓聲苦長，流響入孤枕。", "衆醉如不聞，强聒亦已甚。", "夜短竟無寢，困瞳劇塵磣。"]'),
('11844f9b-1844-48fc-b5de-058ec9cd1be9','和中道雨中見寄','梅堯臣','宋','宋诗','song-poetry','','[]','雨淫上復落，雲暗不少開。',72,'全唐诗/poet.song.13000.json','["雨淫上復落，雲暗不少開。", "泥將沒馬脛，思子日幾迴。", "我既不可往，子亦不可來。", "屋漏又苦甚，巾舄生莓苔。", "安肯問農畝，唯憂無酒材。", "但能置醇酎，莫負吾樽罍。"]'),
('7d1fd8ce-2a2a-4bdf-8209-b175702996d9','送謝寺丞新賜及第赴扶溝宰','梅堯臣','宋','宋诗','song-poetry','','[]','世所重登科，如君特才選。',48,'全唐诗/poet.song.13000.json','["世所重登科，如君特才選。", "麗賦驚宗工，妙譽動京輦。", "行鷁路非遐，雙旗風欲展。", "聊閱民版餘，應不負墳典。"]'),
('d0ffbb69-be5b-42e3-8e8e-a9a9435a2e39','和李廷老三月十四日','梅堯臣','宋','宋诗','song-poetry','','[]','三月日幾望，士游溱水陽。',84,'全唐诗/poet.song.13000.json','["三月日幾望，士游溱水陽。", "溱流已渙渙，有美此鷱翔。", "偶來適此願，月色同滿牀。", "士曰陟少室，女曰歸大梁。", "及晨各異役，悲喜竟回腸。", "芍藥有遺風，贈好期不忘。", "固匪子能逮，是焉繼新章。"]'),
('89642258-7ee6-4726-aee7-d25704ffc6f1','苦熱','梅堯臣','宋','宋诗','song-poetry','','[]','赤日若射火，林風不動梢。',60,'全唐诗/poet.song.13000.json','["赤日若射火，林風不動梢。", "羸汗尚流沛，冠服豈堪包。", "貴人諒有稟，慣習非强教。", "竊觀行車馬，坌蕩劇煨炮。", "寧思山中人，石泉浸兩骹。"]'),
('6b670fc0-1fc1-4732-9731-066ebd5913b9','劉薛二君過予遇雨','梅堯臣','宋','宋诗','song-poetry','','[]','猛雨迫好鳥，止我屋室隅。',72,'全唐诗/poet.song.13000.json','["猛雨迫好鳥，止我屋室隅。", "是時有劉薛，亦既此焉俱。", "我厩秣爾馬，我厨飯爾奴。", "二人乃可語，因觀爾馬圖。", "古筆得神妙，俗工非所模。", "收圖雨且止，鳥飛當駕驅。"]'),
('ffcd9c32-2b7d-4d89-8ed3-0af6269238a6','答廷評宗說遺冰','梅堯臣','宋','宋诗','song-poetry','','[]','仲夏遘餘閏，屋室如炊蒸。',60,'全唐诗/poet.song.13000.json','["仲夏遘餘閏，屋室如炊蒸。", "孰云窮處者，言贈太官冰。", "時靡有暍死，實亦頼友朋。", "定能凉一席，既已却青蠅。", "吾心久自信，飲已不以矜。"]'),
('892a0a93-299c-4775-9a25-e20039d19ff3','劉牧殿丞通判建州','梅堯臣','宋','宋诗','song-poetry','','[]','平生交游少，海內寡與期。',84,'全唐诗/poet.song.13000.json','["平生交游少，海內寡與期。", "識君且恨晚，一見已將離。", "人言何嗟別，曾此非舊知。", "借曰匪我舊，亦既接音詞。", "譬彼空林鳥，止息偶同枝。", "忽有振翮去，尚爾鳴聲悲。", "我今臨流送，安顧俗所爲。"]'),
('af5aa932-46ea-49cd-bacf-e05a8dd8560a','和中道伏日次韻','梅堯臣','宋','宋诗','song-poetry','','[]','伏日每苦熱，古來亡事侵。',48,'全唐诗/poet.song.13000.json','["伏日每苦熱，古來亡事侵。", "嘗聞東方朔，割肉趨庭陰。", "百職當早罷，將畏赫日臨。", "我無歸遺人，懷念空霑襟。"]'),
('247c6bc1-6ced-4308-8a77-037db0a92cbe','和蔡仲謀苦熱','梅堯臣','宋','宋诗','song-poetry','','[]','大熱曝萬物，萬物不可逃。',96,'全唐诗/poet.song.13000.json','["大熱曝萬物，萬物不可逃。", "燥者欲出火，液者欲流膏。", "飛鳥厭其羽，走獸厭其毛。", "人亦畏絺綌，况乃服冠袍。", "廣厦雖云託，呼風不動毫。", "未知林泉間，何以異我曹。", "蠅蚊更晝夜，膚體困爬搔。", "四序苟迭代，會有秋氣高。"]'),
('5ba7ff7b-3987-4e82-b016-e44ae2dd991b','儼上人粹隠堂','梅堯臣','宋','宋诗','song-poetry','','[]','十年不出戶，世事皆剗鋤。',108,'全唐诗/poet.song.13000.json','["十年不出戶，世事皆剗鋤。", "時無車馬游，焚香坐讀書。", "有堂曰粹隠，惟見安且舒。", "心遠迹非遠，歲月速輪輿。", "寓目暫爲實，過者即爲虛。", "譬若開是室，終日於此居。", "欲問昨日事，已覺今日疎。", "明朝却視今，復與前何如。", "聊悟此中樂，猶觀濠上魚。"]'),
('4bf517ff-a69b-42f0-8f5d-35f01f43be8b','送鄭太保瀛州都監','梅堯臣','宋','宋诗','song-poetry','','[]','秋氣入關河，匈奴久已和。',48,'全唐诗/poet.song.13000.json','["秋氣入關河，匈奴久已和。", "琱弓聊可試，寶劍不須磨。", "草木將摇落，牛羊自寢訛。", "能知塞垣景，持以贈吾歌。"]'),
('e1af77d4-af14-4a13-8636-4226a3f16849','送刁安豐','梅堯臣','宋','宋诗','song-poetry','','[]','嘗游芍陂上，頗見楚人爲。',48,'全唐诗/poet.song.13000.json','["嘗游芍陂上，頗見楚人爲。", "水有鳥魚美，土多薑芋宜。", "寧無董生孝，將奉叔敖祠。", "舊令乃吾友，寄聲於此時。"]'),
('8da087eb-0edd-419f-9a18-1c628475131b','劉八飲將散分得非休沐不得會','梅堯臣','宋','宋诗','song-poetry','','[]','君非休沐時，茲會豈能得。',36,'全唐诗/poet.song.13000.json','["君非休沐時，茲會豈能得。", "我無官局縈，幸爾預歡適。", "莫辭衝雨歸，歸時烏帽側。"]'),
('adb8bbef-16f5-46c6-9051-21d41fd67509','贈張處士','梅堯臣','宋','宋诗','song-poetry','','[]','聞爾閒於琴，寢處未嘗輟。',48,'全唐诗/poet.song.13000.json','["聞爾閒於琴，寢處未嘗輟。", "抱之京師來，豈與工師列。", "一奏流水聲，落指鳴决决。", "既曰林壑人，安事塵土轍。"]'),
('961e7776-5030-4c83-bcd4-b163fa6a5757','將行與蔡仲謀飲分席上果得桃','梅堯臣','宋','宋诗','song-poetry','','[]','曾無千歲人，安見千歲實。',24,'全唐诗/poet.song.13000.json','["曾無千歲人，安見千歲實。", "聊效昔所投，瓊瑶報非一。"]'),
('00669cfd-5b1f-4ddc-8149-bcc6f771d19a','答裴送序意','梅堯臣','宋','宋诗','song-poetry','','[]','我欲之許子有贈，爲我爲學勿所偏。',176,'全唐诗/poet.song.13000.json','["我欲之許子有贈，爲我爲學勿所偏。", "誠知子心苦愛我，欲我文字無不全。", "居常見我足吟詠，乃以述作爲不然。", "始曰子知今則否，固亦未能無諭焉。", "我於詩言豈徒爾，因事激風成小篇。", "辭雖淺陋頗剋苦，未到二雅未忍捐。", "安取唐季二三子，區區物象磨窮年。", "苦苦著書豈無意，貧希祿廩塵俗牽。", "書辭辯說多碌碌，吾敢虛語同後先。", "唯當稍稍緝銘誌，願以直法書諸賢。", "恐子未諭我此意，把筆慨歎臨長川。"]'),
('7feeed27-1cae-40c9-a1b2-e76481c8f5ad','和張士曹應之晚景','梅堯臣','宋','宋诗','song-poetry','','[]','遠空雲解駁，南陌雨初收。',48,'全唐诗/poet.song.13000.json','["遠空雲解駁，南陌雨初收。", "獨鳥去煙外，斜陽明樹頭。", "凉飇虛枕席，漲澇起汀洲。", "會有從軍役，將離更暮愁。"]'),
('b5d57ea6-be0f-421a-af56-0da08286045e','送楊浩秘丞入蜀','梅堯臣','宋','宋诗','song-poetry','','[]','有才不得試，志亦無所干。',60,'全唐诗/poet.song.13000.json','["有才不得試，志亦無所干。", "有母不得養，法當之遠官。", "雖曰在民政，孝心寧得安。", "志願且未遂，而趨蜀道難。", "行思叱馭者，勿復苦長歎。"]'),
('33208406-575c-4cef-9ea7-d26096c1e608','乙酉六月二十一日予應辟許昌京師內外之親則有刁氏昆弟蔡氏子予之二季友人則胥平叔宋中道裴如晦各携肴酒送我于王氏之園盡懽而去明日予作詩以寄焉','梅堯臣','宋','宋诗','song-poetry','','[]','性僻交游寡，所從天下才。',132,'全唐诗/poet.song.13000.json','["性僻交游寡，所從天下才。", "今朝誰出祖，親戚持樽罍。", "晚節相知人，唯有胥宋裴。", "所欠謝夫子，歸穰尚未迴。", "岸傍逢名園，繫舟共徘徊。", "嘉蓮如笑迎，照水呈丹顋。", "南庭莆萄架，萬乳纍將磓。", "羣卉競瑣細，紫紅相低偎。", "尋常固邂逅，孰辨落與開。", "酒闌各分散，白日將西頹。", "城隅遂有隔，北道望吹臺。"]'),
('b646f01a-67b1-40ec-a659-54d06a7014a8','開封古城阻淺聞永叔喪女','梅堯臣','宋','宋诗','song-poetry','','[]','去年我喪子與妻，君聞我悲嘗俛眉。',128,'全唐诗/poet.song.13000.json','["去年我喪子與妻，君聞我悲嘗俛眉。", "今年我聞君喪女，野岸孤坐還增思。", "思君平昔憐此女，戲弄膝下無不宜。", "昨來稍長應慧黠，想能學母粉黛施。", "幾多恩愛付涕淚，灑作秋雨隨風吹。", "風吹北來霑我袂，哀樂相恤唯己知。", "自古壽夭不可詰，天高杳杳誰主之。", "以道爲任自可遣，目前况有寧馨兒。"]'),
('777b5bc7-a564-4848-850a-c6e4d9b2be25','寄謝開封宰薛贊善','梅堯臣','宋','宋诗','song-poetry','','[]','予生多不偶，事事相與背。',204,'全唐诗/poet.song.13000.json','["予生多不偶，事事相與背。", "適從平川役，乃遇河决潰。", "舟膠在中野，寸步使心痗。", "誰知赤縣尹，勤恤每外內。", "文符飭亭長，寇盜虞鼠輩。", "仍能饋餠餌，童稚仰所賫。", "今又置酒壺，惠問亦已再。", "令我清夜飲，是夕值月晦。", "獨酌效謫僊，而復無影對。", "如何亡情游，似亦有世態。", "家人誠可同，况我昨喪配。", "雖曰預朝裾，左右無粉黛。", "兀然唯書史，舊學厭瑣碎。", "欲探文字工，下筆語多礙。", "却思君西齋，新治虛可愛。", "燕坐禽鳥寂，吟哦簿書退。", "此樂吾未如，區區勞覆載。"]'),
('91d9d246-7f0e-4999-b2f7-44cd21e332f3','草木','梅堯臣','宋','宋诗','song-poetry','','[]','草木無處所，動摇知風形。',48,'全唐诗/poet.song.13000.json','["草木無處所，動摇知風形。", "今日萬葉黄，昨日萬葉青。", "青既漸衰變，黄亦漸凋零。", "人生恃歲月，種柏滿郊坰。"]'),
('1fd18d58-7f4b-4cc5-96e5-b1b8563fa627','夢登河漢','梅堯臣','宋','宋诗','song-poetry','','[]','夜夢上河漢，星辰布其傍。',264,'全唐诗/poet.song.13000.json','["夜夢上河漢，星辰布其傍。", "位次稍能辯，羅列爭光芒。", "自箕歷牛女，與斗直相當。", "既悟到上天，百事應可詳。", "其中有神官，張目如電光。", "玄衣乘蒼虬，身佩水玉璫。", "丘蛇與穹鼈，盤結爲紀綱。", "我心恐且怪，再拜忽禍殃。", "臣實居下土，不意涉此方。", "既得接威靈，敢問固不量。", "有牛豈不力，何憚使服箱。", "有女豈不工，何憚縫衣裳。", "有斗豈不柄，何憚挹酒漿。", "卷舌不得言，安用施穹蒼。", "何彼東方箕，有惡務簸揚。", "唯識此五者，願言無我忘。", "神官呼我前，告我無不臧。", "上天非汝知，何苦詰其常。", "豈惜盡告汝，於汝恐不祥。", "至如人間疑，汝敢問於王。", "扣頭謝神官，臣言大爲狂。", "駭汗忽爾覺，殘燈熒空堂。"]'),
('c46d3f5b-f6b2-46bf-a0c9-03d763c55ab5','寄宋次道中道','梅堯臣','宋','宋诗','song-poetry','','[]','再來魏闕下，舊友無一人。',204,'全唐诗/poet.song.13000.json','["再來魏闕下，舊友無一人。", "或爲美官去，或爲泉下塵。", "晚節相知者，操節許松筠。", "日世常山公，伯仲文學均。", "與我數還往，以義爲比鄰。", "屢假篋中書，校證多護真。", "次述盈百卷，補亡如繼秦。", "中作淵明詩，平淡可擬倫。", "於時多驕佚，黄卷罕所親。", "昨以興西師，往往劍射伸。", "短衣誇走馬，睅目語常瞋。", "欲效西山勇，遂笑東魯仁。", "捨本趨富貴，乃與市賈濱。", "以此較於子，素業固未泯。", "前日之許昌，別君已經旬。", "偶然值河决，窮坐如涸鱗。", "臨風思有寄，夜詠還達晨。"]'),
('3a8bf461-0def-4ca6-b206-6d32d95fe52a','日蝕','梅堯臣','宋','宋诗','song-poetry','','[]','赫赫初出咸池中，浴光洗跡生天東。',296,'全唐诗/poet.song.13000.json','["赫赫初出咸池中，浴光洗跡生天東。", "不覺有物來晦昧，團團一片如頑銅。", "前時蝦蟆食爾妃，天下戢戢無有忠。", "責駡四方誰膽大，仰頭憤憤唯盧仝。", "欲持寸刃去其害，氣力雖有天難通。", "是時了無毫芒益，徒有文字辯且雄。", "仝死於今百餘載，日月幾度遭遮蒙。", "有人見之如不見，誰肯開口咨天公。", "老鴉居處已自穩，三足鼎峙何乖慵。", "而今有觜不能噪，而今有爪不能攻。", "任看怪物瞖天眼，方且省事保爾躬。", "日月與物固無惡，應由此鳥招禍凶。", "吾意髣髴料此鳥，定亦閃避離日宮。", "安逢后羿不乖暴，直與審慤彎强弓。", "射此賈怨鳥，以謝毒惡蟲。", "二曜各安次，災害無由逢。", "南不尤赤鳥，東不誚蒼龍。", "北龜勿吐氣，西虎勿嘯風。", "五行不汩陳，虞舜生重瞳。", "我今作此詩，可與仝比功。"]'),
('d21bb2c6-8689-41c9-8ec1-59785bc4700e','寄王江州','梅堯臣','宋','宋诗','song-poetry','','[]','休嗟謫官去，山根勝窮邊。',48,'全唐诗/poet.song.13000.json','["休嗟謫官去，山根勝窮邊。", "當職言無隠，他時事好還。", "何嘗聞堠火，唯是對爐煙。", "潮到盆城否，猶期信可傳。"]'),
('729a7506-f74d-45b5-99b5-ee4a065a2dd5','薛九公期請賦山水字詩','梅堯臣','宋','宋诗','song-poetry','','[]','薛君堂懸山水字，請我試作山水詩。',192,'全唐诗/poet.song.13000.json','["薛君堂懸山水字，請我試作山水詩。", "呼童磨墨慰君意，强作安得有好辭。", "昔年曾是杜陵客，東城水上橫此碑。", "字方數尺形勢健，豈似取次筆畫爲。", "東城父老語於我，推本剏自開元時。", "不知當時何所用，費功鑱刻爲瓌奇。", "我去長安十載後，此石誰輦來京師。", "苑中構殿激流水，暮春修禊浮酒巵。", "是時祠臣出不意，酒半使賦或氣萎。", "日斜鳴蹕不可駐，未就引去如鞭笞。", "脫我幸得預此列，玉階立寫從然萁。", "今雖下筆不稱意，已書滿幅令君嗤。"]'),
('068b184c-05a5-40ca-bae3-35f94434c19e','七夕有感','梅堯臣','宋','宋诗','song-poetry','','[]','去年此夕肝腸絕，歲月淒涼百事非。',32,'全唐诗/poet.song.13000.json','["去年此夕肝腸絕，歲月淒涼百事非。", "一逝九泉無處問，又看牛女渡河歸。"]'),
('87de69bd-1379-43c0-9f3a-beba76e35903','過開封古城','梅堯臣','宋','宋诗','song-poetry','','[]','荒城臨殘日，雞犬三四家。',48,'全唐诗/poet.song.13000.json','["荒城臨殘日，雞犬三四家。", "豈復古阡陌，但問新桑麻。", "頹垣下多穴，所窟狐與蛇。", "漢兵墮銅鏃，青血爲土花。"]'),
('16b6c714-6b03-4f4b-b760-c24b26b00e17','通判桃花廳','梅堯臣','宋','宋诗','song-poetry','','[]','種桃西庭下，有意延東風。',72,'全唐诗/poet.song.13000.json','["種桃西庭下，有意延東風。", "東風與雨至，染出枝上紅。", "花底有小鳥，其字曰桃蟲。", "既於桃得名，爲桃言女工。", "翦羅作舞衣，奉君歡莫窮。", "舉杯無愧者，避世武陵翁。"]'),
('b6179bf3-1cff-4447-be67-b1ade4f57eef','任廷平歸京','梅堯臣','宋','宋诗','song-poetry','','[]','言之少室西，定陟轘轅險。',48,'全唐诗/poet.song.13000.json','["言之少室西，定陟轘轅險。", "歸心不避危，夕枕屢成魘。", "秋聲故苑空，野氣荒陵掩。", "獨念京洛塵，曾將客衣染。"]'),
('88eee5cf-6867-4820-80c0-11c919715b74','和通判太博雞冠花十韻','梅堯臣','宋','宋诗','song-poetry','','[]','神農記百卉，五色異甘酸。',120,'全唐诗/poet.song.13000.json','["神農記百卉，五色異甘酸。", "乃有秋花實，全如雞幘丹。", "籠煙何聳聳，泫露更團團。", "取譬可無意，得名殊足觀。", "逼真歸造化，任巧即彫剜。", "赤玉書留魏，丹砂句誦韓。", "誠能因物比，誰謂一時難。", "有客驅辭穎，臨風運筆端。", "嘗嗟古吟缺，每惜此芳殘。", "揣情苦精妙，繼音慙未安。"]'),
('fa33c62e-7278-4ac9-abb9-08e18bdcb13b','秋夜感懷','梅堯臣','宋','宋诗','song-poetry','','[]','風葉相追逐，庭響如人行。',60,'全唐诗/poet.song.13000.json','["風葉相追逐，庭響如人行。", "獨宿不成寐，起坐心屏營。", "哀哉齊體人，魂氣今何征。", "曾不若隕籜，繞樹猶有聲。", "涕淚不能止，月落雞號鳴。"]'),
('4f3b7515-64aa-4b81-8fe0-9ff2a1483d61','依韻和通判八月十五夜招翫月二章  其一','梅堯臣','宋','宋诗','song-poetry','','[]','尋常圓魄豈不好，競愛今宵分外明。',32,'全唐诗/poet.song.13000.json','["尋常圓魄豈不好，競愛今宵分外明。", "明極只知無隔礙，誰言桂樹向中生。"]'),
('a5e85135-4598-460c-ad2d-00272ba5d75a','依韻和通判八月十五夜招翫月二章  其二','梅堯臣','宋','宋诗','song-poetry','','[]','一年一見最堪惜，百歲百夕能幾多。',32,'全唐诗/poet.song.13000.json','["一年一見最堪惜，百歲百夕能幾多。", "縱有明年似今夕，明年同會復如何。"]'),
('151d4637-eae6-4493-a616-60a057790620','蚯蚓','梅堯臣','宋','宋诗','song-poetry','','[]','蚯蚓在泥穴，出縮常似盈。',72,'全唐诗/poet.song.13000.json','["蚯蚓在泥穴，出縮常似盈。", "龍蟠亦以蟠，龍鳴亦以鳴。", "自謂與龍比，恨不頭角生。", "螻蟈似相助，草根無停聲。", "聒亂我不寐，每夕但欲明。", "天地且容畜，憎惡唯人情。"]'),
('f38b98f3-b11b-4cee-afdb-1b469f8d315d','秋風','梅堯臣','宋','宋诗','song-poetry','','[]','秋風不饒物，斗至聲已惡。',48,'全唐诗/poet.song.13000.json','["秋風不饒物，斗至聲已惡。", "青林葉尚繁，雖好將恐落。", "人意誠愛惜，節候肯相若。", "白髮無再玄，盛衰茲可度。"]'),
('3e161a71-0cad-4958-b977-8e10b564d514','韓宗彥寺丞通判鄧州','梅堯臣','宋','宋诗','song-poetry','','[]','往歲陪祠泰壇下，始一相見如相知。',192,'全唐诗/poet.song.13000.json','["往歲陪祠泰壇下，始一相見如相知。", "我今入幙君有待，喜得款語勝前時。", "便嗟陳事日侵汨，雖欲數面曾無期。", "忽聞兵吏已迎候，馬有行色車將脂。", "賀君有意事清簡，太守亦鄙尋常爲。", "騏驥步驟豈局促，鳳皇羽翼多威儀。", "漢家近親不復有，召父舊聞於今隳。", "隳由狂者生利害，曾未略究民間宜。", "祇言引水幸圭賦，矯請罷毀功何施。", "千載厚惠一日去，至今農畝空嗟咨。", "夫子才高識且遠，勿畏勢力重扶持。", "他年人作去思頌，願以大字書長碑。"]'),
('b8d5f1c6-2173-4eea-bd5d-920cc44525cf','韓欽聖問西洛牡丹之盛','梅堯臣','宋','宋诗','song-poetry','','[]','韓君問我洛陽花，爭新較舊無窮已。',208,'全唐诗/poet.song.13000.json','["韓君問我洛陽花，爭新較舊無窮已。", "今年誇好方絕倫，明年更好還相比。", "君疑造化特著意，果乃區區可羞恥。", "嘗聞都邑有勝意，既不鍾人必鍾此。", "由是其中立品名，紅紫葉繁矜色美。", "萌芽始見長蒿萊，氣焰旋看壓桃李。", "乃知得地偶增異，遂出羣葩號奇偉。", "亦如廣陵多芍藥，閭井荒殘無可齒。", "淮山邃秀付草樹，不産髦英産佳卉。", "人於天地亦一物，固與萬類同生死。", "天意無私任自然，損益推遷寧有彼。", "彼盛此衰皆一時，豈關覆燾爲偏委。", "呼兒持紙書此說，爲我緘之報韓子。"]'),
('7d0e768b-9595-4813-ad6a-a735624f8173','夢感','梅堯臣','宋','宋诗','song-poetry','','[]','生哀百十載，死苦千萬春。',60,'全唐诗/poet.song.13000.json','["生哀百十載，死苦千萬春。", "何爲千萬春，厚地不復晨。", "我非忘情者，夢故不夢新。", "宛若昔之日，言語尋常親。", "及寤動悲腸，痛逆如刮鱗。"]'),
('8309d77e-b4e1-4d49-8ecc-1365c2372d44','秋鴈','梅堯臣','宋','宋诗','song-poetry','','[]','秋鴈多夜飛，前羣後孤來。',48,'全唐诗/poet.song.13000.json','["秋鴈多夜飛，前羣後孤來。", "儔合鳴自得，隻去音已哀。", "哀音能感人，腸酸非食梅。", "共將形影對，安得不早衰。"]'),
('76e0e92c-8bff-4025-b769-c742acda70be','依韻和通判把菊有寄','梅堯臣','宋','宋诗','song-poetry','','[]','湖邊草樹多，蠹葉已少色。',84,'全唐诗/poet.song.13000.json','["湖邊草樹多，蠹葉已少色。", "唯菊不畏霜，淡豔如有德。", "自與蘭並生，非因人所植。", "愛貴曾未厭，秋日短苦逼。", "朋好各相望，採持空歎息。", "臨杯不能飲，對案不能食。", "借問君何憂，節物感人極。"]'),
('b2acee5e-28e7-4686-bd58-5f3373b6d4d8','曹承制知永康軍','梅堯臣','宋','宋诗','song-poetry','','[]','鐵驄黄金羈，年少蜀城守。',72,'全唐诗/poet.song.13000.json','["鐵驄黄金羈，年少蜀城守。", "蜀城臨古江，正在離岸口。", "離岸李凉鑿，其利實不久。", "既避沫水害，又以溉田畝。", "大此百民宜，遺祠奉牲酒。", "行當謹厥事，無乃爲政首。"]'),
('e0a5c7cc-d9fd-4c50-a929-eeccb05272dc','三鳥','梅堯臣','宋','宋诗','song-poetry','','[]','翩翩三奇鳥，各擇松桂宜。',72,'全唐诗/poet.song.13000.json','["翩翩三奇鳥，各擇松桂宜。", "二鳥同所向，並立高高枝。", "一鳥依別樹，屈比二鳥卑。", "嗟嗟天下鳥，莫與三鳥期。", "三鳥鳴少和，蒿間多鸒斯。", "頻頻徒爾黨，三鳥安可期。"]'),
('d04fbd28-7613-43c4-842a-3573c58b2ee1','龍箕一首','梅堯臣','宋','宋诗','song-poetry','','[]','龍箕在天，莫不孕靈，我公生之。',96,'全唐诗/poet.song.13000.json','["龍箕在天，莫不孕靈，我公生之。", "既生既德，曾誰與京。", "爰弼帝右，繼序其榮之。", "贊我太平，萬事其成之。", "殿我輔邦，庶民其寧之。", "政靡薄厚，百職其揚之。", "宜言顯光，永錫乎后王。", "迺祝眉壽，迺獻兕觥，福祿其將之。"]'),
('2eeba412-b7c4-4496-812f-574eec87c184','李廷老自蔡州見訪云明日便歸鄭','梅堯臣','宋','宋诗','song-poetry','','[]','故人夜相過，秉燭爲開席。',48,'全唐诗/poet.song.13000.json','["故人夜相過，秉燭爲開席。", "車馬立在門，罇酒豈暇索。", "亹亹別後言，怱怱恨將適。", "既去暝色合，不可見行跡。"]'),
('66f98382-1dea-4f26-bf10-1f4727f9d37b','墨竹','梅堯臣','宋','宋诗','song-poetry','','[]','許有盧娘能畫竹，重抹細拖神且速。',64,'全唐诗/poet.song.13000.json','["許有盧娘能畫竹，重抹細拖神且速。", "如將石上蕭蕭枝，生向筆間天意足。", "戰葉斜尖點映間，透勢虛黏斷還續。", "粉節中心豈可知，淡墨分明在君目。"]'),
('a16d2558-b861-4166-9f09-1a741b56df7a','江寧李諫議','梅堯臣','宋','宋诗','song-poetry','','[]','滄江石頭下，沄沄瀉天東。',60,'全唐诗/poet.song.13000.json','["滄江石頭下，沄沄瀉天東。", "寒潮日夕至，不與廢興同。", "陛下始封地，氣象常鬰葱。", "六代有舊跡，物景付與公。", "切莫負山水，可追王謝風。"]'),
('dfad4df7-725c-4ade-9547-8181ce0e1e48','方在許昌幕內弟滁州謝判官有書邀余詩送近聞歐陽永叔移守此郡爲我寄聲也','梅堯臣','宋','宋诗','song-poetry','','[]','從事滁陽去，寄音苦求詩。',132,'全唐诗/poet.song.13000.json','["從事滁陽去，寄音苦求詩。", "吾詩固少愛，唯爾太守知。", "不敢輒所拒，勉勉作此辭。", "山城本寂寞，物色同淮夷。", "淮俗舊輕僄，未識遠博宜。", "無將麟在郊，便欲等文貍。", "爾去事太守，當矯庸庸爲。", "伊人道義富，嘗立天子墀。", "我輩在蟻垤，難謂太華卑。", "又若游蹄涔，安見滄海涯。", "况於爾實親，告爾爾勿疑。"]'),
('e8766d51-bfdf-4f8d-a6f3-c7d191104555','送胥裴二子迴馬上作','梅堯臣','宋','宋诗','song-poetry','','[]','陰陰雪雲低，游子去將懶。',48,'全唐诗/poet.song.13000.json','["陰陰雪雲低，游子去將懶。", "豈惟游子倦，疲馬行亦款。", "送罷我獨還，迴看鴈爲伴。", "念此日暮時，寂寞閉竹館。"]'),
('834a53a9-fe43-4d6c-ba77-678a9fee23b2','初冬夜坐憶桐城山行','梅堯臣','宋','宋诗','song-poetry','','[]','我昔吏桐鄉，窮山使屢躡。',168,'全唐诗/poet.song.13000.json','["我昔吏桐鄉，窮山使屢躡。", "路險獨後來，心危常自怯。", "下顧雲容容，前溪未可涉。", "半崕風颯然，驚鳥爭墮葉。", "修蔓不知名，丹實坼在莢。", "林端野鼠飛，緣挽一何捷。", "馬行聞虎氣，豎耳鼻息嗋。", "遂投山家宿，駭汗衣尚浹。", "歸來撫童僕，前事語妻妾。", "吾妻常有言，艱勤壯時業。", "安慕終日間，笑媚看婦靨。", "自是甘努力，於今無所懾。", "老大官雖暇，失偶淚滿睫。", "書之空自知，城上鼓三疊。"]'),
('b0157472-5adb-4dcd-a0e1-401b2b989000','和平叔道傍竹','梅堯臣','宋','宋诗','song-poetry','','[]','野田有修竹，叢踈飽於霜。',60,'全唐诗/poet.song.13000.json','["野田有修竹，叢踈飽於霜。", "下上乏佳禽，左右雜枯桑。", "豈無行路子，行路厭榛荒。", "忽見此翠色，徘徊未能忘。", "車馬去何疾，迴顧隔山岡。"]'),
('839c55c6-d1f7-4b65-b073-1f7b6b9053a1','答裴如晦','梅堯臣','宋','宋诗','song-poetry','','[]','懷我歌我辭，乃知行子倦。',48,'全唐诗/poet.song.13000.json','["懷我歌我辭，乃知行子倦。", "音雖彼妙發，想若此可見。", "歌竟夜燈青，野窗鳴濕霰。", "髣髴聞孤鴻，飛急應有羨。"]'),
('cee176ba-8981-4583-b17e-cd6baa24468c','夜酌趙侯家聞合流曹光道詣府遂訪之一夕縱談明日光道赴本任邀余詩送因敘其言以贈焉','梅堯臣','宋','宋诗','song-poetry','','[]','方與舊將飲，談兵燈燭前。',120,'全唐诗/poet.song.13000.json','["方與舊將飲，談兵燈燭前。", "聞有故交至，心喜輒輪邊。", "跨馬踏明月，往見競留連。", "且共語出處，子懷予久然。", "男兒太平時，功業未可先。", "故當守詩書，道義躋古賢。", "苟復不得用，卷以放林泉。", "吾藴誠若此，奈何貧所纏。", "仕宦偶同郡，文字可以傳。", "行行志茲語，聊用樂永年。"]'),
('1804e983-368d-4d03-b406-8c8258d2abdd','暮雪','梅堯臣','宋','宋诗','song-poetry','','[]','暮雪止復落，暗積如避人。',72,'全唐诗/poet.song.13000.json','["暮雪止復落，暗積如避人。", "平明視庭中，物物各已新。", "草木一變妍，枯槁忘其真。", "隨風來無迹，高下得以均。", "采薇歌卒章，霏霏霑車輪。", "今豈無是作，勞苦不足陳。"]'),
('53b3cc46-fc28-42a0-a6bf-4d31163085b9','西湖對雪','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','獨玩湖中雪，移舟水凍灣。',48,'全唐诗/poet.song.13000.json','["獨玩湖中雪，移舟水凍灣。", "寒塘起孤鴈，危樹失前山。", "著物偏能積，衝風不礙還。", "無慙子猷興，都盡剡溪間。"]'),
('70c231e1-be26-4d49-9b2e-6d3abcd9ab8c','依韻和資政侍郎雪後書事','梅堯臣','宋','宋诗','song-poetry','','[]','風旗冷落偏欺酒，衆樹芳菲欲並梅。',32,'全唐诗/poet.song.13000.json','["風旗冷落偏欺酒，衆樹芳菲欲並梅。", "人意不知南畝望，只驚鴻鴈向川來。"]'),
('f75b9999-2dbf-4e75-9239-a9885a2c5a6c','王龍圖知江陵','梅堯臣','宋','宋诗','song-poetry','','[]','捧詔出荆州，天心寄遠憂。',96,'全唐诗/poet.song.13000.json','["捧詔出荆州，天心寄遠憂。", "行車踐殘雪，寒色犯輕裘。", "祖軷山川闊，歌驪道路愁。", "吏迎多越乘，兵衛粲吳鈎。", "地與蠻溪接，江通漢水流。", "風宜橘林賦，俗尚竹枝謳。", "樽俎思疇日，煙雲感舊遊。", "終當勞侍從，寧久渚宮留。"]'),
('7fb272ea-47ea-4392-95b2-ae2d54fe46a0','依韻和通判太博雪後招飲二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','雪晴何所樂，樂趣在杯中。',24,'全唐诗/poet.song.13000.json','["雪晴何所樂，樂趣在杯中。", "况復君家美，雕盤膾縷紅。"]'),
('e858db7e-2186-4a88-86f5-2b6da442c829','依韻和通判太博雪後招飲二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','邀飲奏醴醪，案杯烹蟹螯。',24,'全唐诗/poet.song.13000.json','["邀飲奏醴醪，案杯烹蟹螯。", "吾非獨醒者，莫誦楚人騷。"]'),
('ba281b28-c355-4c97-bf76-e44abe498911','依韻和資政侍郎雪後登看山亭','梅堯臣','宋','宋诗','song-poetry','','[]','湖上晴煙凍未收，湖中佳景可遲留。',32,'全唐诗/poet.song.13000.json','["湖上晴煙凍未收，湖中佳景可遲留。", "更臨危樹看羣岫，雪色嵐光向酒浮。"]'),
('c486d1d9-bec3-4401-aa90-c9e6f038ef8c','雪中通判家飲迴','梅堯臣','宋','宋诗','song-poetry','','[]','朔風聲滿枯桑枝，陰雲不定蛟龍歸。',96,'全唐诗/poet.song.13000.json','["朔風聲滿枯桑枝，陰雲不定蛟龍歸。", "凍禽聚立高樹時，密雲萬里增寒威。", "訪君留連舉酒巵，胡琴奏罷歡已微。", "小駒跨去沒四蹄，飄花凌亂霑人衣。", "醉目遠望天地迷，何暇更問孤鴻飛。", "茅屋豈無單且饑，平明共賀麥隴肥。"]'),
('ab058df4-6071-403c-8c44-a0894886ef1e','雪後資政侍郎西湖宴集偶書','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','潭心不凍處，鴈鶩自相依。',48,'全唐诗/poet.song.13000.json','["潭心不凍處，鴈鶩自相依。", "積雪正無際，因風忽起飛。", "初驚如避弋，復下信忘機。", "偶得從公飲，聊書此景歸。"]'),
('57692857-b6ab-456b-b7ef-382d2ef2849a','近有謝師厚寄襄陽柑子乃吳人所謂綠橘耳今王德言遺姑蘇者十枚此真物也因以詩答','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','荆州持大橘，亦自名黄柑。',36,'全唐诗/poet.song.13000.json','["荆州持大橘，亦自名黄柑。", "忽得洞庭美，氣味何可參。", "遂生吳洲思，恨不羽翼南。"]'),
('469462df-4ee4-4ff4-9e32-d5a9c091d9c5','運使劉察院因按歷歸西京拜省','梅堯臣','宋','宋诗','song-poetry','','[]','在昔志四海，所遇非一途。',120,'全唐诗/poet.song.13000.json','["在昔志四海，所遇非一途。", "朝以言悟主，夕即被金朱。", "于茲亦未幾，用直升雲衢。", "臺分東西屬，御史從子除。", "天馬日千里，豈並局促駒。", "朔北遏亂萌，褒嘉賜璽書。", "乃衣漢使繡，威譽傾國都。", "借問世上榮，萬國與此殊。", "明朝歸洛陽，聊且餞高車。", "亭堠况非遠，春郊無疾驅。"]'),
('33736a4a-f111-4103-846d-1601fd376c99','余之親家有女子能點酥爲詩并花果麟鳳等物一皆妙絕其家持以爲歲日辛盤之助余喪偶兒女服未除不作歲因轉贈通判通判有詩見答故走筆酬之','梅堯臣','宋','宋诗','song-poetry','','[]','翦竹纏金大於掌，紅縷龜紋挑作網。',64,'全唐诗/poet.song.13000.json','["翦竹纏金大於掌，紅縷龜紋挑作網。", "瓊酥點出探春詩，玉刻小書題在牓。", "名花雜果能眩真，祥獸珍禽得非廣。", "礧落男兒不足爲，女工餘思聊可賞。"]'),
('c0940f85-2e9f-448e-afcd-afdbfdf14466','元日','梅堯臣','宋','宋诗','song-poetry','','[]','昔遇風雪時，孤舟泊吳埭。',192,'全唐诗/poet.song.13000.json','["昔遇風雪時，孤舟泊吳埭。", "江潮未應浦，盡室坐相對。", "行庖得海物，鹹酸何瑣碎。", "久作北州人，食此欣已再。", "是時值新歲，慶拜乃唯內。", "草率具盤餐，約略施粉黛。", "舉杯更獻酬，各爾祝鮐背。", "咀橘齒病酸，目已驚老態。", "豈意未幾年，中路苦失配。", "嘉辰衆所喜，悲淚我何耐。", "曩歡今已哀，日月不可頼。", "前視四十春，空期此身在。", "世事都厭聞，讀書未忍退。", "過目雖已忘，寧捨心久愛。", "何當往京口，竹里翦荒穢。", "行歌樂暮節，薪菽甘自刈。"]'),
('2ad7e205-cf98-4840-b052-3764d03daaea','通判遺新柳','梅堯臣','宋','宋诗','song-poetry','','[]','園柳發新荑，官居雪尚壅。',36,'全唐诗/poet.song.13000.json','["園柳發新荑，官居雪尚壅。", "君喜持報春，衰意非舊勇。", "芳菲即可插，余髮慙種種。"]'),
('1a8e2213-ed8a-4ebe-ba10-4084fa81b536','送孫曼卿鎖廳赴舉','梅堯臣','宋','宋诗','song-poetry','','[]','舊果豈非好，截樹接新枝。',60,'全唐诗/poet.song.13000.json','["舊果豈非好，截樹接新枝。", "欲變明年花，曾不根本移。", "屈彼自然性，曰茲山木卑。", "子才實豔富，久爲人所推。", "固當升高科，我送作此詩。"]'),
('23900509-c6eb-4b99-9c13-bde1c882ce23','依韻和劉察院送客迴過潩水馬上有作','梅堯臣','宋','宋诗','song-poetry','','[]','車騎踏春堤，翛然思如濯。',48,'全唐诗/poet.song.13000.json','["車騎踏春堤，翛然思如濯。", "望驄人自避，解凍魚方樂。", "拏流古樹根，跨岸枯薪彴。", "煙雲淡淡天，嫩綠生叢薄。"]'),
('dbbdf2a1-892c-4dee-94f6-b8f069c6cba3','不知夢','梅堯臣','宋','宋诗','song-poetry','','[]','夢中不知夢，但謂平常時。',48,'全唐诗/poet.song.13000.json','["夢中不知夢，但謂平常時。", "相與共笑言，焉問久別離。", "有贈若有得，及覺已失之。", "人生在世間，何異夢寐爲。"]'),
('2a34a62d-b130-4fba-8764-ad159cc51888','郟城道中','梅堯臣','宋','宋诗','song-poetry','','[]','行行溪水邊，鏡碧不可唾。',48,'全唐诗/poet.song.13000.json','["行行溪水邊，鏡碧不可唾。", "安知有沫流，草木多偃卧。", "潭鳥瞥復沒，灘沙浄如簸。", "不獨荆州民，居險頸癭大。"]'),
('18c1f987-7dfb-4fe8-a4e9-bc17d2b1b828','汝州後池聽水','梅堯臣','宋','宋诗','song-poetry','','[]','春水泉脈動，分巖臨澗源。',48,'全唐诗/poet.song.13000.json','["春水泉脈動，分巖臨澗源。", "津津出石齒，泠泠縈竹根。", "猶和野雲翠，復落郡池喧。", "心靜意自適，不知朝市煩。"]'),
('2f4ba69a-a23e-47be-836a-d7f12c09e6b1','春鳩','梅堯臣','宋','宋诗','song-poetry','','[]','鳴鳩識陰晦，聒聒雌逐雄。',48,'全唐诗/poet.song.13000.json','["鳴鳩識陰晦，聒聒雌逐雄。", "鵲巢汝得共，可蔽雨與風。", "春物況不晚，杏萼已半紅。", "試看池館間，燕雀隨西東。"]'),
('097714c8-f872-47ed-98ca-b4f573ade135','留別汝守王待制仲儀','梅堯臣','宋','宋诗','song-poetry','','[]','來時柳未芽，去見杏吐萼。',48,'全唐诗/poet.song.13000.json','["來時柳未芽，去見杏吐萼。", "相歡無幾日，節候已非昨。", "邂逅二十年，三遇三暌索。", "會合信難常，焉用計疎數。"]'),
('2889b9a1-8452-41d3-8002-c8e5d3089ee6','夢覺','梅堯臣','宋','宋诗','song-poetry','','[]','夕夢多夢之，覺來遂成憶。',60,'全唐诗/poet.song.13000.json','["夕夢多夢之，覺來遂成憶。", "憶子生平時，事往無一得。", "信若此夢寐，豈不見顔色。", "復存來告言，言虛音匪默。", "是覺曷爲真，覺夢可以惑。"]'),
('6c9dcdae-cb48-4732-86e2-cf5b48493dca','汝州','梅堯臣','宋','宋诗','song-poetry','','[]','主人少聽我，爲言風土殊。',48,'全唐诗/poet.song.13000.json','["主人少聽我，爲言風土殊。", "美哉面有顙，生此頸若壺。", "噫號無冬夏，歲禱無嗟吁。", "只憐郡池上，不異山林居。"]'),
('181e687c-e5dd-46c0-9f92-6390b93a0755','逢牧','梅堯臣','宋','宋诗','song-poetry','','[]','國馬一何多，來牧郊甸初。',96,'全唐诗/poet.song.13000.json','["國馬一何多，來牧郊甸初。", "大羣幾百雜，小羣數十驅。", "或聚如鬭蟻，或散如驚烏。", "或踐麥無根，或齧樹無膚。", "牧卒殊不顧，抱鞭入民墟。", "欲酒與之飲，欲食與之餔。", "日暮卒醉飽，枕鞭當路隅。", "茫茫非其土，誰念有官租。"]'),
('8e7938ef-64c5-4c76-afe9-208b59df4ee6','寄滁州歐陽永叔','梅堯臣','宋','宋诗','song-poetry','','[]','昔讀韋公集，固多滁州詞。',293,'全唐诗/poet.song.13000.json','["昔讀韋公集，固多滁州詞。", "爛熳寫風土，下上窮幽奇。", "君今得此郡，名與前人馳。", "君才比江海，浩浩觀無涯。", "下筆猶高帆，十幅美滿吹。", "一舉一千里，只在頃刻時。", "尋常行舟艫，傍岸撐牽疲。", "有才苟如此，但恨不勇爲。", "仲尼著春秋，貶骨常苦笞。", "後世各有史，善惡亦不遺。", "君能切體類，鏡照嫫與施。", "直辭鬼膽懼，微文姦魄悲。", "不書兒女書，不作風月詩。", "唯存先王法，好醜無使疑。", "安求一時譽，當期千載知。", "此外有甘脆，可以奉親慈。", "山蔬采筍蕨，野膳獵麏麋。", "鱸膾古來美，梟{炙火=肉}今且推。", "夏果亦瑣細，一一舊頗窺。", "圓尖剝水實，青紅摘林枝。", "又足供宴樂，聊與子所宜。", "慎勿思北來，我言非狂癡。", "洗慮當以浄，洗垢當以脂。", "此語同飲食，遠寄入君脾。"]'),
('0225fcf6-ad39-4b75-9209-921dbac33320','衛州通判趙中舍','梅堯臣','宋','宋诗','song-poetry','','[]','我久在河內，頗知衛風俗。',48,'全唐诗/poet.song.13000.json','["我久在河內，頗知衛風俗。", "沙田多種稻，野飯殊脫粟。", "況聞別乘至，佇望大河曲。", "飲罷何以贈，柔條路傍綠。"]'),
('73d66f3c-6b25-4125-b63d-7de1601df442','資政王侍郎命賦梅花用芳字','梅堯臣','宋','宋诗','song-poetry','','[]','許都二月杏初盛，公府後園梅亦芳。',112,'全唐诗/poet.song.13000.json','["許都二月杏初盛，公府後園梅亦芳。", "因思江南花最早，開時不避雪與霜。", "主人惜春春未晚，遂命官屬携壺觴。", "酒行守吏摘花至，素豔紫萼繁於裝。", "夭桃穠李不可比，又況無此清淡香。", "豈辭盡醉對顔色，頻嗅競黏鬚蘂黄。", "何時結子助調鼎，我心舊職不敢忘。"]'),
('da0b6953-6332-488e-89c0-68e06da775f4','歐陽永叔寄琅琊山李陽冰篆十八字并永叔詩一首欲予繼作因成十四韻奉答','梅堯臣','宋','宋诗','song-poetry','','[]','我坐許昌塵土中，山翠泉聲違眼耳。',224,'全唐诗/poet.song.13000.json','["我坐許昌塵土中，山翠泉聲違眼耳。", "公雖被謫守滁陽，日少郡事窮山水。", "東南有風西北來，忽得書詩連數紙。", "并寄陽冰古篆字，字形矯矯龍蛇起。", "其文乃只題姓名，大曆六年春氣尾。", "報云此篆無人知，野僧好事爲公指。", "公留巖下久徘徊，公剔莓苔汲泉洗。", "點畫雖然未苦訛，霜侵風剝多皴理。", "公疑鳥迹踏蒼崖，山祇愛惜將有以。", "雲藏至今不近俗，月伴古源清且泚。", "此石公知石不知，公與前人定知己。", "墨模幾幅許傳玩，譬於玦玉終可喜。", "況復爲詩刻其下，句奇字峻驚山鬼。", "何當少得從公游，爲公揮筆寧非美。"]'),
('0de87f09-1606-44fe-a46c-2cb7c6e9098e','依韻答范天民','梅堯臣','宋','宋诗','song-poetry','','[]','古今冠佩立朝人，多作北山松下塵。',32,'全唐诗/poet.song.13000.json','["古今冠佩立朝人，多作北山松下塵。", "我愛蟠桃種來久，開花結子不由春。"]'),
('4ee1ac90-37fd-4a9c-b31d-ec622190e672','樊推官勸予止酒','梅堯臣','宋','宋诗','song-poetry','','[]','少年好飲酒，飲酒人少過。',96,'全唐诗/poet.song.13000.json','["少年好飲酒，飲酒人少過。", "今既齒髮衰，好飲飲不多。", "每飲輒嘔泄，安得六府和。", "朝酲頭不舉，屋室如盤渦。", "取樂反得病，衛生理則那。", "予欲從此止，但畏人譏訶。", "樊子亦能勸，苦口無所阿。", "乃知止爲是，不止將如何。"]'),
('5901f8f7-e9f0-4f7f-8a26-7c0eb92eddde','依韻和通判二月十五日雨中','梅堯臣','宋','宋诗','song-poetry','','[]','仲春月既望，物候恰分中。',48,'全唐诗/poet.song.13000.json','["仲春月既望，物候恰分中。", "窗聽五更雨，花開前日風。", "詩成止酒後，病怯舉杯空。", "短髮雖然黑，心如一老翁。"]'),
('ecfc7464-12ae-40d3-8910-d5f74092e391','感春之際以病止酒水丘有簡云時雨乍晴物景鮮麗疑其未是止酒時因成短章奉答','梅堯臣','宋','宋诗','song-poetry','','[]','東風固無迹，何處見春歸。',48,'全唐诗/poet.song.13000.json','["東風固無迹，何處見春歸。", "土逐草心坼，雨兼花片飛。", "雖憐柔甲長，只恐豔條稀。", "君但惜晴景，休言止酒非。"]'),
('a44930e5-6a2c-48f3-a624-b5bb5fcbb199','和永叔琅琊山六詠 歸雲洞','梅堯臣','宋','宋诗','song-poetry','','[]','洞深豈不有神物，朝朝但見雲飛還。',32,'全唐诗/poet.song.13000.json','["洞深豈不有神物，朝朝但見雲飛還。", "雲收雨歇草樹濕，澗下流水空潺潺。"]'),
('4ba3a73b-e58b-41bb-afe8-630de6e05f7a','和永叔琅琊山六詠 琅琊溪','梅堯臣','宋','宋诗','song-poetry','','[]','枯藤垂溪水已消，溪水濺濺石間亂。',32,'全唐诗/poet.song.13000.json','["枯藤垂溪水已消，溪水濺濺石間亂。", "潭靜鳥呼人渡時，鳥驚人語來還散。"]'),
('40ba7185-ed0e-4fd5-b2f0-34fac6920637','和永叔琅琊山六詠 班春亭','梅堯臣','宋','宋诗','song-poetry','','[]','林下鳴鳩坼晴杏，田間水漫春溶溶。',32,'全唐诗/poet.song.13000.json','["林下鳴鳩坼晴杏，田間水漫春溶溶。", "使君固自足風美，時傍青山去問農。"]'),
('adf7c3b7-6c88-4270-9628-a990fe711057','和永叔琅琊山六詠 庶子泉','梅堯臣','宋','宋诗','song-poetry','','[]','沙穴石竇無限泉，此泉緣底名不滅。',32,'全唐诗/poet.song.13000.json','["沙穴石竇無限泉，此泉緣底名不滅。", "庶子去來多少年，依舊清心共泉潔。"]'),
('51f75d7e-06f3-4006-bb8e-35d4fabd0574','和永叔琅琊山六詠 石屏路','梅堯臣','宋','宋诗','song-poetry','','[]','尋常畫屏多畫山，何意此山還作屏。',32,'全唐诗/poet.song.13000.json','["尋常畫屏多畫山，何意此山還作屏。", "峭排直上幾千尺，下有石路莓苔青。"]'),
('810f588f-e21a-4162-a064-b28403b7819f','和永叔琅琊山六詠 惠覺方丈','梅堯臣','宋','宋诗','song-poetry','','[]','松門隠者我未識，一見君詩如已奭。',32,'全唐诗/poet.song.13000.json','["松門隠者我未識，一見君詩如已奭。", "歲月任隨人事遷，此身不動雲生壁。"]'),
('e0926097-5472-434d-936b-ba2118bb4f60','答宋學士次道寄澄心堂紙百幅','梅堯臣','宋','宋诗','song-poetry','','[]','寒溪浸楮舂夜月，敲冰舉簾勻割脂。',192,'全唐诗/poet.song.13000.json','["寒溪浸楮舂夜月，敲冰舉簾勻割脂。", "焙乾堅滑若鋪玉，一幅百錢曾不疑。", "江南老人有在者，爲予嘗說江南時。", "李主用以藏秘府，外人取次不得窺。", "城破猶存數千幅，致入本朝誰謂奇。", "漫堆閒屋任塵土，七十年來人不知。", "而今製作已輕薄，比於古紙誠堪嗤。", "古紙精光肉理厚，邇歲好事亦稍推。", "五六年前吾永叔，贈予兩軸令寶之。", "是時頗敘此本末，遂號澄心堂紙詩。", "我不善書心每愧，君又何此百幅遺。", "重增吾赧不敢拒，且置縑箱何所爲。"]'),
('6cc8041b-115c-4d58-8c5e-70ffe166acfb','二月雨後有蚊蚋','梅堯臣','宋','宋诗','song-poetry','','[]','春夜一二蚊蚋飛，久不見之尚可喜。',32,'全唐诗/poet.song.13000.json','["春夜一二蚊蚋飛，久不見之尚可喜。", "而今稍喧來聒人，向後更暖奈爾觜。"]'),
('0f80a32b-98b3-4fd5-ac43-8e4dc2b07902','春寒','梅堯臣','宋','宋诗','song-poetry','','[]','春晝自陰陰，雲容薄更深。',48,'全唐诗/poet.song.13000.json','["春晝自陰陰，雲容薄更深。", "蝶寒方斂翅，花冷不開心。", "亞樹青帘動，依山片雨臨。", "未嘗辜景物，多病不能尋。"]'),
('5e183090-d894-44a6-9203-39742a189199','答韓三子華韓五持國韓六玉汝見贈述詩','梅堯臣','宋','宋诗','song-poetry','','[]','聖人於詩言，曾不專其中。',264,'全唐诗/poet.song.13000.json','["聖人於詩言，曾不專其中。", "因事有所激，因物興以通。", "自下而磨上，是之謂國風。", "雅章及頌篇，刺美亦道同。", "不獨識鳥獸，而爲文字工。", "屈原作離騷，自哀其志窮。", "憤世嫉邪意，寄在草木蟲。", "邇來道頗喪，有作皆言空。", "煙雲寫形象，葩卉詠青紅。", "人事極諛諂，引古稱辨雄。", "經營唯切偶，榮利因被蒙。", "遂使世上人，只曰一藝充。", "以巧比戲弈，以聲喻鳴桐。", "嗟嗟一何陋，甘用無言終。", "然古有登歌，緣辭合徵宮。", "辭由士大夫，不出於瞽矇。", "予言與時輩，難用猶篤癃。", "雖唱誰能聽，所遇輒瘖聾。", "諸君前有贈，愛我言過豐。", "君家好兄弟，響合如笙叢。", "雖欲一一報，强說恐非衷。", "聊書類頑石，不敢事磨礱。"]'),
('9873a7b9-224f-4469-9c2e-b6116bc12f10','前以詩答韓三子華後得其簡因敘下情','梅堯臣','宋','宋诗','song-poetry','','[]','前者報君詩，妄說良有以。',132,'全唐诗/poet.song.13000.json','["前者報君詩，妄說良有以。", "昔予在京師，多爲人所詆。", "短章然無工，實未甘藝比。", "因君有過褒，聊且發憤悱。", "何言敢爲師，乃是貴不韙。", "平常遭口語，攢集猶毒矢。", "此論苟一出，是非必蜂起。", "偶爾道瘖聾，多疑已竊指。", "雖恃不欺衷，恨未致速死。", "安得二頃田，歸耕曷爲恥。", "誰能事州郡，雞狗徒聒耳。"]'),
('e5ef4ae6-5c46-4dbf-bf2b-20262d9d5da2','過穎橋懷永叔','梅堯臣','宋','宋诗','song-poetry','','[]','昔送之官東郡時，夜闌對酒風揭屋。',32,'全唐诗/poet.song.13000.json','["昔送之官東郡時，夜闌對酒風揭屋。", "君今淮海予再過，古驛依依老槐綠。"]'),
('7f392a15-8dd4-47b6-93e8-a8d941941d8f','椹澗晝夢','梅堯臣','宋','宋诗','song-poetry','','[]','誰謂死無知，每出輒來夢。',48,'全唐诗/poet.song.13000.json','["誰謂死無知，每出輒來夢。", "豈其憂在途，似亦會相送。", "初看不異昔，及寤始悲痛。", "人間轉面非，清魂歿猶共。"]'),
('6d89957a-1ba7-402a-b9a9-52be2687b749','靈樹鋪夕夢','梅堯臣','宋','宋诗','song-poetry','','[]','晝夢同坐偶，夕夢立我左。',48,'全唐诗/poet.song.13000.json','["晝夢同坐偶，夕夢立我左。", "自置五色絲，色透縑囊過。", "意在留補綴，恐衣或綻破。", "歿仍憂我身，使存心得墮。"]'),
('f7461779-42c7-4b98-a7d1-ceccefe68167','汝州王待制以長篇勸予復飲酒因謝之','梅堯臣','宋','宋诗','song-poetry','','[]','前因飲酒多，乃苦傷營衛。',240,'全唐诗/poet.song.13000.json','["前因飲酒多，乃苦傷營衛。", "嘔血踰數升，幾不成病肺。", "上念父母老，下念妻兒稚。", "不死常抱痾，於身寧自貴。", "樊子來勸我，止飲良有謂。", "公復遺我詩，責我詞甚毅。", "指以年齒衰，非酒何養氣。", "春飲景可樂，夏飲暑可避。", "秋飲心忘愁，冬飲暖勝被。", "醉歌人不怪，醉言人不忌。", "在酒功實多，止酒酒何罪。", "假如壽九十，今子已半世。", "不飲徒自苦，未必止爲利。", "胡汨妄與真，恐乖達者意。", "屈原吟澤畔，方悟獨醒累。", "子居今之時，安免人病議。", "是以告子勤，子守亦謬詩。", "我讀纔一過，不覺顔起愧。", "自茲願少飲，但不使疾熾。", "書此以謝公，公言誠有味。"]'),
('40fe7f6a-2629-47c5-8046-b4ab7aec2c7e','和王待制清凉院觀牡丹賦詩','梅堯臣','宋','宋诗','song-poetry','','[]','公言牡丹盛，未覩古人詩。',48,'全唐诗/poet.song.13000.json','["公言牡丹盛，未覩古人詩。", "品衆自爭貴，葉多方見奇。", "名因他姓著，色爲別根移。", "華髮我何感，洛陽年少時。"]'),
('9b0f6d1b-9ccb-4632-b15f-f3c5aec9c3dc','和王待制牡丹詠','梅堯臣','宋','宋诗','song-poetry','','[]','誰移洛川花，一日來汝海。',48,'全唐诗/poet.song.13000.json','["誰移洛川花，一日來汝海。", "濃淡百般開，風露幾番改。", "傍欄人自醉，惜翦春有待。", "使君方少年，共賞喜我在。"]'),
('d4b6c238-dd71-49a2-abad-cb26e70b614d','洛陽牡丹','梅堯臣','宋','宋诗','song-poetry','','[]','古來多貴色，歿去定何歸。',48,'全唐诗/poet.song.13000.json','["古來多貴色，歿去定何歸。", "清魄不應散，豔花還所依。", "紅棲金谷妓，黄值洛川妃。", "朱紫亦皆附，可言人世稀。"]'),
('18533624-8996-4038-9959-869aec2fd612','汝州等慈寺閣望嵩岳','梅堯臣','宋','宋诗','song-poetry','','[]','崢嶸古寺閣，蒼山插晴簷。',48,'全唐诗/poet.song.13000.json','["崢嶸古寺閣，蒼山插晴簷。", "少室出天外，巍巍何尊嚴。", "王都在其下，風露國所霑。", "日暮飛雲歸，已失中頂尖。"]'),
('3f94c5c7-6bbc-4448-be7a-83f2c80f069e','睡意','梅堯臣','宋','宋诗','song-poetry','','[]','少時好睡常不足，上事親尊日拘束。',160,'全唐诗/poet.song.13000.json','["少時好睡常不足，上事親尊日拘束。", "夜吟朝誦無暫休，目胔生瘡臂消肉。", "今踰四十無所聞，又況喪妻仍獨宿。", "虛堂浄掃焚清香，安寢都忘世間欲。", "花時啼鳥不妨喧，清暑北窗聊避燠。", "葉落夜雨聲滿階，雪下曉寒低壓屋。", "四時自得興味佳，豈必鏘金與鳴玉。", "萬事易厭此不厭，真可養恬無夭促。", "且夢莊周化蝴蝶，焉顧仲尼譏朽木。", "人事幾不如夢中，休用區區走榮祿。"]'),
('d3c6d9c6-54b6-4702-bbcb-1a6ab24c3210','三月十四日汝州夢','梅堯臣','宋','宋诗','song-poetry','','[]','我歸十九年，飲不負升斗。',60,'全唐诗/poet.song.13000.json','["我歸十九年，飲不負升斗。", "昨夕夢見之，謂須多置酒。", "雖慰魂來言，定不復入口。", "俟當返吾廬，且爲貯甖缶。", "夢寐何敢欺，從笑愚所守。"]'),
('a6749173-1301-4825-b857-8b3bbd0cf369','再別仲儀','梅堯臣','宋','宋诗','song-poetry','','[]','前別歲月遠，道同情相親。',48,'全唐诗/poet.song.13000.json','["前別歲月遠，道同情相親。", "三旬忽相見，愈厚不厭頻。", "昔云思數面，今無愧古人。", "睠然東去懷，紛若陌上塵。"]'),
('36841e43-11d2-4670-ae8a-92920df2c77f','夕發陽翟','梅堯臣','宋','宋诗','song-poetry','','[]','我行陽翟道，暮雨原上急。',48,'全唐诗/poet.song.13000.json','["我行陽翟道，暮雨原上急。", "麒麟塚相望，霹靂碑下立。", "農耕傍山去，鬼火迸林入。", "莫問泉下人，馬隤衣更濕。"]'),
('87896f73-e8d5-454d-935c-f1300320b33e','缺月','梅堯臣','宋','宋诗','song-poetry','','[]','缺月來照屋角時，西家狗吠東家疑。',32,'全唐诗/poet.song.13000.json','["缺月來照屋角時，西家狗吠東家疑。", "夜深精靈鬼初動，窸窣古莽無風吹。"]'),
('77da14f0-1b21-4f76-b0e9-14ad1a851e1b','道次靈井','梅堯臣','宋','宋诗','song-poetry','','[]','井面水不動，傍分龍鱗激。',48,'全唐诗/poet.song.13000.json','["井面水不動，傍分龍鱗激。", "泉氣時生漚，上湧光的皪。", "深苔翠堪染，石底清可覿。", "旱歲或來祠，彈絃屬靈覡。"]'),
('a255dbaa-640b-43e4-a615-6b199bc8932e','答江十鄰幾','梅堯臣','宋','宋诗','song-poetry','','[]','蔡州雖非遐，作書素所懶。',48,'全唐诗/poet.song.13000.json','["蔡州雖非遐，作書素所懶。", "春風領燕來，得君詞款款。", "燕迴須在秋，此報莫言緩。", "何日見嵇康，重彈廣陵散。"]'),
('8ddcbcd3-b60b-4921-9b90-42f4631c4ea0','喜謝師厚及第','梅堯臣','宋','宋诗','song-poetry','','[]','宿雨洗新綠，朝日初聞鶑。',72,'全唐诗/poet.song.13000.json','["宿雨洗新綠，朝日初聞鶑。", "風從天門來，吹下玉簡名。", "列星二十八，經緯何縱橫。", "南方朱鳥目，光焰令人驚。", "其餘撒沙衆，龜鼈瓜瓠明。", "吾欣安石後，世世有令聲。"]'),
('b30b4e67-0c99-4688-91a6-eafeec7cc1fa','孟夏二日通判太博惠庭花二十枝云是手植因以爲答','梅堯臣','宋','宋诗','song-poetry','','[]','前日已春盡，夏卉抽嫩青。',48,'全唐诗/poet.song.13000.json','["前日已春盡，夏卉抽嫩青。", "唯君所植花，餘紅猶滿庭。", "常惜畏景逼，贈未及飄零。", "欲插爲之醉，但慙髮星星。"]'),
('96abace3-68d0-4046-b2d3-093c5c30f532','水丘於西湖得活鯽魚三尾見遺余頃在襄城獲數尾時歐陽永叔方自乾德移滑臺留待其至且有詩後居京師蔡仲謀者亦有以贈乃思襄時所留復有詩於今三得三詠之矣','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','襄城得圓鯽，留以待吾友。',72,'全唐诗/poet.song.13000.json','["襄城得圓鯽，留以待吾友。", "大梁又得之，始憶終按酒。", "今君復持贈，重念滁陽守。", "滁陽石瀨中，此物豈無有。", "三得實嘉遺，我敢自私口。", "口且不爭甘，事亦難利誘。"]'),
('4aec7c25-3c88-49c5-99d0-0a285df877dd','和江鄰幾見寄','梅堯臣','宋','宋诗','song-poetry','','[]','清風當晝起，吹我庭下槐。',96,'全唐诗/poet.song.13000.json','["清風當晝起，吹我庭下槐。", "軒軒枝上葉，碎影亂綠苔。", "左右無人聲，時有啼禽來。", "啼禽感所懷，其音一何哀。", "思歸無曉夕，血滴山榴開。", "曰予當是時，爲之腸九迴。", "江子方謫官，復有擬古才。", "遠寄平淡辭，曷報瓊與瓌。"]'),
('5d1c3376-5c45-4c19-8e1e-ea0840994a78','雀奪燕巢生四雛','梅堯臣','宋','宋诗','song-poetry','','[]','去年燕營巢，銜泥入我廬。',84,'全唐诗/poet.song.13000.json','["去年燕營巢，銜泥入我廬。", "秋歸春復來，橫被雀所居。", "翩然去不較，義者欲與除。", "毀覆必傷卵，愛彼此何疎。", "乃竢長黄口，逐之寧曰紓。", "果得生四雛，卉色頭戢如。", "後當還燕巢，穿屋不害余。"]'),
('6233013d-6a2d-4e75-9dab-0b35476c6384','和歐陽永叔啼鳥十八韻','梅堯臣','宋','宋诗','song-poetry','','[]','南方窮山多野鳥，百種巧口乘春鳴。',288,'全唐诗/poet.song.13000.json','["南方窮山多野鳥，百種巧口乘春鳴。", "深林參天不見日，滿壑呼嘯難識名。", "但依音響得其字，因與爾雅殊形聲。", "我昔曾有禽言詩，粗究一二啼嚎情。", "苦竹岡頭泥滑滑，君時最賞趣向精。", "餘篇亦各有思致，恨未與盡衆鳥評。", "君今山郡日無事，靜聽鳥語如交爭。", "提壺相與來勸飲，戴勝亦助能勸耕。", "我念此鳥頗有益，如欲使君勤以行。", "勸耕幸且强職事，勸飲亦冀無獨醒。", "杜鵑蜀魄哭歸去，小人懷土慎勿聽。", "城頭春鳩自謂拙，鵲巢輒處安得平。", "高窠喬木美毛羽，哢吭葉底無如鶑。", "口中調簧定何益，下啄蚯蚓孰曰清。", "自餘多類不足數，一一推本煩神靈。", "我居中土別無鳥，老鴉鸜鵒方縱橫。", "教雛叫噪日羣集，豈有勸酒花下傾。", "願君切莫厭啼鳥，啼鳥於君無所營。"]'),
('35ce3b38-b7a7-4192-8742-7522c2d69702','和永叔桐花十四韻','梅堯臣','宋','宋诗','song-poetry','','[]','湛湛碧井水，其上有梧桐。',168,'全唐诗/poet.song.13000.json','["湛湛碧井水，其上有梧桐。", "春隨井氣生，白花飛濛濛。", "曉枝滴甘露，味落寒泉中。", "結實待瑞羽，歲晚半枯空。", "桐既無鳳皇，井豈潛蛟龍。", "乃知至神物，未易令人逢。", "當時集潁川，偶值黄次公。", "次公入爲相，此鳥曷不從。", "遂使神鶡雀，竟用奇怪窮。", "我言非毀古，欲遵平直蹤。", "我願二千石，但使德化隆。", "有桐鳳不來，於桐無愧容。", "有鳳政不舉，於鳳何爲崇。", "答君桐花篇，聊以發我衷。"]'),
('814dcb7c-2e1b-4c11-86ea-eaf0ad1f0178','和王仲儀詠癭二十韻','梅堯臣','宋','宋诗','song-poetry','','[]','汝水出山險，汝民多病癭。',240,'全唐诗/poet.song.13000.json','["汝水出山險，汝民多病癭。", "或如雞精滿，或若猿嗛並。", "女慙高掩襟，男大闊裁領。", "飲水擬注壺，吐詞侔有鯁。", "樗里既已聞，杜預亦不幸。", "秦人號智囊，吳瓠繫狗頸。", "𦢏𩲞常柱頤，伶仃安及脛。", "只欲仰問天，無由俯窺井。", "挾带歲月深，冒犯風霜冷。", "厭惡雖自知，剖割且誰肯。", "不唯羞把鏡，仍亦愁弔影。", "內療煩羊厴，外砭費針穎。", "在木曰楠榴，刳之可爲皿。", "此誠無所用，既有何能辟。", "膨脝厠無首，臃腫異臚頂。", "難將面目施，可與胎胞逞。", "賢哉臨汝守，世德調金鼎。", "氓俗雖醜乖，教令日修整。", "風土恐隨遷，晨昏憂屢省。", "儻欲便慈顔，名城不難請。"]'),
('9ff64502-6f18-46f3-8d37-82df7c0bb9b2','憶吳松江晚泊','梅堯臣','宋','宋诗','song-poetry','','[]','念昔西歸時，晚泊吳江口。',48,'全唐诗/poet.song.13000.json','["念昔西歸時，晚泊吳江口。", "迴堤遡清風，淡月生古柳。", "夕鳥獨遠來，漁舟猶在後。", "當時誰與同，涕憶泉下婦。"]'),
('95de1687-a931-4a59-ab78-65b065621935','使者自隨州來知尹師魯寓止僧舍語其處物景甚詳因作詩以寄焉','梅堯臣','宋','宋诗','song-poetry','','[]','驛使話漢東，故人遷謫處。',72,'全唐诗/poet.song.13000.json','["驛使話漢東，故人遷謫處。", "所居雖非居，有樹即嘉樹。", "日膳或雞肫，時蔬多筍芋。", "夜堂蛇結蟠，晝戶鵲噪聚。", "著書今未成，愛靜已得趣。", "予欲訪其人，炎蒸未能去。"]'),
('29fc22fe-6d69-4185-b0f4-ad2c4e9944d6','夏日對雨偶成寄韓仲文兄弟','梅堯臣','宋','宋诗','song-poetry','','[]','日日城頭雨，還愁湖上波。',48,'全唐诗/poet.song.13000.json','["日日城頭雨，還愁湖上波。", "窗中人自聽，門外潦應多。", "不畏車生耳，還愁麥化蛾。", "吾廬無所有，頻看壁間梭。"]'),
('33fc2cab-479e-4b2b-b284-54c078048882','憶將渡揚子江','梅堯臣','宋','宋诗','song-poetry','','[]','月暈知天風，舟人夜相語。',48,'全唐诗/poet.song.13000.json','["月暈知天風，舟人夜相語。", "平明好挂帆，白浪須出浦。", "此身猶在吳，歸夢預到楚。", "今日念同來，吾妻已爲土。"]'),
('f23ed79e-c434-4f26-876d-c72badfd593d','秀叔頭蝨','梅堯臣','宋','宋诗','song-poetry','','[]','吾兒久失恃，髮括仍少櫛。',72,'全唐诗/poet.song.13000.json','["吾兒久失恃，髮括仍少櫛。", "曾誰具湯沐，正爾多蟣蝨。", "變黑居其元，懷絮宅非吉。", "蒸如蟻亂緣，聚若蠶初出。", "鬢搔劇蓬葆，何暇嗜梨栗。", "翦除誠未難，所惡累形質。"]'),
('e0d22db2-9944-4dc1-8017-3c2b7e1d389f','稚子獲雀雛','梅堯臣','宋','宋诗','song-poetry','','[]','屋頭小雀雛，氣力苦未長。',48,'全唐诗/poet.song.13000.json','["屋頭小雀雛，氣力苦未長。", "乘暄學調羽，忽掛蜘蛛網。", "其母不能救，啁啾空下上。", "乃爲人所探，不是蟲絲枉。"]'),
('eeb1e669-4658-406b-9513-06194c1432f7','丙戌五月二十二日晝寢夢亡妻謝氏同在江上早行忽逢岸次大山遂往遊陟予賦百餘言述所覩物狀及寤尚記句有共登雲母山不得同宮處倣像夢中意續以成篇','梅堯臣','宋','宋诗','song-poetry','','[]','晝夢與予行，早發江上渚。',120,'全唐诗/poet.song.13000.json','["晝夢與予行，早發江上渚。", "共登雲母山，不得同宮處。", "何嗟不同宮，似所厭途旅。", "樹杪俯烏巢，坼鷇方仰乳。", "雄雌更守林，號噪見飛鼠。", "鼠驚豎毛怒，裊枝如發弩。", "逡巡吼風雲，遠望射巖雨。", "東南橫虹霓，萬壑水噴吐。", "下尋歸路迷，欲暮各愁語。", "忽覺皆已非，空庭日方午。"]'),
('86c1b93c-bc83-4377-9c42-bd29f4c7f025','蜜','梅堯臣','宋','宋诗','song-poetry','','[]','燕銜芹根泥，蜂掇花上蕊。',72,'全唐诗/poet.song.13000.json','["燕銜芹根泥，蜂掇花上蕊。", "带雨兩股飛，所取日能幾。", "調和露與英，凝甘滑於髓。", "天寒百蟲蟄，割房霜在匕。", "燕已成雛歸，蜂憂凍餒死。", "乃見萬物心，多爲造化使。"]'),
('b1507d6b-a3eb-4b75-9681-b615c850cd8a','王德言自後圃來問疾且曰圃甚蕪何不治因答','梅堯臣','宋','宋诗','song-poetry','','[]','幾日不行圃，野草過人頭。',48,'全唐诗/poet.song.13000.json','["幾日不行圃，野草過人頭。", "客怪若荒穢，誰與持鋤鉤。", "雖然自薅薙，抱痾方告休。", "即當秋風高，掃籜將遲遊。"]'),
('112a6b8e-1848-4b46-aa02-6bb2ede24c83','夢覩','梅堯臣','宋','宋诗','song-poetry','','[]','閉目光不揚，夢覩良亦審。',48,'全唐诗/poet.song.13000.json','["閉目光不揚，夢覩良亦審。", "既非由目光，所見定何稟。", "白日杳無朕，冥遇嘗在寢。", "此恨不可窮，悲淚空流枕。"]'),
('3de3f058-110f-4afd-8608-699c1ff62447','悲書','梅堯臣','宋','宋诗','song-poetry','','[]','悲愁快於刀，內割肝腸痛。',72,'全唐诗/poet.song.13000.json','["悲愁快於刀，內割肝腸痛。", "有在皆舊物，唯爾與此共。", "衣裳昔所製，篋笥忍更弄。", "朝夕拜空位，繪寫恨少動。", "雖死情難遷，合姓義已重。", "吾身行將衰，同穴詩可誦。"]'),
('fd1e5a45-131b-47f5-91c4-e79582b31750','合流曹光道惠鉅李知其炎酷中有此味亦可樂也輒以詩寄','梅堯臣','宋','宋诗','song-poetry','','[]','穎傍成蹊李，其實小於拳。',72,'全唐诗/poet.song.13000.json','["穎傍成蹊李，其實小於拳。", "誰知皴枝瘦，生此紺玉鮮。", "摘以筠梢籠，沉以石根泉。", "濛濛粉未落，粲粲葉猶連。", "蔭樹咀甘液，安知有苦煎。", "報君惜茲樂，時詠逍遥篇。"]'),
('58cf677b-ba4a-4a4d-9ea1-700b88bbdf0c','深夏忽見柰樹上猶存一顆實','梅堯臣','宋','宋诗','song-poetry','','[]','纍纍後堂柰，落盡風雨枝。',48,'全唐诗/poet.song.13000.json','["纍纍後堂柰，落盡風雨枝。", "行樂偶散步，倚杖聊縱窺。", "林葉隠孤實，山鳥曾未知。", "物亦以晦存，悟茲身世爲。"]'),
('95dda444-872f-4ec7-ada0-1227a9448958','病癰在告韓仲文贈烏賊觜生醅醤蛤蜊醤因筆戲答','梅堯臣','宋','宋诗','song-poetry','','[]','我嘗爲吳客，家亦有吳婢。',48,'全唐诗/poet.song.13000.json','["我嘗爲吳客，家亦有吳婢。", "忽驚韓夫子，來遺越鄉味。", "與官官不識，問儂儂不記。", "雖然苦病癰，饞吻未能忌。"]'),
('ded7ee6d-67f2-4230-a935-1958aecd1b8c','寄光化退居李晉卿','梅堯臣','宋','宋诗','song-poetry','','[]','久無歸田人，今喜子去祿。',144,'全唐诗/poet.song.13000.json','["久無歸田人，今喜子去祿。", "移家漢水濱，日見漢水綠。", "川鱗可爲饔，山毛可爲蔌。", "竟歲厭往還，行堤樂風俗。", "青巾艑上郎，漆鬢顔如玉。", "倚檣臨落照，獨唱江南曲。", "聽若在江南，歡然自爲足。", "我心雖有羨，未遂平生欲。", "更期畢婚嫁，方可事巖麓。", "買山須買泉，種樹須種竹。", "泉以濯吾纓，竹以慕賢躅。", "此志應不忘，他時同隠錄。"]'),
('b86980f5-3253-4d46-99cf-c9426f8049a4','汝南江鄰幾云鄎南並淮浮光山有張隠居種松檜於其上養母甚孝時有猛獸馴庭中又郡西麻田山土沃泉美久不墾有劉叟者闢而居之近董氏黄氏欲買土爲鄰故江有慕之之作予輒次其韻','梅堯臣','宋','宋诗','song-poetry','','[]','峨峨淮山上，中有隠者棲。',132,'全唐诗/poet.song.13000.json','["峨峨淮山上，中有隠者棲。", "不知松檜下，但見虎豹蹊。", "人羣固已遠，樵客入猶迷。", "且奉采蘭養，應無抱玉啼。", "麻田異麻源，石路春無泥。", "高士不近俗，更在西嶺西。", "石泉飲自足，深壑無人躋。", "不學淮南王，安問犬與雞。", "二人逍遥性，所樂唯杖蔾。", "復有來慕鄰，他年寧答嵇。", "願君且勉職，聖世未易暌。"]'),
('af51a996-4ed1-4064-8db4-b6710a91a648','魏文以予病渴贈薏苡二叢值庭下走筆戲謝','梅堯臣','宋','宋诗','song-poetry','','[]','媿無相如才，偶病相如渴。',48,'全唐诗/poet.song.13000.json','["媿無相如才，偶病相如渴。", "潩水有丈人，薏苡分叢茇。", "爲飲可扶衰，餘生幸且活。", "安知惡己者，不願變野葛。"]'),
('66fb690b-d3ec-49e1-b049-b7327ea9904f','和資政侍郎湖亭雜詠絕句十首 遠山','梅堯臣','宋','宋诗','song-poetry','','[]','插雲千萬重，一望不可暫。',24,'全唐诗/poet.song.13000.json','["插雲千萬重，一望不可暫。", "前嶺與後峯，翠色濃復淡。"]'),
('c093cd21-c983-41af-86ad-558b5b6d3020','和資政侍郎湖亭雜詠絕句十首 蓮塘','梅堯臣','宋','宋诗','song-poetry','','[]','不畏塘雨急，鈿葉自相遮。',24,'全唐诗/poet.song.13000.json','["不畏塘雨急，鈿葉自相遮。", "紋禽忽飛去，衝落波上霞。"]'),
('3e79c78c-f7fa-4619-8bf9-e68b5e18443b','和資政侍郎湖亭雜詠絕句十首 漁潭','梅堯臣','宋','宋诗','song-poetry','','[]','煙潭深不極，鑑碧無菱花。',24,'全唐诗/poet.song.13000.json','["煙潭深不極，鑑碧無菱花。", "日脚下波心，澄江見魚蝦。"]'),
('4565c55f-2fc2-44e1-ae95-86af69c23818','和資政侍郎湖亭雜詠絕句十首 稻畦','梅堯臣','宋','宋诗','song-poetry','','[]','淺淺碧水平，青青稻苗長。',24,'全唐诗/poet.song.13000.json','["淺淺碧水平，青青稻苗長。", "偏知楚客愛，白鷺飛下上。"]'),
('75375ede-161d-4bd5-8d77-13dc2a5c5052','和資政侍郎湖亭雜詠絕句十首 苔徑','梅堯臣','宋','宋诗','song-poetry','','[]','林間夏雨滋，復有斜陽照。',24,'全唐诗/poet.song.13000.json','["林間夏雨滋，復有斜陽照。", "綠浄不摇風，從教春草笑。"]'),
('84010532-be01-4123-b502-cbafcb89de4c','和資政侍郎湖亭雜詠絕句十首 流泉','梅堯臣','宋','宋诗','song-poetry','','[]','石齒嚼寒聲，粼粼縈曲處。',24,'全唐诗/poet.song.13000.json','["石齒嚼寒聲，粼粼縈曲處。", "有時浮落英，又過城根去。"]'),
('38b10f18-88e7-44f6-bcd1-9af8c20ce41f','和資政侍郎湖亭雜詠絕句十首 小橋','梅堯臣','宋','宋诗','song-poetry','','[]','伐桂向芳洲，跨波灣勢小。',24,'全唐诗/poet.song.13000.json','["伐桂向芳洲，跨波灣勢小。", "時愛游人渡，游人在林杪。"]'),
('d9d817dc-43c1-4c5f-93ee-e1c428c842ba','和資政侍郎湖亭雜詠絕句十首 漁艇','梅堯臣','宋','宋诗','song-poetry','','[]','古木刳爲舟，野藤牽作纜。',24,'全唐诗/poet.song.13000.json','["古木刳爲舟，野藤牽作纜。", "釣人寒雨中，遠望煙蓑暗。"]'),
('ecbcc6d5-b5bd-4795-b4cf-d1d560774e43','和資政侍郎湖亭雜詠絕句十首 採菱','梅堯臣','宋','宋诗','song-poetry','','[]','紫角菱實肥，青銅菱葉老。',24,'全唐诗/poet.song.13000.json','["紫角菱實肥，青銅菱葉老。", "孤根未能定，不及寒塘草。"]'),
('22afe217-1ec0-4370-b36d-75488d4068de','和資政侍郎湖亭雜詠絕句十首 汀鷺','梅堯臣','宋','宋诗','song-poetry','','[]','食魚日已晚，矯翼煙際還。',24,'全唐诗/poet.song.13000.json','["食魚日已晚，矯翼煙際還。", "不與鴈鶩競，風標亦自閒。"]'),
('b32fb7ef-8b71-401d-b462-b52a2fa34d14','王德言夏日西湖晚步十韻次而和之','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雨餘殘照在，塘靜獨行行。',120,'全唐诗/poet.song.13000.json','["雨餘殘照在，塘靜獨行行。", "荷積水珠重，天收霓帔輕。", "倦禽倚卧柳，聚蚓殢坳泓。", "帽側林枝礙，裳褰野蔓縈。", "芡韜園客剝，蒲刃水妖驚。", "决决流泉活，濛濛夕霧平。", "榴房生蠹落，蛛網害蟲成。", "坎黽無時怒，渾魚自樂清。", "高臺從獸窟，古道有根橫。", "寫景未能就，娟娟月上城。"]'),
('21e8c046-6aa7-45a4-9cdc-079651418c17','新沼竹軒','梅堯臣','宋','宋诗','song-poetry','','[]','作軒仍見竹，瀟灑排青幢。',48,'全唐诗/poet.song.13000.json','["作軒仍見竹，瀟灑排青幢。", "斜烏與落月，靜影晝寒窗。", "光沒影亦沒，激水自淙淙。", "夜深猶讀易，誰更憶清江。"]'),
('3f89c1c6-77f6-4be8-b5ec-4737d822a738','麥門冬內子吳中手植甚繁鬰罷官移之而歸不幸內子道且亡而茲草亦屢枯今所存三之一耳遂感而賦云','梅堯臣','宋','宋诗','song-poetry','','[]','香草葉常碧，本生巖澗邊。',84,'全唐诗/poet.song.13000.json','["香草葉常碧，本生巖澗邊。", "佳人昔所愛，移植堂堦前。", "自吳北歸梁，復以盆盎遷。", "佳人路中死，此草未忍捐。", "與我日憔悴，根不通下泉。", "勤勤爲澆沃，稍見萌穎鮮。", "終當置墳側，長茂松柏埏。"]'),
('416f1e9b-640e-4cfe-afee-1208b32b47c3','野鴿','梅堯臣','宋','宋诗','song-poetry','','[]','孤來有野鴿，觜眼肖春鳩。',120,'全唐诗/poet.song.13000.json','["孤來有野鴿，觜眼肖春鳩。", "饑腸欲得食，立我南屋頭。", "我見如不見，夜去向何求。", "一日偶出羣，盤空恣嬉游。", "誰借風鈴響，朝夕聲不休。", "饑色猶未改，翻翅如我仇。", "炳哉有靈鳳，天抑爲爾儔。", "翕翼處其間，顧我獨遲留。", "鳳至吾道行，鳳去吾道休。", "鴿乎何所爲，勿污吾鐺甌。"]'),
('6f9036fd-9ff4-41c2-9821-943ed3cd0006','孫曼叔暮行汴上見鶻擊蝙蝠以去語於予','梅堯臣','宋','宋诗','song-poetry','','[]','野鶻性决裂，所食唯獰飛。',60,'全唐诗/poet.song.13000.json','["野鶻性决裂，所食唯獰飛。", "小鳥不入眼，拳發强弩機。", "日暮未有獲，豈擇大與肥。", "瞥下攫蝙蝠，去以填腸饑。", "休笑老鴟飽，銜得腐鼠歸。"]'),
('451f6073-f07d-4c3e-98ee-0b951f0e6612','寄宋中道','梅堯臣','宋','宋诗','song-poetry','','[]','爾書我不答，爾怒從爾駡。',48,'全唐诗/poet.song.13000.json','["爾書我不答，爾怒從爾駡。", "天馬新羈時，氣橫未可駕。", "儻我一日死，爾豈無悲咤。", "唯知道義深，小失不足謝。"]'),
('8d884729-b340-4b09-948c-8e0e417bcb70','梨花憶','梅堯臣','宋','宋诗','song-poetry','','[]','欲問梨花發，江南信始通。',48,'全唐诗/poet.song.13000.json','["欲問梨花發，江南信始通。", "開因寒食雨，落盡故園風。", "白玉佳人死，青銅寶鏡空。", "今朝兩眼淚，怨苦屬衰公。"]'),
('b2641bb1-2705-43f7-ae3d-a190e76d5f43','畫竹枝扇','梅堯臣','宋','宋诗','song-poetry','','[]','石上老瘦竹，忽在紈扇中。',48,'全唐诗/poet.song.13000.json','["石上老瘦竹，忽在紈扇中。", "執之意已凉，不待摇清風。", "小節未見粉，淚痕應合紅。", "日將炎暑退，畏蠹生秋蟲。"]'),
('5e43aa50-fd72-4d71-b8b2-694a16c32f33','兩日苦風思江南','梅堯臣','宋','宋诗','song-poetry','','[]','擺磨萬木聲，朝吼暮不止。',108,'全唐诗/poet.song.13000.json','["擺磨萬木聲，朝吼暮不止。", "吹沙作雲飛，物狀顔色死。", "還念江上山，落瀑鳴幾里。", "茅茨松竹間，翠的門前水。", "下窺石穴魚，出入數十尾。", "是時殘照微，古路誰家子。", "羸馬入煙林，區區何若此。", "昔笑今已迷，薄官正如彼。", "何當歸去來，臨流重洗耳。"]'),
('d5488b2c-8348-41d0-ad8f-f6b921df974d','送謝師厚歸南陽','梅堯臣','宋','宋诗','song-poetry','','[]','竹館蔭以風，灑水坐猶熱。',48,'全唐诗/poet.song.13000.json','["竹館蔭以風，灑水坐猶熱。", "念子遠歸時，焦煙起車轍。", "落日原上微，鳥棲人欲別。", "我心明月在，相照異盈缺。"]'),
('23e7d8be-3407-4d89-ac0c-aa1782a4e4a1','資政王侍郎南京留守','梅堯臣','宋','宋诗','song-poetry','','[]','百世興王地，乘時已建都。',120,'全唐诗/poet.song.13000.json','["百世興王地，乘時已建都。", "離宮萬戶寄，京邑四方模。", "尹以名臣擇，朝仍宿哲俞。", "果資卿屬重，將俾國人蘇。", "迎餞車交轍，奔馳士結途。", "許嗟人惠奪，宋遲德恩敷。", "日月天闈近，山河地勢趨。", "壓城隋柳密，開苑漢池枯。", "文物希前代，謳歌得大儒。", "鄒枚跡雖古，賓從豈今無。"]'),
('2d9379f5-64ce-4cb1-b066-8618228ac04b','送通判太博','梅堯臣','宋','宋诗','song-poetry','','[]','相見不在久，見久未必親。',48,'全唐诗/poet.song.13000.json','["相見不在久，見久未必親。", "無爲歲月淺，豈不膠漆均。", "猶嗟欲別日，事疊如排鱗。", "安得獨携酒，遠送秋水濱。"]'),
('ac48ef0e-81cd-4b87-baa4-7d4cba64e186','和韓子華桂花','梅堯臣','宋','宋诗','song-poetry','','[]','莫以天下桂，皆爲月中物。',48,'全唐诗/poet.song.13000.json','["莫以天下桂，皆爲月中物。", "猶言月有兔，野豈無狡窟。", "空山桂花多，豔色粲然發。", "樵客不知貴，奈何薪爨屈。"]'),
('184f32d1-1025-4071-ae24-6d0b0b75c59d','宿安上人門外裴如晦胥平叔來訪','梅堯臣','宋','宋诗','song-poetry','','[]','胥裴喜我至，冒雨夜出城。',72,'全唐诗/poet.song.13000.json','["胥裴喜我至，冒雨夜出城。", "燈前相對語，怪我面骨生。", "爲言憔悴志，因意多不平。", "亦見子頷鬚，長黑已可驚。", "知子有所立，毛髮隨世情。", "子心且如舊，後輩苦前輕。"]'),
('99a2caa2-6a4a-4980-96ca-59d6fabca7d4','宋中道失小女戲寬之','梅堯臣','宋','宋诗','song-poetry','','[]','宋子失汝嬰，苦將造物怪。',48,'全唐诗/poet.song.13000.json','["宋子失汝嬰，苦將造物怪。", "造物本無惡，爾責亦已隘。", "且如工作器，寧復保存壞。", "收淚切勿悲，他時多壻拜。"]'),
('b7d4975f-ca78-4eef-8c2b-235b3f97cb86','刁經臣將歸南徐許予尋隠居之所及亡室墳地因走筆奉呈','梅堯臣','宋','宋诗','song-poetry','','[]','欲居江上山，試與問京峴。',84,'全唐诗/poet.song.13000.json','["欲居江上山，試與問京峴。", "嘗觀鮑家詩，心慕已不淺。", "行當卜結廬，依農事清畝。", "傍葬吾先妻，同穴晚未免。", "買谷勿險深，求岡要平顯。", "松竹應所宜，蒿萊預教翦。", "我志决不移，君言幸須踐。"]'),
('419c2f07-1f64-4df3-9571-2ac11eb9abc0','尉氏縣阮籍嘯堂','梅堯臣','宋','宋诗','song-poetry','','[]','古城多瘦棘，莽莽連荒臺。',72,'全唐诗/poet.song.13000.json','["古城多瘦棘，莽莽連荒臺。", "不見長嘯人，黄土空崔嵬。", "北顧蓬池上，枯廢生蒿萊。", "當時思大梁，還望已徘徊。", "今我復懷昔，豈不傷且哀。", "鳥呼有遺響，英靈同土灰。"]'),
('906f9eca-cb90-49da-be1f-158092df0aae','送趙仲寶永興乾耀提舉捉賊','梅堯臣','宋','宋诗','song-poetry','','[]','知君少以勇，曾向蕭關戰。',60,'全唐诗/poet.song.13000.json','["知君少以勇，曾向蕭關戰。", "橫刀突虜圍，奪馬傷胡箭。", "當時獨免歸，猛毅邊人羨。", "今來提漢卒，寇盜清秦縣。", "未足賀功名，功名它日見。"]'),
('3f9e6b2e-7f58-460c-8203-8efd69310aaf','合流河堤上亭子','梅堯臣','宋','宋诗','song-poetry','','[]','隔河桑榆晚，藹藹明遠川。',48,'全唐诗/poet.song.13000.json','["隔河桑榆晚，藹藹明遠川。", "寒漁下灘時，翠鳥飛我前。", "山藥植瑣細，野性仍所便。", "令人思濠上，獨詠莊叟篇。"]'),
('b6f48340-dd9d-42f4-a53c-e8664edc4d72','早至穎上縣','梅堯臣','宋','宋诗','song-poetry','','[]','夜發曉未止，獨行淮水西。',48,'全唐诗/poet.song.13000.json','["夜發曉未止，獨行淮水西。", "明知寒草露，暗濕瘦驄蹄。", "半滅竹林火，數聞茅屋雞。", "秋天畏殘暑，不爲月光迷。"]'),
('75603126-6beb-4d3f-94de-25f57e066014','欲陰','梅堯臣','宋','宋诗','song-poetry','','[]','鸜鵒知天風，鵓鴣知天雨。',48,'全唐诗/poet.song.13000.json','["鸜鵒知天風，鵓鴣知天雨。", "途路厭塵昏，車馬煩泥沮。", "陰仍老易覺，體質預辛楚。", "安坐與壯年，慎勿忘酒脯。"]'),
('770e1d58-ca9d-4e50-a642-9757f4feb17b','正陽驛舍夢鄭并州寄書開之即三山圖也','梅堯臣','宋','宋诗','song-poetry','','[]','我來清淮側，夢得鄭公書。',60,'全唐诗/poet.song.13000.json','["我來清淮側，夢得鄭公書。", "開書一把玩，乃是三山圖。", "山形雄且邃，筆畫簡而疎。", "紙幅不盈尺，萬仞勢有餘。", "卷置懷袖中，意獲寤已無。"]'),
('72df6986-6ab8-4c0f-903b-b423c1a515ca','新婚','梅堯臣','宋','宋诗','song-poetry','','[]','前日爲新婚，喜今復悲昔。',48,'全唐诗/poet.song.13000.json','["前日爲新婚，喜今復悲昔。", "閫中事有託，月下影免隻。", "慣呼猶口誤，似往頗心積。", "幸皆柔淑姿，稟賦誠所獲。"]'),
('9f9e2c7d-2bd5-4fda-bf31-7ab4928bb5a8','登舟','梅堯臣','宋','宋诗','song-poetry','','[]','向起風沙地，暫假烏榜還。',48,'全唐诗/poet.song.13000.json','["向起風沙地，暫假烏榜還。", "浩然起遠思，欲與魚鳥閒。", "景目洗已清，詠句稱且慳。", "時看秋空雲，雨意濃淡間。"]'),
('156b63eb-8672-4d10-8633-85ee033dd747','諭鷗','梅堯臣','宋','宋诗','song-poetry','','[]','翩翩沙上鷗，安用避漁舟。',24,'全唐诗/poet.song.13000.json','["翩翩沙上鷗，安用避漁舟。", "漁人在魚利，何異爾所求。"]'),
('ececb4e7-c8aa-47b4-9b2b-1970d567bc83','釣蟹','梅堯臣','宋','宋诗','song-poetry','','[]','老蟹飽經霜，紫螯青石殻。',48,'全唐诗/poet.song.13000.json','["老蟹飽經霜，紫螯青石殻。", "肥大窟深淵，曷虞遭食沫。", "香餌與長絲，下沉寧自覺。", "未免利者求，潛潭不爲邈。"]'),
('f7487a7b-c1d1-44d5-ac71-5d530f2be7a4','取𧍧','梅堯臣','宋','宋诗','song-poetry','','[]','東灣暖無沙，有𧍧淵泥下。',48,'全唐诗/poet.song.13000.json','["東灣暖無沙，有𧍧淵泥下。", "輕舠復翠竿，預致曾誰捨。", "刳肉不知數，持爲楚鄉鮓。", "嗜味固足珍，況亦椒橙假。"]'),
('f3c95306-9c67-4ae2-a58c-6ce4446543af','潁水費公渡觀飲牛人','梅堯臣','宋','宋诗','song-poetry','','[]','渡口飲牛歸，村墟夕陽裏。',48,'全唐诗/poet.song.13000.json','["渡口飲牛歸，村墟夕陽裏。", "黄犢未及羣，抱带過寒水。", "利心乃如仁，耕領破不止。", "當時彼何高，獨能譏洗耳。"]'),
('1104fda2-c544-43ef-92e6-d7deafcfb07e','潁水','梅堯臣','宋','宋诗','song-poetry','','[]','潁水苦流瀑，淺平秋與冬。',48,'全唐诗/poet.song.13000.json','["潁水苦流瀑，淺平秋與冬。", "岸深開地勢，底碧寫天容。", "道枉隨灣去，村遥近日逢。", "迷魚是潭曲，寧見窟蛟龍。"]'),
('d141cf9a-eef2-4a33-be71-8757187f44e4','打魚','梅堯臣','宋','宋诗','song-poetry','','[]','插葦截灣流，寒魚未能越。',48,'全唐诗/poet.song.13000.json','["插葦截灣流，寒魚未能越。", "安知罟師意，設網遮其闕。", "不須芳餌懸，何待清歌發。", "所獲勝綸竿，寧聞憂澤竭。"]'),
('debd8058-6bd4-451f-915e-ed2c3dbae2ba','八日就湖上會飲呈晏相公','梅堯臣','宋','宋诗','song-poetry','','[]','明當是重九，黄菊還開不。',48,'全唐诗/poet.song.13000.json','["明當是重九，黄菊還開不。", "先將掇其英，秋逕未能有。", "頹齡無以制，但不負此酒。", "紅頰誰使歌，公憐牛馬走。"]'),
('3610cb59-0ee0-4f38-ba73-1437a386109d','九日擷芳園會呈晏相公','梅堯臣','宋','宋诗','song-poetry','','[]','今日始見菊，雖見未全開。',60,'全唐诗/poet.song.13000.json','["今日始見菊，雖見未全開。", "猶勝昔無酒，持望白衣來。", "破纇浮金英，雜蟻已盈杯。", "何必探丹萸，結佩上高臺。", "自不愧佳節，安聽飛鴻哀。"]'),
('4ce90461-08cf-4d58-b8fc-50d08e8db2b9','謝晏相公','梅堯臣','宋','宋诗','song-poetry','','[]','刻意向詩筆，行將三十年。',48,'全唐诗/poet.song.13000.json','["刻意向詩筆，行將三十年。", "嘗經長者目，未及古人肩。", "昔慕荀文若，多稱王仲宣。", "今慙此微賤，重辱相君憐。"]'),
('d9988d10-b421-4a7c-9362-a1c9241cb205','道中謝晏相公寄酒','梅堯臣','宋','宋诗','song-poetry','','[]','赬泥墨印幾壺醁，將慰窮途阮步兵。',32,'全唐诗/poet.song.13000.json','["赬泥墨印幾壺醁，將慰窮途阮步兵。", "一夜臨流對明月，舉杯愁聽雁來聲。"]'),
('6ab4841d-4807-4788-83e7-73704bdfa0df','水苔','梅堯臣','宋','宋诗','song-poetry','','[]','深苔何所若，苦詠費毫尖。',48,'全唐诗/poet.song.13000.json','["深苔何所若，苦詠費毫尖。", "繞繞水仙髮，茸茸蛟客髯。", "綠縈秋石浄，嫩值翠篙黏。", "尚芼參差荇，薄言無此嫌。"]'),
('b348ce57-ff92-4577-b851-c7077824d94f','新雁','梅堯臣','宋','宋诗','song-poetry','','[]','寒雁與寒來，夜落汀洲宿。',24,'全唐诗/poet.song.13000.json','["寒雁與寒來，夜落汀洲宿。", "泊船人不寐，月下聲相續。"]'),
('aa329628-b745-4cad-bd93-68b6e8255701','依韻和晏相公','梅堯臣','宋','宋诗','song-poetry','','[]','微生守賤貧，文字出肝膽。',120,'全唐诗/poet.song.13000.json','["微生守賤貧，文字出肝膽。", "一爲清潁行，物象頗所覽。", "泊舟寒潭陰，野興入秋菼。", "因吟適情性，稍欲到平淡。", "苦辭未圓熟，刺口劇菱芡。", "方將挹溟海，器小已瀲灧。", "廣流不拒細，愧抱獨慊慊。", "疲馬去軒時，戀嘶芻秣減。", "茲繼周南篇，短橈寧及艦。", "試知不自量，感涕屢揮摻。"]'),
('aacba401-e16d-4154-b3fe-8f93289dd3d8','以近詩贄尚書晏相公忽有酬贈之什稱之甚過不敢輒有所敘謹依韻綴前日坐末教誨之言以和','梅堯臣','宋','宋诗','song-poetry','','[]','嘗記論詩語，辭卑名亦淪。',48,'全唐诗/poet.song.13000.json','["嘗記論詩語，辭卑名亦淪。", "寧從陶令野，不取孟郊新。", "琢礫難希寶，噓枯强費春。", "今將風什付，可與二南陳。"]'),
('aea103c8-f6a3-4163-bc8e-8ec337381c71','途中寄上尚書晏相公二十韻','梅堯臣','宋','宋诗','song-poetry','','[]','驚飇入林鴉亂飛，舞空落葉相追隨。',320,'全唐诗/poet.song.13000.json','["驚飇入林鴉亂飛，舞空落葉相追隨。", "秋權摧物不見跡，但使萬古生愁悲。", "登山臨水昔感別，身作旅人安得宜。", "單舟匹婦更無婢，朝餐每愧婦親炊。", "平生獨以文字樂，曾未敢恥貧賤爲。", "官雖寸進實過分，名姓已被賢者知。", "疏愚生不謁豪貴，守此退縮行將衰。", "潁州相公秉道德，一見不以論高卑。", "久調元化費精力，猶且未倦刪書詩。", "唐之文章剔蕪穢，纖悉寧有差毫釐。", "謂其躭學可與語，便語淵奧袪佹疑。", "浮言近意不歷口，直欲海窟拏蛟螭。", "再拜膝前荷勤誨，垂橐稇載歸忘饑。", "解艇水驛無幾舍，新詩又遣牙兵持。", "上言行李覽物景，聊可與婦陳酒巵。", "下言狂斐頗及古，陶韋比格吾不私。", "相公貴且事翰墨，我輩豈得專遊嬉。", "今將蒿芹薦俎豆，定亦不以微薄遺。", "嘗令有詠無巨細，當因川陸舟車貽。", "日對順流思疾置，老魚姦怯潛鱗鬐。"]'),
('736b938e-9084-4761-94f5-d261bcebdc43','舟中夜與家人飲','梅堯臣','宋','宋诗','song-poetry','','[]','月出斷岸口，影照別舸背。',48,'全唐诗/poet.song.13000.json','["月出斷岸口，影照別舸背。", "且獨與婦飲，頗勝俗客對。", "月漸上我席，暝色亦稍退。", "豈必在秉燭，此景已可愛。"]'),
('201479ff-e8cd-492c-89c1-7de101c69e97','舟中行自采枸杞子','梅堯臣','宋','宋诗','song-poetry','','[]','野岸竟多杞，小實霜且丹。',72,'全唐诗/poet.song.13000.json','["野岸竟多杞，小實霜且丹。", "繫舟聊以掇，粲粲忽盈盤。", "助吾苦羸苶，豈必採琅玕。", "自異驕華人，百金求祕丸。", "昔聞王子喬，上帝降玉棺。", "此焉即不免，但願在世安。"]'),
('baccb69a-a27e-41f2-ad37-80855f931017','蔡河阻淺','梅堯臣','宋','宋诗','song-poetry','','[]','陸乏百鈞駞，水假孤艇進。',72,'全唐诗/poet.song.13000.json','["陸乏百鈞駞，水假孤艇進。", "潁苦灣灘長，曲折劇篆印。", "蔡方阻淺涸，寸步出慳吝。", "膠舟看在前，暗磧疑難慎。", "誰能使奡盪，空自思禹濬。", "丈夫少壯時，必在馳駔駿。"]'),
('e9d52905-b426-443f-a3d3-4b242dad074e','黄駁','梅堯臣','宋','宋诗','song-poetry','','[]','維舟飯孤村，隔岸見黄駁。',48,'全唐诗/poet.song.13000.json','["維舟飯孤村，隔岸見黄駁。", "瘦牧正苦饑，瘡鳥復下啄。", "閔心無柘彈，投塊徒自數。", "力小不能中，汗顔慙且渥。"]'),
('ca5ebc84-12a5-4813-9bf4-bf69dc2def2e','入澤王河口','梅堯臣','宋','宋诗','song-poetry','','[]','遠水路已別，古汊未窮源。',48,'全唐诗/poet.song.13000.json','["遠水路已別，古汊未窮源。", "定知前山雨，瀑泳至且渾。", "暗生秋草下，稍復夏潦痕。", "更去待月上，猶應可到門。"]'),
('a03ceaca-98bc-4d9d-88f6-8cf001afe15d','西華逢李令子翼','梅堯臣','宋','宋诗','song-poetry','','[]','適從潁水歸，道逢西華長。',48,'全唐诗/poet.song.13000.json','["適從潁水歸，道逢西華長。", "不見二十年，顔鬚我非曩。", "君問洛陽日，舊友多泉壤。", "更別如前時，應復少吾黨。"]'),
('8f94d0cd-66a3-43d7-bb2c-a4b948f58c86','合流值雨與曹光道飲','梅堯臣','宋','宋诗','song-poetry','','[]','秋風嚎衰林，秋雨阻歸客。',48,'全唐诗/poet.song.13000.json','["秋風嚎衰林，秋雨阻歸客。", "頼有故時交，舉杯聊岸幘。", "談兵與論文，曾不涉陳迹。", "必竟無所施，醉去思泉石。"]'),
('936dce9c-9888-4a5d-8cae-4e0aeb53a829','寄送謝師厚餘姚宰','梅堯臣','宋','宋诗','song-poetry','','[]','我從淮上歸，君向海澨去。',120,'全唐诗/poet.song.13000.json','["我從淮上歸，君向海澨去。", "安知無幾舍，邂逅不相遇。", "頗知飛空雲，到月不得附。", "月行既不留，雲亦值風故。", "誠知會合難，豈是忘所赴。", "我雖躡新屩，心不捨舊屨。", "誰謂若世人，食瓜思棄瓠。", "君南我赴北，日見陽雁度。", "茲欲遠寄音，雁行高且鶩。", "但誦金石言，於時儻無忤。"]'),
('010746b2-aef1-4c1b-8781-fbeb0dea665a','李密學遺苔醤脯云是自採爲之','梅堯臣','宋','宋诗','song-poetry','','[]','潩流寒且急，岸草已凋摧。',48,'全唐诗/poet.song.13000.json','["潩流寒且急，岸草已凋摧。", "石髮尚堪把，江人曾不來。", "誰知烏榜去，留採碧潭隈。", "持作吳鄉味，能令案淥杯。"]'),
('29b78871-5edd-4272-be53-60f28bd4f590','陽翟縣城凝嵩亭','梅堯臣','宋','宋诗','song-poetry','','[]','西北望嵩色，憶上大室時。',48,'全唐诗/poet.song.13000.json','["西北望嵩色，憶上大室時。", "陟彼已不淺，坐此安能知。", "今誰絕壁下，但見前峯危。", "正與曩未異，目存迹焉追。"]'),
('be2027ca-147f-4ad3-8c81-eaedfdb0431b','王仲儀寄鬬茶','梅堯臣','宋','宋诗','song-poetry','','[]','白乳葉家春，銖兩直錢萬。',48,'全唐诗/poet.song.13000.json','["白乳葉家春，銖兩直錢萬。", "資之石泉味，特以陽芽嫩。", "宜言難購多，串片大可寸。", "謬爲識別人，予生固無恨。"]'),
('5eef0401-87c0-480f-b7b8-30a315ebefea','次韻和王道損風雨戲寄','梅堯臣','宋','宋诗','song-poetry','','[]','小雪纔過大雪前，蕭蕭風雨紙窗穿。',32,'全唐诗/poet.song.13000.json','["小雪纔過大雪前，蕭蕭風雨紙窗穿。", "而今共唱新詞飲，切莫相邀薄暮天。"]'),
('df229485-d9f5-4d0b-82f6-78e7a694afa9','鬬鵪鶉孫曼叔邀作','梅堯臣','宋','宋诗','song-poetry','','[]','脫命秋隼下，鳴鬭自爲勇。',48,'全唐诗/poet.song.13000.json','["脫命秋隼下，鳴鬭自爲勇。", "爭雄在數粒，一敗勢莫擁。", "慙將縮袖間，懷負默而拱。", "勝且勿苦欣，猶驚辱與寵。"]'),
('0807e403-66b5-4343-9e5f-d5022d8fb401','和道損欲雪與家人小兒輩飲','梅堯臣','宋','宋诗','song-poetry','','[]','陰雲濃壓野，風獵樹高鳴。',48,'全唐诗/poet.song.13000.json','["陰雲濃壓野，風獵樹高鳴。", "寒禽並枝立，頗以見物情。", "目前兩稚子，爲慰豈異卿。", "欲置一壺酒，且獨對婦傾。"]'),
('07614297-0b93-4139-b969-fa83be6010bf','韓持國邀賦鬬山鵲','梅堯臣','宋','宋诗','song-poetry','','[]','俗有巧鬭心，畜此巧鬭禽。',48,'全唐诗/poet.song.13000.json','["俗有巧鬭心，畜此巧鬭禽。", "搏擊無迅節，爪觜自相侵。", "胡能知遠人，角勝合百金。", "鳳皇安在哉，徒此望丹岑。"]'),
('baca85c4-c1f5-4739-ba98-2200094dcd03','依韻和酬韓仲文昆季聯句見謝','梅堯臣','宋','宋诗','song-poetry','','[]','冬日晴且暖，林塘思浄居。',240,'全唐诗/poet.song.13000.json','["冬日晴且暖，林塘思浄居。", "往興都未盡，遂經韓氏廬。", "韓氏兄弟賢，各各趨義塗。", "吾儕與之游，何異田蘇俱。", "經疑反此質，學陋慙無餘。", "況茲諸少年，高論傾國都。", "以及治民術，縱橫無所拘。", "又涉方外說，於道曾不殊。", "詩評杜兼李，字法褚與虞。", "啜茗豈非好，啗栗强爲娛。", "久厭官局檢，聊休體質舒。", "次第極言笑，左右排圖書。", "終日欣博約，貶異正則扶。", "所頼存泛愛，未以我爲愚。", "持歸接士論，頗亦類販沽。", "復聯長詩來，味若餐瓊腴。", "其辭多自損，似欲大厥譽。", "顔子乃庶幾，仲尼稱弗如。", "不厭會遇頻，雲龍實相須。", "最和躡麟趾，舉步未敢渝。"]'),
('782c9387-2d2c-493d-b6bf-4bf04a61c794','種藥','梅堯臣','宋','宋诗','song-poetry','','[]','雲外陽翟山，實與嵩少接。',96,'全唐诗/poet.song.13000.json','["雲外陽翟山，實與嵩少接。", "山中採藥人，能自辨苗葉。", "當須斸其根，以遂素所愜。", "野籜包舊土，遠置風雨捷。", "故本含新芽，枯莛带空莢。", "植雖乖地勢，培壅得專輒。", "冬誰論臭香，春定引蜂蝶。", "豈惟識草木，庶用補羸苶。"]'),
('46f16648-3f60-4300-bd99-78c886b44bd6','答韓六玉汝戲題西軒','梅堯臣','宋','宋诗','song-poetry','','[]','吾軒今於水，吾居易爲足。',48,'全唐诗/poet.song.13000.json','["吾軒今於水，吾居易爲足。", "誰與哦其間，風窗數竿竹。", "雖無泉石清，尚不愧茅屋。", "所樂違俗暄，此趣大已熟。"]'),
('3c82e6a3-ea1d-42f1-bf61-37503cc6594b','和韓五持國乞分道損山藥之什','梅堯臣','宋','宋诗','song-poetry','','[]','不種東陵瓜，不利千畦韭。',120,'全唐诗/poet.song.13000.json','["不種東陵瓜，不利千畦韭。", "山藥數十本，带土移野叟。", "故葉萎未醒，傷根亦何咎。", "既爲君子好，豈與騷人負。", "騷人比畫工，丹青出其口。", "欲分欄下苗，馳奴仍置簍。", "主人可無吝，所尚非獨有。", "從茲各勤灌，肯在園蔬後。", "今雖勝曝蓄，畢意資玉臼。", "人事固已然，祕方看繫肘。"]'),
('b9b6dfc2-030a-43fc-8001-6f4e18e641aa','送長陵清辨師歸寧','梅堯臣','宋','宋诗','song-poetry','','[]','山房古柏暗，近在漢陵邊。',48,'全唐诗/poet.song.13000.json','["山房古柏暗，近在漢陵邊。", "天供不爲樂，母心常所懸。", "朝途髮根冷，暮野鳥行先。", "子道豈殊衆，誰云絕世緣。"]'),
('517647aa-1e35-4f60-a73b-15350632e631','依韻和李密學會流杯亭','梅堯臣','宋','宋诗','song-poetry','','[]','園林固足勝，景著必人賢。',48,'全唐诗/poet.song.13000.json','["園林固足勝，景著必人賢。", "將泛杯中物，遠分湖水泉。", "來從百花底，轉向衆賓前。", "易醉緣多病，陪公愧少年。"]'),
('a0b00a0b-0b07-489c-911a-83277e7c4321','依韻和韓子華陪王舅道損宴集','梅堯臣','宋','宋诗','song-poetry','','[]','雲低未成雪，寒氣已侵席。',192,'全唐诗/poet.song.13000.json','["雲低未成雪，寒氣已侵席。", "凍醪傾白濁，乾果列紫赤。", "風微時破面，亭敞宜張帟。", "來望野興通，古城何額額。", "邀射弓鈞開，破的翦羽白。", "助中聲喧呼，不覺屢傾幘。", "醉驚一發功，誰許百金易。", "非等將帥能，聊將賓友適。", "中酒作暴謔，心親語多劇。", "吾儕固不羈，安可限常格。", "去忌無俗流，起酌驚臧獲。", "八龍觀諸韓，頭角相戢迫。", "參差玉峯前，愛慕不知夕。", "誰嗟短景移，能使吝情釋。", "爲賀主人翁，賢甥無久隔。", "此會舉世稀，頻頻奚所惜。"]'),
('5eee6cea-1d00-4ff6-895c-0ad16655ec93','飲韓仲文家','梅堯臣','宋','宋诗','song-poetry','','[]','飲酒衆所嗜，未若朋會樂。',120,'全唐诗/poet.song.13000.json','["飲酒衆所嗜，未若朋會樂。", "終日不爲荒，於時豈多怍。", "坐客十餘人，七子實棣萼。", "杯行發嚴令，孰不資善謔。", "巧詞劇猱捷，辨機如弩彍。", "醉舌强且遲，罰觥奚屢酌。", "正言訐詭諛，簡禮去酬酢。", "迭嘲果與蔬，相呼花間藥。", "是非不親親，笑語何落落。", "夜歸歡有餘，孩稚扶仍噱。"]'),
('5eed89a4-6ba7-49c5-b9f9-efc8655cbde3','玉汝贈永興冰蜜梨十顆','梅堯臣','宋','宋诗','song-poetry','','[]','梨傳真定間，其甘曰如蜜。',48,'全唐诗/poet.song.13000.json','["梨傳真定間，其甘曰如蜜。", "君得咸陽中，味兼冰作質。", "遺之析朝酲，亦以蠲煩疾。", "吾兒勿多嗜，不比盤中栗。"]'),
('78c87b2f-0825-43c6-a30f-fdc8a09b77f6','王道損贈永興冰蜜梨四顆','梅堯臣','宋','宋诗','song-poetry','','[]','名果出西州，霜前競以收。',48,'全唐诗/poet.song.13000.json','["名果出西州，霜前競以收。", "老嫌冰熨齒，渴愛蜜過喉。", "色向瑶盤發，甘應蟻酒投。", "仙桃無此比，不畏小兒偷。"]'),
('f1590fb6-3eb2-4758-821a-fde8b71654b5','寄題滁州豐樂亭','梅堯臣','宋','宋诗','song-poetry','','[]','泠泠幽谷泉，近在青峯下。',144,'全唐诗/poet.song.13000.json','["泠泠幽谷泉，近在青峯下。", "使君去窮源，林外留車馬。", "一徑穿篠深，蔽日復瀟灑。", "行盡逢泓澄，翠影如可瀉。", "雲樹陰其旁，造物將有假。", "引水開石池，結宇覆碧瓦。", "乃知愛玩心，朝夕未忍捨。", "近移溪上石，怪古蒼蘚惹。", "芍藥廣陵來，山卉雜夭冶。", "春禽時相鳴，賓從不應寡。", "欲問淮南趣，還思洛陽社。", "勝事已不辜，吟觴無倦把。"]'),
('41fe003c-5e4e-4a67-b0d5-8f7650190827','和韓仲文西齋閒夜有懷道損舅及予','梅堯臣','宋','宋诗','song-poetry','','[]','冬日每苦短，方愛夜漏永。',48,'全唐诗/poet.song.13000.json','["冬日每苦短，方愛夜漏永。", "積雲寒擁齋，徘徊延月影。", "獨能懷親友，出門見參井。", "是時發清詠，筆若天驥騁。"]'),
('7151a48c-f267-41af-8060-f15f792147eb','前此諸韓來飲獨仲連以小兒病不至明日仲連有夜坐見懷之什因成答章','梅堯臣','宋','宋诗','song-poetry','','[]','夜與賢豪飲，方聞默坐時。',48,'全唐诗/poet.song.13000.json','["夜與賢豪飲，方聞默坐時。", "我斟相樂酒，君詠寄來詩。", "莫恨殊喧寂，真緣篤愛慈。", "何當因雪興，過此未應遲。"]'),
('84230e85-eba9-4c43-bc83-a537c49b1c2b','奉和子華持國玉汝來飲西軒','梅堯臣','宋','宋诗','song-poetry','','[]','我誠官局冷，終日事靡括。',252,'全唐诗/poet.song.13000.json','["我誠官局冷，終日事靡括。", "每躭古人書，似與世俗闊。", "同道三四人，來過慰饑渴。", "迭相陳語言，曾未厭刀呾。", "自中將過晡，留飯具麄糲。", "薄酒繼以斟，不覺寒日沒。", "愚妻方罷沐，供飯愧倉卒。", "凍婢昧煎和，親調首忘髴。", "每食各驚顧，誰謂不黔突。", "倦僕暖吾薪，饑馬飽吾秣。", "馬無歸嘶聲，僕有顔色活。", "安穩不知疲，明釭仍爲撥。", "醉言實無次，曾未窮本末。", "諸君競相先，出口論莫奪。", "復云天地間，此能有幾達。", "我聞顔汗下，恐後謗難遏。", "其間常有言，但未見疵齾。", "終當輕有若，悔目已屢䀣。", "信哉羣玉林，豈得依朽枿。", "吾心爲之然，收舌如斷割。", "寄音謝豪俊，茲藴只圭撮。"]'),
('c3725322-ec0c-4b28-bae6-c14976c7456e','和道損喜雪','梅堯臣','宋','宋诗','song-poetry','','[]','密雪已迎臘，隨風來拂巾。',96,'全唐诗/poet.song.13000.json','["密雪已迎臘，隨風來拂巾。", "偏知寒夜屋，不管醉歸人。", "暗積空庭合，偷裝衆樹新。", "沃田將望歲，壓癘且忘貧。", "薄厚曾無意，飄揚似有因。", "既能先覆物，乃見未饒春。", "作陣從天落，何功得地均。", "暫欣供一賞，惜逐馬蹄塵。"]'),
('3031596c-b88a-40a5-a3ff-c9b48e3eec1d','答持國遺魦魚皮膾','梅堯臣','宋','宋诗','song-poetry','','[]','海魚沙玉皮，翦膾金齏釅。',48,'全唐诗/poet.song.13000.json','["海魚沙玉皮，翦膾金齏釅。", "遠持享佳賓，豈用飾寶劍。", "予貧食幾稀，君愛則已泛。", "終當飯葵藿，此味不爲欠。"]'),
('7fb1ad98-8ace-48b2-a140-a3a0a2b5939a','與仲文子華陪觀新水磑','梅堯臣','宋','宋诗','song-poetry','','[]','湖壖此興磑，許俗見仍稀。',48,'全唐诗/poet.song.13000.json','["湖壖此興磑，許俗見仍稀。", "激射聊因勢，回環豈息機。", "水如巖下過，人悟雪中歸。", "坐想韓夫子，心應不道非。"]'),
('e2865e37-f15a-42c2-b700-8737ad5c6eec','與道損仲文子華陪泛西湖','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','冰消湖已綠，渺渺鴨頭春。',48,'全唐诗/poet.song.13000.json','["冰消湖已綠，渺渺鴨頭春。", "船學吳兒刺，吟稀楚老新。", "對山憐去鳥，隔樹識游人。", "誰念滄江上，風柔採白蘋。"]'),
('d2bd2484-dad7-4d3b-bff1-c46883d45a8c','和持國石蘚','梅堯臣','宋','宋诗','song-poetry','','[]','石根雲常蒸，老蘚密於毯。',48,'全唐诗/poet.song.13000.json','["石根雲常蒸，老蘚密於毯。", "濕翠連澗陰，浄綠繞巖坎。", "不異泉上芹，丰茸猶可擥。", "安知山中客，遠寄趣已淡。"]'),
('d053feb7-ad03-4994-a685-1c32d4156224','同諸韓飲曼叔家','梅堯臣','宋','宋诗','song-poetry','','[]','富貴豐盤餐，日可侑清角。',84,'全唐诗/poet.song.13000.json','["富貴豐盤餐，日可侑清角。", "不與賢者俱，飽食何所學。", "吾友雖日貧，邀賞不辭數。", "質衣爲酒肴，出論輕管樂。", "其饌精且甘，刀几孰親握。", "是時予苦眩，引去意頗確。", "羸馬雪中歸，醉醒誰復較。"]'),
('8967b5ac-c33a-4078-8557-23add56c3206','和仲文西湖野步至新堰二首  其一','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','决决堰根水，層層湖上田。',48,'全唐诗/poet.song.13000.json','["决决堰根水，層層湖上田。", "寒魚猶著底，白鷺已飛前。", "履惜春泥滑，衣從澀蔓牽。", "偶來成野望，歸興自留連。"]'),
('0b0a1ec1-1329-4d06-a2f4-21ecbe54e3fb','和仲文西湖野步至新堰二首  其二','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','潭上水容暖，野中寒吹橫。',48,'全唐诗/poet.song.13000.json','["潭上水容暖，野中寒吹橫。", "行塘人已晚，吟步日難更。", "凍地坼枯龜，斷冰流破鏡。", "王都且不遠，樂此林泉性。"]'),
('6961feb5-9da6-4af8-8621-adc1e7c6b29c','送韓奉禮','梅堯臣','宋','宋诗','song-poetry','','[]','將欲侍親去，獨要予贈言。',48,'全唐诗/poet.song.13000.json','["將欲侍親去，獨要予贈言。", "世風還自有，文體不須論。", "稍愛春波急，微生野岸根。", "舟行寧覺遠，幾日到都門。"]'),
('d4f6e35d-88ed-4b40-99b5-a21aa195f2bb','諸韓來會別','梅堯臣','宋','宋诗','song-poetry','','[]','諸韓行有日，別思更依依。',48,'全唐诗/poet.song.13000.json','["諸韓行有日，別思更依依。", "獨歎從予少，還看似子稀。", "呼童聊奏酒，灑水爲開扉。", "蘇合染裘美，雪中閶闔歸。"]'),
('b97b9d7f-11b2-43d7-a193-2c6439b62116','送仲文','梅堯臣','宋','宋诗','song-poetry','','[]','三年不出戶，考行閭井聞。',48,'全唐诗/poet.song.13000.json','["三年不出戶，考行閭井聞。", "近俗遂知化，豈非由所薰。", "御琴趨國門，何必長守墳。", "美哉若君子，忠可移於君。"]'),
('8f43818d-9455-476f-b161-3c5c800f588b','送子華','梅堯臣','宋','宋诗','song-poetry','','[]','識君雖恨晚，說詩屢解頤。',48,'全唐诗/poet.song.13000.json','["識君雖恨晚，說詩屢解頤。", "吾徒固難合，所合終不移。", "冒寒躍馬來，且言行有期。", "河上冰始坼，輕棹去未遲。"]'),
('bd717ec7-9a48-40bc-a335-0b067e5a5755','送仲連','梅堯臣','宋','宋诗','song-poetry','','[]','別緒如亂絲，欲理還不可。',48,'全唐诗/poet.song.13000.json','["別緒如亂絲，欲理還不可。", "却悲嬌女詩，寧戀更效左。", "是時遠道懷，紛紛上歸舸。", "憐君正如此，豈任風雨俀。"]'),
('e19ddb7a-385f-4782-8cd4-73da7d6eb035','送玉汝','梅堯臣','宋','宋诗','song-poetry','','[]','談笑去拘忌，乃見相與深。',48,'全唐诗/poet.song.13000.json','["談笑去拘忌，乃見相與深。", "風騷得往返，但見非知音。", "明日車馬北，豈不動離襟。", "春風蘼蕪綠，別恨生遥岑。"]'),
('0b5e356b-ee95-4e11-a11a-a4e4c4bf4b5a','玉汝遺橄欖','梅堯臣','宋','宋诗','song-poetry','','[]','南國青青果，涉冬知始摘。',48,'全唐诗/poet.song.13000.json','["南國青青果，涉冬知始摘。", "雖咀澀難任，竟當甘莫敵。", "來從萬里外，或以苦口擲。", "所投同木瓜，欲報無瓊璧。"]'),
('9e6ac0ab-e955-410f-9d02-6bd4272dbc82','和王待制出郊馬上口占寄兄道損次韻','梅堯臣','宋','宋诗','song-poetry','','[]','日暖寒郊不起風，使君車騎出城中。',32,'全唐诗/poet.song.13000.json','["日暖寒郊不起風，使君車騎出城中。", "遥知望處思兄弟，鴻雁連連下遠空。"]'),
('ad448e54-5df3-4ec2-bb95-055f3b6799de','寄題蘇子美滄浪亭','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','聞買滄浪水，遂作滄浪人。',216,'全唐诗/poet.song.13000.json','["聞買滄浪水，遂作滄浪人。", "置亭滄浪上，日與滄浪親。", "宜曰滄浪叟，老向滄浪濱。", "滄浪何處是，洞庭相與鄰。", "竹樹種已合，魚蟹時可緡。", "春羹芼白菘，夏鼎烹紫蓴。", "黄柑摘霜晚，香稻炊玉新。", "行吟招隠詩，懶戴醉中巾。", "憂患兩都忘，還往誰與頻。", "昨得滁陽書，語彼事頗真。", "曩子初去國，我勉勿迷津。", "四方不可之，中土百物淳。", "今子居所樂，豈不遠埃塵。", "被髮異泰伯，結客非春申。", "莫與吳俗尚，吳俗多文身。", "蛟龍刺兩股，未變此遺民。", "讀書本爲道，不計賤與貧。", "當須化閭里，庶使禮義臻。"]'),
('a76ea85a-cc1d-4299-9102-b83865ecdda7','送河東轉運劉察院','梅堯臣','宋','宋诗','song-poetry','','[]','塞郡屯師久，飛芻始得人。',96,'全唐诗/poet.song.13000.json','["塞郡屯師久，飛芻始得人。", "權傾擁旄將，詔輟繡衣臣。", "舊里過京洛，辭家渡盟津。", "紫裘蘇合染，驄馬玉環辰。", "榆莢關頭雨，梨花谷口春。", "高車方陟險，豐膳暫違親。", "山勢北臨岱，地雄西隔秦。", "行臺知不遠，能使問安頻。"]'),
('02cd1c78-60e6-42bf-bd5d-0b0773345e6b','次韻和玉汝對月見懷西軒','梅堯臣','宋','宋诗','song-poetry','','[]','坐見沙頭月，復憐衣上輝。',48,'全唐诗/poet.song.13000.json','["坐見沙頭月，復憐衣上輝。", "正如從我飲，還欲照君歸。", "相逐影徒是，共嗟歡已非。", "夜深依岸落，寒色入傷違。"]');
